import { NextRequest, NextResponse } from "next/server";

import { apiHandlerWithParams } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { notFoundError } from "@/shared/errors/app-error";
import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import { assertAiPathRunAccess, requireAiPathsAccess } from "@/features/ai-paths/server/access";

async function GET_handler(
  req: NextRequest,
  _ctx: ApiHandlerContext,
  params: { runId: string }
): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    const runId = params.runId;
    const repo = getPathRunRepository();
    const run = await repo.findRunById(runId);
    if (!run) {
      throw notFoundError("Run not found", { runId });
    }
    assertAiPathRunAccess(access, run);
    const nodes = await repo.listRunNodes(runId);
    const events = await repo.listRunEvents(runId);
    return NextResponse.json({ run, nodes, events });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.detail",
      fallbackMessage: "Failed to load run details",
    });
  }
}

export const GET = apiHandlerWithParams<{ runId: string }>(GET_handler, { source: "ai-paths.runs.detail" });

import { NextRequest } from "next/server";

import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { notFoundError } from "@/shared/errors/app-error";
import { assertAiPathRunAccess, requireAiPathsAccess } from "@/features/ai-paths/server/access";

const TERMINAL_STATUSES = new Set([
  "completed",
  "failed",
  "canceled",
  "dead_lettered",
]);
const normalizeLimit = (value: number, fallback: number) => {
  if (!Number.isFinite(value) || value <= 0) return fallback;
  return Math.floor(value);
};
const EVENT_BATCH_LIMIT = normalizeLimit(
  Number(process.env.AI_PATHS_STREAM_EVENT_LIMIT ?? "200"),
  200
);

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

const toISOStringSafe = (value?: Date | string | null) => {
  if (!value) return null;
  if (typeof value === "string") return value;
  return value.toISOString();
};

const parseSinceParam = (value: string | null): Date | null => {
  if (!value) return null;
  const parsed = new Date(value);
  if (!Number.isNaN(parsed.getTime())) return parsed;
  const numeric = Number(value);
  if (Number.isFinite(numeric)) {
    const asDate = new Date(numeric);
    if (!Number.isNaN(asDate.getTime())) return asDate;
  }
  return null;
};

export async function GET(
  req: NextRequest,
  ctx: { params: Promise<{ runId: string }> }
): Promise<Response> {
  const { runId } = await ctx.params;
  let access;
  try {
    access = await requireAiPathsAccess();
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.stream",
      fallbackMessage: "Unauthorized.",
    });
  }
  const repo = getPathRunRepository();
  const initialRun = await repo.findRunById(runId);
  if (!initialRun) {
    return createErrorResponse(notFoundError("Run not found", { runId }), {
      request: req,
      source: "ai-paths.runs.stream",
      fallbackMessage: "Run not found",
    });
  }
  try {
    assertAiPathRunAccess(access, initialRun);
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.stream",
      fallbackMessage: "Forbidden.",
    });
  }
  const encoder = new TextEncoder();
  const sinceParam = new URL(req.url).searchParams.get("since");
  const initialSince = parseSinceParam(sinceParam);

  let cancelled = false;
  req.signal.addEventListener("abort", () => {
    cancelled = true;
  });

  const stream = new ReadableStream({
    async start(controller) {
      const send = (event: string, data: unknown) => {
        const payload = `event: ${event}\n` + `data: ${JSON.stringify(data)}\n\n`;
        controller.enqueue(encoder.encode(payload));
      };

      const run = initialRun;

      send("ready", { runId });
      send("run", run);

      let lastRunUpdatedAt = toISOStringSafe(run.updatedAt ?? run.createdAt);
      let lastNodeUpdatedAt: string | null = null;
      let lastEventCreatedAt = initialSince
        ? initialSince.toISOString()
        : null;

      while (!cancelled) {
        const nextRun = await repo.findRunById(runId);
        if (!nextRun) {
          send("error", { message: "Run not found", runId });
          break;
        }

        const nextRunUpdatedAt = toISOStringSafe(
          nextRun.updatedAt ?? nextRun.createdAt
        );
        if (nextRunUpdatedAt && nextRunUpdatedAt !== lastRunUpdatedAt) {
          send("run", nextRun);
          lastRunUpdatedAt = nextRunUpdatedAt;
        }

        const nodes = await repo.listRunNodes(runId);
        const maxNodeUpdatedAt = nodes.reduce<string | null>((max, node) => {
          const candidate = toISOStringSafe(node.updatedAt ?? node.createdAt);
          if (!candidate) return max;
          if (!max) return candidate;
          return candidate > max ? candidate : max;
        }, null);
        if (maxNodeUpdatedAt && maxNodeUpdatedAt !== lastNodeUpdatedAt) {
          send("nodes", nodes);
          lastNodeUpdatedAt = maxNodeUpdatedAt;
        }

        const events = await repo.listRunEvents(runId, {
          ...(lastEventCreatedAt ? { since: lastEventCreatedAt } : {}),
          limit: EVENT_BATCH_LIMIT + 1,
        });
        if (events.length > 0) {
          const overflow = events.length > EVENT_BATCH_LIMIT;
          const batch = overflow ? events.slice(0, EVENT_BATCH_LIMIT) : events;
          send("events", { events: batch, overflow, limit: EVENT_BATCH_LIMIT });
          const latestEventTime = batch.reduce<string | null>((max, event) => {
            const candidate = toISOStringSafe(event.createdAt);
            if (!candidate) return max;
            if (!max) return candidate;
            return candidate > max ? candidate : max;
          }, lastEventCreatedAt);
          if (latestEventTime) {
            lastEventCreatedAt = latestEventTime;
          }
        }

        if (TERMINAL_STATUSES.has(nextRun.status)) {
          send("done", { runId, status: nextRun.status });
          break;
        }

        await sleep(1000);
      }

      controller.close();
    },
    cancel() {
      cancelled = true;
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache, no-transform",
      Connection: "keep-alive",
    },
  });
}

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { resumePathRun } from "@/features/ai-paths/services/path-run-service";
import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import { startAiPathRunQueue } from "@/features/jobs/server";
import {
  assertAiPathRunAccess,
  enforceAiPathsActionRateLimit,
  requireAiPathsAccess,
} from "@/features/ai-paths/server/access";

const requeueSchema = z.object({
  runIds: z.array(z.string().trim().min(1)).optional(),
  pathId: z.string().trim().optional().nullable(),
  query: z.string().trim().optional(),
  mode: z.enum(["resume", "replay"]).optional(),
  limit: z.number().int().min(1).max(1000).optional(),
});

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    enforceAiPathsActionRateLimit(access, "run-requeue");
    const parsed = await parseJsonBody(req, requeueSchema, {
      logPrefix: "ai-paths.runs.dead-letter.requeue",
    });
    if (!parsed.ok) return parsed.response;

    const runIds = Array.isArray(parsed.data.runIds) ? parsed.data.runIds : [];
    const pathId = parsed.data.pathId?.trim() || undefined;
    const mode = parsed.data.mode ?? "resume";
    const query = parsed.data.query?.trim() || undefined;
    const limit = parsed.data.limit ?? undefined;

    const repo = getPathRunRepository();
    let targetRunIds = runIds;

    if (targetRunIds.length === 0) {
      const { runs } = await repo.listRuns({
        ...(!access.isElevated ? { userId: access.userId } : {}),
        ...(pathId ? { pathId } : {}),
        ...(query ? { query } : {}),
        status: "dead_lettered",
        ...(limit ? { limit } : {}),
      });
      targetRunIds = runs.map((run: { id: string }) => run.id);
    }

    if (targetRunIds.length === 0) {
      return NextResponse.json({ requeued: 0, runIds: [], errors: [] });
    }

    const requeuedRunIds: string[] = [];
    const errors: Array<{ runId: string; error: string }> = [];

    for (const runId of targetRunIds) {
      try {
        const run = await repo.findRunById(runId);
        if (!run) {
          errors.push({ runId, error: "Run not found" });
          continue;
        }
        try {
          assertAiPathRunAccess(access, run);
        } catch (error) {
          errors.push({
            runId,
            error: error instanceof Error ? error.message : "Run access denied",
          });
          continue;
        }
        if (run.status !== "dead_lettered") {
          errors.push({ runId, error: `Run is ${run.status}` });
          continue;
        }
        await resumePathRun(runId, mode);
        requeuedRunIds.push(runId);
      } catch (error) {
        errors.push({
          runId,
          error: error instanceof Error ? error.message : "Failed to requeue run",
        });
      }
    }

    if (requeuedRunIds.length > 0) {
      startAiPathRunQueue();
    }

    return NextResponse.json({
      requeued: requeuedRunIds.length,
      runIds: requeuedRunIds,
      errors,
    });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.dead-letter.requeue",
      fallbackMessage: "Failed to requeue dead-letter runs",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 {
  source: "ai-paths.runs.dead-letter.requeue",
});

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { badRequestError } from "@/shared/errors/app-error";
import { enqueuePathRun } from "@/features/ai-paths/services/path-run-service";
import { startAiPathRunQueue } from "@/features/jobs/server";
import type { AiNode, Edge } from "@/shared/types/ai-paths";
import { enforceAiPathsRunRateLimit, requireAiPathsAccess } from "@/features/ai-paths/server/access";

const enqueueSchema = z.object({
  pathId: z.string().trim().min(1),
  pathName: z.string().trim().optional(),
  nodes: z.array(z.any()).optional(),
  edges: z.array(z.any()).optional(),
  triggerEvent: z.string().trim().optional(),
  triggerNodeId: z.string().trim().optional(),
  triggerContext: z.record(z.string(), z.any()).optional().nullable(),
  entityId: z.string().trim().optional().nullable(),
  entityType: z.string().trim().optional().nullable(),
  maxAttempts: z.number().int().min(1).max(50).optional(),
  backoffMs: z.number().int().min(0).max(60_000).optional(),
  backoffMaxMs: z.number().int().min(0).max(10 * 60_000).optional(),
  meta: z.record(z.string(), z.any()).optional().nullable(),
});

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    await enforceAiPathsRunRateLimit(access);
    const parsed = await parseJsonBody(req, enqueueSchema, {
      logPrefix: "ai-paths.runs.enqueue",
    });
    if (!parsed.ok) return parsed.response;

    const { nodes, edges, ...rest } = parsed.data;
    if (!Array.isArray(nodes) || !Array.isArray(edges)) {
      throw badRequestError("Nodes and edges are required to enqueue a run.");
    }

    const run = await enqueuePathRun({
      userId: access.userId,
      pathId: rest.pathId,
      pathName: rest.pathName ?? null,
      nodes: nodes as AiNode[],
      edges: edges as Edge[],
      ...(rest.triggerEvent ? { triggerEvent: rest.triggerEvent } : {}),
      ...(rest.triggerNodeId ? { triggerNodeId: rest.triggerNodeId } : {}),
      triggerContext: rest.triggerContext ?? null,
      entityId: rest.entityId ?? null,
      entityType: rest.entityType ?? null,
      ...(rest.maxAttempts !== undefined ? { maxAttempts: rest.maxAttempts } : {}),
      ...(rest.backoffMs !== undefined ? { backoffMs: rest.backoffMs } : {}),
      ...(rest.backoffMaxMs !== undefined ? { backoffMaxMs: rest.backoffMaxMs } : {}),
      meta: rest.meta ?? null,
    });
    startAiPathRunQueue();
    return NextResponse.json({ run });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.enqueue",
      fallbackMessage: "Failed to enqueue AI Path run",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "ai-paths.runs.enqueue" });

