import { NextRequest, NextResponse } from "next/server";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import type { AiPathRunStatus } from "@/shared/types/ai-paths";
import { requireAiPathsAccess } from "@/features/ai-paths/server/access";

const RUN_STATUSES: AiPathRunStatus[] = [
  "queued",
  "running",
  "paused",
  "completed",
  "failed",
  "canceled",
  "dead_lettered",
];

async function GET_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    const url = new URL(req.url);
    const pathId = url.searchParams.get("pathId")?.trim() || undefined;
    const query = url.searchParams.get("query")?.trim() || undefined;
    const statusParam = url.searchParams.get("status")?.trim() || "";
    const status = RUN_STATUSES.includes(statusParam as AiPathRunStatus)
      ? (statusParam as AiPathRunStatus)
      : undefined;
    const limitParam = url.searchParams.get("limit");
    const offsetParam = url.searchParams.get("offset");
    const limitRaw = limitParam ? Number.parseInt(limitParam, 10) : NaN;
    const offsetRaw = offsetParam ? Number.parseInt(offsetParam, 10) : NaN;
    const limit =
      Number.isFinite(limitRaw) && limitRaw > 0 ? Math.min(limitRaw, 500) : undefined;
    const offset =
      Number.isFinite(offsetRaw) && offsetRaw >= 0 ? offsetRaw : undefined;
    const repo = getPathRunRepository();
    const result = await repo.listRuns({
      ...(!access.isElevated ? { userId: access.userId } : {}),
      ...(pathId ? { pathId } : {}),
      ...(query ? { query } : {}),
      ...(status ? { status } : {}),
      ...(limit !== undefined ? { limit } : {}),
      ...(offset !== undefined ? { offset } : {}),
    });
    return NextResponse.json(result);
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.runs.list",
      fallbackMessage: "Failed to load AI Path runs",
    });
  }
}

export const GET = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => GET_handler(req, ctx),
 { source: "ai-paths.runs.list" });

import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { parseJsonBody } from "@/features/products/server";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { badRequestError, notFoundError, validationError } from "@/shared/errors/app-error";
import { productUpdateSchema } from "@/features/products/server";
import { noteUpdateSchema } from "@/features/notesapp";
import { getProductRepository } from "@/features/products/server";
import { noteService } from "@/features/notesapp/server";
import { removeUndefined } from "@/shared/utils";
import { NoteUpdateInput } from "@/shared/types/notes";
import {
  enforceAiPathsActionRateLimit,
  ensureAiPathsPermission,
  requireAiPathsAccess,
} from "@/features/ai-paths/server/access";

const updateSchema = z.object({
  entityType: z.enum(["product", "note", "custom"]),
  entityId: z.string().trim().optional(),
  updates: z.record(z.string(), z["unknown"]()).optional(),
  mode: z.enum(["replace", "append"]).optional(),
});

const mergeAppendValue = (current: unknown, next: unknown): unknown => {
  if (next === undefined) return undefined;
  if (current === undefined || current === null) return next;
  if (Array.isArray(current)) {
    const currentArr = current as unknown[];
    if (Array.isArray(next)) {
      return [...currentArr, ...(next as unknown[])];
    }
    return [...currentArr, next];
  }
  if (typeof current === "string" && typeof next === "string") {
    if (!current) return next;
    if (!next) return current;
    return `${current}\n${next}`;
  }
  if (
    current &&
    typeof current === "object" &&
    next &&
    typeof next === "object" &&
    !Array.isArray(next)
  ) {
    return { ...(current as Record<string, unknown>), ...(next as Record<string, unknown>) };
  }
  return next;
};

const applyAppendMode = (
  updates: Record<string, unknown>,
  current: Record<string, unknown>
): Record<string, unknown> => {
  const next: Record<string, unknown> = {};
  Object.entries(updates).forEach(([key, value]: [string, unknown]) => {
    next[key] = mergeAppendValue(current[key], value);
  });
  return next;
};

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const access = await requireAiPathsAccess();
    enforceAiPathsActionRateLimit(access, "entity-update");
    const parsed = await parseJsonBody(req, updateSchema, {
      logPrefix: "ai-paths.update",
    });
    if (!parsed.ok) return parsed.response;

    const { entityType, entityId, updates, mode } = parsed.data;
    const normalizedUpdates =
      updates && typeof updates === "object" ? updates : {};

    if (Object.keys(normalizedUpdates).length === 0) {
      throw badRequestError("No updates provided");
    }

    if (entityType !== "custom" && !entityId?.trim()) {
      throw badRequestError("Entity id is required");
    }

    if (entityType === "custom") {
      return NextResponse.json({
        ok: true,
        entityType,
        entityId: entityId ?? null,
        updates: normalizedUpdates,
        note: "Custom entities are not persisted yet.",
      });
    }

    if (entityType === "product") {
      ensureAiPathsPermission(access, "products.manage", "Forbidden.");
      const productRepository = await getProductRepository();
      const existing =
        mode === "append" ? await productRepository.getProductById(entityId as string) : null;
      if (mode === "append" && !existing) {
        throw notFoundError("Product not found", { productId: entityId });
      }
      const prepared =
        mode === "append" && existing
          ? applyAppendMode(normalizedUpdates, existing as Record<string, unknown>)
          : normalizedUpdates;
      const validated = productUpdateSchema.safeParse(prepared);
      if (!validated.success) {
        throw validationError("Invalid product update", {
          issues: validated.error.flatten(),
        });
      }
      const updateData = removeUndefined(validated.data);
      if (Object.keys(updateData).length === 0) {
        throw badRequestError("No valid product fields to update");
      }
      const updated = await productRepository.updateProduct(
        entityId as string,
        updateData
      );
      if (!updated) {
        throw notFoundError("Product not found", { productId: entityId });
      }
      return NextResponse.json({
        ok: true,
        entityType,
        entityId,
        updates: updateData,
      });
    }

    if (entityType === "note") {
      ensureAiPathsPermission(access, "notes.manage", "Forbidden.");
      const existing =
        mode === "append" ? await noteService.getById(entityId as string) : null;
      if (mode === "append" && !existing) {
        throw notFoundError("Note not found", { noteId: entityId });
      }
      const prepared =
        mode === "append" && existing
          ? applyAppendMode(normalizedUpdates, existing as Record<string, unknown>)
          : normalizedUpdates;
      const validated = noteUpdateSchema.safeParse(prepared);
      if (!validated.success) {
        throw validationError("Invalid note update", {
          issues: validated.error.flatten(),
        });
      }
      const updateData = removeUndefined(validated.data);
      if (Object.keys(updateData).length === 0) {
        throw badRequestError("No valid note fields to update");
      }
      const updated = await noteService.update(entityId as string, updateData as NoteUpdateInput);
      if (!updated) {
        throw notFoundError("Note not found", { noteId: entityId });
      }
      return NextResponse.json({
        ok: true,
        entityType,
        entityId,
        updates: updateData,
      });
    }

    throw badRequestError("Unsupported entity type");
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "ai-paths.update",
      fallbackMessage: "Failed to update entity",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
 { source: "ai-paths.update" });

import { NextRequest, NextResponse } from "next/server";
import type { IndexSpecification } from "mongodb";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { AI_PATHS_MONGO_INDEXES } from "@/features/ai-paths/services/path-run-repository/mongo-path-run-repository";

type IndexInfo = {
  name?: string;
  key: IndexSpecification;
};

type CollectionIndexStatus = {
  name: string;
  expected: IndexInfo[];
  existing: IndexInfo[];
  missing: IndexInfo[];
  extra: IndexInfo[];
  error?: string;
};

const serializeKey = (key: IndexSpecification) => JSON.stringify(key);

const buildExpectedByCollection = () =>
  AI_PATHS_MONGO_INDEXES.reduce<Record<string, IndexInfo[]>>((acc, index) => {
    if (!index.collection) return acc;
    const collection = index.collection;
    const existing = acc[collection] ?? [];
    existing.push({ key: index.key });
    acc[collection] = existing;
    return acc;
  }, {});

const buildDiagnostics = async (db: Awaited<ReturnType<typeof getMongoDb>>) => {
  const expectedByCollection = buildExpectedByCollection();
  const collections: CollectionIndexStatus[] = [];

  for (const [collectionName, expected] of Object.entries(expectedByCollection)) {
    let existing: IndexInfo[] = [];
    let errorMessage: string | undefined;
    try {
      const existingIndexes = await db
        .collection(collectionName)
        .listIndexes()
        .toArray();
      existing = existingIndexes.map((index) => ({
        name: index.name,
        key: index.key as IndexSpecification,
      }));
    } catch (error) {
      errorMessage = error instanceof Error ? error.message : "Failed to load indexes";
    }
    const expectedSet = new Set(expected.map((item) => serializeKey(item.key)));
    const existingSet = new Set(existing.map((item) => serializeKey(item.key)));

    const missing = expected.filter((item) => !existingSet.has(serializeKey(item.key)));
    const extra = existing.filter(
      (item) =>
        item.name !== "_id_" && !expectedSet.has(serializeKey(item.key))
    );

    collections.push({
      name: collectionName,
      expected,
      existing,
      missing,
      extra,
      ...(errorMessage ? { error: errorMessage } : {}),
    });
  }

  return collections;
};

async function GET_handler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  const db = await getMongoDb();
  const collections = await buildDiagnostics(db);
  return NextResponse.json({
    generatedAt: new Date().toISOString(),
    collections,
  });
}

async function POST_handler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  const db = await getMongoDb();
  const expectedByCollection = buildExpectedByCollection();
  const created: Array<{ collection: string; key: IndexSpecification }> = [];

  for (const [collectionName, expected] of Object.entries(expectedByCollection)) {
    for (const index of expected) {
      try {
        await db.collection(collectionName).createIndex(index.key);
        created.push({ collection: collectionName, key: index.key });
      } catch (_error) {
        // Ignore errors to allow remaining indexes to be created.
      }
    }
  }

  const collections = await buildDiagnostics(db);
  return NextResponse.json({
    generatedAt: new Date().toISOString(),
    created,
    collections,
  });
}

export const GET = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => GET_handler(req, ctx),
  {
    source: "system.diagnostics.mongo-indexes",
    logSuccess: false,
  }
);

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
  {
    source: "system.diagnostics.mongo-indexes.rebuild",
    logSuccess: true,
  }
);

