  NODE_WIDTH,
  PORT_SIZE,
  getPortOffsetY,
  formatRuntimeValue,
  typeStyles,
  validateConnection,
} from "@/features/ai-paths/lib";
import { formatPortLabel } from "../utils/ui-utils";

type EdgePath = { id: string; path: string; label?: string; arrow?: { x: number; y: number; angle: number } };

type CanvasBoardProps = {
  viewportRef: React.RefObject<HTMLDivElement | null>;
  canvasRef: React.RefObject<HTMLDivElement | null>;
  nodes: AiNode[];
  edges: Edge[];
  runtimeState: RuntimeState;
  edgePaths: EdgePath[];
  view: { x: number; y: number; scale: number };
  panState: { startX: number; startY: number; originX: number; originY: number } | null;
  lastDrop: { x: number; y: number } | null;
  connecting: { fromNodeId: string; fromPort: string; start: { x: number; y: number } } | null;
  connectingPos: { x: number; y: number } | null;
  connectingFromNode: AiNode | null;
  selectedNodeId: string | null;
  draggingNodeId: string | null;
  selectedEdgeId: string | null;
  onSelectEdgeId: (edgeId: string | null) => void;
  onRemoveEdge: (edgeId: string) => void;
  onSelectNode: (nodeId: string) => void;
  onOpenNodeConfig: (nodeId: string) => void;
  onFireTrigger: (node: AiNode, event?: React.MouseEvent<HTMLButtonElement>) => void;
  onPointerDownNode: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  onPointerMoveNode: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  onPointerUpNode: (event: React.PointerEvent<HTMLDivElement>, nodeId: string) => void;
  onStartConnection: (
    event: React.PointerEvent<HTMLButtonElement>,
    node: AiNode,
    port: string
  ) => void;
  onCompleteConnection: (
    event: React.PointerEvent<HTMLButtonElement>,
    node: AiNode,
    port: string
  ) => void;
  onDrop: (event: React.DragEvent<HTMLDivElement>) => void;
  onDragOver: (event: React.DragEvent<HTMLDivElement>) => void;
  onPanStart: (event: React.PointerEvent<HTMLDivElement>) => void;
  onPanMove: (event: React.PointerEvent<HTMLDivElement>) => void;
  onPanEnd: (event: React.PointerEvent<HTMLDivElement>) => void;
  onZoomTo: (scale: number) => void;
  onFitToNodes: () => void;
  onResetView: () => void;
};

export function CanvasBoard({
  viewportRef,
  canvasRef,
  nodes,
  edges,
  runtimeState,
  edgePaths,
  view,
  panState,
  lastDrop,
  connecting,
  connectingPos,
  connectingFromNode,
  selectedNodeId,
  draggingNodeId,
  selectedEdgeId,
  onSelectEdgeId,
  onRemoveEdge,
  onSelectNode,
  onOpenNodeConfig,
  onFireTrigger,
  onPointerDownNode,
  onPointerMoveNode,
  onPointerUpNode,
  onStartConnection,
  onCompleteConnection,
  onDrop,
  onDragOver,
  onPanStart,
  onPanMove,
  onPanEnd,
  onZoomTo,
  onFitToNodes,
  onResetView,
}: CanvasBoardProps): React.JSX.Element {
  const [hoveredConnectorKey, setHoveredConnectorKey] = React.useState<string | null>(null);
  const [pinnedConnectorKey, setPinnedConnectorKey] = React.useState<string | null>(null);

  const buildConnectorKey = (
    direction: "input" | "output",
    nodeId: string,
    port: string
  ) => `${direction}:${nodeId}:${port}`;

  const formatConnectorValue = (value: unknown) => {
    if (value === undefined) return "No data yet.";
    if (value === null) return "null";
    const formatted = typeof value === "string" ? value : formatRuntimeValue(value);
    if (formatted.length > 1200) return `${formatted.slice(0, 1200)}…`;
    return formatted;
  };

  const stringifyForDiff = (value: unknown) => {
    if (value === undefined) return "";
    if (value === null) return "null";
    if (typeof value === "string") return value;
    if (typeof value === "number" || typeof value === "boolean") return String(value);
    try {
      return JSON.stringify(value, null, 2);
    } catch {
      return "[Complex Object]";
    }
  };

  const buildDiffLines = (prev: string, next: string, limit = 120) => {
    const prevLines = prev.split("\n");
    const nextLines = next.split("\n");
    const max = Math.max(prevLines.length, nextLines.length);
    const lines: Array<{ type: "add" | "remove" | "same"; text: string }> = [];
    let truncated = false;
    for (let index = 0; index < max; index += 1) {
      const prevLine = prevLines[index];
      const nextLine = nextLines[index];
      if (prevLine === nextLine) {
        if (prevLine !== undefined) {
          lines.push({ type: "same", text: prevLine });
        }
      } else {
        if (prevLine !== undefined) {
          lines.push({ type: "remove", text: prevLine });
        }
        if (nextLine !== undefined) {
          lines.push({ type: "add", text: nextLine });
        }
      }
      if (lines.length >= limit) {
        truncated = true;
        break;
      }
    }
    return { lines, truncated };
  };

  const getPortValue = (
    direction: "input" | "output",
    nodeId: string,
    port: string
  ) => {
    const source = direction === "input" ? runtimeState.inputs : runtimeState.outputs;
    const nodeValues = source?.[nodeId] ?? {};
    return (nodeValues as Record<string, unknown>)[port];
  };

  const renderConnectorTooltip = (
    direction: "input" | "output",
    nodeId: string,
    port: string
  ) => {
    const value = getPortValue(direction, nodeId, port);
    const label = direction === "input" ? "Input" : "Output";
    const history = Array.isArray(value) ? value : null;
    const currentValue = history ? history[history.length - 1] : value;
    const isHistory = Array.isArray(value) && value.length > 1;
    const diff =
      history && history.length > 1
        ? buildDiffLines(
            stringifyForDiff(history[history.length - 2]),
            stringifyForDiff(history[history.length - 1])
          )
        : null;
    return (
      <div className="space-y-1">
        <div className="text-[11px] text-gray-400">
          {label}: {formatPortLabel(port)}
        </div>
        {Array.isArray(value) ? (
          <div className="text-[10px] text-amber-200">
            {isHistory ? `History (${value.length})` : "Single value"}
          </div>
        ) : null}
        <pre className="mt-1 max-h-56 overflow-auto whitespace-pre-wrap text-[11px] text-gray-200">
          {formatConnectorValue(currentValue)}
        </pre>
        {diff ? (
          <div className="mt-2">
            <div className="text-[10px] text-gray-400">Diff (last two passes)</div>
            <div className="mt-1 max-h-40 overflow-auto rounded bg-black/50 p-2 font-mono text-[10px] leading-relaxed">
              {diff.lines.map((line, index) => {
                const prefix = line.type === "add" ? "+ " : line.type === "remove" ? "- " : "  ";
                const colorClass =
                  line.type === "add"
                    ? "text-emerald-300"
                    : line.type === "remove"
                      ? "text-rose-300"
                      : "text-gray-300";
                return (
                  <div
                    key={`${line.type}-${index}`}
                    className={`whitespace-pre ${colorClass}`}
                  >
                    {prefix}
                    {line.text}
                  </div>
                );
              })}
              {diff.truncated ? (
                <div className="mt-1 text-gray-500">Diff truncated…</div>
              ) : null}
            </div>
          </div>
        ) : null}
      </div>
    );
  };

  const triggerConnected = React.useMemo((): Set<string> => {
    const triggerIds = nodes.filter((node: AiNode) => node.type === "trigger").map((node: AiNode) => node.id);
    if (triggerIds.length === 0) return new Set<string>();
    const adjacency = new Map<string, Set<string>>();
    edges.forEach((edge: Edge) => {
      if (!edge.from || !edge.to) return;
      const fromSet = adjacency.get(edge.from) ?? new Set<string>();
      fromSet.add(edge.to);
      adjacency.set(edge.from, fromSet);
      const toSet = adjacency.get(edge.to) ?? new Set<string>();
      toSet.add(edge.from);
      adjacency.set(edge.to, toSet);
    });
    const visited = new Set<string>();
    const queue = [...triggerIds];
    triggerIds.forEach((id: string) => visited.add(id));
    while (queue.length) {
      const current = queue.shift();
      if (!current) continue;
      const neighbors = adjacency.get(current);
      if (!neighbors) continue;
      neighbors.forEach((neighbor: string) => {
        if (visited.has(neighbor)) return;
        visited.add(neighbor);
        queue.push(neighbor);
      });
    }
    return visited;
  }, [nodes, edges]);
  const edgeMetaMap = React.useMemo(
    (): Map<string, Edge> => new Map(edges.map((edge: Edge) => [edge.id, edge])),
    [edges]
  );

  return (
    <div
      ref={viewportRef}
      className={`relative min-h-[560px] rounded-lg border bg-card/70 backdrop-blur overflow-hidden ${
        panState ? "cursor-grabbing" : "cursor-grab"
      }`}
      onDrop={onDrop}
      onDragOver={onDragOver}
      onPointerDown={onPanStart}
      onPointerMove={onPanMove}
      onPointerUp={onPanEnd}
      onPointerLeave={onPanEnd}
    >
      <div className="absolute bottom-3 left-3 z-10 rounded-md border bg-card/70 backdrop-blur px-3 py-2 text-[11px] text-gray-400">
        Nodes: {nodes.length}
        {lastDrop ? ` • Last drop: ${Math.round(lastDrop.x)}, ${Math.round(lastDrop.y)}` : ""}
        {` • View: ${Math.round(view.x)}, ${Math.round(view.y)} @ ${Math.round(view.scale * 100)}%`}
      </div>
      <div className="absolute bottom-4 right-4 z-10 rounded-md border bg-card/70 backdrop-blur p-2 text-xs text-gray-300">
        <div className="mb-2 text-[11px] uppercase text-gray-500">View Controls</div>
        <div className="flex items-center gap-2">
          <Button
            className="h-7 w-7 rounded-full border text-xs text-white hover:bg-muted/60"
            type="button"
            onClick={() => onZoomTo(view.scale - 0.1)}
          >
            -
          </Button>
          <span className="min-w-[56px] text-center text-[11px] text-gray-300">
            {Math.round(view.scale * 100)}%
          </span>
          <Button
            className="h-7 w-7 rounded-full border text-xs text-white hover:bg-muted/60"
            type="button"
            onClick={() => onZoomTo(view.scale + 0.1)}
          >
            +
          </Button>
          <Button
            className="h-7 rounded-full border px-2 text-[11px] text-white hover:bg-muted/60"
            type="button"
            onClick={onFitToNodes}
          >
            Fit
          </Button>
          <Button
            className="h-7 rounded-full border px-2 text-[11px] text-white hover:bg-muted/60"
            type="button"
            onClick={onResetView}
          >
            Reset
          </Button>
        </div>
      </div>
      <div
        ref={canvasRef}
        className="absolute left-0 top-0"
        onDrop={onDrop}
        onDragOver={onDragOver}
        style={{
          width: CANVAS_WIDTH,
          height: CANVAS_HEIGHT,
          transform: `translate(${view.x}px, ${view.y}px) scale(${view.scale})`,
          transformOrigin: "0 0",
          backgroundImage:
            "radial-gradient(circle at 1px 1px, rgba(148,163,184,0.18) 1px, transparent 0)",
          backgroundSize: "24px 24px",
        }}
      >
        {lastDrop ? (
          <div
            className="absolute"
            style={{
              width: 10,
              height: 10,
              transform: `translate(${lastDrop.x}px, ${lastDrop.y}px)`,
            }}
          >
            <span className="absolute inset-0 rounded-full bg-sky-400/40 animate-ping" />
            <span className="absolute inset-0 rounded-full border border-sky-300/70 bg-sky-500/60" />
          </div>
        ) : null}
        <svg
          className="absolute inset-0"
          width={CANVAS_WIDTH}
          height={CANVAS_HEIGHT}
          style={{ pointerEvents: "auto" }}
        >
          {edgePaths.map((edge: EdgePath): React.JSX.Element => {
            const isSelected = selectedEdgeId === edge.id;
            const edgeMeta = edgeMetaMap.get(edge.id);
            const isManualConnector =
              edgeMeta?.fromPort === "aiPrompt" || edgeMeta?.toPort === "queryCallback";
            // Check if this is a schema connection (db_schema -> database)
            const fromNode = edgeMeta ? nodes.find((n: AiNode) => n.id === edgeMeta.from) : null;
            const toNode = edgeMeta ? nodes.find((n: AiNode) => n.id === edgeMeta.to) : null;
            const isSchemaConnection =
              fromNode?.type === "db_schema" && toNode?.type === "database";
            const isActivePath =
              !isManualConnector &&
              !isSchemaConnection &&
              edgeMeta &&
              triggerConnected.has(edgeMeta.from) &&
              triggerConnected.has(edgeMeta.to);
            const edgeClass = `transition-all duration-150 ${
              isSelected
                ? "text-blue-400"
                : isSchemaConnection
                  ? "text-yellow-400/70 group-hover:text-cyan-300/80"
                  : isManualConnector
                    ? "text-amber-400/65 group-hover:text-amber-300/80"
                    : isActivePath
                      ? "text-sky-400/60 group-hover:text-sky-300/80"
                      : "text-slate-400/45 group-hover:text-blue-400/70"
            }`;
            const arrowSize = isSelected ? 9 : 8;
            const arrowWidth = isSelected ? 6 : 5;
            const arrowPath = `M 0 0 L -${arrowSize} ${arrowWidth / 2} L -${arrowSize} -${arrowWidth / 2} Z`;
            return (
              <g key={edge.id} className="group cursor-pointer">
                <path
                  d={edge.path}
                  stroke="transparent"
                  strokeWidth="14"
                  fill="none"
                  style={{ pointerEvents: "stroke" }}
                  onContextMenu={(event: React.MouseEvent<SVGPathElement>) => {
                    event.preventDefault();
                    onRemoveEdge(edge.id);
                  }}
                  onClick={(event: React.MouseEvent<SVGPathElement>) => {
                    event.preventDefault();
                    event.stopPropagation();
                    onSelectEdgeId(edge.id);
                  }}
                />
                <path
                  d={edge.path}
                  className={edgeClass}
                  strokeWidth={isSelected ? 2.5 : 1.6}
                  strokeDasharray={isManualConnector ? "5 4" : isSchemaConnection ? "3 3" : undefined}
                  stroke="currentColor"
                  fill="none"
                  style={{ pointerEvents: "none" }}
                />
                {edge.arrow ? (
                  <path
                    d={arrowPath}
                    transform={`translate(${edge.arrow.x} ${edge.arrow.y}) rotate(${edge.arrow.angle})`}
                    className={edgeClass}
                    fill="currentColor"
                    stroke="none"
                    style={{ pointerEvents: "none" }}
                  />
                ) : null}
              </g>
            );
          })}
          {connecting && connectingPos ? ((): React.JSX.Element => {
            const fromX = connecting.start.x;
            const fromY = connecting.start.y;
            const toX = connectingPos.x;
            const toY = connectingPos.y;
            const midX = fromX + (toX - fromX) * 0.5;
            const path = `M ${fromX} ${fromY} C ${midX} ${fromY}, ${midX} ${toY}, ${toX} ${toY}`;
            return (
              <path
                d={path}
                stroke="rgba(148,163,184,0.7)"
                strokeWidth="1.6"
                fill="none"
                strokeDasharray="4 3"
              />
            );
          })() : null}
        </svg>

        {nodes.map((node: AiNode) => {
          const isSelected = node.id === selectedNodeId;
          const style = typeStyles[node.type];
          const modelStatus =
            node.type === "model"
              ? (runtimeState.outputs[node.id]?.status as string | undefined)
              : undefined;
          const modelStatusLabel =
            modelStatus === "completed"
              ? "Completed"
              : modelStatus === "failed"
                ? "Failed"
                : modelStatus === "queued"
                  ? "Queued"
                  : modelStatus
                    ? "Pending"
                    : null;
          const modelStatusClasses =
            modelStatus === "completed"
              ? "border-emerald-400/60 bg-emerald-500/15 text-emerald-200"
              : modelStatus === "failed"
                ? "border-rose-500/60 bg-rose-500/15 text-rose-200"
                : "border-sky-500/60 bg-sky-500/15 text-sky-200";
          const pollStatus =
            node.type === "poll"
              ? (runtimeState.outputs[node.id]?.status as string | undefined)
              : undefined;
          const pollStatusLabel =
            pollStatus === "completed"
              ? "Completed"
              : pollStatus === "failed"
                ? "Failed"
                : pollStatus === "timeout"
                  ? "Timed Out"
                  : pollStatus === "polling"
                    ? "Polling"
                    : pollStatus
                      ? "Pending"
                      : null;
          const pollStatusClasses =
            pollStatus === "completed"
              ? "border-emerald-400/60 bg-emerald-500/15 text-emerald-200"
              : pollStatus === "failed" || pollStatus === "timeout"
                ? "border-rose-500/60 bg-rose-500/15 text-rose-200"
                : "border-sky-500/60 bg-sky-500/15 text-sky-200";
          return (
            <div
              key={node.id}
              className={`absolute ${draggingNodeId === node.id ? "cursor-grabbing" : "cursor-grab"}`}
              style={{
                width: NODE_WIDTH,
                transform: `translate(${node.position.x}px, ${node.position.y}px)`,
              }}
              onPointerDown={(event: React.PointerEvent<HTMLDivElement>) => onPointerDownNode(event, node.id)}
              onPointerMove={(event: React.PointerEvent<HTMLDivElement>) => onPointerMoveNode(event, node.id)}
              onPointerUp={(event: React.PointerEvent<HTMLDivElement>) => onPointerUpNode(event, node.id)}
              onClick={() => onSelectNode(node.id)}
              onDoubleClick={(event: React.MouseEvent<HTMLDivElement>) => {
                event.stopPropagation();
                onSelectNode(node.id);
                onOpenNodeConfig(node.id);
              }}
            >
              <div
                className={`relative flex flex-col gap-2 rounded-xl border bg-card/80 p-3 text-xs text-gray-200 shadow-lg backdrop-blur ${
                  style.border
                } ${style.glow} ${isSelected ? "ring-2 ring-white/20" : ""}`}
              >
                {node.inputs.map((input: string, index: number) => (
                  <div
                    key={`input-${node.id}-${input}`}
                    className="absolute flex items-center"
                    style={{
                      left: -(PORT_SIZE / 2) - 4,
                      top: getPortOffsetY(index, node.inputs.length) - PORT_SIZE / 2,
                    }}
                    onMouseEnter={() => setHoveredConnectorKey(buildConnectorKey("input", node.id, input))}
                    onMouseLeave={() =>
                      setHoveredConnectorKey((prev) =>
                        prev === buildConnectorKey("input", node.id, input) ? null : prev
                      )
                    }
                  >
                    {(() : React.JSX.Element => {
                      const isConnecting = Boolean(connecting && connectingFromNode);
                      const isConnectable = isConnecting
                        ? validateConnection(
                            connectingFromNode as AiNode,
                            node,
                            connecting?.fromPort ?? "",
                            input
                          ).valid
                        : false;
                      const connectorKey = buildConnectorKey("input", node.id, input);
                      const isPinned = pinnedConnectorKey === connectorKey;
                      const isHovered = hoveredConnectorKey === connectorKey;
                      const isTooltipOpen = isPinned || isHovered;
                      return (
                        <>
                          <Tooltip
                            content={renderConnectorTooltip("input", node.id, input)}
                            side="right"
                            maxWidth="360px"
                            open={isTooltipOpen}
                            disableHover
                          >
                            <button
                              type="button"
                              data-port="input"
                              className={`cursor-pointer rounded-full border bg-sky-500/20 shadow-[0_0_8px_rgba(56,189,248,0.35)] hover:border-sky-200 ${
                                isConnecting
                                  ? isConnectable
                                    ? "border-emerald-300/80 bg-emerald-500/30 shadow-[0_0_14px_rgba(52,211,153,0.55)] ring-2 ring-emerald-400/60"
                                    : "border-border/60 bg-card/20 opacity-40 shadow-none"
                                  : isPinned
                                    ? "border-amber-300/80 ring-2 ring-amber-300/70"
                                    : "border-sky-400/60"
                              }`}
                              style={{
                                width: PORT_SIZE + 2,
                                height: PORT_SIZE + 2,
                              }}
                              onPointerDown={(event: React.PointerEvent<HTMLButtonElement>) =>
                                onCompleteConnection(event, node, input)
                              }
                              onPointerUp={(event: React.PointerEvent<HTMLButtonElement>) =>
                                onCompleteConnection(event, node, input)
                              }
                              onClick={(event: React.MouseEvent<HTMLButtonElement>) => {
                                event.stopPropagation();
                                setPinnedConnectorKey((prev) =>
                                  prev === connectorKey ? null : connectorKey
                                );
                              }}
                              aria-label={`Connect to ${formatPortLabel(input)}`}
                              title={`Input: ${formatPortLabel(input)}`}
                            />
                          </Tooltip>
                          <span
                            className={`ml-1.5 rounded px-1 py-0.5 text-[8px] font-medium ${
                              isConnecting
                                ? isConnectable
                                  ? "bg-emerald-500/15 text-emerald-200"
                                  : "bg-muted/60 text-gray-500"
                                : "bg-sky-500/10 text-sky-300"
                            }`}
                          >
                            {formatPortLabel(input)}
                          </span>
                        </>
                      );
                    })()}
                  </div>
                ))}
                {node.outputs.map((output: string, index: number) => (
                  <div
                    key={`output-${node.id}-${output}`}
                    className="absolute flex items-center"
                    style={{
                      right: -(PORT_SIZE / 2) - 4,
                      top: getPortOffsetY(index, node.outputs.length) - PORT_SIZE / 2,
                    }}
                    onMouseEnter={() => setHoveredConnectorKey(buildConnectorKey("output", node.id, output))}
                    onMouseLeave={() =>
                      setHoveredConnectorKey((prev) =>
                        prev === buildConnectorKey("output", node.id, output) ? null : prev
                      )
                    }
                  >
                    {((): React.JSX.Element => {
                      const connectorKey = buildConnectorKey("output", node.id, output);
                      const isPinned = pinnedConnectorKey === connectorKey;
                      const isHovered = hoveredConnectorKey === connectorKey;
                      const isTooltipOpen = isPinned || isHovered;
                      return (
                        <>
                    <span className="mr-1.5 rounded bg-amber-500/10 px-1 py-0.5 text-[8px] font-medium text-amber-300">
                      {formatPortLabel(output)}
                    </span>
                    <Tooltip
                      content={renderConnectorTooltip("output", node.id, output)}
                      side="left"
                      maxWidth="360px"
                      open={isTooltipOpen}
                      disableHover
                    >
                      <button
                        type="button"
                        data-port="output"
                        className={`cursor-pointer rounded-full border bg-amber-500/20 shadow-[0_0_8px_rgba(251,191,36,0.35)] hover:border-amber-200 ${
                          isPinned ? "border-amber-300/80 ring-2 ring-amber-300/70" : "border-amber-400/60"
                        }`}
                        style={{
                          width: PORT_SIZE + 2,
                          height: PORT_SIZE + 2,
                        }}
                        onPointerDown={(event: React.PointerEvent<HTMLButtonElement>) => onStartConnection(event, node, output)}
                        onClick={(event: React.MouseEvent<HTMLButtonElement>) => {
                          event.stopPropagation();
                          setPinnedConnectorKey((prev) =>
                            prev === connectorKey ? null : connectorKey
                          );
                        }}
                        aria-label={`Start connection from ${formatPortLabel(output)}`}
                        title={`Output: ${formatPortLabel(output)}`}
                      />
                    </Tooltip>
                        </>
                      );
                    })()}
                  </div>
                ))}
                <div className="flex items-center justify-between">
                  <span className="text-xs font-semibold text-white">{node.title}</span>
                  <span className="rounded-full border px-2 py-[1px] text-[10px] uppercase text-gray-400">
                    {node.type}
                  </span>
                </div>
                {node.type === "model" && modelStatusLabel && (
                  <div
                    className={`inline-flex w-fit items-center gap-1 rounded-full border px-2 py-[2px] text-[9px] uppercase tracking-wide ${modelStatusClasses}`}
                  >
                    {modelStatusLabel}
                  </div>
                )}
                {node.type === "poll" && pollStatusLabel && (
                  <div
                    className={`inline-flex w-fit items-center gap-1 rounded-full border px-2 py-[2px] text-[9px] uppercase tracking-wide ${pollStatusClasses}`}
                  >
                    {pollStatusLabel}
                  </div>
                )}
                {node.type === "viewer" && !triggerConnected.has(node.id) && (
                  <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-2 py-1 text-[9px] text-amber-200">
                    Not wired to a Trigger
                  </div>
                )}
                {node.type === "trigger" && (
                  <Button
                    className="self-start rounded-md border border-emerald-500/40 px-2 py-1 text-[10px] text-emerald-200 hover:bg-emerald-500/10"
                    type="button"
                    onPointerDown={(event: React.PointerEvent<HTMLButtonElement>) => event.stopPropagation()}
                    onClick={(event: React.MouseEvent<HTMLButtonElement>) => onFireTrigger(node, event)}
                  >
                    Fire Trigger
                  </Button>
                )}
                {node.type === "trigger" && (
                  <div className="text-[10px] uppercase text-lime-200/80">
                    Accepts simulation input
                  </div>
                )}
                {node.type === "context" && (
                  <span className="text-[10px] uppercase text-emerald-300/80">
                    Role output can feed any Trigger
                  </span>
                )}
                {node.type === "simulation" && (
                  <span className="text-[10px] uppercase text-cyan-300/80">
                    Connect simulation → Trigger
                  </span>
                )}
                {node.type === "viewer" && (
                  <div className="rounded-md border border-border bg-card/60 px-2 py-1 text-[10px] text-gray-400">
                    Open node to view results
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import React from "react";

import { Button, Input, Label, Textarea } from "@/shared/ui";

import type { ClusterPreset } from "@/features/ai-paths/lib";

export type ClusterPresetDraft = {
  name: string;
  description: string;
  bundlePorts: string;
  template: string;
};

type ClusterPresetsPanelProps = {
  presetDraft: ClusterPresetDraft;
  setPresetDraft: React.Dispatch<React.SetStateAction<ClusterPresetDraft>>;
  editingPresetId: string | null;
  onResetPresetDraft: () => void;
  onPresetFromSelection: () => void;
  onSavePreset: () => void;
  clusterPresets: ClusterPreset[];
  onLoadPreset: (preset: ClusterPreset) => void;
  onApplyPreset: (preset: ClusterPreset) => void;
  onDeletePreset: (presetId: string) => void;
  onExportPresets: () => void;
};

export function ClusterPresetsPanel({
  presetDraft,
  setPresetDraft,
  editingPresetId,
  onResetPresetDraft,
  onPresetFromSelection,
  onSavePreset,
  clusterPresets,
  onLoadPreset,
  onApplyPreset,
  onDeletePreset,
  onExportPresets,
}: ClusterPresetsPanelProps): React.JSX.Element {
  return (
    <div className="rounded-lg border border-border bg-card/60 p-4">
      <div className="mb-3 flex items-center justify-between text-sm font-semibold text-white">
        <span>Cluster Presets</span>
        <div className="flex items-center gap-2">
          <Button
            type="button"
            className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
            onClick={onPresetFromSelection}
          >
            From Selection
          </Button>
          {editingPresetId && (
            <Button
              type="button"
              className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
              onClick={onResetPresetDraft}
            >
              New
            </Button>
          )}
        </div>
      </div>
      <div className="space-y-3 text-xs text-gray-300">
        <div>
          <Label className="text-[10px] uppercase text-gray-500">Name</Label>
          <Input
            className="mt-2 w-full rounded-md border border-border bg-card/70 px-3 py-2 text-xs text-white"
            value={presetDraft.name}
            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
              setPresetDraft((prev) => ({ ...prev, name: event.target.value }))
            }
          />
        </div>
        <div>
          <Label className="text-[10px] uppercase text-gray-500">Description</Label>
          <Textarea
            className="mt-2 min-h-[64px] w-full rounded-md border border-border bg-card/70 text-xs text-white"
            value={presetDraft.description}
            onChange={(event: React.ChangeEvent<HTMLTextAreaElement>) =>
              setPresetDraft((prev) => ({ ...prev, description: event.target.value }))
            }
          />
        </div>
        <div>
          <Label className="text-[10px] uppercase text-gray-500">
            Bundle Ports (one per line)
          </Label>
          <Textarea
            className="mt-2 min-h-[90px] w-full rounded-md border border-border bg-card/70 text-xs text-white"
            value={presetDraft.bundlePorts}
            onChange={(event: React.ChangeEvent<HTMLTextAreaElement>) =>
              setPresetDraft((prev) => ({ ...prev, bundlePorts: event.target.value }))
            }
          />
        </div>
        <div>
          <Label className="text-[10px] uppercase text-gray-500">Template</Label>
          <Textarea
            className="mt-2 min-h-[90px] w-full rounded-md border border-border bg-card/70 text-xs text-white"
            value={presetDraft.template}
            onChange={(event: React.ChangeEvent<HTMLTextAreaElement>) =>
              setPresetDraft((prev) => ({ ...prev, template: event.target.value }))
            }
          />
        </div>
        <Button
          className="w-full rounded-md border border-emerald-500/40 text-xs text-emerald-200 hover:bg-emerald-500/10"
          type="button"
          onClick={onSavePreset}
        >
          {editingPresetId ? "Update Preset" : "Save Preset"}
        </Button>
      </div>
      <div className="mt-4 space-y-2 text-xs text-gray-400">
        <div className="text-[11px] uppercase text-gray-500">Library</div>
        {clusterPresets.length === 0 && (
          <div className="rounded-md border border-border bg-card/50 p-3 text-[11px] text-gray-500">
            No presets yet. Save a bundle + template pair to reuse across apps.
          </div>
        )}
        {clusterPresets.map((preset) => (
          <div
            key={preset.id}
            className="rounded-md border border-border bg-card/50 p-3"
          >
            <div className="flex items-center justify-between gap-2">
              <div>
                <div className="text-xs font-semibold text-white">{preset.name}</div>
                {preset.description && (
                  <div className="text-[11px] text-gray-500">{preset.description}</div>
                )}
              </div>
              <div className="flex items-center gap-2">
                <Button
                  type="button"
                  className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
                  onClick={() => onLoadPreset(preset)}
                >
                  Edit
                </Button>
                <Button
                  type="button"
                  className="rounded-md border border-emerald-500/40 px-2 py-1 text-[10px] text-emerald-200 hover:bg-emerald-500/10"
                  onClick={() => onApplyPreset(preset)}
                >
                  Apply
                </Button>
                <Button
                  type="button"
                  className="rounded-md border border-rose-500/40 px-2 py-1 text-[10px] text-rose-200 hover:bg-rose-500/10"
                  onClick={() => onDeletePreset(preset.id)}
                >
                  Delete
                </Button>
              </div>
            </div>
            <div className="mt-2 text-[10px] text-gray-500">
              Updated: {new Date(preset.updatedAt).toLocaleString()}
            </div>
          </div>
        ))}
        <Button
          type="button"
          className="w-full rounded-md border text-xs text-white hover:bg-muted/60"
          onClick={onExportPresets}
        >
          Export / Import
        </Button>
      </div>
    </div>
  );
}

"use client";

import React from "react";

import {
  Button,
  Input,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Textarea,
} from "@/shared/ui";
import { useQuery } from "@tanstack/react-query";

import { runsApi } from "@/features/ai-paths/lib";
import type {
  AiPathRunEventRecord,
  AiPathRunNodeRecord,
  AiPathRunRecord,
  RuntimeHistoryEntry,
} from "@/features/ai-paths/lib";
import { RunHistoryEntries } from "./RunHistoryEntries";
import { buildHistoryNodeOptions } from "./run-history-utils";
import { safeJsonStringify } from "./AiPathsSettingsUtils";

type JobQueuePanelProps = {
  activePathId?: string | null;
};

type RunDetail = {
  run: AiPathRunRecord;
  nodes: AiPathRunNodeRecord[];
  events: AiPathRunEventRecord[];
};

type QueueStatus = {
  running: boolean;
  healthy: boolean;
  processing: boolean;
  activeRuns: number;
  concurrency: number;
  lastPollTime: number;
  timeSinceLastPoll: number;
};

const PAGE_SIZES = [10, 25, 50];
const SEARCH_DEBOUNCE_MS = 300;
const STATUS_FILTERS = [
  { id: "all", label: "All" },
  { id: "queued", label: "Queued" },
  { id: "running", label: "Running" },
  { id: "paused", label: "Paused" },
  { id: "completed", label: "Completed" },
  { id: "failed", label: "Failed" },
  { id: "canceled", label: "Canceled" },
  { id: "dead_lettered", label: "Dead-lettered" },
] as const;

const formatDate = (value?: Date | string | null): string => {
  if (!value) return "-";
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) return "-";
  return date.toLocaleString();
};

const formatDurationMs = (value?: number | null): string => {
  if (value === null || value === undefined || Number.isNaN(value)) return "-";
  if (value < 1000) return `${Math.max(0, value)}ms`;
  const seconds = Math.round(value / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remaining = seconds % 60;
  return `${minutes}m ${remaining}s`;
};

const safePrettyJson = (value: unknown): string => {
  const raw = safeJsonStringify(value);
  if (!raw) return "";
  try {
    return JSON.stringify(JSON.parse(raw), null, 2);
  } catch {
    return raw;
  }
};

const getLatestEventTimestamp = (events: AiPathRunEventRecord[]) => {
  let max = 0;
  events.forEach((event) => {
    const time = new Date(event.createdAt).getTime();
    if (Number.isFinite(time) && time > max) {
      max = time;
    }
  });
  return max > 0 ? new Date(max).toISOString() : null;
};

export function JobQueuePanel({ activePathId }: JobQueuePanelProps): React.JSX.Element {
  const [pathFilter, setPathFilter] = React.useState(activePathId ?? "");
  const [searchQuery, setSearchQuery] = React.useState("");
  const [debouncedQuery, setDebouncedQuery] = React.useState(searchQuery);
  const [statusFilter, setStatusFilter] = React.useState<(typeof STATUS_FILTERS)[number]["id"]>("all");
  const [pageSize, setPageSize] = React.useState(25);
  const [page, setPage] = React.useState(1);
  const [expandedRunIds, setExpandedRunIds] = React.useState<Set<string>>(new Set());
  const [runDetails, setRunDetails] = React.useState<Record<string, RunDetail | null>>({});
  const [runDetailLoading, setRunDetailLoading] = React.useState<Set<string>>(new Set());
  const [runDetailErrors, setRunDetailErrors] = React.useState<Record<string, string>>({});
  const [historySelection, setHistorySelection] = React.useState<Record<string, string>>({});
  const [streamStatuses, setStreamStatuses] = React.useState<
    Record<string, "connecting" | "live" | "stopped">
  >({});
  const streamSourcesRef = React.useRef<Map<string, EventSource>>(new Map());

  const normalizedPathFilter = pathFilter.trim();
  const normalizedQuery = debouncedQuery.trim();
  const offset = (page - 1) * pageSize;

  React.useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedQuery(searchQuery);
    }, SEARCH_DEBOUNCE_MS);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  React.useEffect(() => {
    setPage(1);
  }, [normalizedPathFilter, normalizedQuery, statusFilter, pageSize]);

  const runsQuery = useQuery<{ runs: AiPathRunRecord[]; total: number }>({
    queryKey: [
      "ai-paths-job-queue",
      normalizedPathFilter,
      normalizedQuery,
      statusFilter,
      page,
      pageSize,
    ],
    queryFn: async () => {
      const response = await runsApi.list({
        ...(normalizedPathFilter ? { pathId: normalizedPathFilter } : {}),
        ...(normalizedQuery ? { query: normalizedQuery } : {}),
        ...(statusFilter !== "all" ? { status: statusFilter } : {}),
        limit: pageSize,
        offset,
      });
      if (!response.ok) {
        throw new Error(response.error || "Failed to load job queue.");
      }
      return response.data as { runs: AiPathRunRecord[]; total: number };
    },
  });

  const queueStatusQuery = useQuery<{ status: QueueStatus }>({
    queryKey: ["ai-paths-queue-status"],
    queryFn: async () => {
      const response = await runsApi.queueStatus();
      if (!response.ok) {
        throw new Error(response.error || "Failed to load queue status.");
      }
      return response.data as { status: QueueStatus };
    },
    refetchInterval: 5000,
  });

  const total = runsQuery.data?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / pageSize));
  const runs = runsQuery.data?.runs ?? [];
  const queueStatus = queueStatusQuery.data?.status;

  React.useEffect(() => {
    return () => {
      streamSourcesRef.current.forEach((source) => source.close());
      streamSourcesRef.current.clear();
    };
  }, []);

  React.useEffect(() => {
    streamSourcesRef.current.forEach((source, runId) => {
      if (!expandedRunIds.has(runId)) {
        source.close();
        streamSourcesRef.current.delete(runId);
        setStreamStatuses((prev) => ({ ...prev, [runId]: "stopped" }));
      }
    });

    expandedRunIds.forEach((runId) => {
      if (streamSourcesRef.current.has(runId)) return;
      const existing = runDetails[runId];
      const since = existing ? getLatestEventTimestamp(existing.events) : null;
      const params = new URLSearchParams();
      if (since) params.set("since", since);
      const url = params.toString()
        ? `/api/ai-paths/runs/${encodeURIComponent(runId)}/stream?${params.toString()}`
        : `/api/ai-paths/runs/${encodeURIComponent(runId)}/stream`;
      const source = new EventSource(url);
      streamSourcesRef.current.set(runId, source);
      setStreamStatuses((prev) => ({ ...prev, [runId]: "connecting" }));

      const mergeEvents = (incoming: AiPathRunEventRecord[]) => {
        setRunDetails((prev) => {
          const current = prev[runId];
          if (!current) {
            return prev;
          }
          const existingIds = new Set(current.events.map((event) => event.id));
          const merged = [...current.events];
          incoming.forEach((event) => {
            if (!existingIds.has(event.id)) {
              merged.push(event);
            }
          });
          merged.sort((a, b) => {
            const aTime = new Date(a.createdAt).getTime();
            const bTime = new Date(b.createdAt).getTime();
            return aTime - bTime;
          });
          return { ...prev, [runId]: { ...current, events: merged } };
        });
      };

      source.addEventListener("ready", () => {
        setStreamStatuses((prev) => ({ ...prev, [runId]: "live" }));
      });
      source.addEventListener("run", (event) => {
        try {
          const payload = JSON.parse(event.data) as AiPathRunRecord;
          setRunDetails((prev) => {
            const current = prev[runId];
            if (current) {
              return { ...prev, [runId]: { ...current, run: payload } };
            }
            return { ...prev, [runId]: { run: payload, nodes: [], events: [] } };
          });
        } catch {
          // ignore parse errors
        }
      });
      source.addEventListener("nodes", (event) => {
        try {
          const payload = JSON.parse(event.data) as AiPathRunNodeRecord[];
          setRunDetails((prev) => {
            const current = prev[runId];
            if (!current) return prev;
            return { ...prev, [runId]: { ...current, nodes: payload } };
          });
        } catch {
          // ignore parse errors
        }
      });
      source.addEventListener("events", (event) => {
        try {
          const payload = JSON.parse(event.data) as
            | AiPathRunEventRecord[]
            | { events?: AiPathRunEventRecord[] };
          if (Array.isArray(payload)) {
            mergeEvents(payload);
            return;
          }
          const events = Array.isArray(payload.events) ? payload.events : [];
          mergeEvents(events);
        } catch {
          // ignore parse errors
        }
      });
      source.addEventListener("done", () => {
        setStreamStatuses((prev) => ({ ...prev, [runId]: "stopped" }));
        source.close();
        streamSourcesRef.current.delete(runId);
      });
      source.addEventListener("error", () => {
        setStreamStatuses((prev) => ({ ...prev, [runId]: "stopped" }));
        source.close();
        streamSourcesRef.current.delete(runId);
      });
    });
  }, [expandedRunIds, runDetails]);

  const loadRunDetail = React.useCallback(async (runId: string): Promise<void> => {
    setRunDetailErrors((prev) => {
      const next = { ...prev };
      delete next[runId];
      return next;
    });
    setRunDetailLoading((prev) => new Set(prev).add(runId));
    try {
      const response = await runsApi.get(runId);
      if (!response.ok) {
        throw new Error(response.error || "Failed to load run details.");
      }
      const data = response.data as RunDetail;
      setRunDetails((prev) => ({ ...prev, [runId]: data }));
    } catch (error) {
      setRunDetailErrors((prev) => ({
        ...prev,
        [runId]: error instanceof Error ? error.message : "Failed to load run details.",
      }));
    } finally {
      setRunDetailLoading((prev) => {
        const next = new Set(prev);
        next.delete(runId);
        return next;
      });
    }
  }, []);

  const toggleRun = (runId: string): void => {
    setExpandedRunIds((prev) => {
      const next = new Set(prev);
      if (next.has(runId)) {
        next.delete(runId);
      } else {
        next.add(runId);
      }
      return next;
    });
    if (!runDetails[runId]) {
      void loadRunDetail(runId);
    }
  };

  const ensureHistorySelection = React.useCallback(
    (runId: string, options: { id: string }[]): string | null => {
      if (!options.length) return null;
      const existing = historySelection[runId];
      if (existing && options.some((option) => option.id === existing)) return existing;
      return options[0].id;
    },
    [historySelection]
  );

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <div className="text-sm font-semibold text-white">Job Queue</div>
          <div className="text-xs text-gray-400">Full run payloads and queue snapshots.</div>
        </div>
        <Button
          type="button"
          className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
          onClick={() => { void runsQuery.refetch(); }}
          disabled={runsQuery.isFetching}
        >
          {runsQuery.isFetching ? "Refreshing..." : "Refresh"}
        </Button>
      </div>

      <div className="grid gap-3 md:grid-cols-2 xl:grid-cols-4">
        <div className="rounded-md border border-border/60 bg-card/50 p-3 text-xs text-gray-300">
          <div className="text-[10px] uppercase text-gray-500">Worker</div>
          <div className="mt-1 text-sm text-white">
            {queueStatus ? (queueStatus.running ? "Running" : "Stopped") : "-"}
          </div>
          <div className="mt-1 text-[11px] text-gray-400">
            Healthy: {queueStatus ? (queueStatus.healthy ? "Yes" : "No") : "-"}
          </div>
        </div>
        <div className="rounded-md border border-border/60 bg-card/50 p-3 text-xs text-gray-300">
          <div className="text-[10px] uppercase text-gray-500">Concurrency</div>
          <div className="mt-1 text-sm text-white">
            {queueStatus?.concurrency ?? "-"}
          </div>
          <div className="mt-1 text-[11px] text-gray-400">
            Active runs: {queueStatus?.activeRuns ?? 0}
          </div>
        </div>
        <div className="rounded-md border border-border/60 bg-card/50 p-3 text-xs text-gray-300">
          <div className="text-[10px] uppercase text-gray-500">Last poll</div>
          <div className="mt-1 text-sm text-white">
            {queueStatus?.lastPollTime
              ? new Date(queueStatus.lastPollTime).toLocaleTimeString()
              : "-"}
          </div>
          <div className="mt-1 text-[11px] text-gray-400">
            Age:{" "}
            {formatDurationMs(queueStatus?.timeSinceLastPoll ?? null)}
          </div>
        </div>
        <div className="rounded-md border border-border/60 bg-card/50 p-3 text-xs text-gray-300">
          <div className="text-[10px] uppercase text-gray-500">Status</div>
          <div className="mt-1 text-sm text-white">
            {queueStatusQuery.isFetching ? "Refreshing..." : "Live"}
          </div>
          {queueStatusQuery.error ? (
            <div className="mt-1 text-[11px] text-rose-200">
              {queueStatusQuery.error instanceof Error
                ? queueStatusQuery.error.message
                : "Failed to load queue status."}
            </div>
          ) : (
            <div className="mt-1 text-[11px] text-gray-400">
              Updated every 5s
            </div>
          )}
        </div>
      </div>

      <div className="grid gap-3 lg:grid-cols-[minmax(0,1fr)_minmax(0,1fr)_auto]">
        <div className="space-y-1">
          <Label className="text-[10px] uppercase text-gray-500">Path filter</Label>
          <Input
            className="h-9 rounded-md border border-border bg-card/60 px-3 text-sm text-white"
            value={pathFilter}
            onChange={(event: React.ChangeEvent<HTMLInputElement>) => setPathFilter(event.target.value)}
            placeholder={activePathId ? `Active path: ${activePathId}` : "All paths"}
          />
        </div>
        <div className="space-y-1">
          <Label className="text-[10px] uppercase text-gray-500">Search</Label>
          <Input
            className="h-9 rounded-md border border-border bg-card/60 px-3 text-sm text-white"
            value={searchQuery}
            onChange={(event: React.ChangeEvent<HTMLInputElement>) => setSearchQuery(event.target.value)}
            placeholder="Run ID, path name, entity, error..."
          />
        </div>
        <div className="space-y-1">
          <Label className="text-[10px] uppercase text-gray-500">Page size</Label>
          <Select
            value={String(pageSize)}
            onValueChange={(value) => setPageSize(Number.parseInt(value, 10))}
          >
            <SelectTrigger className="h-9 w-[110px] border-border bg-card/70 text-[11px] text-white">
              <SelectValue />
            </SelectTrigger>
            <SelectContent className="border-border bg-gray-900 text-white">
              {PAGE_SIZES.map((size) => (
                <SelectItem key={size} value={String(size)}>
                  {size}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <div className="flex flex-wrap gap-2">
        {STATUS_FILTERS.map((filter) => {
          const active = statusFilter === filter.id;
          return (
            <Button
              key={filter.id}
              type="button"
              className={`rounded-md border px-2 py-1 text-[10px] ${
                active ? "border-emerald-500/50 text-emerald-200" : "text-gray-300 hover:bg-muted/60"
              }`}
              onClick={() => setStatusFilter(filter.id)}
            >
              {filter.label}
            </Button>
          );
        })}
      </div>

      <div className="flex flex-wrap items-center justify-between gap-2 text-[11px] text-gray-400">
        <span>
          Showing {runs.length} of {total} runs
        </span>
        <div className="flex items-center gap-2">
          <Button
            type="button"
            className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
            onClick={() => setPage((prev) => Math.max(1, prev - 1))}
            disabled={page <= 1}
          >
            Prev
          </Button>
          <span>
            Page {page} / {totalPages}
          </span>
          <Button
            type="button"
            className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
            onClick={() => setPage((prev) => Math.min(totalPages, prev + 1))}
            disabled={page >= totalPages}
          >
            Next
          </Button>
        </div>
      </div>

      {runs.length === 0 ? (
        <div className="rounded-md border border-border bg-card/40 p-4 text-sm text-gray-400">
          No runs found for the current filters.
        </div>
      ) : (
        <div className="space-y-3">
          {runs.map((run) => {
            const isExpanded = expandedRunIds.has(run.id);
            const detail = runDetails[run.id];
            const detailLoading = runDetailLoading.has(run.id);
            const detailError = runDetailErrors[run.id];
            const detailRun = detail?.run ?? run;
            const streamStatus = streamStatuses[run.id] ?? "stopped";
            const nodes = detail?.nodes ?? [];
            const events = detail?.events ?? [];
            const history = (detailRun.runtimeState?.history ?? undefined) as
              | Record<string, RuntimeHistoryEntry[]>
              | undefined;
            const historyOptions = buildHistoryNodeOptions(
              history,
              nodes,
              detailRun.graph?.nodes ?? null
            );
            const selectedHistoryNodeId = ensureHistorySelection(run.id, historyOptions);
            const historyEntries =
              selectedHistoryNodeId && history
                ? history[selectedHistoryNodeId] ?? []
                : [];

            return (
              <div
                key={run.id}
                className="rounded-md border border-border/60 bg-card/70 p-3 text-xs text-gray-300"
              >
                <div className="flex flex-wrap items-start justify-between gap-3">
                  <div>
                    <div className="text-[10px] uppercase text-gray-400">{detailRun.status}</div>
                    <div className="text-sm text-white">{detailRun.pathName ?? "AI Path"}</div>
                    <div className="text-[11px] text-gray-400">
                      Run ID: <span className="font-mono">{detailRun.id}</span>
                    </div>
                    <div className="text-[11px] text-gray-500">
                      Created {formatDate(detailRun.createdAt)}
                    </div>
                    <div className="text-[11px] text-gray-500">
                      Stream: {streamStatus}
                    </div>
                    {(detailRun.entityType || detailRun.entityId) && (
                      <div className="text-[11px] text-gray-500">
                        Entity: {detailRun.entityType ?? "?"} {detailRun.entityId ?? ""}
                      </div>
                    )}
                    {detailRun.errorMessage && (
                      <div className="mt-1 rounded-md border border-rose-500/30 bg-rose-500/10 px-2 py-1 text-[11px] text-rose-200">
                        Error: {detailRun.errorMessage}
                      </div>
                    )}
                  </div>
                  <div className="flex flex-wrap items-center gap-2">
                    <Button
                      type="button"
                      className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
                      onClick={() => toggleRun(run.id)}
                    >
                      {isExpanded ? "Hide details" : "Details"}
                    </Button>
                    <Button
                      type="button"
                      className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
                      onClick={() => void loadRunDetail(run.id)}
                      disabled={detailLoading}
                    >
                      {detailLoading ? "Loading..." : "Refresh detail"}
                    </Button>
                  </div>
                </div>

                {isExpanded ? (
                  <div className="mt-4 space-y-3">
                    {detailError ? (
                      <div className="rounded-md border border-rose-500/30 bg-rose-500/10 p-3 text-[11px] text-rose-200">
                        {detailError}
                      </div>
                    ) : null}

                    {!detail && !detailLoading ? (
                      <div className="text-[11px] text-gray-500">
                        Loading run details...
                      </div>
                    ) : null}

                    {detail ? (
                      <>
                        <div className="grid gap-3 sm:grid-cols-2 lg:grid-cols-3 text-[11px] text-gray-400">
                          <div>
                            <span className="uppercase text-gray-500">Path ID</span>
                            <div className="text-white">{detailRun.pathId ?? "-"}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Status</span>
                            <div className="text-white">{detailRun.status}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Trigger</span>
                            <div className="text-white">{detailRun.triggerEvent ?? "-"}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Started</span>
                            <div className="text-white">{formatDate(detailRun.startedAt)}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Finished</span>
                            <div className="text-white">{formatDate(detailRun.finishedAt)}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Dead-lettered</span>
                            <div className="text-white">{formatDate(detailRun.deadLetteredAt)}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Retry</span>
                            <div className="text-white">
                              {detailRun.retryCount ?? 0}/{detailRun.maxAttempts ?? "-"}
                            </div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Next retry</span>
                            <div className="text-white">{formatDate(detailRun.nextRetryAt)}</div>
                          </div>
                          <div>
                            <span className="uppercase text-gray-500">Trigger node</span>
                            <div className="text-white">{detailRun.triggerNodeId ?? "-"}</div>
                          </div>
                        </div>

                        <details className="rounded-md border border-border/70 bg-black/20 p-3">
                          <summary className="cursor-pointer text-[11px] uppercase text-gray-400">
                            Run history
                          </summary>
                          {historyOptions.length > 1 ? (
                            <div className="mt-3 flex flex-wrap items-center gap-2">
                              <Label className="text-[10px] uppercase text-gray-500">
                                Node
                              </Label>
                              <Select
                                value={selectedHistoryNodeId ?? undefined}
                                onValueChange={(value) =>
                                  setHistorySelection((prev) => ({ ...prev, [run.id]: value }))
                                }
                              >
