"use client";

import React from "react";

import {
  Button,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/shared/ui";

import type { AiPathRunRecord, RuntimeHistoryEntry } from "@/features/ai-paths/lib";
import { RunHistoryEntries } from "./RunHistoryEntries";
import { buildHistoryNodeOptions } from "./run-history-utils";

export type RunHistoryFilter = "all" | "active" | "failed" | "dead";

type RunHistoryPanelProps = {
  runs: AiPathRunRecord[];
  isRefreshing: boolean;
  onRefresh: () => void;
  runFilter: RunHistoryFilter;
  setRunFilter: React.Dispatch<React.SetStateAction<RunHistoryFilter>>;
  expandedRunHistory: Record<string, boolean>;
  setExpandedRunHistory: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
  runHistorySelection: Record<string, string>;
  setRunHistorySelection: React.Dispatch<React.SetStateAction<Record<string, string>>>;
  onOpenRunDetail: (runId: string) => void;
  onResumeRun: (runId: string, mode: "resume" | "replay") => void;
  onCancelRun: (runId: string) => void;
  onRequeueDeadLetter: (runId: string) => void;
};

export function RunHistoryPanel({
  runs,
  isRefreshing,
  onRefresh,
  runFilter,
  setRunFilter,
  expandedRunHistory,
  setExpandedRunHistory,
  runHistorySelection,
  setRunHistorySelection,
  onOpenRunDetail,
  onResumeRun,
  onCancelRun,
  onRequeueDeadLetter,
}: RunHistoryPanelProps): React.JSX.Element {
  const filteredRunList = React.useMemo((): AiPathRunRecord[] => {
    if (runFilter === "all") return runs;
    if (runFilter === "active") {
      return runs.filter(
        (run) => run.status === "queued" || run.status === "running"
      );
    }
    if (runFilter === "failed") {
      return runs.filter(
        (run) => run.status === "failed" || run.status === "paused"
      );
    }
    return runs.filter((run) => run.status === "dead_lettered");
  }, [runFilter, runs]);

  return (
    <div className="rounded-lg border border-border bg-card/60 p-4">
      <div className="mb-3 flex items-center justify-between">
        <span className="text-sm font-semibold text-white">Run History</span>
        <Button
          type="button"
          className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
          onClick={onRefresh}
          disabled={isRefreshing}
        >
          {isRefreshing ? "Refreshing..." : "Refresh"}
        </Button>
      </div>
      <div className="mb-3 flex flex-wrap gap-2">
        {[
          { id: "all", label: "All" },
          { id: "active", label: "Active" },
          { id: "failed", label: "Failed" },
          { id: "dead", label: "Dead-letter" },
        ].map((filter) => (
          <Button
            key={filter.id}
            type="button"
            className={`rounded-md border px-2 py-1 text-[10px] ${
              runFilter === filter.id
                ? "border-emerald-500/50 text-emerald-200"
                : "text-gray-300 hover:bg-muted/60"
            }`}
            onClick={() => setRunFilter(filter.id as RunHistoryFilter)}
          >
            {filter.label}
          </Button>
        ))}
      </div>
      {filteredRunList.length === 0 ? (
        <div className="text-[11px] text-gray-500">No runs yet.</div>
      ) : (
        <div className="space-y-2 text-xs text-gray-300">
          {filteredRunList.slice(0, 6).map((run) => {
            const statusClass =
              run.status === "completed"
                ? "text-emerald-200"
                : run.status === "failed"
                  ? "text-rose-200"
                  : run.status === "dead_lettered"
                    ? "text-rose-300"
                    : run.status === "running"
                      ? "text-sky-200"
                      : run.status === "queued"
                        ? "text-amber-200"
                        : "text-gray-300";
            const runHistory = (run.runtimeState?.history ?? undefined) as
              | Record<string, RuntimeHistoryEntry[]>
              | undefined;
            const runHistoryOptions = buildHistoryNodeOptions(
              runHistory,
              null,
              run.graph?.nodes ?? null
            );
            const rawSelectedHistoryNodeId = runHistorySelection[run.id] ?? null;
            const selectedHistoryNodeId = runHistoryOptions.some(
              (option) => option.id === rawSelectedHistoryNodeId
            )
              ? rawSelectedHistoryNodeId
              : runHistoryOptions[0]?.id ?? null;
            const historyOpen = Boolean(expandedRunHistory[run.id]);
            const historyEntries =
              selectedHistoryNodeId && runHistory
                ? runHistory[selectedHistoryNodeId] ?? []
                : [];
            return (
              <div
                key={run.id}
                className="rounded-md border border-border/60 bg-card/70 p-2"
              >
                <div className="flex items-center justify-between">
                  <div>
                    <div className={`text-[10px] uppercase ${statusClass}`}>
                      {run.status}
                    </div>
                    <div className="text-[11px] text-gray-400">
                      {new Date(run.createdAt).toLocaleString()}
                    </div>
                    {typeof run.retryCount === "number" &&
                      typeof run.maxAttempts === "number" && (
                        <div className="text-[10px] text-gray-500">
                          Retries: {run.retryCount}/{run.maxAttempts}
                        </div>
                      )}
                    {run.nextRetryAt && (
                      <div className="text-[10px] text-amber-200">
                        Retry at {new Date(run.nextRetryAt).toLocaleString()}
                      </div>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <Button
                      type="button"
                      className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
                      onClick={() => onOpenRunDetail(run.id)}
                    >
                      Details
                    </Button>
                    <Button
                      type="button"
                      className="rounded-md border px-2 py-1 text-[10px] text-gray-200 hover:bg-muted/60"
                      onClick={() => {
                        setExpandedRunHistory((prev) => ({
                          ...prev,
                          [run.id]: !prev[run.id],
                        }));
                        if (!runHistorySelection[run.id] && runHistoryOptions[0]?.id) {
                          setRunHistorySelection((prev) => ({
                            ...prev,
                            [run.id]: runHistoryOptions[0].id,
                          }));
                        }
                      }}
                    >
                      {historyOpen ? "Hide history" : "History"}
                    </Button>
                    {(run.status === "failed" || run.status === "paused") && (
                      <Button
                        type="button"
                        className="rounded-md border px-2 py-1 text-[10px] text-amber-200 hover:bg-amber-500/10"
                        onClick={() => onResumeRun(run.id, "resume")}
                      >
                        Resume
                      </Button>
                    )}
                    <Button
                      type="button"
                      className="rounded-md border px-2 py-1 text-[10px] text-sky-200 hover:bg-sky-500/10"
                      onClick={() => onResumeRun(run.id, "replay")}
                    >
                      Replay
                    </Button>
                    {(run.status === "queued" || run.status === "running") && (
                      <Button
                        type="button"
                        className="rounded-md border px-2 py-1 text-[10px] text-rose-200 hover:bg-rose-500/10"
                        onClick={() => onCancelRun(run.id)}
                      >
                        Cancel
                      </Button>
                    )}
                    {run.status === "dead_lettered" && (
                      <Button
                        type="button"
                        className="rounded-md border px-2 py-1 text-[10px] text-amber-200 hover:bg-amber-500/10"
                        onClick={() => onRequeueDeadLetter(run.id)}
                      >
                        Requeue
                      </Button>
                    )}
                  </div>
                </div>
                {run.errorMessage && (
                  <div className="mt-2 text-[10px] text-rose-300">
                    {run.errorMessage}
                  </div>
                )}
                {historyOpen && (
                  <div className="mt-2 rounded-md border border-border/70 bg-black/20 p-3">
                    <div className="flex flex-wrap items-center gap-2">
                      <Label className="text-[10px] uppercase text-gray-500">History</Label>
                      {runHistory ? (
                        runHistoryOptions.length > 1 ? (
                          <Select
                            value={selectedHistoryNodeId ?? undefined}
                            onValueChange={(value) =>
                              setRunHistorySelection((prev) => ({
                                ...prev,
                                [run.id]: value,
                              }))
                            }
                          >
                            <SelectTrigger className="h-7 w-[220px] border-border bg-card/70 text-[11px] text-white">
                              <SelectValue placeholder="Select node" />
                            </SelectTrigger>
                            <SelectContent className="border-border bg-gray-900 text-white">
                              {runHistoryOptions.map((option) => (
                                <SelectItem key={option.id} value={option.id}>
                                  {option.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        ) : (
                          <div className="text-[11px] text-gray-400">
                            {runHistoryOptions[0]?.label ?? "No nodes"}
                          </div>
                        )
                      ) : null}
                    </div>
                    {runHistory && selectedHistoryNodeId ? (
                      <div className="mt-3">
                        <RunHistoryEntries
                          entries={historyEntries}
                          emptyMessage="No history for this node."
                        />
                      </div>
                    ) : (
                      <div className="mt-2 text-[11px] text-gray-500">
                        No history recorded for this run.
                      </div>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

"use client";

import React from "react";

import { Button, Tooltip } from "@/shared/ui";

import type {
  AiPathRunEventRecord,
  AiPathRunNodeRecord,
  AiPathRunRecord,
} from "@/features/ai-paths/lib";

type TimelineItem = {
  id: string;
  timestamp: Date;
  label: string;
  description?: string;
  status?: string | null;
  kind: "run" | "node";
  meta?: string;
};

type TimelineFilter = "run" | "node" | "event";

type NodeDurationRow = {
  id: string;
  label: string;
  status?: string | null;
  durationMs: number | null;
  durationLabel: string | null;
};

const STATUS_SORT_STORAGE_KEY = "ai-paths-run-timeline-status-sort";
const FILTERS_STORAGE_KEY = "ai-paths-run-timeline-filters";

const statusBadgeStyles: Record<string, string> = {
  queued: "border-slate-500/40 bg-slate-500/10 text-slate-200",
  running: "border-sky-500/40 bg-sky-500/10 text-sky-200",
  paused: "border-amber-500/40 bg-amber-500/10 text-amber-200",
  completed: "border-emerald-500/40 bg-emerald-500/10 text-emerald-200",
  failed: "border-rose-500/40 bg-rose-500/10 text-rose-200",
  canceled: "border-orange-500/40 bg-orange-500/10 text-orange-200",
  dead_lettered: "border-purple-500/40 bg-purple-500/10 text-purple-200",
  pending: "border-slate-500/40 bg-slate-500/10 text-slate-200",
  skipped: "border-zinc-500/40 bg-zinc-500/10 text-zinc-200",
  blocked: "border-amber-500/40 bg-amber-500/10 text-amber-200",
};

const levelBadgeStyles: Record<string, string> = {
  info: "border-sky-500/40 bg-sky-500/10 text-sky-200",
  warning: "border-amber-500/40 bg-amber-500/10 text-amber-200",
  error: "border-rose-500/40 bg-rose-500/10 text-rose-200",
};

const toDate = (value?: Date | string | null): Date | null => {
  if (!value) return null;
  if (value instanceof Date) return value;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};

const formatDuration = (start?: Date | string | null, end?: Date | string | null): string | null => {
  const startDate = toDate(start);
  const endDate = toDate(end);
  if (!startDate || !endDate) return null;
  const diffMs = Math.max(endDate.getTime() - startDate.getTime(), 0);
  if (diffMs < 1000) return `${diffMs}ms`;
  const seconds = Math.round(diffMs / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remaining = seconds % 60;
  return `${minutes}m ${remaining}s`;
};

const formatDurationMs = (diffMs: number | null): string | null => {
  if (diffMs === null || Number.isNaN(diffMs)) return null;
  if (diffMs < 1000) return `${Math.max(diffMs, 0)}ms`;
  const seconds = Math.round(diffMs / 1000);
  if (seconds < 60) return `${seconds}s`;
  const minutes = Math.floor(seconds / 60);
  const remaining = seconds % 60;
  if (minutes < 60) return `${minutes}m ${remaining}s`;
  const hours = Math.floor(minutes / 60);
  const minutesRemaining = minutes % 60;
  return `${hours}h ${minutesRemaining}m`;
};

const getDurationMs = (
  start?: Date | string | null,
  end?: Date | string | null
): number | null => {
  const startDate = toDate(start);
  const endDate = toDate(end);
  if (!startDate || !endDate) return null;
  return Math.max(endDate.getTime() - startDate.getTime(), 0);
};

const buildTimelineItems = (
  run: AiPathRunRecord,
  nodes: AiPathRunNodeRecord[]
): TimelineItem[] => {
  const items: TimelineItem[] = [];
  const createdAt = toDate(run.createdAt);
  if (createdAt) {
    items.push({
      id: `run-created-${run.id}`,
      timestamp: createdAt,
      label: "Run queued",
      description: run.pathName ?? run.pathId ?? "AI Path",
      status: "queued",
      kind: "run",
    });
  }
  const startedAt = toDate(run.startedAt);
  if (startedAt) {
    items.push({
      id: `run-started-${run.id}`,
      timestamp: startedAt,
      label: "Run started",
      description: run.pathName ?? run.pathId ?? "AI Path",
      status: "running",
      kind: "run",
    });
  }

  nodes.forEach((node) => {
    const nodeLabel = node.nodeTitle ?? node.nodeId;
    const nodeMeta = node.nodeType ? `${nodeLabel} (${node.nodeType})` : nodeLabel;
    const startAt = toDate(node.startedAt);
    if (startAt) {
      items.push({
        id: `node-start-${node.id}`,
        timestamp: startAt,
        label: "Node started",
        description: nodeMeta,
        status: "running",
        kind: "node",
      });
    }
    const finishAt = toDate(node.finishedAt);
    if (finishAt) {
      const duration = formatDuration(node.startedAt, node.finishedAt);
      const finishDescription = duration ? `${nodeMeta} · ${duration}` : nodeMeta;
      items.push({
        id: `node-finish-${node.id}`,
        timestamp: finishAt,
        label: `Node ${node.status}`,
        description: finishDescription,
        status: node.status,
        kind: "node",
        meta: node.errorMessage ? `Error: ${node.errorMessage}` : undefined,
      });
    }
  });

  const finishedAt = toDate(run.finishedAt);
  if (finishedAt) {
    items.push({
      id: `run-finished-${run.id}`,
      timestamp: finishedAt,
      label: `Run ${run.status}`,
      description: run.pathName ?? run.pathId ?? "AI Path",
      status: run.status,
      kind: "run",
      meta: run.errorMessage ? `Error: ${run.errorMessage}` : undefined,
    });
  }

  return items
    .filter((item) => Number.isFinite(item.timestamp.getTime()))
    .sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
};

const formatMetadata = (metadata?: Record<string, unknown> | null): string | null => {
  if (!metadata || Object.keys(metadata).length === 0) return null;
  try {
    return JSON.stringify(metadata, null, 2);
  } catch {
    return String(metadata);
  }
};

export function RunTimeline({
  run,
  nodes,
  events,
  eventsOverflow,
  eventsBatchLimit,
}: {
  run: AiPathRunRecord;
  nodes: AiPathRunNodeRecord[];
  events: AiPathRunEventRecord[];
  eventsOverflow?: boolean;
  eventsBatchLimit?: number | null;
}): React.JSX.Element {
  const timelineItems = React.useMemo(
    () => buildTimelineItems(run, nodes),
    [run, nodes]
  );

  const sortedEvents = React.useMemo(
    () =>
      [...events].sort(
        (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      ),
    [events]
  );

  const [visibleSections, setVisibleSections] = React.useState<Record<TimelineFilter, boolean>>(
    () => {
      if (typeof window === "undefined") {
        return { run: true, node: true, event: true };
      }
      try {
        const raw = window.localStorage.getItem(FILTERS_STORAGE_KEY);
        const parsed = raw ? (JSON.parse(raw) as Partial<Record<TimelineFilter, boolean>>) : null;
        return {
          run: parsed?.run ?? true,
          node: parsed?.node ?? true,
          event: parsed?.event ?? true,
        };
      } catch {
        return { run: true, node: true, event: true };
      }
    }
  );

  React.useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(FILTERS_STORAGE_KEY, JSON.stringify(visibleSections));
  }, [visibleSections]);

  const filteredTimelineItems = React.useMemo(
    () => timelineItems.filter((item) => visibleSections[item.kind]),
    [timelineItems, visibleSections]
  );

  const runEntryCount = React.useMemo(
    () => timelineItems.filter((item) => item.kind === "run").length,
    [timelineItems]
  );

  const nodeEntryCount = React.useMemo(
    () => timelineItems.filter((item) => item.kind === "node").length,
    [timelineItems]
  );

  const nodeDurationRows = React.useMemo<NodeDurationRow[]>(
    () =>
      nodes.map((node) => {
        const nodeLabel = node.nodeTitle ?? node.nodeId;
        const nodeMeta = node.nodeType ? `${nodeLabel} (${node.nodeType})` : nodeLabel;
        const durationMs = getDurationMs(node.startedAt, node.finishedAt);
        return {
          id: node.id,
          label: nodeMeta,
          status: node.status,
          durationMs,
          durationLabel: formatDuration(node.startedAt, node.finishedAt),
        };
      }),
    [nodes]
  );

  const durationStats = React.useMemo(() => {
    const durations = nodeDurationRows
      .map((row) => row.durationMs)
      .filter((duration): duration is number => typeof duration === "number");
    const total = durations.reduce((acc, value) => acc + value, 0);
    const average = durations.length > 0 ? Math.round(total / durations.length) : null;
    const min = durations.length > 0 ? Math.min(...durations) : null;
    const max = durations.length > 0 ? Math.max(...durations) : null;
    return {
      total,
      average,
      min,
      max,
      timedCount: durations.length,
      totalCount: nodeDurationRows.length,
    };
  }, [nodeDurationRows]);

  const durationByStatus = React.useMemo(() => {
    const buckets = new Map<
      string,
      { count: number; timedCount: number; totalMs: number; min: NodeDurationRow | null; max: NodeDurationRow | null }
    >();
    nodeDurationRows.forEach((row) => {
      const key = row.status ?? "unknown";
      const bucket =
        buckets.get(key) ?? { count: 0, timedCount: 0, totalMs: 0, min: null, max: null };
      bucket.count += 1;
      if (typeof row.durationMs === "number") {
        bucket.timedCount += 1;
        bucket.totalMs += row.durationMs;
        if (!bucket.min || row.durationMs < (bucket.min.durationMs ?? Infinity)) {
          bucket.min = row;
        }
        if (!bucket.max || row.durationMs > (bucket.max.durationMs ?? -Infinity)) {
          bucket.max = row;
        }
      }
      buckets.set(key, bucket);
    });

    return Array.from(buckets.entries()).map(([status, data]) => ({
      status,
      count: data.count,
      timedCount: data.timedCount,
      totalMs: data.totalMs,
      averageMs: data.timedCount > 0 ? Math.round(data.totalMs / data.timedCount) : null,
      min: data.min,
      max: data.max,
    }));
  }, [nodeDurationRows]);

  const [statusSort, setStatusSort] = React.useState<"count" | "avg" | "total" | "alpha">(
    () => {
      if (typeof window === "undefined") return "count";
      const saved = window.localStorage.getItem(STATUS_SORT_STORAGE_KEY);
      if (saved === "count" || saved === "avg" || saved === "total" || saved === "alpha") {
        return saved;
      }
      return "count";
    }
  );

  React.useEffect(() => {
    if (typeof window === "undefined") return;
    window.localStorage.setItem(STATUS_SORT_STORAGE_KEY, statusSort);
  }, [statusSort]);

  const sortedDurationByStatus = React.useMemo(() => {
    const list = [...durationByStatus];
    if (statusSort === "count") {
      list.sort((a, b) => {
        if (b.count !== a.count) return b.count - a.count;
        return a.status.localeCompare(b.status);
      });
      return list;
    }
    list.sort((a, b) => {
      if (statusSort === "alpha") {
        return a.status.localeCompare(b.status);
      }
      if (statusSort === "total") {
        if (b.totalMs !== a.totalMs) return b.totalMs - a.totalMs;
        if (b.count !== a.count) return b.count - a.count;
        return a.status.localeCompare(b.status);
      }
      const aAvg = a.averageMs ?? -1;
      const bAvg = b.averageMs ?? -1;
      if (bAvg !== aAvg) return bAvg - aAvg;
      if (b.count !== a.count) return b.count - a.count;
      return a.status.localeCompare(b.status);
    });
    return list;
  }, [durationByStatus, statusSort]);

  const minMaxNodeDuration = React.useMemo(() => {
    const timed = nodeDurationRows.filter(
      (row) => typeof row.durationMs === "number"
    );
    if (timed.length === 0) {
      return { min: null, max: null } as const;
    }
    let min = timed[0];
    let max = timed[0];
    timed.forEach((row) => {
      if ((row.durationMs ?? 0) < (min.durationMs ?? 0)) min = row;
      if ((row.durationMs ?? 0) > (max.durationMs ?? 0)) max = row;
    });
    return { min, max } as const;
  }, [nodeDurationRows]);

  const toggleSection = (section: TimelineFilter): void => {
    setVisibleSections((prev) => ({ ...prev, [section]: !prev[section] }));
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-2">
        <div className="text-[11px] uppercase text-gray-500">Filters</div>
        <div className="flex flex-wrap items-center gap-2">
          <span className="rounded-md border border-emerald-500/30 bg-emerald-500/10 px-2 py-1 text-[10px] text-emerald-200">
            Persisted
          </span>
          <Button
            type="button"
            className="rounded-md border px-2 py-1 text-[10px] text-gray-300 hover:bg-muted/60"
            onClick={() => {
              setVisibleSections({ run: true, node: true, event: true });
              setStatusSort("count");
            }}
          >
            Restore defaults
          </Button>
          <Button
            type="button"
            className="rounded-md border px-2 py-1 text-[10px] text-gray-300 hover:bg-muted/60"
            onClick={() => setVisibleSections({ run: true, node: true, event: true })}
          >
            Filters only
          </Button>
          {[
            { id: "run", label: `Run (${runEntryCount})` },
            { id: "node", label: `Nodes (${nodeEntryCount})` },
            { id: "event", label: `Events (${sortedEvents.length})` },
          ].map((filter) => {
            const active = visibleSections[filter.id as TimelineFilter];
            return (
              <Button
                key={filter.id}
                type="button"
                className={`rounded-md border px-2 py-1 text-[10px] ${
                  active
                    ? "border-emerald-500/50 text-emerald-200"
                    : "text-gray-300 hover:bg-muted/60"
                }`}
                onClick={() => toggleSection(filter.id as TimelineFilter)}
              >
                {filter.label}
              </Button>
            );
          })}
        </div>
      </div>

      {visibleSections.node ? (
        <div className="rounded-md border border-border/70 bg-black/20 p-3">
          <div className="flex flex-wrap items-center justify-between gap-2 text-[11px] text-gray-500">
            <span className="uppercase">Node duration summary</span>
            <span>{nodeDurationRows.length} nodes</span>
          </div>
          <div className="mt-1 text-[11px] text-gray-500">
            Total {formatDurationMs(durationStats.total) ?? "—"} · Avg{" "}
            {formatDurationMs(durationStats.average) ?? "—"} ·{" "}
            {minMaxNodeDuration.min ? (
              <Tooltip
                content={`Fastest: ${minMaxNodeDuration.min.label} · ${formatDurationMs(
                  minMaxNodeDuration.min.durationMs
                )}`}
              >
                <span className="cursor-help">
                  Min {formatDurationMs(durationStats.min) ?? "—"}
                </span>
              </Tooltip>
            ) : (
              <span>Min —</span>
            )}{" "}
            ·{" "}
            {minMaxNodeDuration.max ? (
              <Tooltip
                content={`Slowest: ${minMaxNodeDuration.max.label} · ${formatDurationMs(
                  minMaxNodeDuration.max.durationMs
                )}`}
              >
                <span className="cursor-help">
                  Max {formatDurationMs(durationStats.max) ?? "—"}
                </span>
              </Tooltip>
            ) : (
              <span>Max —</span>
            )}{" "}
            · Timed {durationStats.timedCount}/{durationStats.totalCount}
          </div>
          {sortedDurationByStatus.length > 0 ? (
            <div className="mt-2 space-y-2 text-[11px] text-gray-400">
              <div className="flex flex-wrap items-center gap-2 text-gray-500">
                <span className="uppercase">Sort by</span>
                {([
                  { id: "count", label: "Count" },
                  { id: "avg", label: "Avg duration" },
                  { id: "total", label: "Total duration" },
                  { id: "alpha", label: "A-Z" },
                ] as const).map((option) => {
                  const active = statusSort === option.id;
                  return (
                    <Button
                      key={option.id}
                      type="button"
                      className={`rounded-md border px-2 py-1 text-[10px] ${
                        active
                          ? "border-emerald-500/50 text-emerald-200"
                          : "text-gray-300 hover:bg-muted/60"
                      }`}
                      onClick={() => setStatusSort(option.id)}
                    >
                      {option.label}
                    </Button>
                  );
                })}
              </div>
              <div className="flex flex-wrap gap-2">
                {sortedDurationByStatus.map((bucket) => {
                  const badgeClass =
                    statusBadgeStyles[bucket.status] ??
                    "border-border bg-card/40 text-gray-200";
                  const tooltipContent =
                    bucket.min || bucket.max
                      ? [
                          bucket.min
                            ? `Fastest: ${bucket.min.label} · ${formatDurationMs(
                                bucket.min.durationMs
                              )}`
                            : "Fastest: —",
                          bucket.max
                            ? `Slowest: ${bucket.max.label} · ${formatDurationMs(
                                bucket.max.durationMs
                              )}`
                            : "Slowest: —",
                        ].join("\n")
                      : null;
                  const chip = (
                    <div
                      key={bucket.status}
                      className="flex items-center gap-2 rounded-full border border-border/60 bg-black/30 px-3 py-1"
                    >
                      <span className={`rounded-full border px-2 py-0.5 ${badgeClass}`}>
                        {bucket.status}
                      </span>
                      <span>
                        Avg {formatDurationMs(bucket.averageMs) ?? "—"}
                      </span>
                      <span>
                        Total {formatDurationMs(bucket.totalMs) ?? "—"}
                      </span>
                      <span>
                        Min {formatDurationMs(bucket.min?.durationMs ?? null) ?? "—"}
                      </span>
                      <span>
                        Max {formatDurationMs(bucket.max?.durationMs ?? null) ?? "—"}
                      </span>
                      <span>
                        Timed {bucket.timedCount}/{bucket.count}
                      </span>
                    </div>
                  );
                  return tooltipContent ? (
                    <Tooltip key={bucket.status} content={tooltipContent}>
                      {chip}
                    </Tooltip>
                  ) : (
                    chip
                  );
                })}
              </div>
            </div>
          ) : null}
          {nodeDurationRows.length === 0 ? (
            <div className="mt-2 text-[11px] text-gray-500">
              No node timing data available yet.
            </div>
          ) : (
            <div className="mt-2 max-h-[200px] overflow-auto space-y-2">
              {nodeDurationRows.map((row) => {
                const badgeClass =
                  statusBadgeStyles[row.status ?? ""] ??
                  "border-border bg-card/40 text-gray-200";
                return (
                  <div
                    key={row.id}
                    className="flex flex-wrap items-center justify-between gap-2 rounded-md border border-border/60 bg-black/30 px-3 py-2"
                  >
                    <div className="min-w-[180px] flex-1 text-sm text-white">
                      {row.label}
                    </div>
                    <div className="flex items-center gap-2 text-[11px] text-gray-400">
                      <span className={`rounded-full border px-2 py-0.5 ${badgeClass}`}>
                        {row.status ?? "unknown"}
                      </span>
                      <span>{row.durationLabel ?? "—"}</span>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      ) : null}

      <div>
        <div className="flex items-center justify-between">
          <div className="text-[11px] uppercase text-gray-500">Runtime timeline</div>
          <div className="text-[11px] text-gray-500">
            {filteredTimelineItems.length} entries
          </div>
        </div>
        {filteredTimelineItems.length === 0 ? (
          <div className="mt-3 rounded-md border border-border bg-card/40 p-4 text-xs text-gray-400">
            Timeline is empty for the current filters.
          </div>
        ) : (
          <div className="mt-3 max-h-[320px] overflow-auto rounded-md border border-border bg-black/20 p-4">
            <div className="relative border-l border-border/60 pl-4">
              {filteredTimelineItems.map((item, index) => {
                const badgeClass =
                  statusBadgeStyles[item.status ?? ""] ??
                  "border-border bg-card/40 text-gray-200";
                return (
                  <div key={`${item.id}-${index}`} className="relative pb-4">
                    <div className="absolute -left-[7px] top-2 h-2.5 w-2.5 rounded-full bg-gray-400" />
                    <div className="flex flex-wrap items-center gap-2 text-xs text-gray-300">
                      <span className="text-[11px] text-gray-500">
                        {item.timestamp.toLocaleString()}
                      </span>
                      <span className={`rounded-full border px-2 py-0.5 text-[11px] ${badgeClass}`}>
                        {item.status ?? item.kind}
                      </span>
                      <span className="text-[11px] uppercase text-gray-500">
                        {item.kind}
                      </span>
                    </div>
                    <div className="mt-1 text-sm text-white">{item.label}</div>
                    {item.description ? (
                      <div className="text-xs text-gray-400">{item.description}</div>
                    ) : null}
                    {item.meta ? (
                      <div className="mt-2 rounded-md border border-rose-500/30 bg-rose-500/10 p-2 text-[11px] text-rose-200">
                        {item.meta}
                      </div>
                    ) : null}
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {visibleSections.event ? (
        <div>
          <div className="flex items-center gap-2">
            <div className="text-[11px] uppercase text-gray-500">Logs</div>
            {eventsOverflow ? (
              <span className="rounded border border-amber-400/50 bg-amber-500/10 px-2 py-0.5 text-[10px] text-amber-200">
                Truncated{eventsBatchLimit ? ` (limit ${eventsBatchLimit})` : ""}
              </span>
            ) : null}
          </div>
          {sortedEvents.length === 0 ? (
            <div className="mt-3 rounded-md border border-border bg-card/40 p-4 text-xs text-gray-400">
              No logs captured for this run yet.
            </div>
          ) : (
            <div className="mt-3 max-h-[360px] overflow-auto rounded-md border border-border bg-black/20">
              <div className="divide-y divide-border/70">
                {sortedEvents.map((event) => {
                  const badgeClass =
                    levelBadgeStyles[event.level] ??
                    "border-border bg-card/40 text-gray-200";
                  const metadata = formatMetadata(event.metadata);
                  return (
                    <div key={event.id} className="p-3">
                      <div className="flex flex-wrap items-center gap-2 text-xs text-gray-400">
                        <span>{new Date(event.createdAt).toLocaleString()}</span>
                        <span className={`rounded-full border px-2 py-0.5 text-[10px] ${badgeClass}`}>
                          {event.level}
                        </span>
                      </div>
                      <div className="mt-1 text-sm text-white">{event.message}</div>
                      {metadata ? (
                        <pre className="mt-2 max-h-40 overflow-auto rounded-md border border-border bg-black/30 p-2 text-[11px] text-gray-200">
                          {metadata}
                        </pre>
                      ) : null}
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      ) : null}
    </div>
  );
}

"use client";

import React from "react";

import {
  Button,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  Input,
  Label,
} from "@/shared/ui";

import type { AiNode } from "@/features/ai-paths/lib";

type SimulationDialogProps = {
  openNodeId: string | null;
  onClose: () => void;
  nodes: AiNode[];
  setNodes: React.Dispatch<React.SetStateAction<AiNode[]>>;
  onRunSimulation: (node: AiNode) => void;
};

export function SimulationDialog({
  openNodeId,
  onClose,
  nodes,
  setNodes,
  onRunSimulation,
}: SimulationDialogProps): React.JSX.Element | null {
  if (!openNodeId) return null;
  const simulationNode = nodes.find((node: AiNode): boolean => node.id === openNodeId);

  return (
    <Dialog
      open={Boolean(openNodeId)}
      onOpenChange={(open: boolean): void => {
        if (!open) onClose();
      }}
    >
      <DialogContent className="max-w-md border border-border bg-card text-white">
        <DialogHeader>
          <DialogTitle className="text-lg">Simulation Modal</DialogTitle>
          <DialogDescription className="text-sm text-gray-400">
            Set an Entity ID and simulate the connected trigger action.
          </DialogDescription>
        </DialogHeader>
        {simulationNode ? (() => {
          const simulationConfig = simulationNode.config?.simulation ?? { productId: "" };
          const simulationEntityValue =
            simulationConfig.entityId?.trim()
              ? simulationConfig.entityId
              : simulationConfig.productId ?? "";
          return (
            <div className="space-y-4">
              <div>
                <Label className="text-xs text-gray-400">Entity ID</Label>
                <Input
                  className="mt-2 w-full rounded-md border border-border bg-card/70 text-sm text-white"
                  value={simulationEntityValue}
                  onChange={(event: React.ChangeEvent<HTMLInputElement>) => {
                    const value = event.target.value;
                    setNodes((prev: AiNode[]): AiNode[] =>
                      prev.map((node: AiNode): AiNode =>
                        node.id === simulationNode.id
                          ? {
                              ...node,
                              config: {
                                ...node.config,
                                simulation: {
                                  productId: value,
                                  entityId: value,
                                  entityType: simulationConfig.entityType ?? "product",
                                },
                              },
                            }
                          : node
                      )
                    );
                  }}
                />
                <p className="mt-2 text-[11px] text-gray-500">
                  Current entity type: {simulationConfig.entityType ?? "product"}
                </p>
              </div>
              <Button
                className="w-full rounded-md border border-cyan-500/40 text-sm text-cyan-200 hover:bg-cyan-500/10"
                type="button"
                onClick={() => onRunSimulation(simulationNode)}
              >
                Simulate Trigger
              </Button>
            </div>
          );
        })() : null}
      </DialogContent>
    </Dialog>
  );
}

