                                      </pre>
                                    </div>
                                  </div>
                                </TableCell>
                              </TableRow>
                            ) : null}
                          </Fragment>
                        );
                      })}
                      {detail.nodes.length === 0 ? (
                        <TableRow>
                          <TableCell colSpan={7} className="h-16 text-center text-xs text-gray-400">
                            No nodes recorded.
