                          {event.metadata ? (
                            <pre className="mt-2 max-h-28 overflow-auto rounded bg-black/40 p-2 text-[10px] text-gray-200 whitespace-pre-wrap">
                              {JSON.stringify(event.metadata, null, 2)}
