                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          ) : (
            <div className="text-sm text-gray-400">No detail available.</div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

