import "server-only";

import type {
  AiNode,
  AiPathRunRecord,
  Edge,
  RuntimeHistoryEntry,
  RuntimePortValues,
  RuntimeState,
} from "@/shared/types/ai-paths";
import { evaluateGraph, normalizeNodes, sanitizeEdges } from "@/features/ai-paths/lib";
import { getPathRunRepository } from "@/features/ai-paths/services/path-run-repository";
import { ErrorSystem } from "@/features/observability/services/error-system";
import { getProductRepository } from "@/features/products/services/product-repository";
import { noteService } from "@/features/notesapp/server";

const parseRuntimeState = (value: unknown): RuntimeState => {
  if (!value) return { inputs: {}, outputs: {} };
  if (typeof value === "string") {
    try {
      const parsed = JSON.parse(value) as RuntimeState;
      return parsed && typeof parsed === "object" ? parsed : { inputs: {}, outputs: {} };
    } catch {
      return { inputs: {}, outputs: {} };
    }
  }
  if (typeof value === "object") {
    return value as RuntimeState;
  }
  return { inputs: {}, outputs: {} };
};

const toJsonSafe = (value: unknown): unknown => {
  const seen = new WeakSet();
  const replacer = (_key: string, val: unknown) => {
    if (typeof val === "bigint") return val.toString();
    if (val instanceof Date) return val.toISOString();
    if (val instanceof Set) return Array.from(val.values()) as unknown[];
    if (val instanceof Map) return Object.fromEntries(val.entries()) as Record<string, unknown>;
    if (typeof val === "function" || typeof val === "symbol") return undefined;
          if (val && typeof val === "object") {
            if (seen.has(val)) return undefined;
            seen.add(val);
          }

    return val;
  };
  try {
    return JSON.parse(JSON.stringify(value, replacer)) as unknown;
  } catch {
    return null;
  }
};

const sanitizeRuntimeState = (state: RuntimeState): RuntimeState => {
  const safe = toJsonSafe(state);
  if (safe && typeof safe === "object") {
    return safe as RuntimeState;
  }
  return { inputs: {}, outputs: {} };
};

const computeDownstreamNodes = (
  edges: Edge[],
  startNodes: Set<string>
): Set<string> => {
  const adjacency = new Map<string, Set<string>>();
  edges.forEach((edge: Edge) => {
    if (!edge.from || !edge.to) return;
    const set = adjacency.get(edge.from) ?? new Set<string>();
    set.add(edge.to);
    adjacency.set(edge.from, set);
  });
  const queue = Array.from(startNodes);
  const visited = new Set<string>(startNodes);
  while (queue.length > 0) {
    const current = queue.shift();
    if (!current) continue;
    const next = adjacency.get(current);
    if (!next) continue;
    next.forEach((nodeId: string) => {
      if (visited.has(nodeId)) return;
      visited.add(nodeId);
      queue.push(nodeId);
    });
  }
  return visited;
};

const resolveTriggerNodeId = (
  nodes: AiNode[],
  edges: Edge[],
  triggerEvent?: string | null,
  explicit?: string | null
): string | undefined => {
  if (explicit && nodes.some((node: AiNode) => node.id === explicit)) return explicit;
  const triggerNodes = nodes.filter((node: AiNode) => node.type === "trigger");
  if (triggerNodes.length === 0) return undefined;
  const matching = triggerEvent
    ? triggerNodes.filter(
        (node: AiNode) => (node.config?.trigger?.event ?? "").trim() === triggerEvent
      )
    : triggerNodes;
  const candidates = matching.length > 0 ? matching : triggerNodes;
  const connected = candidates.find((node: AiNode) =>
    edges.some((edge: Edge) => edge.from === node.id || edge.to === node.id)
  );
  return connected?.id ?? candidates[0]?.id;
};

const buildSkipSet = (
  run: AiPathRunRecord,
  edges: Edge[],
  nodeStatusMap: Map<string, string>
): Set<string> => {
  const meta = (run.meta ?? {}) as {
    resumeMode?: string;
    retryNodeIds?: string[];
  };
  const mode = meta.resumeMode ?? "replay";
  if (mode === "replay") return new Set<string>();

  const completed = new Set(
    Array.from(nodeStatusMap.entries())
      .filter(([, status]: [string, string]) => status === "completed")
      .map(([nodeId]: [string, string]) => nodeId)
  );
  if (mode === "resume") {
    const failedNodes = new Set(
      Array.from(nodeStatusMap.entries())
        .filter(([, status]: [string, string]) => status === "failed")
        .map(([nodeId]: [string, string]) => nodeId)
    );
    if (failedNodes.size === 0) {
      return completed;
    }
    const affected = computeDownstreamNodes(edges, failedNodes);
    return new Set(Array.from(completed).filter((nodeId: string) => !affected.has(nodeId)));
  }
  if (mode === "retry") {
    const retryNodes = new Set(meta.retryNodeIds ?? []);
    const affected = computeDownstreamNodes(edges, retryNodes);
    return new Set(Array.from(completed).filter((nodeId: string) => !affected.has(nodeId)));
  }
  return new Set<string>();
};

const fetchEntityByType = async (entityType: string, entityId: string): Promise<Record<string, unknown> | null> => {
  if (!entityType || !entityId) return null;
  const normalized = entityType.toLowerCase();
  if (normalized === "product") {
    const repo = await getProductRepository();
    return (await repo.getProductById(entityId)) as Record<string, unknown> | null;
  }
  if (normalized === "note") {
    return (await noteService.getById(entityId)) as Record<string, unknown> | null;
  }
  return null;
};

export const executePathRun = async (run: AiPathRunRecord): Promise<void> => {
  const repo = getPathRunRepository();
  const graph = run.graph;
  if (!graph || !Array.isArray(graph.nodes) || !Array.isArray(graph.edges)) {
    await repo.updateRun(run.id, {
      status: "failed",
      errorMessage: "Run graph is missing or invalid.",
      finishedAt: new Date(),
    });
    await repo.createRunEvent({
      runId: run.id,
      level: "error",
      message: "Run graph is missing or invalid.",
    });
    return;
  }

  const nodes = normalizeNodes(graph.nodes as AiNode[]);
  const edges = sanitizeEdges(nodes, graph.edges as Edge[]);
  const triggerNodeId = resolveTriggerNodeId(
    nodes,
    edges,
    run.triggerEvent ?? undefined,
    run.triggerNodeId ?? undefined
  );

  const runtimeState = parseRuntimeState(run.runtimeState);
  const historyLimit = Number.parseInt(process.env.AI_PATHS_HISTORY_LIMIT ?? "", 10);
  const resolvedHistoryLimit =
    Number.isFinite(historyLimit) && historyLimit > 0 ? historyLimit : 50;
  const nodeRecords = await repo.listRunNodes(run.id);
  const nodeStatusMap = new Map(
    nodeRecords.map((record: any) => [record.nodeId, record.status])
  );
  const nodeAttemptMap = new Map(
    nodeRecords.map((record: any) => [record.nodeId, record.attempt ?? 0])
  );
  const skipNodes = buildSkipSet(run, edges, nodeStatusMap);
  const reportAiPathsError = async (error: unknown, meta: Record<string, unknown>, summary?: string): Promise<void> => {
    await ErrorSystem.captureException(error, {
      service: "ai-paths-runtime",
      pathRunId: run.id,
      summary,
      ...meta,
    });
    await repo.createRunEvent({
      runId: run.id,
      level: "error",
      message: summary ?? "AI Paths runtime error",
      metadata: {
        error: error instanceof Error ? error.message : String(error),
        ...meta,
      },
    });
  };
  const toast = (): void => {};

  try {
    const resultState = await evaluateGraph({
      nodes,
      edges,
      activePathId: run.pathId ?? null,
      activePathName: run.pathName ?? null,
      ...(triggerNodeId ? { triggerNodeId } : {}),
      ...(run.triggerEvent ? { triggerEvent: run.triggerEvent } : {}),
      ...(run.triggerContext ? { triggerContext: run.triggerContext as Record<string, unknown> } : {}),
      seedOutputs: runtimeState.outputs,
      seedHashes: runtimeState.hashes ?? undefined,
      seedHistory: runtimeState.history ?? undefined,
      recordHistory: true,
      historyLimit: resolvedHistoryLimit,
      skipNodeIds: skipNodes,
      fetchEntityByType,
      reportAiPathsError: (error: unknown, meta: Record<string, unknown>, summary?: string) => {
        void reportAiPathsError(error, meta, summary);
      },
      toast,
      onNodeStart: async ({ node, nodeInputs, prevOutputs }: { node: AiNode; nodeInputs: RuntimePortValues; prevOutputs: RuntimePortValues }) => {
        const nextAttempt = (nodeAttemptMap.get(node.id) ?? 0) + 1;
        nodeAttemptMap.set(node.id, nextAttempt);
        await repo.upsertRunNode(run.id, node.id, {
          nodeType: node.type,
          nodeTitle: node.title ?? null,
          status: "running",
          attempt: nextAttempt,
          inputs: toJsonSafe(nodeInputs) as RuntimePortValues,
          outputs: toJsonSafe(prevOutputs) as RuntimePortValues,
          startedAt: new Date(),
          errorMessage: null,
        });
        await repo.createRunEvent({
          runId: run.id,
          level: "info",
          message: `Node ${node.title ?? node.id} started.`,
          metadata: {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: node.title ?? null,
            status: "running",
            attempt: nextAttempt,
          },
        });
      },
      onNodeFinish: async ({
        node,
        nodeInputs,
        nextOutputs,
        cached,
        iteration,
      }: {
        node: AiNode;
        nodeInputs: RuntimePortValues;
        nextOutputs: RuntimePortValues;
        cached?: boolean;
        iteration: number;
      }) => {
        if (cached) {
          if (iteration === 0) {
            await repo.upsertRunNode(run.id, node.id, {
              nodeType: node.type,
              nodeTitle: node.title ?? null,
              status: "completed",
              attempt: nodeAttemptMap.get(node.id) ?? 0,
              inputs: toJsonSafe(nodeInputs) as RuntimePortValues,
              outputs: toJsonSafe(nextOutputs) as RuntimePortValues,
              finishedAt: new Date(),
              errorMessage: null,
            });
            await repo.createRunEvent({
              runId: run.id,
              level: "info",
              message: `Node ${node.title ?? node.id} reused cached outputs.`,
              metadata: {
                nodeId: node.id,
                nodeType: node.type,
                nodeTitle: node.title ?? null,
                status: "completed",
                cached: true,
                attempt: nodeAttemptMap.get(node.id) ?? 0,
              },
            });
          }
          return;
        }
        await repo.upsertRunNode(run.id, node.id, {
          nodeType: node.type,
          nodeTitle: node.title ?? null,
          status: "completed",
          attempt: nodeAttemptMap.get(node.id) ?? 0,
          inputs: toJsonSafe(nodeInputs) as RuntimePortValues,
          outputs: toJsonSafe(nextOutputs) as RuntimePortValues,
          finishedAt: new Date(),
          errorMessage: null,
        });
        await repo.createRunEvent({
          runId: run.id,
          level: "info",
          message: `Node ${node.title ?? node.id} completed.`,
          metadata: {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: node.title ?? null,
            status: "completed",
            attempt: nodeAttemptMap.get(node.id) ?? 0,
          },
        });
      },
      onNodeError: async ({ node, nodeInputs, prevOutputs, error }: { node: AiNode; nodeInputs: RuntimePortValues; prevOutputs: RuntimePortValues; error: unknown }) => {
        await repo.upsertRunNode(run.id, node.id, {
          nodeType: node.type,
          nodeTitle: node.title ?? null,
          status: "failed",
          attempt: nodeAttemptMap.get(node.id) ?? 0,
          inputs: toJsonSafe(nodeInputs) as RuntimePortValues,
          outputs: toJsonSafe(prevOutputs) as RuntimePortValues,
          finishedAt: new Date(),
          errorMessage: error instanceof Error ? error.message : String(error),
        });
        await repo.createRunEvent({
          runId: run.id,
          level: "error",
          message: `Node ${node.title ?? node.id} failed.`,
          metadata: {
            nodeId: node.id,
            nodeType: node.type,
            nodeTitle: node.title ?? null,
            status: "failed",
            attempt: nodeAttemptMap.get(node.id) ?? 0,
            error: error instanceof Error ? error.message : String(error),
          },
        });
      },
      onIterationEnd: async ({
        inputs,
        outputs,
        hashes,
        history,
      }: {
        inputs: Record<string, RuntimePortValues>;
        outputs: Record<string, RuntimePortValues>;
        hashes?: Record<string, string>;
        history?: Record<string, RuntimeHistoryEntry[]>;
      }) => {
        await repo.updateRun(run.id, {
          runtimeState: sanitizeRuntimeState({ inputs, outputs, hashes, history }),
        });
      },
    });

    await repo.updateRun(run.id, {
      status: "completed",
      runtimeState: sanitizeRuntimeState(resultState),
      finishedAt: new Date(),
      errorMessage: null,
      meta: {
        ...(run.meta ?? {}),
        resumeMode: "replay",
        retryNodeIds: [],
      },
    });
    await repo.createRunEvent({
      runId: run.id,
      level: "info",
      message: "Run completed successfully.",
    });
  } catch (error) {
    await repo.updateRun(run.id, {
      status: "failed",
      finishedAt: new Date(),
      errorMessage: error instanceof Error ? error.message : String(error),
    });
    await repo.createRunEvent({
      runId: run.id,
      level: "error",
      message: "Run failed.",
      metadata: {
        error: error instanceof Error ? error.message : String(error),
      },
    });
    throw error;
  }
};

import "server-only";

import { randomUUID } from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import type {
  AiPathRunEventRecord,
  AiPathRunNodeRecord,
  AiPathRunRecord,
} from "@/shared/types/ai-paths";
import {
  AiPathRunEventCreateInput,
  AiPathRunListOptions,
  AiPathRunCreateInput,
  AiPathRunRepository,
  AiPathRunUpdate,
  AiPathRunNodeUpdate,
} from "../../types/path-run-repository";
import type { AiNode } from "@/shared/types/ai-paths";

const RUNS_COLLECTION = "ai_path_runs";
const NODES_COLLECTION = "ai_path_run_nodes";
const EVENTS_COLLECTION = "ai_path_run_events";

type MongoIndexSpec = {
  collection: string;
  key: Record<string, 1 | -1>;
};

export const AI_PATHS_MONGO_INDEXES: MongoIndexSpec[] = [
  { collection: RUNS_COLLECTION, key: { id: 1 } },
  { collection: RUNS_COLLECTION, key: { userId: 1 } },
  { collection: RUNS_COLLECTION, key: { pathId: 1 } },
  { collection: RUNS_COLLECTION, key: { status: 1, createdAt: -1 } },
  { collection: RUNS_COLLECTION, key: { userId: 1, createdAt: -1 } },
  { collection: RUNS_COLLECTION, key: { status: 1, nextRetryAt: 1, createdAt: 1 } },
  { collection: NODES_COLLECTION, key: { runId: 1 } },
  { collection: NODES_COLLECTION, key: { runId: 1, nodeId: 1 } },
  { collection: NODES_COLLECTION, key: { runId: 1, createdAt: 1 } },
  { collection: EVENTS_COLLECTION, key: { runId: 1, createdAt: 1 } },
];

let indexesReady = false;
let indexesPromise: Promise<void> | null = null;

const ensureIndexes = async () => {
  if (indexesReady) return;
  if (!indexesPromise) {
    indexesPromise = (async () => {
      const db = await getMongoDb();
      await Promise.all(
        AI_PATHS_MONGO_INDEXES.map((index) =>
          db.collection(index.collection).createIndex(index.key)
        )
      );
      indexesReady = true;
    })().catch((error) => {
      indexesPromise = null;
      throw error;
    });
  }
  await indexesPromise;
};

type RunDocument = {
  _id: string;
  id?: string;
  userId?: string | null;
  pathId: string;
  pathName?: string | null;
  status: string;
  triggerEvent?: string | null;
  triggerNodeId?: string | null;
  triggerContext?: Record<string, unknown> | null;
  graph?: Record<string, unknown> | null;
  runtimeState?: Record<string, unknown> | null;
  meta?: Record<string, unknown> | null;
  entityId?: string | null;
  entityType?: string | null;
  errorMessage?: string | null;
  retryCount?: number;
  maxAttempts?: number;
  nextRetryAt?: Date | null;
  deadLetteredAt?: Date | null;
  createdAt: Date;
  updatedAt?: Date;
  startedAt?: Date | null;
  finishedAt?: Date | null;
};

type NodeDocument = {
  _id: string;
  runId: string;
  nodeId: string;
  nodeType: string;
  nodeTitle?: string | null;
  status: string;
  attempt: number;
  inputs?: Record<string, unknown> | null;
  outputs?: Record<string, unknown> | null;
  errorMessage?: string | null;
  createdAt: Date;
  updatedAt?: Date;
  startedAt?: Date | null;
  finishedAt?: Date | null;
};

type EventDocument = {
  _id: string;
  runId: string;
  level: string;
  message: string;
  metadata?: Record<string, unknown> | null;
  createdAt: Date;
};

const toRunRecord = (doc: RunDocument): AiPathRunRecord => ({
  id: doc.id || doc._id,
  userId: doc.userId ?? null,
  pathId: doc.pathId ?? null,
  pathName: doc.pathName ?? null,
  prompt: null,
  status: doc.status as AiPathRunRecord["status"],
  triggerEvent: doc.triggerEvent ?? null,
  triggerNodeId: doc.triggerNodeId ?? null,
  triggerContext: doc.triggerContext ?? null,
  graph: (doc.graph as AiPathRunRecord["graph"]) ?? null,
  runtimeState: (doc.runtimeState as AiPathRunRecord["runtimeState"]) ?? null,
  meta: doc.meta ?? null,
  entityId: doc.entityId ?? null,
  entityType: doc.entityType ?? null,
  errorMessage: doc.errorMessage ?? null,
  retryCount: doc.retryCount ?? 0,
  maxAttempts: doc.maxAttempts ?? 3,
  nextRetryAt: doc.nextRetryAt ?? null,
  deadLetteredAt: doc.deadLetteredAt ?? null,
  createdAt: doc.createdAt,
  updatedAt: doc.updatedAt ?? null,
  startedAt: doc.startedAt ?? null,
  finishedAt: doc.finishedAt ?? null,
});

const toNodeRecord = (doc: NodeDocument): AiPathRunNodeRecord => ({
  id: doc._id,
  runId: doc.runId,
  nodeId: doc.nodeId,
  nodeType: doc.nodeType,
  nodeTitle: doc.nodeTitle ?? null,
  status: doc.status as AiPathRunNodeRecord["status"],
  attempt: doc.attempt ?? 0,
  inputs: (doc.inputs as AiPathRunNodeRecord["inputs"]) ?? null,
  outputs: (doc.outputs as AiPathRunNodeRecord["outputs"]) ?? null,
  errorMessage: doc.errorMessage ?? null,
  createdAt: doc.createdAt,
  updatedAt: doc.updatedAt ?? null,
  startedAt: doc.startedAt ?? null,
  finishedAt: doc.finishedAt ?? null,
});

const toEventRecord = (doc: EventDocument): AiPathRunEventRecord => ({
  id: doc._id,
  runId: doc.runId,
  level: doc.level as AiPathRunEventRecord["level"],
  message: doc.message,
  metadata: doc.metadata ?? null,
  createdAt: doc.createdAt,
});

const escapeRegex = (value: string) => value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");

export const mongoPathRunRepository: AiPathRunRepository = {
  async createRun(input: AiPathRunCreateInput) {
    await ensureIndexes();
    const db = await getMongoDb();
    const now = new Date();
    const id = randomUUID();
    const document: RunDocument = {
      _id: id,
      id,
      userId: input.userId ?? null,
      pathId: input.pathId,
      pathName: input.pathName ?? null,
      status: "queued",
      triggerEvent: input.triggerEvent ?? null,
      triggerNodeId: input.triggerNodeId ?? null,
      triggerContext: input.triggerContext ?? null,
      graph: (input.graph as Record<string, unknown>) ?? null,
      runtimeState: (input.runtimeState as Record<string, unknown>) ?? null,
      meta: input.meta ?? null,
      entityId: input.entityId ?? null,
      entityType: input.entityType ?? null,
      errorMessage: null,
      retryCount: input.retryCount ?? 0,
      maxAttempts: input.maxAttempts ?? 3,
      nextRetryAt: input.nextRetryAt ? new Date(input.nextRetryAt) : null,
      deadLetteredAt: null,
      createdAt: now,
      updatedAt: now,
      startedAt: null,
      finishedAt: null,
    };
    await db.collection<RunDocument>(RUNS_COLLECTION).insertOne(document);
    return toRunRecord(document);
  },

  async updateRun(runId: string, data: AiPathRunUpdate) {
    await ensureIndexes();
    const db = await getMongoDb();
    const now = new Date();
    const updateData = { ...data, updatedAt: now } as Record<string, unknown>;
    if (updateData.nextRetryAt && typeof updateData.nextRetryAt === "string") {
      updateData.nextRetryAt = new Date(updateData.nextRetryAt);
    }
    if (updateData.deadLetteredAt && typeof updateData.deadLetteredAt === "string") {
      updateData.deadLetteredAt = new Date(updateData.deadLetteredAt);
    }
    if (updateData.startedAt && typeof updateData.startedAt === "string") {
      updateData.startedAt = new Date(updateData.startedAt);
    }
    if (updateData.finishedAt && typeof updateData.finishedAt === "string") {
      updateData.finishedAt = new Date(updateData.finishedAt);
    }
    const result = await db
      .collection<RunDocument>(RUNS_COLLECTION)
      .findOneAndUpdate(
        { $or: [{ _id: runId }, { id: runId }] },
        { $set: updateData },
        { returnDocument: "after" }
      );
    if (!result) {
      throw new Error("Run not found");
    }
    return toRunRecord(result);
  },

  async findRunById(runId: string) {
    await ensureIndexes();
    const db = await getMongoDb();
    const doc = await db
      .collection<RunDocument>(RUNS_COLLECTION)
      .findOne({ $or: [{ _id: runId }, { id: runId }] });
    return doc ? toRunRecord(doc) : null;
  },

  async listRuns(options: AiPathRunListOptions = {}) {
    await ensureIndexes();
    const db = await getMongoDb();
    const filter: Record<string, unknown> = {};
    if (options.userId) {
      filter.userId = options.userId;
    }
    if (options.pathId) {
      filter.pathId = options.pathId;
    }
    const statuses = Array.isArray(options.statuses) ? options.statuses.filter(Boolean) : [];
    if (statuses.length > 0) {
      filter.status = { $in: statuses };
    } else if (options.status) {
      filter.status = options.status;
    }
    const query = options.query?.trim();
    if (query) {
      const regex = new RegExp(escapeRegex(query), "i");
      filter.$or = [
        { id: { $regex: regex } },
        { _id: { $regex: regex } },
        { pathId: { $regex: regex } },
        { pathName: { $regex: regex } },
        { entityId: { $regex: regex } },
        { errorMessage: { $regex: regex } },
      ];
    }
    const parseDate = (value: Date | string | null | undefined): Date | null => {
      if (!value) return null;
      const date = typeof value === "string" ? new Date(value) : value;
      return Number.isNaN(date.getTime()) ? null : date;
    };
    const createdAfter = parseDate(options.createdAfter);
    const createdBefore = parseDate(options.createdBefore);
    if (createdAfter || createdBefore) {
      filter.createdAt = {
        ...(createdAfter ? { $gte: createdAfter } : {}),
        ...(createdBefore ? { $lte: createdBefore } : {}),
      };
    }
    const cursor = db
      .collection<RunDocument>(RUNS_COLLECTION)
      .find(filter)
      .sort({ createdAt: -1 });
    if (typeof options.offset === "number") {
      cursor.skip(options.offset);
    }
    if (typeof options.limit === "number") {
      cursor.limit(options.limit);
    }
    const [docs, total] = await Promise.all([
      cursor.toArray(),
      db.collection<RunDocument>(RUNS_COLLECTION).countDocuments(filter),
    ]);
    return { runs: docs.map(toRunRecord), total };
  },

  async claimNextQueuedRun() {
    await ensureIndexes();
    const db = await getMongoDb();
    const now = new Date();
    const result = await db
      .collection<RunDocument>(RUNS_COLLECTION)
      .findOneAndUpdate(
        { status: "queued", $or: [{ nextRetryAt: null }, { nextRetryAt: { $lte: now } }] },
        { $set: { status: "running", startedAt: now, updatedAt: now } },
        { sort: { createdAt: 1 }, returnDocument: "after" }
      );
    if (!result) return null;
    return toRunRecord(result);
  },

  async createRunNodes(runId: string, nodes: AiNode[]) {
    await ensureIndexes();
    if (!nodes || nodes.length === 0) return;
    const db = await getMongoDb();
    const now = new Date();
    const docs: NodeDocument[] = nodes.map((node: AiNode) => ({
      _id: randomUUID(),
      runId,
      nodeId: node.id,
      nodeType: node.type,
      nodeTitle: node.title ?? null,
      status: "pending",
      attempt: 0,
      createdAt: now,
      updatedAt: now,
      startedAt: null,
      finishedAt: null,
    }));
    await db.collection<NodeDocument>(NODES_COLLECTION).insertMany(docs);
  },

  async upsertRunNode(
    runId: string,
    nodeId: string,
    data: AiPathRunNodeUpdate & { nodeType: string; nodeTitle?: string | null }
  ) {
    await ensureIndexes();
    const db = await getMongoDb();
    const now = new Date();
    const updateData = {
      ...data,
      updatedAt: now,
    } as Record<string, unknown>;
    const result = await db
      .collection<NodeDocument>(NODES_COLLECTION)
      .findOneAndUpdate(
        { runId, nodeId },
        { $set: updateData, $setOnInsert: { _id: randomUUID(), runId, nodeId, createdAt: now } },
        { returnDocument: "after", upsert: true }
      );
    if (!result) {
      throw new Error("Run node not found");
    }
    return toNodeRecord(result);
  },

  async listRunNodes(runId: string) {
    await ensureIndexes();
    const db = await getMongoDb();
    const docs = await db
      .collection<NodeDocument>(NODES_COLLECTION)
      .find({ runId })
      .sort({ createdAt: 1 })
      .toArray();
    return docs.map(toNodeRecord);
  },

  async createRunEvent(input: AiPathRunEventCreateInput) {
    await ensureIndexes();
    const db = await getMongoDb();
    const document: EventDocument = {
      _id: randomUUID(),
      runId: input.runId,
      level: input.level,
      message: input.message,
      metadata: input.metadata ?? null,
      createdAt: new Date(),
    };
    await db.collection<EventDocument>(EVENTS_COLLECTION).insertOne(document);
    return toEventRecord(document);
  },

  async listRunEvents(
    runId: string,
    options: { since?: Date | string | null; limit?: number } = {}
  ) {
    await ensureIndexes();
    const db = await getMongoDb();
    const filter: Record<string, unknown> = { runId };
    const sinceValue = options.since
      ? options.since instanceof Date
        ? options.since
        : new Date(options.since)
      : null;
    const since =
      sinceValue && !Number.isNaN(sinceValue.getTime()) ? sinceValue : null;
    if (since) {
      filter.createdAt = { $gt: since };
    }
    const cursor = db
      .collection<EventDocument>(EVENTS_COLLECTION)
      .find(filter)
      .sort({ createdAt: 1 });
    if (typeof options.limit === "number") {
      cursor.limit(options.limit);
    }
    const docs = await cursor.toArray();
    return docs.map(toEventRecord);
  },

  async markStaleRunningRuns(maxAgeMs: number) {
    await ensureIndexes();
    const db = await getMongoDb();
    const cutoff = new Date(Date.now() - maxAgeMs);
    const result = await db
      .collection<RunDocument>(RUNS_COLLECTION)
      .updateMany(
        { status: "running", startedAt: { $lt: cutoff } },
        {
          $set: {
            status: "failed",
            finishedAt: new Date(),
            errorMessage: "Run marked failed due to stale running state.",
          },
        }
      );
    return { count: result.modifiedCount ?? 0 };
  },
};

import "server-only";

import prisma from "@/shared/lib/db/prisma";
import type {
  AiPathRunEventRecord,
  AiPathRunNodeRecord,
  AiPathRunRecord,
} from "@/shared/types/ai-paths";
import type {
  AiPathRunCreateInput,
  AiPathRunEventCreateInput,
  AiPathRunListOptions,
  AiPathRunRepository,
  AiPathRunUpdate,
  AiPathRunNodeUpdate,
} from "@/features/ai-paths/types/path-run-repository";
import type { AiNode } from "@/shared/types/ai-paths";

const prismaAny = prisma as unknown as {
  aiPathRun?: {
    create: (args: unknown) => Promise<unknown>;
    update: (args: unknown) => Promise<unknown>;
    findUnique: (args: unknown) => Promise<unknown>;
    findMany: (args: unknown) => Promise<unknown[]>;
    findFirst: (args: unknown) => Promise<unknown>;
    count: (args: unknown) => Promise<number>;
    updateMany: (args: unknown) => Promise<unknown>;
  };
  aiPathRunNode?: {
    createMany: (args: unknown) => Promise<unknown>;
    upsert: (args: unknown) => Promise<unknown>;
    findMany: (args: unknown) => Promise<unknown[]>;
  };
  aiPathRunEvent?: {
    create: (args: unknown) => Promise<unknown>;
    findMany: (args: unknown) => Promise<unknown[]>;
  };
};

const mapRun = (run: unknown): AiPathRunRecord => {
  const r = run as Record<string, unknown>;
  return {
    id: String(r.id),
    userId: (r.userId as string) ?? null,
    pathId: (r.pathId as string) ?? null,
    pathName: (r.pathName as string) ?? null,
    prompt: (r.prompt as string) ?? null,
    status: r.status as AiPathRunRecord["status"],
    triggerEvent: (r.triggerEvent as string) ?? null,
    triggerNodeId: (r.triggerNodeId as string) ?? null,
    triggerContext: (r.triggerContext as AiPathRunRecord["triggerContext"]) ?? null,
    graph: (r.graph as AiPathRunRecord["graph"]) ?? null,
    runtimeState: (r.runtimeState as AiPathRunRecord["runtimeState"]) ?? null,
    meta: (r.meta as AiPathRunRecord["meta"]) ?? null,
    entityId: (r.entityId as string) ?? null,
    entityType: (r.entityType as string) ?? null,
    errorMessage: (r.errorMessage as string) ?? null,
    retryCount: (r.retryCount as number) ?? 0,
    maxAttempts: (r.maxAttempts as number) ?? 3,
    nextRetryAt: (r.nextRetryAt as Date) ?? null,
    deadLetteredAt: (r.deadLetteredAt as Date) ?? null,
    createdAt: r.createdAt as Date,
    updatedAt: (r.updatedAt as Date) ?? null,
    startedAt: (r.startedAt as Date) ?? null,
    finishedAt: (r.finishedAt as Date) ?? null,
  };
};

const mapNode = (node: unknown): AiPathRunNodeRecord => {
  const n = node as Record<string, unknown>;
  return {
    id: String(n.id),
    runId: String(n.runId),
    nodeId: String(n.nodeId),
    nodeType: String(n.nodeType),
    nodeTitle: (n.nodeTitle as string) ?? null,
    status: n.status as AiPathRunNodeRecord["status"],
    attempt: (n.attempt as number) ?? 0,
    inputs: (n.inputs as AiPathRunNodeRecord["inputs"]) ?? null,
    outputs: (n.outputs as AiPathRunNodeRecord["outputs"]) ?? null,
