  DEFAULT_AUTH_SECURITY_POLICY,
  normalizeAuthSecurityPolicy,
  type AuthSecurityPolicy,
} from "@/features/auth/utils/auth-security";
import { useAuthUserSecurity } from "@/features/auth/hooks/useAuthQueries";
import { disableMfa, setupMfa, verifyMfa } from "@/features/auth/api/mfa";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/useSettings";
import { useMutation } from "@tanstack/react-query";

export default function AuthSettingsPage() {
  const { toast } = useToast();
  const { data: session } = useSession();
  const [roles, setRoles] = useState<AuthRole[]>(DEFAULT_AUTH_ROLES);
  const [defaultRole, setDefaultRole] = useState<string>("viewer");
  const [securityPolicy, setSecurityPolicy] = useState<AuthSecurityPolicy>(
    DEFAULT_AUTH_SECURITY_POLICY
  );
  const [defaultDirty, setDefaultDirty] = useState(false);
  const [securityDirty, setSecurityDirty] = useState(false);
  const [mfaEnabled, setMfaEnabled] = useState(false);
  const [mfaSecret, setMfaSecret] = useState<string | null>(null);
  const [mfaOtpAuth, setMfaOtpAuth] = useState<string | null>(null);
  const [mfaToken, setMfaToken] = useState("");
  const [mfaDisableCode, setMfaDisableCode] = useState("");
  const [recoveryCodes, setRecoveryCodes] = useState<string[]>([]);
  const settingsQuery = useSettingsMap();
  const updateDefaultRole = useUpdateSetting();
  const updateSecurityPolicy = useUpdateSetting();
  const mfaSetupMutation = useMutation({ mutationFn: setupMfa });
  const mfaVerifyMutation = useMutation({ mutationFn: verifyMfa });
  const mfaDisableMutation = useMutation({ mutationFn: disableMfa });
  const userSecurityQuery = useAuthUserSecurity(session?.user?.id);

  useEffect(() => {
    if (!settingsQuery.error) return;
    console.error("Failed to load auth settings:", settingsQuery.error);
    toast("Failed to load auth settings.", { variant: "error" });
  }, [settingsQuery.error, toast]);

  const roleOptions = useMemo(
    () =>
      mergeDefaultRoles(roles).map((role) => ({
        id: role.id,
        name: role.name,
      })),
    [roles]
  );

  useEffect(() => {
    if (!settingsQuery.data) return;
    const storedRoles = mergeDefaultRoles(
      parseJsonSetting<AuthRole[]>(
        settingsQuery.data.get(AUTH_SETTINGS_KEYS.roles),
        DEFAULT_AUTH_ROLES
      )
    );
    setRoles(storedRoles);
    const storedDefault = settingsQuery.data.get(AUTH_SETTINGS_KEYS.defaultRole);
    const nextDefault =
      storedDefault && storedRoles.some((role) => role.id === storedDefault)
        ? storedDefault
        : storedRoles.find((role) => role.id === "viewer")?.id ??
          storedRoles[0]?.id ??
          "viewer";
    setDefaultRole(nextDefault);
    setDefaultDirty(false);

    const storedPolicyRaw = settingsQuery.data.get(AUTH_SETTINGS_KEYS.securityPolicy);
    const parsedPolicy = storedPolicyRaw
      ? normalizeAuthSecurityPolicy(parseJsonSetting(storedPolicyRaw, DEFAULT_AUTH_SECURITY_POLICY))
      : DEFAULT_AUTH_SECURITY_POLICY;
    setSecurityPolicy(parsedPolicy);
    setSecurityDirty(false);
  }, [settingsQuery.data]);

  useEffect(() => {
    if (!userSecurityQuery.data) return;
    setMfaEnabled(Boolean(userSecurityQuery.data.mfaEnabled));
  }, [userSecurityQuery.data]);

  const saveDefaultRole = async () => {
    try {
      await updateDefaultRole.mutateAsync({
        key: AUTH_SETTINGS_KEYS.defaultRole,
        value: defaultRole,
      });
      setDefaultDirty(false);
      toast("Default role saved.", { variant: "success" });
    } catch (error) {
      toast(
        error instanceof Error ? error.message : "Failed to save settings.",
        { variant: "error" }
      );
    }
  };

  const saveSecurityPolicy = async () => {
    try {
      await updateSecurityPolicy.mutateAsync({
        key: AUTH_SETTINGS_KEYS.securityPolicy,
        value: JSON.stringify(securityPolicy),
      });
      setSecurityDirty(false);
      toast("Security policy saved.", { variant: "success" });
    } catch (error) {
      toast(
        error instanceof Error ? error.message : "Failed to save security policy.",
        { variant: "error" }
      );
    }
  };

  const handleMfaSetup = async () => {
    try {
      setMfaSecret(null);
      setMfaOtpAuth(null);
      setRecoveryCodes([]);
      const res = await mfaSetupMutation.mutateAsync();
      if (!res.ok) throw new Error("Failed to start MFA setup.");
      const payload = res.payload as { secret?: string; otpauthUrl?: string };
      setMfaSecret(payload.secret ?? null);
      setMfaOtpAuth(payload.otpauthUrl ?? null);
      toast("MFA setup started. Enter the code from your authenticator app.", {
        variant: "success",
      });
    } catch (error) {
      toast(
        error instanceof Error ? error.message : "Failed to start MFA setup.",
        { variant: "error" }
      );
    }
  };

  const handleMfaVerify = async () => {
    if (!mfaToken.trim()) {
      toast("Enter the MFA code from your authenticator app.", { variant: "error" });
      return;
    }
    try {
      const res = await mfaVerifyMutation.mutateAsync(mfaToken.trim());
      const payload = res.payload as {
        recoveryCodes?: string[];
        error?: string;
      } | null;
      if (!res.ok) {
        throw new Error(payload?.error ?? "Failed to verify MFA.");
      }
      setRecoveryCodes(payload?.recoveryCodes ?? []);
      setMfaEnabled(true);
      setMfaToken("");
      toast("MFA enabled. Save your recovery codes.", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to verify MFA.", {
        variant: "error",
      });
    }
  };

  const handleMfaDisable = async () => {
    if (!mfaDisableCode.trim()) {
      toast("Enter a code to disable MFA.", { variant: "error" });
      return;
    }
    try {
      const res = await mfaDisableMutation.mutateAsync({
        token: mfaDisableCode.trim(),
        recoveryCode: mfaDisableCode.trim(),
      });
      const payload = res.payload as { error?: string } | null;
      if (!res.ok) {
        throw new Error(payload?.error ?? "Failed to disable MFA.");
      }
      setMfaEnabled(false);
      setMfaSecret(null);
      setMfaOtpAuth(null);
      setRecoveryCodes([]);
      setMfaDisableCode("");
      toast("MFA disabled.", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to disable MFA.", {
        variant: "error",
      });
    }
  };

  return (
    <SectionPanel className="p-6 space-y-6">
      <SectionHeader
        title="Auth Settings"
        description="Authentication data source is managed globally."
      />

      <div className="rounded-md border border-border bg-card p-4">
        <h2 className="text-lg font-semibold text-white">Default role</h2>
        <p className="mt-1 text-xs text-gray-400">
          Users without an explicit role will receive this role. To avoid
          unintended access, set this to a low-privilege role.
        </p>
        <div className="mt-4 flex flex-wrap items-center gap-3">
          <Select
            value={defaultRole}
            onValueChange={(value) => {
              setDefaultRole(value);
              setDefaultDirty(true);
            }}
            disabled={settingsQuery.isPending}
          >
            <SelectTrigger className="w-64 bg-gray-900 border text-white">
              <SelectValue placeholder="Select default role" />
            </SelectTrigger>
            <SelectContent>
              {roleOptions.map((role) => (
                <SelectItem key={role.id} value={role.id}>
                  {role.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
          <Button
            onClick={() => void saveDefaultRole()}
            disabled={!defaultDirty || updateDefaultRole.isPending}
          >
            {updateDefaultRole.isPending ? "Saving..." : "Save"}
          </Button>
        </div>
      </div>

      <div className="rounded-md border border-border bg-card p-4 space-y-4">
        <div>
          <h2 className="text-lg font-semibold text-white">Security policy</h2>
          <p className="mt-1 text-xs text-gray-400">
            Control password strength and login protection rules.
          </p>
        </div>
        <div className="grid gap-4 md:grid-cols-2">
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Minimum password length</Label>
            <Input
              type="number"
              min={6}
              max={64}
              value={securityPolicy.minPasswordLength}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  minPasswordLength: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Require strong password</Label>
            <div className="flex items-center gap-3">
              <Checkbox
                checked={securityPolicy.requireStrongPassword} onCheckedChange={(checked) => {
                  setSecurityPolicy((prev) => ({
                    ...prev,
                    requireStrongPassword: Boolean(checked),
                  }));
                  setSecurityDirty(true);
                }}
                className="h-4 w-4 rounded border bg-gray-900"
              />
              <span className="text-xs text-gray-400">
                Enforce uppercase, lowercase, number, and symbol.
              </span>
            </div>
          </div>
          <div className="space-y-2 md:col-span-2">
            <Label className="text-xs text-gray-300">Password rules</Label>
            <div className="flex flex-wrap gap-4 text-xs text-gray-400">
              {(
                [
                  ["requireUppercase", "Uppercase"],
                  ["requireLowercase", "Lowercase"],
                  ["requireNumber", "Number"],
                  ["requireSymbol", "Symbol"],
                ] as const
              ).map(([key, label]) => (
                <Label key={key} className="flex items-center gap-2">
                  <Checkbox
                    checked={securityPolicy[key]} onCheckedChange={(checked) => {
                      setSecurityPolicy((prev) => ({
                        ...prev,
                        [key]: Boolean(checked),
                      }));
                      setSecurityDirty(true);
                    }}
                    className="h-4 w-4 rounded border bg-gray-900"
                  />
                  {label}
                </Label>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Email lockout attempts</Label>
            <Input
              type="number"
              min={1}
              max={50}
              value={securityPolicy.lockoutMaxAttempts}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  lockoutMaxAttempts: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Email lockout window (minutes)</Label>
            <Input
              type="number"
              min={1}
              max={120}
              value={securityPolicy.lockoutWindowMinutes}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  lockoutWindowMinutes: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Email lockout duration (minutes)</Label>
            <Input
              type="number"
              min={1}
              max={120}
              value={securityPolicy.lockoutDurationMinutes}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  lockoutDurationMinutes: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">IP rate limit attempts</Label>
            <Input
              type="number"
              min={1}
              max={200}
              value={securityPolicy.ipRateLimitMaxAttempts}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  ipRateLimitMaxAttempts: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">IP rate limit window (minutes)</Label>
            <Input
              type="number"
              min={1}
              max={120}
              value={securityPolicy.ipRateLimitWindowMinutes}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  ipRateLimitWindowMinutes: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">IP rate limit duration (minutes)</Label>
            <Input
              type="number"
              min={1}
              max={120}
              value={securityPolicy.ipRateLimitDurationMinutes}
              onChange={(event) => {
                setSecurityPolicy((prev) => ({
                  ...prev,
                  ipRateLimitDurationMinutes: Number(event.target.value),
                }));
                setSecurityDirty(true);
              }}
              className="bg-gray-900 border text-white"
            />
          </div>
        </div>
        <div className="flex justify-end">
          <Button
            onClick={() => void saveSecurityPolicy()}
            disabled={!securityDirty || updateSecurityPolicy.isPending}
          >
            {updateSecurityPolicy.isPending ? "Saving..." : "Save security policy"}
          </Button>
        </div>
      </div>

      <div className="rounded-md border border-border bg-card p-4 space-y-4">
        <div>
          <h2 className="text-lg font-semibold text-white">Multi-factor authentication</h2>
          <p className="mt-1 text-xs text-gray-400">
            Enable MFA for your account and store recovery codes securely.
          </p>
        </div>
        <div className="text-xs text-gray-400">
          Status: {mfaEnabled ? "Enabled" : "Disabled"}
        </div>
        {!mfaEnabled ? (
          <div className="space-y-3">
            <Button onClick={() => void handleMfaSetup()} disabled={mfaSetupMutation.isPending}>
              {mfaSetupMutation.isPending ? "Starting..." : "Start MFA setup"}
            </Button>
            {mfaSecret ? (
              <div className="rounded-md border border-border bg-card/40 p-3 text-xs text-gray-300 space-y-2">
                <div>Secret: {mfaSecret}</div>
                {mfaOtpAuth ? <div>OTP URL: {mfaOtpAuth}</div> : null}
              </div>
            ) : null}
            {mfaSecret ? (
              <div className="space-y-2">
                <Label className="text-xs text-gray-300">Enter MFA code</Label>
                <Input
                  value={mfaToken}
                  onChange={(event) => setMfaToken(event.target.value)}
                  className="bg-gray-900 border text-white"
                  placeholder="123456"
                />
                <Button onClick={() => void handleMfaVerify()} disabled={mfaVerifyMutation.isPending}>
                  {mfaVerifyMutation.isPending ? "Verifying..." : "Verify & enable"}
                </Button>
              </div>
            ) : null}
            {recoveryCodes.length > 0 ? (
              <div className="rounded-md border border-amber-500/40 bg-amber-500/10 p-3 text-xs text-amber-100">
                <div className="font-semibold">Recovery codes (save these now)</div>
                <div className="mt-2 grid gap-1">
                  {recoveryCodes.map((code) => (
                    <div key={code}>{code}</div>
                  ))}
                </div>
              </div>
            ) : null}
          </div>
        ) : (
          <div className="space-y-2">
            <Label className="text-xs text-gray-300">Disable MFA (enter code)</Label>
            <Input
              value={mfaDisableCode}
              onChange={(event) => setMfaDisableCode(event.target.value)}
              className="bg-gray-900 border text-white"
              placeholder="MFA code or recovery code"
            />
            <Button
              variant="outline"
              onClick={() => void handleMfaDisable()}
              disabled={mfaDisableMutation.isPending}
            >
              {mfaDisableMutation.isPending ? "Disabling..." : "Disable MFA"}
            </Button>
          </div>
        )}
      </div>

      <div className="rounded-md border border-amber-500/40 bg-amber-500/10 p-4 text-sm text-amber-100">
        Go to Settings → Database to choose the global provider for the entire app.
      </div>
      <div>
        <Link
          href="/admin/settings/database"
          className="text-sm font-semibold text-blue-400 underline"
        >
          Open Database Settings
        </Link>
      </div>
    </SectionPanel>
  );
}

"use client";

import { Button, Card, CardContent, CardDescription, CardHeader, CardTitle, Label, Switch, useToast, SectionHeader, SectionPanel } from "@/shared/ui";
import { useEffect, useState } from "react";







import { AUTH_SETTINGS_KEYS } from "@/features/auth/utils/auth-management";
import { parseJsonSetting, serializeSetting } from "@/shared/utils/settings-json";
import {
  DEFAULT_AUTH_USER_PAGE_SETTINGS,
  type AuthUserPageSettings,
} from "@/features/auth/utils/auth-user-pages";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/useSettings";

export default function AuthUserPagesPage() {
  const { toast } = useToast();
  const settingsQuery = useSettingsMap();

  useEffect(() => {
    if (!settingsQuery.error) return;
    console.error("Failed to load user page settings:", settingsQuery.error);
    toast("Failed to load user page settings", { variant: "error" });
  }, [settingsQuery.error, toast]);

  if (settingsQuery.isPending || !settingsQuery.data) {
    return (
      <SectionPanel className="p-6 text-sm text-gray-400">
        Loading user page settings...
      </SectionPanel>
    );
  }

  const initialSettings = parseJsonSetting<AuthUserPageSettings>(
    settingsQuery.data.get(AUTH_SETTINGS_KEYS.userPages),
    DEFAULT_AUTH_USER_PAGE_SETTINGS
  );

  return <AuthUserPagesForm initialSettings={initialSettings} />;
}

function AuthUserPagesForm({
  initialSettings,
}: {
  initialSettings: AuthUserPageSettings;
}) {
  const { toast } = useToast();
  const [settings, setSettings] = useState<AuthUserPageSettings>(initialSettings);
  const [dirty, setDirty] = useState(false);
  const updateSetting = useUpdateSetting();

  const handleToggle = (key: keyof AuthUserPageSettings) => {
    setSettings((prev) => ({ ...prev, [key]: !prev[key] }));
    setDirty(true);
  };

  const handleSave = async () => {
    try {
      await updateSetting.mutateAsync({
        key: AUTH_SETTINGS_KEYS.userPages,
        value: serializeSetting(settings),
      });
      setDirty(false);
      toast("User page settings saved", { variant: "success" });
    } catch (error) {
      console.error("Failed to save user page settings:", error);
      toast("Failed to save user page settings", { variant: "error" });
    }
  };

  return (
    <div className="space-y-6">
      <SectionPanel className="p-6">
        <SectionHeader
          title="User Pages"
          description="Configure which authentication flows are available in the public UI."
        />
      </SectionPanel>

      <Card className="bg-card border-border">
        <CardHeader>
          <CardTitle className="text-white text-lg">Authentication Flows</CardTitle>
          <CardDescription className="text-gray-500">
            Toggle each flow on/off. Password strength rules live in Auth Settings.
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          {(
            [
              ["allowSignup", "Allow sign-up", "Enable self-service user registration."],
              ["allowPasswordReset", "Allow password reset", "Enable forgot-password flow."],
              ["allowSocialLogin", "Allow social login", "Show OAuth providers on login."],
              ["requireEmailVerification", "Require email verification", "Block access until email is verified."],
            ] as const
          ).map(([key, title, description]) => (
            <div
              key={key}
              className="flex items-center justify-between rounded-md border border-border bg-card/40 px-4 py-3"
            >
              <div>
                <Label className="text-sm text-gray-200">{title}</Label>
                <div className="text-xs text-gray-500">{description}</div>
              </div>
              <Switch
                checked={settings[key]}
                onCheckedChange={() => handleToggle(key)}
              />
            </div>
          ))}
        </CardContent>
      </Card>

      <div className="flex justify-end">
        <Button
          onClick={() => void handleSave()}
          disabled={!dirty || updateSetting.isPending}
        >
          {updateSetting.isPending ? "Saving..." : "Save settings"}
        </Button>
      </div>
    </div>
  );
}

"use client";

import { Button, ListPanel, SectionHeader, SectionPanel, Dialog, DialogContent, DialogFooter, DialogHeader, DialogTitle, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Table, TableBody, TableCell, TableHead, TableHeader, TableRow, useToast, Textarea, Checkbox } from "@/shared/ui";
import { useEffect, useMemo, useState } from "react";










import {
  AUTH_SETTINGS_KEYS,
  DEFAULT_AUTH_ROLES,
  mergeDefaultRoles,
  type AuthRole,
  type AuthUserRoleMap,
} from "@/features/auth/utils/auth-management";
import { parseJsonSetting, serializeSetting } from "@/shared/utils/settings-json";
import { DEFAULT_AUTH_SECURITY_POLICY } from "@/features/auth/utils/auth-security";
import type { AuthUserSummary } from "@/features/auth/types";

import {
  useAuthUsers,
  useAuthUserSecurity,
  useMockSignIn,
  useRegisterUser,
  useUpdateAuthUser,
  useUpdateAuthUserSecurity,
} from "@/features/auth/hooks/useAuthQueries";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/useSettings";

const EMPTY_CREATE = { name: "", email: "", password: "", roleId: "none", verified: false };

export default function AuthUsersPage() {
  const { toast } = useToast();
  const [users, setUsers] = useState<AuthUserSummary[]>([]);
  const [provider, setProvider] = useState<"prisma" | "mongodb">("prisma");
  const [roles, setRoles] = useState<AuthRole[]>(DEFAULT_AUTH_ROLES);
  const [userRoles, setUserRoles] = useState<AuthUserRoleMap>({});
  const [search, setSearch] = useState("");
  const [dirtyRoles, setDirtyRoles] = useState(false);

  const [editingUser, setEditingUser] = useState<AuthUserSummary | null>(null);
  const [editName, setEditName] = useState("");
  const [editEmail, setEditEmail] = useState("");
  const [editVerified, setEditVerified] = useState(false);
  const [editDisabled, setEditDisabled] = useState(false);
  const [editBanned, setEditBanned] = useState(false);
  const [editAllowedIps, setEditAllowedIps] = useState("");
  const [editMfaEnabled, setEditMfaEnabled] = useState(false);

  const [createOpen, setCreateOpen] = useState(false);
  const [createForm, setCreateForm] = useState(EMPTY_CREATE);

  const [mockEmail, setMockEmail] = useState("");
  const [mockPassword, setMockPassword] = useState("");
  const [mockStatus, setMockStatus] = useState<"idle" | "success" | "error">("idle");
  const [mockMessage, setMockMessage] = useState("");
  const [mockOpen, setMockOpen] = useState(false);
  const authUsersQuery = useAuthUsers();
  const settingsQuery = useSettingsMap();
  const updateSetting = useUpdateSetting();
  const updateAuthUserMutation = useUpdateAuthUser();
  const updateAuthUserSecurityMutation = useUpdateAuthUserSecurity();
  const registerUserMutation = useRegisterUser();
  const mockSignInMutation = useMockSignIn();
  const userSecurityQuery = useAuthUserSecurity(editingUser?.id);
  const loading = authUsersQuery.isPending || settingsQuery.isPending;
  const loadingSecurity = userSecurityQuery.isPending;

  useEffect(() => {
    if (!authUsersQuery.error) return;
    console.error("Failed to load users:", authUsersQuery.error);
    toast("Failed to load users", { variant: "error" });
  }, [authUsersQuery.error, toast]);

  useEffect(() => {
    if (!settingsQuery.error) return;
    console.error("Failed to load user roles:", settingsQuery.error);
    toast("Failed to load user roles", { variant: "error" });
  }, [settingsQuery.error, toast]);

  useEffect(() => {
    if (!userSecurityQuery.error) return;
    console.error("Failed to load security profile:", userSecurityQuery.error);
  }, [userSecurityQuery.error]);

  useEffect(() => {
    if (authUsersQuery.data) {
      setUsers(authUsersQuery.data.users ?? []);
      setProvider(authUsersQuery.data.provider ?? "prisma");
    }
  }, [authUsersQuery.data]);

  useEffect(() => {
    if (!settingsQuery.data) return;
    const storedRoles = mergeDefaultRoles(
      parseJsonSetting<AuthRole[]>(
        settingsQuery.data.get(AUTH_SETTINGS_KEYS.roles),
        DEFAULT_AUTH_ROLES
      )
    );
    const storedUserRoles = parseJsonSetting<AuthUserRoleMap>(
      settingsQuery.data.get(AUTH_SETTINGS_KEYS.userRoles),
      {}
    );
    setRoles(storedRoles);
    setUserRoles(storedUserRoles);
    setDirtyRoles(false);
  }, [settingsQuery.data]);

  const filteredUsers = useMemo(() => {
    const query = search.trim().toLowerCase();
    if (!query) return users;
    return users.filter((user) => {
      return (
        user.email?.toLowerCase().includes(query) ||
        user.name?.toLowerCase().includes(query) ||
        user.id.toLowerCase().includes(query)
      );
    });
  }, [search, users]);

  const handleRoleChange = (userId: string, roleId: string) => {
    setUserRoles((prev) => {
      const next = { ...prev };
      if (!roleId || roleId === "none") {
        delete next[userId];
      } else {
        next[userId] = roleId;
      }
      return next;
    });
    setDirtyRoles(true);
  };

  const handleSaveRoles = async () => {
    try {
      await updateSetting.mutateAsync({
        key: AUTH_SETTINGS_KEYS.userRoles,
        value: serializeSetting(userRoles),
      });
      setDirtyRoles(false);
      toast("User roles updated", { variant: "success" });
    } catch (error) {
      console.error("Failed to save user roles:", error);
      toast("Failed to save user roles", { variant: "error" });
    }
  };

  const handleOpenEdit = (user: AuthUserSummary) => {
    setEditingUser(user);
    setEditName(user.name ?? "");
    setEditEmail(user.email ?? "");
    setEditVerified(Boolean(user.emailVerified));
    setEditDisabled(false);
    setEditBanned(false);
    setEditAllowedIps("");
    setEditMfaEnabled(false);
  };

  useEffect(() => {
    if (!userSecurityQuery.data || !editingUser) return;
    setEditDisabled(Boolean(userSecurityQuery.data.disabledAt));
    setEditBanned(Boolean(userSecurityQuery.data.bannedAt));
    setEditAllowedIps((userSecurityQuery.data.allowedIps ?? []).join("\n"));
    setEditMfaEnabled(Boolean(userSecurityQuery.data.mfaEnabled));
  }, [userSecurityQuery.data, editingUser]);

  const handleSaveUser = async () => {
    if (!editingUser) return;
    if (!editEmail.trim()) {
      toast("Email is required", { variant: "error" });
      return;
    }
    try {
      const payload: { name?: string; email: string; emailVerified?: boolean } = {
        email: editEmail.trim(),
      };
      if (editName.trim()) {
        payload.name = editName.trim();
      }
      if (editVerified !== Boolean(editingUser.emailVerified)) {
        payload.emailVerified = editVerified;
      }
      const updated = (await updateAuthUserMutation.mutateAsync({
        userId: editingUser.id,
        input: payload,
      }));
      const securityPayload = {
        disabled: editDisabled,
        banned: editBanned,
        allowedIps: editAllowedIps
          .split(/\r?\n|,/)
          .map((entry) => entry.trim())
          .filter(Boolean),
      };
      await updateAuthUserSecurityMutation.mutateAsync({
        userId: editingUser.id,
        input: securityPayload,
      });
      setUsers((prev) =>
        prev.map((user) => (user.id === updated.id ? updated : user))
      );
      toast("User updated", { variant: "success" });
      setEditingUser(null);
    } catch (error) {
      console.error("Failed to update user:", error);
      toast("Failed to update user", { variant: "error" });
    }
  };

  const handleDisableMfa = async () => {
    if (!editingUser) return;
    try {
      await updateAuthUserSecurityMutation.mutateAsync({
        userId: editingUser.id,
        input: { disableMfa: true },
      });
      setEditMfaEnabled(false);
      toast("MFA disabled for user", { variant: "success" });
    } catch (error) {
      console.error("Failed to disable MFA:", error);
      toast("Failed to disable MFA", { variant: "error" });
    }
  };

  const handleCreateUser = async () => {
    if (!createForm.email.trim() || !createForm.password.trim()) {
      toast("Email and password are required", { variant: "error" });
      return;
    }
    if (createForm.password.trim().length < DEFAULT_AUTH_SECURITY_POLICY.minPasswordLength) {
      toast(`Password must be at least ${DEFAULT_AUTH_SECURITY_POLICY.minPasswordLength} characters`, {
        variant: "error",
      });
      return;
    }
    try {
      const res = await registerUserMutation.mutateAsync({
        email: createForm.email.trim(),
        password: createForm.password.trim(),
        name: createForm.name.trim() || undefined,
      });
      if (!res.ok) {
        const errorPayload = res.payload as
          | { error?: string; details?: { issues?: string[] } }
          | null;
        const details = errorPayload?.details?.issues?.join(" ") ?? "";
        toast(
          errorPayload?.error
            ? `${errorPayload.error}${details ? ` ${details}` : ""}`
            : "Failed to create user",
          { variant: "error" }
        );
        return;
      }
      const created = res.payload as { id: string; email: string; name?: string | null };

      if (createForm.roleId && createForm.roleId !== "none") {
        const nextRoles = { ...userRoles, [created.id]: createForm.roleId };
        try {
          await updateSetting.mutateAsync({
            key: AUTH_SETTINGS_KEYS.userRoles,
            value: serializeSetting(nextRoles),
          });
          setUserRoles(nextRoles);
          setDirtyRoles(false);
        } catch {
          // ignore role save errors here; user was created
        }
      }

      if (createForm.verified) {
        await updateAuthUserMutation.mutateAsync({
          userId: created.id,
          input: { emailVerified: true },
        });
      }

      toast("User created", { variant: "success" });
      setCreateOpen(false);
      setCreateForm(EMPTY_CREATE);
      void authUsersQuery.refetch();
    } catch (error) {
      console.error("Failed to create user:", error);
      toast("Failed to create user", { variant: "error" });
    }
  };

  const handleMockSignIn = async () => {
    if (!mockEmail.trim() || !mockPassword.trim()) {
      setMockStatus("error");
      setMockMessage("Email and password are required.");
      return;
    }
    try {
      setMockStatus("idle");
      setMockMessage("");
      const res = await mockSignInMutation.mutateAsync({
        email: mockEmail.trim(),
        password: mockPassword,
      });
      if (!res.ok) {
        throw new Error("Mock sign-in failed");
      }
      const payload = res.payload as { ok?: boolean; message?: string };
      if (payload.ok) {
        setMockStatus("success");
        setMockMessage(payload.message ?? "Credentials are valid.");
      } else {
        setMockStatus("error");
        setMockMessage(payload.message ?? "Sign-in failed. Check credentials.");
      }
    } catch (error) {
      console.error("Mock sign-in failed:", error);
      setMockStatus("error");
      setMockMessage("Sign-in failed. Check server logs.");
    }
  };

  return (
    <>
      <ListPanel
        header={
          <SectionHeader
            title="Users"
            description={`Manage user accounts and assign roles (provider: ${provider}).`}
            actions={
              <>
                <Button
                  variant="outline"
                  onClick={() => {
                    void authUsersQuery.refetch();
                    void settingsQuery.refetch();
                  }}
                  disabled={loading}
                >
                  Refresh
                </Button>
                <Button variant="outline" onClick={() => setMockOpen(true)}>
                  Mock Sign-in
                </Button>
                <Button variant="outline" onClick={() => setCreateOpen(true)}>
                  Create User
                </Button>
                <Button
                  onClick={() => void handleSaveRoles()}
                  disabled={!dirtyRoles || updateSetting.isPending}
                >
                  {updateSetting.isPending ? "Saving..." : "Save Roles"}
                </Button>
              </>
            }
          />
        }
        filters={
          <SectionPanel>
            <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
              <Input
                value={search}
                onChange={(event) => setSearch(event.target.value)}
                placeholder="Search by name, email, or ID"
                className="h-8 text-sm sm:max-w-xs"
              />
              <div className="text-xs text-gray-500">
                {dirtyRoles ? "Unsaved role changes" : "Roles are up to date"}
              </div>
            </div>
          </SectionPanel>
        }
      >
        {loading ? (
          <div className="rounded-md border border-dashed border-border p-6 text-center text-gray-400">
            Loading users...
          </div>
        ) : (
          <Table className="text-gray-200">
            <TableHeader>
              <TableRow>
                <TableHead>Name</TableHead>
                <TableHead>Email</TableHead>
                <TableHead>Verified</TableHead>
                <TableHead>Role</TableHead>
                <TableHead className="text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredUsers.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={5} className="text-center text-gray-500">
                    No users found.
                  </TableCell>
                </TableRow>
              ) : (
                filteredUsers.map((user) => (
                  <TableRow key={user.id}>
                    <TableCell className="font-medium">{user.name ?? "Unnamed"}</TableCell>
                    <TableCell className="text-gray-300">{user.email ?? "No email"}</TableCell>
                    <TableCell>
                      {user.emailVerified ? (
                        <span className="rounded-full bg-green-500/10 px-2 py-1 text-xs text-green-200">
                          Verified
                        </span>
                      ) : (
                        <span className="rounded-full bg-amber-500/10 px-2 py-1 text-xs text-amber-200">
                          Pending
                        </span>
                      )}
                    </TableCell>
                    <TableCell className="min-w-[180px]">
                      {(() => {
                        const currentRoleId = userRoles[user.id];
                        const isValidRole = currentRoleId && roles.some((r) => r.id === currentRoleId);
                        const selectValue = isValidRole ? currentRoleId : "none";
                        return (
                          <Select
                            value={selectValue}
                            onValueChange={(value) => handleRoleChange(user.id, value)}
                          >
                            <SelectTrigger className="h-8 bg-gray-900 border text-white">
                              <SelectValue placeholder="Select role" />
                            </SelectTrigger>
                            <SelectContent>
                              <SelectItem value="none">Unassigned</SelectItem>
                              {roles.map((role) => (
                                <SelectItem key={role.id} value={role.id}>
                                  {role.name}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        );
                      })()}
                    </TableCell>
                    <TableCell className="text-right">
                      <Button variant="ghost" size="sm" onClick={() => handleOpenEdit(user)}>
                        Edit
                      </Button>
                    </TableCell>
                  </TableRow>
                ))
              )}
            </TableBody>
          </Table>
        )}
      </ListPanel>

      <Dialog open={Boolean(editingUser)} onOpenChange={(open) => !open && setEditingUser(null)}>
        <DialogContent className="bg-card border-border text-white">
          <DialogHeader>
            <DialogTitle>Edit User</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="edit-name" className="text-xs text-gray-300">
                Name
              </Label>
              <Input
                id="edit-name"
                value={editName}
                onChange={(event) => setEditName(event.target.value)}
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="edit-email" className="text-xs text-gray-300">
                Email
              </Label>
              <Input
                id="edit-email"
                value={editEmail}
                onChange={(event) => setEditEmail(event.target.value)}
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="flex items-center gap-2">
              <Checkbox
                id="edit-verified"
                checked={editVerified} onCheckedChange={(checked) => setEditVerified(Boolean(checked))}
                className="h-4 w-4 rounded border bg-gray-900"
              />
              <Label htmlFor="edit-verified" className="text-xs text-gray-300">
                Email verified
              </Label>
            </div>
            <div className="rounded-md border border-border bg-card/40 p-3 space-y-3">
              <div className="text-xs font-semibold text-gray-300">
                Security controls
              </div>
              {loadingSecurity ? (
                <div className="text-xs text-gray-500">Loading security profile...</div>
              ) : null}
              <div className="flex items-center gap-2">
                <Checkbox
                  id="edit-disabled"
                  checked={editDisabled} onCheckedChange={(checked) => setEditDisabled(Boolean(checked))}
                  className="h-4 w-4 rounded border bg-gray-900"
                />
                <Label htmlFor="edit-disabled" className="text-xs text-gray-300">
                  Disable account
                </Label>
              </div>
              <div className="flex items-center gap-2">
                <Checkbox
                  id="edit-banned"
                  checked={editBanned} onCheckedChange={(checked) => setEditBanned(Boolean(checked))}
                  className="h-4 w-4 rounded border bg-gray-900"
                />
                <Label htmlFor="edit-banned" className="text-xs text-gray-300">
                  Ban account
                </Label>
              </div>
              <div className="space-y-2">
                <Label htmlFor="edit-allowed-ips" className="text-xs text-gray-300">
                  Allowed IPs (optional)
                </Label>
                <Textarea
                  id="edit-allowed-ips"
                  value={editAllowedIps}
                  onChange={(event) => setEditAllowedIps(event.target.value)}
                  className="min-h-[80px] w-full rounded-md border bg-gray-900 px-3 py-2 text-xs text-white"
                  placeholder="One IP per line or comma-separated"
                />
              </div>
              <div className="text-xs text-gray-500">
                MFA status: {editMfaEnabled ? "enabled" : "disabled"}
              </div>
              {editMfaEnabled ? (
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={() => void handleDisableMfa()}
                >
                  Disable MFA
                </Button>
              ) : null}
            </div>
          </div>
          <DialogFooter className="pt-4">
            <Button variant="outline" onClick={() => setEditingUser(null)}>
              Cancel
            </Button>
            <Button
              onClick={() => void handleSaveUser()}
              disabled={updateAuthUserMutation.isPending || updateAuthUserSecurityMutation.isPending}
            >
              {updateAuthUserMutation.isPending || updateAuthUserSecurityMutation.isPending
                ? "Saving..."
                : "Save changes"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={createOpen} onOpenChange={setCreateOpen}>
        <DialogContent className="bg-card border-border text-white">
          <DialogHeader>
            <DialogTitle>Create User</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <div className="space-y-2">
              <Label htmlFor="create-name" className="text-xs text-gray-300">
                Name
              </Label>
              <Input
                id="create-name"
                value={createForm.name}
                onChange={(event) =>
                  setCreateForm((prev) => ({ ...prev, name: event.target.value }))
                }
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="create-email" className="text-xs text-gray-300">
                Email
              </Label>
              <Input
                id="create-email"
                value={createForm.email}
                onChange={(event) =>
                  setCreateForm((prev) => ({ ...prev, email: event.target.value }))
                }
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="create-password" className="text-xs text-gray-300">
                Temporary password
              </Label>
              <Input
                id="create-password"
                type="password"
                value={createForm.password}
                onChange={(event) =>
                  setCreateForm((prev) => ({ ...prev, password: event.target.value }))
                }
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="create-role" className="text-xs text-gray-300">
                Role
              </Label>
              <Select
                value={createForm.roleId}
                onValueChange={(value) =>
                  setCreateForm((prev) => ({ ...prev, roleId: value }))
                }
              >
                <SelectTrigger className="bg-gray-900 border text-white">
                  <SelectValue placeholder="Select role" />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="none">Unassigned</SelectItem>
                  {roles.map((role) => (
                    <SelectItem key={role.id} value={role.id}>
                      {role.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center gap-2">
              <Checkbox
                id="create-verified"
                checked={createForm.verified} onCheckedChange={(checked) =>
                  setCreateForm((prev) => ({
                    ...prev,
                    verified: Boolean(checked),
                  }))
                }
                className="h-4 w-4 rounded border bg-gray-900"
              />
              <Label htmlFor="create-verified" className="text-xs text-gray-300">
                Mark email as verified
              </Label>
            </div>
          </div>
          <DialogFooter className="pt-4">
            <Button variant="outline" onClick={() => setCreateOpen(false)}>
              Cancel
            </Button>
            <Button onClick={() => void handleCreateUser()} disabled={registerUserMutation.isPending}>
              {registerUserMutation.isPending ? "Creating..." : "Create user"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={mockOpen} onOpenChange={setMockOpen}>
        <DialogContent className="bg-card border-border text-white">
          <DialogHeader>
            <DialogTitle>Mock Sign-in</DialogTitle>
          </DialogHeader>
          <div className="space-y-4">
            <p className="text-xs text-gray-400">
              Verify credentials against MongoDB without changing your session.
            </p>
            <div className="space-y-2">
              <Label htmlFor="mock-email" className="text-xs text-gray-300">
                Email
              </Label>
              <Input
                id="mock-email"
                value={mockEmail}
                onChange={(event) => setMockEmail(event.target.value)}
                className="bg-gray-900 border text-white"
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="mock-password" className="text-xs text-gray-300">
                Password
              </Label>
              <Input
                id="mock-password"
                type="password"
                value={mockPassword}
                onChange={(event) => setMockPassword(event.target.value)}
                className="bg-gray-900 border text-white"
              />
            </div>
            {mockStatus !== "idle" ? (
              <div
                className={`rounded-md border px-3 py-2 text-xs ${
                  mockStatus === "success"
                    ? "border-green-500/40 bg-green-500/10 text-green-200"
                    : "border-red-500/40 bg-red-500/10 text-red-200"
                }`}
              >
                {mockMessage}
              </div>
            ) : null}
          </div>
          <DialogFooter className="pt-4">
            <Button variant="outline" onClick={() => setMockOpen(false)}>
              Close
            </Button>
            <Button onClick={() => void handleMockSignIn()} disabled={mockSignInMutation.isPending}>
              {mockSignInMutation.isPending ? "Testing..." : "Test Sign-in"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import { Button, Input, Label } from "@/shared/ui";
import Link from "next/link";
import { useState } from "react";
import { signIn } from "next-auth/react";
import { AUTH_SETTINGS_KEYS } from "@/features/auth/utils/auth-management";
import { DEFAULT_AUTH_USER_PAGE_SETTINGS } from "@/features/auth/utils/auth-user-pages";
import { DEFAULT_AUTH_SECURITY_POLICY } from "@/features/auth/utils/auth-security";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import { useRegisterUser } from "@/features/auth/hooks/useAuthQueries";
import { useSettingsMap } from "@/shared/hooks/useSettings";



export default function RegisterPage() {
  const settingsQuery = useSettingsMap();

  if (settingsQuery.isLoading || !settingsQuery.data) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-gray-900 px-4">
        <div className="text-gray-400">Loading...</div>
      </div>
    );
  }

  const userPages = parseJsonSetting(
    settingsQuery.data.get(AUTH_SETTINGS_KEYS.userPages),
    DEFAULT_AUTH_USER_PAGE_SETTINGS
  );
  const allowSignup = Boolean(userPages.allowSignup);

  return <RegisterForm allowSignup={allowSignup} />;
}

function RegisterForm({ allowSignup }: { allowSignup: boolean }) {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const registerUserMutation = useRegisterUser();

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      const response = await registerUserMutation.mutateAsync({
        name: name.trim() || undefined,
        email,
        password,
      });

      if (!response.ok) {
        const payload = response.payload as
          | { error?: string; details?: { issues?: string[] } }
          | null;
        const details = payload?.details?.issues?.join(" ") ?? "";
        setError(
          payload?.error
            ? `${payload.error}${details ? ` ${details}` : ""}`
            : "Failed to create account."
        );
        return;
      }

      try {
        await signIn("credentials", {
          email,
          password,
          callbackUrl: "/admin",
        });
      } catch (error) {
        const message =
          error instanceof Error
            ? error.message
            : "Sign-in failed. Please try again.";
        setError(message);
      }
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to create account.";
      setError(message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-900 px-4">
      <div className="w-full max-w-md space-y-6 rounded-lg border border-border bg-card p-6 shadow-lg">
        <div>
          <h1 className="text-2xl font-semibold text-white">Create account</h1>
          <p className="mt-1 text-sm text-gray-400">
            Create a new account with email and password.
          </p>
        </div>
        {error ? (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 p-3 text-xs text-red-200">
            {error}
          </div>
        ) : null}
        {!allowSignup ? (
          <div className="rounded-md border border-amber-500/40 bg-amber-500/10 p-3 text-xs text-amber-100">
            Self-service registration is disabled. Please contact an administrator.
          </div>
        ) : null}
        <form className="space-y-4" onSubmit={(e) => void handleSubmit(e)}>
          <div className="space-y-2">
            <Label className="text-sm text-gray-300" htmlFor="name">
              Name (optional)
            </Label>
            <Input
              id="name"
              type="text"
              className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
              value={name}
              onChange={(event) => setName(event.target.value)}
              disabled={!allowSignup}
            />
          </div>
          <div className="space-y-2">
            <Label className="text-sm text-gray-300" htmlFor="email">
              Email
            </Label>
            <Input
              id="email"
              type="email"
              className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
              value={email}
              onChange={(event) => setEmail(event.target.value)}
              required
              disabled={!allowSignup}
            />
          </div>
          <div className="space-y-2">
            <Label className="text-sm text-gray-300" htmlFor="password">
              Password
            </Label>
            <Input
              id="password"
              type="password"
              className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
              value={password}
              onChange={(event) => setPassword(event.target.value)}
              required
              minLength={DEFAULT_AUTH_SECURITY_POLICY.minPasswordLength}
              disabled={!allowSignup}
            />
            <p className="text-xs text-gray-500">
              Minimum {DEFAULT_AUTH_SECURITY_POLICY.minPasswordLength} characters.
            </p>
          </div>
          <Button
            className="w-full rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200 disabled:cursor-not-allowed disabled:bg-gray-700 disabled:text-gray-300"
            type="submit"
            disabled={isSubmitting || !allowSignup}
          >
            {isSubmitting ? "Creating..." : "Create account"}
          </Button>
        </form>
        <p className="text-xs text-gray-400">
          Already have an account?{" "}
          <Link href="/auth/signin" className="text-white hover:underline">
            Sign in
          </Link>
        </p>
      </div>
    </div>
  );
}

"use client";

import { Button, Input, Label } from "@/shared/ui";
import Link from "next/link";
import { useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import { signIn } from "next-auth/react";
import { AUTH_SETTINGS_KEYS } from "@/features/auth/utils/auth-management";
import { DEFAULT_AUTH_USER_PAGE_SETTINGS } from "@/features/auth/utils/auth-user-pages";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import { useVerifyCredentials } from "@/features/auth/hooks/useAuthQueries";
import { useSettingsMap } from "@/shared/hooks/useSettings";



function SignInPageLoader() {
  const settingsQuery = useSettingsMap();

  if (settingsQuery.isLoading || !settingsQuery.data) {
    return (
      <div className="flex min-h-screen items-center justify-center bg-gray-900 px-4">
        <div className="text-gray-400">Loading...</div>
      </div>
    );
  }

  const userPages = parseJsonSetting(
    settingsQuery.data.get(AUTH_SETTINGS_KEYS.userPages),
    DEFAULT_AUTH_USER_PAGE_SETTINGS
  );
  const allowSocialLogin = Boolean(userPages.allowSocialLogin);

  return <SignInForm allowSocialLogin={allowSocialLogin} />;
}

function SignInForm({ allowSocialLogin }: { allowSocialLogin: boolean }) {
  const searchParams = useSearchParams();
  const error = searchParams.get("error");
  const errorMessage =
    error === "AccountDisabled"
      ? "Account is disabled or banned."
      : error
      ? "Sign-in failed. Please check your credentials and try again."
      : null;
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [otp, setOtp] = useState("");
  const [recoveryCode, setRecoveryCode] = useState("");
  const [challengeId, setChallengeId] = useState<string | null>(null);
  const [mfaRequired, setMfaRequired] = useState(false);
  const [message, setMessage] = useState<string | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const verifyCredentialsMutation = useVerifyCredentials();

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    setIsSubmitting(true);
    setMessage(null);

    if (!mfaRequired) {
      try {
        const { ok, payload } = await verifyCredentialsMutation.mutateAsync({ email, password });
        if (!ok || !payload.ok) {
          setMessage(payload.message ?? "Sign-in failed. Check your credentials.");
          setIsSubmitting(false);
          return;
        }

        if (payload.mfaRequired) {
          setChallengeId(payload.challengeId ?? null);
          setMfaRequired(true);
          setIsSubmitting(false);
          return;
        }

        try {
          await signIn("credentials", {
            email,
            password,
            challengeId: payload.challengeId ?? undefined,
            callbackUrl: "/admin",
          });
        } catch (error) {
          const message =
            error instanceof Error
              ? error.message
              : "Sign-in failed. Please try again.";
          setMessage(message);
        } finally {
          setIsSubmitting(false);
        }
        return;
      } catch (error) {
        const message =
          error instanceof Error
            ? error.message
            : "Unable to verify credentials. Check your connection.";
        setMessage(message);
        setIsSubmitting(false);
        return;
      }
    }

    try {
      await signIn("credentials", {
        email,
        password,
        otp,
        recoveryCode,
        challengeId: challengeId ?? undefined,
        callbackUrl: "/admin",
      });
    } catch (error) {
      const message =
        error instanceof Error
          ? error.message
          : "Sign-in failed. Please try again.";
      setMessage(message);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-gray-900 px-4">
      <div className="w-full max-w-md space-y-6 rounded-lg border border-border bg-card p-6 shadow-lg">
        <div>
          <h1 className="text-2xl font-semibold text-white">Sign in</h1>
          <p className="mt-1 text-sm text-gray-400">
            Use your credentials or a provider.
          </p>
        </div>
        {message ? (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 p-3 text-xs text-red-200">
            {message}
          </div>
        ) : null}
        {errorMessage ? (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 p-3 text-xs text-red-200">
            {errorMessage}
          </div>
        ) : null}
        <form className="space-y-4" onSubmit={(e) => void handleSubmit(e)}>
          <div className="space-y-2">
            <Label className="text-sm text-gray-300" htmlFor="email">
              Email
            </Label>
            <Input
              id="email"
              type="email"
              className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
              value={email}
              onChange={(event) => setEmail(event.target.value)}
              required
            />
          </div>
          <div className="space-y-2">
            <Label className="text-sm text-gray-300" htmlFor="password">
              Password
            </Label>
            <Input
              id="password"
              type="password"
              className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
              value={password}
              onChange={(event) => setPassword(event.target.value)}
              required
            />
          </div>
          {mfaRequired ? (
            <>
              <div className="space-y-2">
                <Label className="text-sm text-gray-300" htmlFor="otp">
                  One-time code
                </Label>
                <Input
                  id="otp"
                  type="text"
                  className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
                  value={otp}
                  onChange={(event) => setOtp(event.target.value)}
                  placeholder="123456"
                />
              </div>
              <div className="space-y-2">
                <Label className="text-sm text-gray-300" htmlFor="recovery">
                  Recovery code (optional)
                </Label>
                <Input
                  id="recovery"
                  type="text"
                  className="w-full rounded-md border border-border bg-gray-900 px-3 py-2 text-white"
                  value={recoveryCode}
                  onChange={(event) => setRecoveryCode(event.target.value)}
                  placeholder="ABCD-1234-EFGH"
                />
              </div>
            </>
          ) : null}
          <Button
            className="w-full rounded-md bg-white px-3 py-2 text-sm font-semibold text-gray-900 hover:bg-gray-200 disabled:cursor-not-allowed disabled:bg-gray-700 disabled:text-gray-300"
            type="submit"
            disabled={isSubmitting}
          >
            {isSubmitting ? "Signing in..." : mfaRequired ? "Verify & sign in" : "Sign in"}
          </Button>
        </form>
        {allowSocialLogin ? (
          <div className="space-y-3">
            <div className="flex items-center gap-3 text-xs text-gray-500">
              <span className="h-px flex-1 bg-gray-800" />
              or
              <span className="h-px flex-1 bg-gray-800" />
            </div>
            <Button
              className="w-full rounded-md border px-3 py-2 text-sm font-semibold text-gray-200 hover:border-gray-500"
              type="button"
              onClick={() => void signIn("google", { callbackUrl: "/admin" })}
            >
              Continue with Google
            </Button>
            <Button
              className="w-full rounded-md border px-3 py-2 text-sm font-semibold text-gray-200 hover:border-gray-500"
              type="button"
              onClick={() => void signIn("facebook", { callbackUrl: "/admin" })}
            >
              Continue with Facebook
            </Button>
          </div>
        ) : null}
        <p className="text-xs text-gray-400">
          No account?{" "}
          <Link href="/auth/register" className="text-white hover:underline">
            Create one
          </Link>
        </p>
      </div>
    </div>
  );
}

export default function SignInPage() {
  return (
    <Suspense fallback={<div>Loading...</div>}>
      <SignInPageLoader />
    </Suspense>
  );
}

import "server-only";

import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import {
  AUTH_SETTINGS_KEYS,
  DEFAULT_AUTH_PERMISSIONS,
  DEFAULT_AUTH_ROLES,
  mergeDefaultRoles,
  ROLE_ELEVATION_THRESHOLD,
  type AuthPermission,
  type AuthRole,
  type AuthUserRoleMap,
} from "@/features/auth/utils/auth-management";
import { parseJsonSetting } from "@/shared/utils/settings-json";

type SettingRecord = { _id: string; key: string; value: string };

const canUsePrismaSettings = () =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readPrismaSetting = async (key: string): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key },
      select: { value: true },
    });
    return setting?.value ?? null;
  } catch {
    return null;
  }
};

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<SettingRecord>("settings")
    .findOne({ $or: [{ _id: key }, { key }] });
  return typeof doc?.value === "string" ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    return readMongoSetting(key);
  }
  return readPrismaSetting(key);
};

export const getAuthPermissions = async (): Promise<AuthPermission[]> => {
  const value = await readSettingValue(AUTH_SETTINGS_KEYS.permissions);
  return parseJsonSetting<AuthPermission[]>(value, DEFAULT_AUTH_PERMISSIONS);
};

export const getAuthRoles = async (): Promise<AuthRole[]> => {
  const value = await readSettingValue(AUTH_SETTINGS_KEYS.roles);
  return mergeDefaultRoles(parseJsonSetting<AuthRole[]>(value, DEFAULT_AUTH_ROLES));
};

export const getAuthUserRoles = async (): Promise<AuthUserRoleMap> => {
  const value = await readSettingValue(AUTH_SETTINGS_KEYS.userRoles);
  return parseJsonSetting<AuthUserRoleMap>(value, {});
};

export const getAuthDefaultRoleId = async (): Promise<string | null> => {
  const value = await readSettingValue(AUTH_SETTINGS_KEYS.defaultRole);
  if (!value) return null;
  return value.trim();
};

export type AuthUserAccess = {
  roleId: string;
  permissions: string[];
  level: number;
  isElevated: boolean;
  role?: AuthRole;
};

export const getAuthAccessForUser = async (userId: string): Promise<AuthUserAccess> => {
  const [roles, userRoles, defaultRoleId] = await Promise.all([
    getAuthRoles(),
    getAuthUserRoles(),
    getAuthDefaultRoleId(),
  ]);
  const roleList = roles.length > 0 ? roles : DEFAULT_AUTH_ROLES;
  const validDefaultRoleId =
    defaultRoleId && roleList.some((role) => role.id === defaultRoleId)
      ? defaultRoleId
      : null;
  const fallbackRoleId =
    roleList.find((role) => role.id === "viewer")?.id ??
    roleList.find((role) => !["super_admin", "superuser", "admin"].includes(role.id))
      ?.id ??
    roleList[0]?.id ??
    "admin";

  const assignedRoleId = userRoles[userId];
  const isAssignedValid = assignedRoleId
    ? roleList.some((role) => role.id === assignedRoleId)
    : false;
  const effectiveRoleId = isAssignedValid
    ? (assignedRoleId as string)
    : validDefaultRoleId ?? fallbackRoleId;

  const role =
    roleList.find((item) => item.id === effectiveRoleId) ??
    roleList[0] ??
    DEFAULT_AUTH_ROLES[0]!;

  const roleLevel = role.level ?? 0;
  const denied = role.deniedPermissions ?? [];
  const permissions = (role.permissions ?? []).filter(
    (permission) => !denied.includes(permission)
  );

  return {
    roleId: role.id,
    permissions,
    level: roleLevel,
    isElevated: roleLevel >= ROLE_ELEVATION_THRESHOLD,
    role,
  };
};

import "server-only";

import crypto from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";

type ChallengeRecord = {
  _id: string;
  userId: string;
  email: string;
  ip: string | null;
  mfaRequired: boolean;
  expiresAt: Date;
  createdAt: Date;
};

const CHALLENGES_COLLECTION = "auth_login_challenges";
const CHALLENGE_TTL_MINUTES = 5;

const memoryChallenges = new Map<string, ChallengeRecord>();
let challengeIndexesReady: Promise<void> | null = null;

const nowPlusMinutes = (minutes: number) =>
  new Date(Date.now() + minutes * 60 * 1000);

const getMongoChallenge = async (id: string) => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  return mongo.collection<ChallengeRecord>(CHALLENGES_COLLECTION).findOne({ _id: id });
};

const setMongoChallenge = async (record: ChallengeRecord) => {
  if (!process.env.MONGODB_URI) return;
  const mongo = await getMongoDb();
  await mongo
    .collection<ChallengeRecord>(CHALLENGES_COLLECTION)
    .updateOne({ _id: record._id }, { $set: record }, { upsert: true });
};

const deleteMongoChallenge = async (id: string) => {
  if (!process.env.MONGODB_URI) return;
  const mongo = await getMongoDb();
  await mongo.collection<ChallengeRecord>(CHALLENGES_COLLECTION).deleteOne({ _id: id });
};

const getMemoryChallenge = (id: string) => memoryChallenges.get(id) ?? null;
const setMemoryChallenge = (record: ChallengeRecord) => memoryChallenges.set(record._id, record);
const deleteMemoryChallenge = (id: string) => memoryChallenges.delete(id);

const getChallenge = async (id: string) => {
  if (process.env.MONGODB_URI) {
    return getMongoChallenge(id);
  }
  return getMemoryChallenge(id);
};

const setChallenge = async (record: ChallengeRecord) => {
  if (process.env.MONGODB_URI) {
    if (!challengeIndexesReady) {
      challengeIndexesReady = (async () => {
        const mongo = await getMongoDb();
        const collection = mongo.collection<ChallengeRecord>(CHALLENGES_COLLECTION);
        await collection.createIndex({ expiresAt: 1 }, { expireAfterSeconds: 0 });
        await collection.createIndex({ userId: 1 });
      })();
    }
    await challengeIndexesReady;
    await setMongoChallenge(record);
    return;
  }
  setMemoryChallenge(record);
};

const deleteChallenge = async (id: string) => {
  if (process.env.MONGODB_URI) {
    await deleteMongoChallenge(id);
    return;
  }
  deleteMemoryChallenge(id);
};

export const createLoginChallenge = async (input: {
  userId: string;
  email: string;
  ip: string | null;
  mfaRequired: boolean;
}) => {
  const id = crypto.randomBytes(32).toString("hex");
  const record: ChallengeRecord = {
    _id: id,
    userId: input.userId,
    email: input.email.toLowerCase(),
    ip: input.ip ?? null,
    mfaRequired: input.mfaRequired,
    expiresAt: nowPlusMinutes(CHALLENGE_TTL_MINUTES),
    createdAt: new Date(),
  };
  await setChallenge(record);
  return { id, expiresAt: record.expiresAt, mfaRequired: record.mfaRequired };
};

export const consumeLoginChallenge = async (input: {
  id: string;
  email: string;
  ip: string | null;
}) => {
  const record = await getChallenge(input.id);
  if (!record) return null;
  await deleteChallenge(input.id);

  if (record.expiresAt.getTime() < Date.now()) return null;
  if (record.email !== input.email.toLowerCase()) return null;
  if (record.ip && input.ip && record.ip !== input.ip) return null;

  return record;
};

import "server-only";

import { Prisma } from "@prisma/client";
import prisma from "@/shared/lib/db/prisma";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import { getAuthDataProvider } from "@/features/auth/services/auth-provider";

export type AuthSecurityProfile = {
  userId: string;
  mfaEnabled: boolean;
  mfaSecret: string | null;
  recoveryCodes: string[];
  allowedIps: string[];
  disabledAt: Date | null;
  bannedAt: Date | null;
  createdAt: Date;
  updatedAt: Date;
};

type MongoProfileDoc = {
  _id: string;
  userId: string;
  mfaEnabled?: boolean;
  mfaSecret?: string | null;
  recoveryCodes?: string[];
  allowedIps?: string[];
  disabledAt?: Date | null;
  bannedAt?: Date | null;
  createdAt?: Date;
  updatedAt?: Date;
};

const PROFILES_COLLECTION = "auth_security_profiles";

const buildDefaultProfile = (userId: string): AuthSecurityProfile => ({
  userId,
  mfaEnabled: false,
  mfaSecret: null,
  recoveryCodes: [],
  allowedIps: [],
  disabledAt: null,
  bannedAt: null,
  createdAt: new Date(),
  updatedAt: new Date(),
});

const normalizeProfile = (profile: AuthSecurityProfile) => ({
  ...profile,
  recoveryCodes: Array.isArray(profile.recoveryCodes) ? profile.recoveryCodes : [],
  allowedIps: Array.isArray(profile.allowedIps) ? profile.allowedIps : [],
});

export const getAuthSecurityProfile = async (
  userId: string
): Promise<AuthSecurityProfile> => {
  const provider = await getAuthDataProvider();
  if (provider === "mongodb") {
    if (!process.env.MONGODB_URI) return buildDefaultProfile(userId);
    const mongo = await getMongoDb();
    const doc = await mongo
      .collection<MongoProfileDoc>(PROFILES_COLLECTION)
      .findOne({ _id: userId });
    if (!doc) return buildDefaultProfile(userId);
    return normalizeProfile({
      userId: doc.userId ?? doc._id,
      mfaEnabled: Boolean(doc.mfaEnabled),
      mfaSecret: doc.mfaSecret ?? null,
      recoveryCodes: doc.recoveryCodes ?? [],
      allowedIps: doc.allowedIps ?? [],
      disabledAt: doc.disabledAt ?? null,
      bannedAt: doc.bannedAt ?? null,
      createdAt: doc.createdAt ?? new Date(),
      updatedAt: doc.updatedAt ?? new Date(),
    });
  }

  if (!process.env.DATABASE_URL) return buildDefaultProfile(userId);
  const profile = await prisma.authSecurityProfile.findUnique({
    where: { userId },
  });
  if (!profile) return buildDefaultProfile(userId);
  return normalizeProfile({
    userId: profile.userId,
    mfaEnabled: profile.mfaEnabled,
    mfaSecret: profile.mfaSecret ?? null,
    recoveryCodes: profile.recoveryCodes ?? [],
    allowedIps: profile.allowedIps ?? [],
    disabledAt: profile.disabledAt ?? null,
    bannedAt: profile.bannedAt ?? null,
    createdAt: profile.createdAt,
    updatedAt: profile.updatedAt,
  });
};

export const updateAuthSecurityProfile = async (
  userId: string,
  updates: Partial<AuthSecurityProfile>
): Promise<AuthSecurityProfile> => {
  const provider = await getAuthDataProvider();
  const now = new Date();
  const payload: Partial<AuthSecurityProfile> = {
    updatedAt: now,
  };
  if (typeof updates.mfaEnabled === "boolean") {
    payload.mfaEnabled = updates.mfaEnabled;
  }
  if (updates.mfaSecret !== undefined) {
    payload.mfaSecret = updates.mfaSecret;
  }
  if (updates.recoveryCodes !== undefined) {
    payload.recoveryCodes = updates.recoveryCodes;
  }
  if (updates.allowedIps !== undefined) {
    payload.allowedIps = updates.allowedIps;
  }
  if (updates.disabledAt !== undefined) {
    payload.disabledAt = updates.disabledAt;
  }
  if (updates.bannedAt !== undefined) {
    payload.bannedAt = updates.bannedAt;
  }

  if (provider === "mongodb") {
    if (!process.env.MONGODB_URI) return buildDefaultProfile(userId);
    const mongo = await getMongoDb();
    await mongo.collection<MongoProfileDoc>(PROFILES_COLLECTION).updateOne(
      { _id: userId },
      {
        $set: {
          _id: userId,
          userId,
          ...payload,
        },
        $setOnInsert: { createdAt: now },
      },
      { upsert: true }
    );
    return getAuthSecurityProfile(userId);
  }

  if (!process.env.DATABASE_URL) return buildDefaultProfile(userId);
  await prisma.authSecurityProfile.upsert({
    where: { userId },
    update: payload as Prisma.AuthSecurityProfileUpdateInput,
    create: {
      userId,
      mfaEnabled: Boolean(updates.mfaEnabled),
      mfaSecret: updates.mfaSecret ?? null,
      recoveryCodes: updates.recoveryCodes ?? [],
      allowedIps: updates.allowedIps ?? [],
      disabledAt: updates.disabledAt ?? null,
      bannedAt: updates.bannedAt ?? null,
      createdAt: now,
      updatedAt: now,
    },
  });
  return getAuthSecurityProfile(userId);
};

import "server-only";

import { getMongoDb } from "@/shared/lib/db/mongo-client";
import prisma from "@/shared/lib/db/prisma";
import {
  AUTH_SETTINGS_KEYS,
} from "@/features/auth/utils/auth-management";
import { parseJsonSetting } from "@/shared/utils/settings-json";
import {
  DEFAULT_AUTH_SECURITY_POLICY,
  normalizeAuthSecurityPolicy,
  type AuthSecurityPolicy,
} from "@/features/auth/utils/auth-security";
import { getAppDbProvider } from "@/shared/lib/db/app-db-provider";
import { logSystemEvent } from "@/features/observability/server";

type SettingRecord = { _id: string; key: string; value: string };

type AttemptRecord = {
  _id: string;
  scope: "email" | "ip";
  value: string;
  count: number;
  firstAttemptAt: Date;
  lastAttemptAt: Date;
  lockedUntil?: Date | null;
  expiresAt?: Date | null;
};

const ATTEMPTS_COLLECTION = "auth_security_attempts";

const memoryAttempts = new Map<string, AttemptRecord>();
let indexesReady: Promise<void> | null = null;

const ensureAuthSecurityIndexes = async () => {
  if (!process.env.MONGODB_URI) return;
  if (!indexesReady) {
    indexesReady = (async () => {
      const mongo = await getMongoDb();
      const collection = mongo.collection<AttemptRecord>(ATTEMPTS_COLLECTION);
      await collection.createIndex({ expiresAt: 1 }, { expireAfterSeconds: 0 });
      await collection.createIndex({ scope: 1, value: 1 });
    })();
  }
  await indexesReady;
};

const canUsePrismaSettings = () =>
  Boolean(process.env.DATABASE_URL) && "setting" in prisma;

const readPrismaSetting = async (key: string): Promise<string | null> => {
  if (!canUsePrismaSettings()) return null;
  try {
    const setting = await prisma.setting.findUnique({
      where: { key },
      select: { value: true },
    });
    return setting?.value ?? null;
  } catch {
    return null;
  }
};

const readMongoSetting = async (key: string): Promise<string | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<SettingRecord>("settings")
    .findOne({ $or: [{ _id: key }, { key }] });
  return typeof doc?.value === "string" ? doc.value : null;
};

const readSettingValue = async (key: string): Promise<string | null> => {
  const provider = await getAppDbProvider();
  if (provider === "mongodb") {
    return readMongoSetting(key);
  }
  return readPrismaSetting(key);
};

export const getAuthSecurityPolicy = async (): Promise<AuthSecurityPolicy> => {
  const storedPolicyValue = await readSettingValue(AUTH_SETTINGS_KEYS.securityPolicy);
  if (storedPolicyValue) {
    const parsed = parseJsonSetting<AuthSecurityPolicy>(
      storedPolicyValue,
      DEFAULT_AUTH_SECURITY_POLICY
    );
    return normalizeAuthSecurityPolicy(parsed);
  }

  const legacyUserPages = await readSettingValue(AUTH_SETTINGS_KEYS.userPages);
  if (legacyUserPages) {
    const parsed = parseJsonSetting<{ requireStrongPassword?: boolean }>(
      legacyUserPages,
      {}
    );
    if (typeof parsed.requireStrongPassword === "boolean") {
      return normalizeAuthSecurityPolicy({
        ...DEFAULT_AUTH_SECURITY_POLICY,
        requireStrongPassword: parsed.requireStrongPassword,
      });
    }
  }

  return DEFAULT_AUTH_SECURITY_POLICY;
};

export const validatePasswordStrength = (
  password: string,
  policy: AuthSecurityPolicy
) => {
  const errors: string[] = [];
  if (password.length < policy.minPasswordLength) {
    errors.push(`Password must be at least ${policy.minPasswordLength} characters.`);
  }

  if (policy.requireStrongPassword) {
    if (policy.requireUppercase && !/[A-Z]/.test(password)) {
      errors.push("Password must include at least one uppercase letter.");
    }
    if (policy.requireLowercase && !/[a-z]/.test(password)) {
      errors.push("Password must include at least one lowercase letter.");
    }
    if (policy.requireNumber && !/[0-9]/.test(password)) {
      errors.push("Password must include at least one number.");
    }
    if (policy.requireSymbol && !/[^A-Za-z0-9]/.test(password)) {
      errors.push("Password must include at least one symbol.");
    }
  }

  return { ok: errors.length === 0, errors };
};

const normalizeKey = (value: string | null | undefined) =>
  value?.trim().toLowerCase() ?? "";

const buildAttemptKey = (scope: "email" | "ip", value: string) =>
  `${scope}:${value}`;

const getMemoryAttempt = (key: string): AttemptRecord | null => {
  const record = memoryAttempts.get(key);
  if (!record) return null;
  return record;
};

const setMemoryAttempt = (key: string, record: AttemptRecord) => {
  memoryAttempts.set(key, record);
};

const clearMemoryAttempt = (key: string) => {
  memoryAttempts.delete(key);
};

const getMongoAttempt = async (key: string): Promise<AttemptRecord | null> => {
  if (!process.env.MONGODB_URI) return null;
  const mongo = await getMongoDb();
  const doc = await mongo
    .collection<AttemptRecord>(ATTEMPTS_COLLECTION)
    .findOne({ _id: key });
  return doc ?? null;
};

const setMongoAttempt = async (record: AttemptRecord) => {
  if (!process.env.MONGODB_URI) return;
  const mongo = await getMongoDb();
  await mongo
    .collection<AttemptRecord>(ATTEMPTS_COLLECTION)
    .updateOne({ _id: record._id }, { $set: record }, { upsert: true });
};

const clearMongoAttempt = async (key: string) => {
  if (!process.env.MONGODB_URI) return;
  const mongo = await getMongoDb();
  await mongo
    .collection<AttemptRecord>(ATTEMPTS_COLLECTION)
    .deleteOne({ _id: key });
};

const getAttempt = async (key: string): Promise<AttemptRecord | null> => {
  if (process.env.MONGODB_URI) {
    return await getMongoAttempt(key);
  }
  return getMemoryAttempt(key);
};

const saveAttempt = async (record: AttemptRecord) => {
  if (process.env.MONGODB_URI) {
    await setMongoAttempt(record);
    return;
  }
  setMemoryAttempt(record._id, record);
};

const clearAttempt = async (key: string) => {
  if (process.env.MONGODB_URI) {
    await clearMongoAttempt(key);
    return;
  }
  clearMemoryAttempt(key);
};

const isLocked = (record: AttemptRecord, now: Date) =>
  record.lockedUntil && record.lockedUntil.getTime() > now.getTime();

const bumpAttempt = async (
  scope: "email" | "ip",
  value: string,
  maxAttempts: number,
  windowMinutes: number,
  lockDurationMinutes: number
) => {
  await ensureAuthSecurityIndexes();
  const key = buildAttemptKey(scope, value);
  const now = new Date();
  const existing = await getAttempt(key);
  if (existing?.expiresAt && existing.expiresAt.getTime() <= now.getTime()) {
    await clearAttempt(key);
  }
  if (existing && isLocked(existing, now)) {
    return { lockedUntil: existing.lockedUntil ?? null, count: existing.count };
  }

  const windowMs = windowMinutes * 60 * 1000;
  const lockMs = lockDurationMinutes * 60 * 1000;

  let nextCount = 1;
  let firstAttemptAt = now;
  if (existing) {
    const elapsed = now.getTime() - existing.firstAttemptAt.getTime();
    if (elapsed <= windowMs) {
      nextCount = existing.count + 1;
      firstAttemptAt = existing.firstAttemptAt;
    }
  }

  const lockedUntil =
    nextCount >= maxAttempts ? new Date(now.getTime() + lockMs) : null;
  const expiresAt = new Date(now.getTime() + (windowMs + lockMs));

  const record: AttemptRecord = {
    _id: key,
    scope,
    value,
    count: nextCount,
    firstAttemptAt,
    lastAttemptAt: now,
    lockedUntil,
    expiresAt,
  };

  await saveAttempt(record);
  return { lockedUntil, count: nextCount };
};

const resetAttempt = async (scope: "email" | "ip", value: string) => {
  const key = buildAttemptKey(scope, value);
  await clearAttempt(key);
};

export const checkLoginAllowed = async (input: {
  email?: string | null;
  ip?: string | null;
}) => {
  await ensureAuthSecurityIndexes();
  const emailKey = normalizeKey(input.email);
  const ipKey = normalizeKey(input.ip);
  const now = new Date();

  if (emailKey) {
    const emailAttempt = await getAttempt(buildAttemptKey("email", emailKey));
    if (emailAttempt?.expiresAt && emailAttempt.expiresAt.getTime() <= now.getTime()) {
      await clearAttempt(buildAttemptKey("email", emailKey));
    } else if (emailAttempt && isLocked(emailAttempt, now)) {
      return {
        allowed: false,
        reason: "EMAIL_LOCKED",
        lockedUntil: emailAttempt.lockedUntil ?? null,
      };
    }
  }

  if (ipKey) {
    const ipAttempt = await getAttempt(buildAttemptKey("ip", ipKey));
    if (ipAttempt?.expiresAt && ipAttempt.expiresAt.getTime() <= now.getTime()) {
      await clearAttempt(buildAttemptKey("ip", ipKey));
    } else if (ipAttempt && isLocked(ipAttempt, now)) {
      return {
        allowed: false,
        reason: "IP_RATE_LIMIT",
        lockedUntil: ipAttempt.lockedUntil ?? null,
      };
    }
  }

  return { allowed: true, reason: null, lockedUntil: null };
};

export const recordLoginFailure = async (input: {
  email?: string | null;
  ip?: string | null;
  request?: Request;
}) => {
  await ensureAuthSecurityIndexes();
  const policy = await getAuthSecurityPolicy();
  const emailKey = normalizeKey(input.email);
  const ipKey = normalizeKey(input.ip);

  if (emailKey) {
    const result = await bumpAttempt(
      "email",
      emailKey,
      policy.lockoutMaxAttempts,
      policy.lockoutWindowMinutes,
      policy.lockoutDurationMinutes
    );
    if (result.lockedUntil) {
      await logSystemEvent({
        level: "warn",
        message: "Auth email lockout triggered",
        source: "auth.security",
        context: {
          email: emailKey,
          lockedUntil: result.lockedUntil.toISOString(),
          attempts: result.count,
        },
        ...(input.request ? { request: input.request } : {}),
      });
    }
  }

  if (ipKey) {
    const result = await bumpAttempt(
      "ip",
      ipKey,
      policy.ipRateLimitMaxAttempts,
      policy.ipRateLimitWindowMinutes,
      policy.ipRateLimitDurationMinutes
    );
    if (result.lockedUntil) {
      await logSystemEvent({
        level: "warn",
        message: "Auth IP rate limit triggered",
        source: "auth.security",
        context: {
          ip: ipKey,
          lockedUntil: result.lockedUntil.toISOString(),
          attempts: result.count,
        },
        ...(input.request ? { request: input.request } : {}),
      });
    }
  }
};

export const recordLoginSuccess = async (input: {
  email?: string | null;
  ip?: string | null;
  request?: Request;
  userId?: string | null;
}) => {
  await ensureAuthSecurityIndexes();
  const emailKey = normalizeKey(input.email);
  const ipKey = normalizeKey(input.ip);
  if (emailKey) await resetAttempt("email", emailKey);
  if (ipKey) await resetAttempt("ip", ipKey);

  await logSystemEvent({
    level: "info",
    message: "User signed in successfully",
    source: "auth.security",
    context: {
      email: emailKey || null,
      ip: ipKey || null,
    },
    ...(input.request ? { request: input.request } : {}),
    userId: input.userId ?? null,
  });
};

export const extractClientIp = (request?: Request | null) => {
  if (!request) return null;
  const forwarded = request.headers.get("x-forwarded-for");
  if (forwarded) return forwarded.split(",")[0]?.trim() ?? null;
  return request.headers.get("x-real-ip") ?? null;
};

