import "server-only";

import crypto from "crypto";

const ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";

const base32Encode = (buffer: Buffer) => {
  let bits = 0;
  let value = 0;
  let output = "";
  for (const byte of buffer) {
    value = (value << 8) | byte;
    bits += 8;
    while (bits >= 5) {
      output += ALPHABET[(value >>> (bits - 5)) & 31];
      bits -= 5;
    }
  }
  if (bits > 0) {
    output += ALPHABET[(value << (5 - bits)) & 31];
  }
  return output;
};

const base32Decode = (input: string) => {
  const clean = input.toUpperCase().replace(/[^A-Z2-7]/g, "");
  let bits = 0;
  let value = 0;
  const output: number[] = [];
  for (const char of clean) {
    const idx = ALPHABET.indexOf(char);
    if (idx === -1) continue;
    value = (value << 5) | idx;
    bits += 5;
    if (bits >= 8) {
      output.push((value >>> (bits - 8)) & 0xff);
      bits -= 8;
    }
  }
  return Buffer.from(output);
};

export const generateTotpSecret = () => {
  const buffer = crypto.randomBytes(20);
  return base32Encode(buffer);
};

export const buildOtpAuthUrl = (params: {
  secret: string;
  label: string;
  issuer: string;
}) => {
  const label = encodeURIComponent(params.label);
  const issuer = encodeURIComponent(params.issuer);
  return `otpauth://totp/${label}?secret=${params.secret}&issuer=${issuer}`;
};

const generateTotp = (secret: string, timestamp: number, digits = 6, step = 30) => {
  const counter = Math.floor(timestamp / 1000 / step);
  const buffer = Buffer.alloc(8);
  buffer.writeBigInt64BE(BigInt(counter));
  const key = base32Decode(secret);
  const hmac = crypto.createHmac("sha1", key).update(buffer).digest();
  const offset = hmac[hmac.length - 1]! & 0x0f;
  const code =
    ((hmac[offset]! & 0x7f) << 24) |
    ((hmac[offset + 1]! & 0xff) << 16) |
    ((hmac[offset + 2]! & 0xff) << 8) |
    (hmac[offset + 3]! & 0xff);
  const otp = (code % 10 ** digits).toString().padStart(digits, "0");
  return otp;
};

export const verifyTotpToken = (
  secret: string,
  token: string,
  window = 1
) => {
  const clean = token.replace(/\s+/g, "");
  const now = Date.now();
  for (let offset = -window; offset <= window; offset += 1) {
    const ts = now + offset * 30 * 1000;
    if (generateTotp(secret, ts) === clean) {
      return true;
    }
  }
  return false;
};

export const generateRecoveryCodes = (count = 8) => {
  return Array.from({ length: count }, () => {
    const raw = crypto.randomBytes(6).toString("hex").toUpperCase();
    return `${raw.slice(0, 4)}-${raw.slice(4, 8)}-${raw.slice(8, 12)}`;
  });
};

export const normalizeRecoveryCode = (code: string) =>
  code.toUpperCase().replace(/[^A-Z0-9]/g, "");

export const hashRecoveryCode = (code: string) => {
  const normalized = normalizeRecoveryCode(code);
  return crypto.createHash("sha256").update(normalized).digest("hex");
};

import "server-only";

import crypto from "crypto";

const AUTH_KEY_ENV = "AUTH_ENCRYPTION_KEY";
const FALLBACK_KEY_ENV = "INTEGRATION_ENCRYPTION_KEY";

const getKey = () => {
  const raw = process.env[AUTH_KEY_ENV] || process.env[FALLBACK_KEY_ENV];
  if (!raw) {
    throw new Error(`${AUTH_KEY_ENV} (or ${FALLBACK_KEY_ENV}) is required for auth secrets`);
  }
  const key = Buffer.from(raw, "base64");
  if (key.length !== 32) {
    throw new Error(`${AUTH_KEY_ENV} must be a base64-encoded 32-byte key`);
  }
  return key;
};

export const encryptAuthSecret = (value: string) => {
  const key = getKey();
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv("aes-256-gcm", key, iv);
  const encrypted = Buffer.concat([cipher.update(value, "utf8"), cipher.final()]);
  const tag = cipher.getAuthTag();
  return [
    iv.toString("base64"),
    tag.toString("base64"),
    encrypted.toString("base64"),
  ].join(":");
};

export const decryptAuthSecret = (payload: string) => {
  const key = getKey();
  const [ivB64, tagB64, dataB64] = payload.split(":");
  if (!ivB64 || !tagB64 || !dataB64) {
    throw new Error("Invalid encrypted payload");
  }
  const iv = Buffer.from(ivB64, "base64");
  const tag = Buffer.from(tagB64, "base64");
  const data = Buffer.from(dataB64, "base64");
  const decipher = crypto.createDecipheriv("aes-256-gcm", key, iv);
  decipher.setAuthTag(tag);
  const decrypted = Buffer.concat([decipher.update(data), decipher.final()]);
  return decrypted.toString("utf8");
};

