            )}
          </div>

          <p className="text-xs text-gray-500">
            Select a section or block from the tree to edit its settings.
          </p>
        </div>
      </TabsContent>

      {/* ---- SEO tab ---- */}
      <TabsContent value="seo" className="flex-1 overflow-y-auto p-4 mt-0">
        <div className="space-y-4">
          <div className="rounded border border-border/40 bg-gray-800/30 px-3 py-2 text-xs text-gray-400">
            <Globe className="mr-1.5 inline size-3" />
            Search Engine Optimization
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="seo-title" className="text-xs text-gray-400">Page title</Label>
            <Input
              id="seo-title"
              value={page.seoTitle ?? ""}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => handleSeoChange("seoTitle", e.target.value)}
              placeholder={page.name}
              className="h-8 text-xs"
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="seo-desc" className="text-xs text-gray-400">Meta description</Label>
            <Input
              id="seo-desc"
              value={page.seoDescription ?? ""}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => handleSeoChange("seoDescription", e.target.value)}
              placeholder="Page description for search engines"
              className="h-8 text-xs"
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="seo-canonical" className="text-xs text-gray-400">Canonical URL</Label>
            <Input
              id="seo-canonical"
              value={page.seoCanonical ?? ""}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => handleSeoChange("seoCanonical", e.target.value)}
              placeholder="https://example.com/page"
              className="h-8 text-xs"
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="seo-og" className="text-xs text-gray-400">OG Image URL</Label>
            <Input
              id="seo-og"
              value={page.seoOgImage ?? ""}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => handleSeoChange("seoOgImage", e.target.value)}
              placeholder="https://example.com/image.png"
              className="h-8 text-xs"
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="seo-robots" className="text-xs text-gray-400">Robots meta</Label>
            <Input
              id="seo-robots"
              value={page.robotsMeta ?? "index,follow"}
              onChange={(e: React.ChangeEvent<HTMLInputElement>): void => handleSeoChange("robotsMeta", e.target.value)}
              placeholder="index,follow"
              className="h-8 text-xs"
            />
          </div>

          {/* SEO Preview */}
          <div className="space-y-1.5 rounded border border-border/30 bg-gray-800/20 p-3">
            <p className="text-[10px] font-medium uppercase tracking-wide text-gray-500">Search preview</p>
            <p className="text-sm font-medium text-blue-400 truncate">
              {page.seoTitle || page.name}
            </p>
            <p className="text-xs text-gray-400 line-clamp-2">
              {page.seoDescription || "No description set"}
            </p>
          </div>
        </div>
      </TabsContent>
    </Tabs>
  );
}

"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type { Page, Slug, CmsTheme, CmsThemeCreateInput, CmsThemeUpdateInput } from "@/features/cms/types";
import {
  createPage,
  deletePage,
  fetchPage,
  fetchPages,
  updatePage,
} from "@/features/cms/api/pages";
import {
  createBlock,
  deleteBlock,
  fetchBlock,
  fetchBlocks,
  updateBlock,
} from "@/features/cms/api/blocks";
import {
  createSlug,
  deleteSlug,
  fetchSlug,
  fetchSlugs,
  updateSlug,
} from "@/features/cms/api/slugs";
import {
  createTheme,
  deleteTheme,
  fetchTheme,
  fetchThemes,
  updateTheme,
} from "@/features/cms/api/themes";

const cmsKeys = {
  pages: ["cms-pages"] as const,
  page: (id: string) => ["cms-page", id] as const,
  blocks: ["cms-blocks"] as const,
  block: (id: string) => ["cms-block", id] as const,
  slugs: ["cms-slugs"] as const,
  slug: (id: string) => ["cms-slug", id] as const,
  themes: ["cms-themes"] as const,
  theme: (id: string) => ["cms-theme", id] as const,
};

export function useCmsPages() {
  return useQuery({
    queryKey: cmsKeys.pages,
    queryFn: fetchPages,
  });
}

export function useCmsPage(id?: string) {
  return useQuery({
    queryKey: id ? cmsKeys.page(id) : cmsKeys.page(""),
    queryFn: () => fetchPage(id as string),
    enabled: !!id,
  });
}

export function useCreatePage() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (input: { name: string; slugIds: string[] }) => {
      const { ok, payload } = await createPage(input);
      if (!ok) throw new Error("Failed to create page");
      return payload;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: cmsKeys.pages });
    },
  });
}

export function useUpdatePage() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async ({ id, input }: { id: string; input: Page }) => {
      const { ok, payload } = await updatePage(id, input);
      if (!ok) throw new Error("Failed to update page");
      return payload;
    },
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: cmsKeys.pages });
      void queryClient.invalidateQueries({ queryKey: cmsKeys.page(variables.id) });
    },
  });
}

export function useDeletePage() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (id: string) => {
      const { ok } = await deletePage(id);
      if (!ok) throw new Error("Failed to delete page");
      return id;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: cmsKeys.pages });
    },
  });
}

