      const { ok } = await deleteTheme(id);
      if (!ok) throw new Error("Failed to delete theme");
      return id;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: cmsKeys.themes });
    },
  });
}

