"use client";

import React, { useState, useEffect } from "react";
import { Button, Input, Label, SectionHeader } from "@/shared/ui";
import { useRouter, useParams } from "next/navigation";
import { useCmsTheme, useUpdateTheme } from "@/features/cms/hooks/useCmsQueries";
import type { CmsThemeColors, CmsThemeTypography, CmsThemeSpacing } from "@/features/cms/types";

export default function EditThemePage(): React.ReactNode {
  const router = useRouter();
  const params = useParams();
  const id = params.id as string;
  const themeQuery = useCmsTheme(id);
  const updateTheme = useUpdateTheme();

  const [name, setName] = useState("");
  const [colors, setColors] = useState<CmsThemeColors>({
    primary: "#3b82f6",
    secondary: "#6366f1",
    accent: "#f59e0b",
    background: "#0f172a",
    surface: "#1e293b",
    text: "#f8fafc",
    muted: "#94a3b8",
  });
  const [typography, setTypography] = useState<CmsThemeTypography>({
    headingFont: "Inter, sans-serif",
    bodyFont: "Inter, sans-serif",
    baseSize: 16,
    headingWeight: 700,
    bodyWeight: 400,
  });
  const [spacing, setSpacing] = useState<CmsThemeSpacing>({
    sectionPadding: "64px",
    containerMaxWidth: "1200px",
  });

  useEffect(() => {
    if (themeQuery.data) {
      setName(themeQuery.data.name);
      setColors(themeQuery.data.colors);
      setTypography(themeQuery.data.typography);
      setSpacing(themeQuery.data.spacing);
    }
  }, [themeQuery.data]);

  const handleSubmit = async (e: React.FormEvent): Promise<void> => {
    e.preventDefault();
    await updateTheme.mutateAsync({ id, input: { name, colors, typography, spacing } });
    router.push("/admin/cms/themes");
  };

  const updateColor = (key: keyof CmsThemeColors, value: string): void => {
    setColors((prev: CmsThemeColors) => ({ ...prev, [key]: value }));
  };

  if (themeQuery.isLoading) {
    return (
      <div className="container mx-auto py-10">
        <p className="text-gray-500">Loading theme...</p>
      </div>
    );
  }

  return (
    <div className="container mx-auto max-w-2xl py-10">
      <SectionHeader title="Edit Theme" className="mb-6" />
      <form onSubmit={(e: React.FormEvent) => { void handleSubmit(e); }} className="space-y-6">
        <div className="space-y-1.5">
          <Label>Theme Name</Label>
          <Input value={name} onChange={(e: React.ChangeEvent<HTMLInputElement>) => setName(e.target.value)} required />
        </div>

        <fieldset className="space-y-3">
          <legend className="text-sm font-medium text-gray-300">Colors</legend>
          <div className="grid grid-cols-2 gap-3">
            {(Object.keys(colors) as Array<keyof CmsThemeColors>).map((key: keyof CmsThemeColors) => (
              <div key={key} className="space-y-1">
                <Label className="text-xs capitalize">{key}</Label>
                <div className="flex items-center gap-2">
                  <input
                    type="color"
                    value={colors[key]}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateColor(key, e.target.value)}
                    className="h-8 w-10 cursor-pointer rounded border border-border/50 bg-transparent p-0.5"
                  />
                  <Input
                    value={colors[key]}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateColor(key, e.target.value)}
                    className="flex-1 text-xs font-mono"
                    maxLength={7}
                  />
                </div>
              </div>
            ))}
          </div>
        </fieldset>

        <fieldset className="space-y-3">
          <legend className="text-sm font-medium text-gray-300">Typography</legend>
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <Label className="text-xs">Heading Font</Label>
              <Input
                value={typography.headingFont}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTypography((p: CmsThemeTypography) => ({ ...p, headingFont: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Body Font</Label>
              <Input
                value={typography.bodyFont}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTypography((p: CmsThemeTypography) => ({ ...p, bodyFont: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Base Size (px)</Label>
              <Input
                type="number"
                value={typography.baseSize}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTypography((p: CmsThemeTypography) => ({ ...p, baseSize: Number(e.target.value) }))}
              />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Heading Weight</Label>
              <Input
                type="number"
                value={typography.headingWeight}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTypography((p: CmsThemeTypography) => ({ ...p, headingWeight: Number(e.target.value) }))}
                min={100}
                max={900}
                step={100}
              />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Body Weight</Label>
              <Input
                type="number"
                value={typography.bodyWeight}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setTypography((p: CmsThemeTypography) => ({ ...p, bodyWeight: Number(e.target.value) }))}
                min={100}
                max={900}
                step={100}
              />
            </div>
          </div>
        </fieldset>

        <fieldset className="space-y-3">
          <legend className="text-sm font-medium text-gray-300">Spacing</legend>
          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1">
              <Label className="text-xs">Section Padding</Label>
              <Input
                value={spacing.sectionPadding}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setSpacing((p: CmsThemeSpacing) => ({ ...p, sectionPadding: e.target.value }))}
              />
            </div>
            <div className="space-y-1">
              <Label className="text-xs">Container Max Width</Label>
              <Input
                value={spacing.containerMaxWidth}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setSpacing((p: CmsThemeSpacing) => ({ ...p, containerMaxWidth: e.target.value }))}
              />
            </div>
          </div>
        </fieldset>

        <Button type="submit" disabled={updateTheme.isPending || !name.trim()}>
          {updateTheme.isPending ? "Saving..." : "Save Theme"}
        </Button>
      </form>
    </div>
  );
}

import "server-only";

import { randomUUID } from "crypto";
import { getMongoDb } from "@/shared/lib/db/mongo-client";
import type { Filter } from "mongodb";
import { ObjectId } from "mongodb";
import type { CmsRepository, PageUpdateData } from "../../types/services/cms-repository";
import type { Block, Page, Slug, PageComponent, CmsTheme, CmsThemeCreateInput, CmsThemeUpdateInput } from "../../types";

const blocksCollection = "cms_blocks";
const pagesCollection = "cms_pages";
const slugsCollection = "cms_slugs";
const themesCollection = "cms_themes";

interface BlockDocument {
  id: string;
  name: string;
  content: unknown;
  createdAt: Date;
  updatedAt: Date;
}

interface PageDocument {
  id: string;
  name: string;
  status: string;
  publishedAt?: Date | null;
  seoTitle?: string | null;
  seoDescription?: string | null;
  seoOgImage?: string | null;
  seoCanonical?: string | null;
  robotsMeta?: string | null;
  themeId?: string | null;
  components: PageComponent[];
  createdAt: Date;
  updatedAt: Date;
}

interface ThemeDocument {
  id: string;
  name: string;
  colors: Record<string, string>;
  typography: Record<string, unknown>;
  spacing: Record<string, string>;
  customCss?: string | null;
  createdAt: Date;
  updatedAt: Date;
}

interface SlugDocument {
  id: string;
  slug: string;
  isDefault: boolean;
  createdAt: Date;
  updatedAt: Date;
}

interface PageSlugDocument {
  pageId: string;
  slugId: string;
  assignedAt: Date;
}

// Helper to remove undefined keys for exactOptionalPropertyTypes compliance
function removeUndefined<T extends object>(obj: T): T {
  const newObj = { ...obj };
  Object.keys(newObj).forEach((key) => {
    if (newObj[key as keyof T] === undefined) {
      delete newObj[key as keyof T];
    }
  });
  return newObj;
}

function buildIdFilter<T extends { id: string }>(id: string): Filter<T> {
  const orFilters: Filter<T>[] = [{ id } as Filter<T>];

  if (ObjectId.isValid(id)) {
    orFilters.push({ _id: new ObjectId(id) } as Filter<T>);
  }

  return { $or: orFilters } as Filter<T>;
}

export const mongoCmsRepository: CmsRepository = {
  // Blocks
  async getBlocks(): Promise<Block[]> {
    const db = await getMongoDb();
    const docs = await db.collection<BlockDocument>(blocksCollection).find().sort({ createdAt: -1 }).toArray();
    return docs.map(doc => ({
      id: doc.id,
      name: doc.name,
      content: doc.content,
    })) as Block[];
  },

  async getBlockById(id: string): Promise<Block | null> {
    const db = await getMongoDb();
    const doc = await db.collection<BlockDocument>(blocksCollection).findOne(buildIdFilter<BlockDocument>(id));
    if (!doc) return null;
    return {
      id: doc.id,
      name: doc.name,
      content: doc.content,
    } as Block;
  },

  async getBlockByName(name: string): Promise<Block | null> {
    const db = await getMongoDb();
    const doc = await db.collection<BlockDocument>(blocksCollection).findOne({ name });
    if (!doc) return null;
    return {
      id: doc.id,
      name: doc.name,
      content: doc.content,
    } as Block;
  },

  async createBlock(data: { name: string; content: unknown }): Promise<Block> {
    const db = await getMongoDb();
    const id = randomUUID();
    const doc: BlockDocument = {
      id,
      name: data.name,
      content: data.content,
      createdAt: new Date(),
      updatedAt: new Date(),
    };
    await db.collection<BlockDocument>(blocksCollection).insertOne(doc);
    return { id, name: doc.name, content: doc.content } as Block;
  },

  async updateBlock(id: string, data: { name?: string | undefined; content?: unknown }): Promise<Block | null> {
    const db = await getMongoDb();
    const update = removeUndefined({
      name: data.name,
      content: data.content,
      updatedAt: new Date(),
    }) as Partial<BlockDocument>;

    const result = await db.collection<BlockDocument>(blocksCollection).findOneAndUpdate(
      buildIdFilter<BlockDocument>(id),
      { $set: update },
      { returnDocument: "after" }
    );
    if (!result) return null;
    const doc = result;
    return {
      id: doc.id,
      name: doc.name,
