                {debugWarehouses.inventoriesRaw ? (
                  <div className="mt-1 space-y-1 text-[11px] text-gray-400">
                    <div>Method: {debugWarehouses.inventoriesRaw.method}</div>
                    <div>Status: {debugWarehouses.inventoriesRaw.statusCode}</div>
