    void loadActiveTemplatePreference();
  }, []);

  useEffect(() => {
    const loadExportActiveTemplate = async () => {
      try {
        const res = await fetch("/api/integrations/exports/base/active-template");
        const payload = (await res.json()) as { templateId?: string | null };
        if (!res.ok) return;
