            templateId: exportActiveTemplateId || null,
          }),
        }),
        fetch("/api/integrations/exports/base/default-inventory", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            inventoryId: exportInventoryId || null,
          }),
        }),
        fetch("/api/integrations/exports/base/default-connection", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            connectionId: selectedBaseConnectionId || null,
          }),
        }),
        fetch("/api/integrations/exports/base/stock-fallback", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            enabled: exportStockFallbackEnabled,
          }),
        }),
        fetch("/api/integrations/exports/base/image-retry-presets", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            presets: imageRetryPresets,
          }),
        }),
      ];
      if (exportInventoryId) {
        requests.push(
          fetch("/api/integrations/imports/base/export-warehouse", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              warehouseId: exportWarehouseId || null,
              inventoryId: exportInventoryId,
            }),
          })
        );
      }
      const responses = await Promise.all(requests);
      const failed = responses.find((res) => !res.ok);
      if (failed) {
        toast("Failed to save export settings.", { variant: "error" });
        return;
      }
      toast("Export settings saved.", { variant: "success" });
    } catch (_error) {
      toast("Failed to save export settings.", { variant: "error" });
    } finally {
      setSavingExportSettings(false);
    }
  };

  const handleImport = async () => {
    if (!inventoryId) {
      toast("Select an inventory before importing.", { variant: "error" });
      return;
    }
    if (!catalogId) {
      toast("Select a catalog before importing.", { variant: "error" });
      return;
    }
    if (importList.length > 0 && selectedImportIds.size === 0) {
      toast("Select at least one product to import.", { variant: "error" });
      return;
    }
    const parsedLimit = limit === "all" ? undefined : Number(limit);
    const selectedIds =
      importList.length > 0 ? Array.from(selectedImportIds) : [];
    setImporting(true);
    try {
      const res = await fetch("/api/integrations/imports/base", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: "import",
          inventoryId,
          catalogId,
          templateId: importTemplateId || undefined,
          limit: parsedLimit,
          imageMode,
          uniqueOnly,
          allowDuplicateSku,
          selectedIds: selectedIds.length > 0 ? selectedIds : undefined,
        }),
      });
      const payload = (await res.json()) as ImportResponse & {
        error?: string;
        skipped?: number;
      };
      if (!res.ok) {
        toast(payload.error || "Import failed.", { variant: "error" });
        return;
      }
      setLastResult(payload);
      const skippedMsg = payload.skipped ? `, ${payload.skipped} skipped (duplicate SKU)` : "";
      toast(`Imported ${payload.imported} product(s)${skippedMsg}.`, {
        variant: "success",
      });
    } catch (_error) {
      toast("Import failed.", { variant: "error" });
    } finally {
      setImporting(false);
    }
  };

  const handleLoadImportList = async () => {
    if (!inventoryId) {
      toast("Select an inventory before loading the list.", {
        variant: "error",
      });
      return;
    }
    const parsedLimit = limit === "all" ? undefined : Number(limit);
    setLoadingImportList(true);
    try {
      const res = await fetch("/api/integrations/imports/base", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          action: "list",
          inventoryId,
          limit: parsedLimit,
          uniqueOnly,
        }),
      });
      const payload = (await res.json()) as {
        products?: ImportListItem[];
        total?: number;
        filtered?: number;
        available?: number;
        existing?: number;
        skuDuplicates?: number;
        error?: string;
      };
      if (!res.ok) {
        toast(payload.error || "Failed to load import list.", {
          variant: "error",
        });
        return;
      }
      setImportList(payload.products ?? []);
      setSelectedImportIds(
        new Set(
          (payload.products ?? [])
            .map((item) => item.baseProductId)
            .filter((id): id is string => Boolean(id))
        )
      );
      setImportListStats(
        payload.total !== undefined
          ? {
              total: payload.total ?? 0,
              filtered: payload.filtered ?? 0,
              available: payload.available ?? payload.filtered ?? 0,
              existing: payload.existing ?? 0,
              skuDuplicates: payload.skuDuplicates ?? 0,
            }
          : null
      );
    } catch (_error) {
      toast("Failed to load import list.", { variant: "error" });
    } finally {
      setLoadingImportList(false);
    }
  };

  const normalizedImportQuery = importSearch.trim().toLowerCase();
  const filteredImportList = normalizedImportQuery
    ? importList.filter((item) => {
        const fields = [
          item.baseProductId,
          item.name,
          item.sku ?? "",
          item.description ?? "",
        ];
        return fields.some((field) =>
          field.toLowerCase().includes(normalizedImportQuery)
        );
      })
    : importList;
  const selectedImportCount = selectedImportIds.size;
  const allVisibleSelected =
    filteredImportList.length > 0 &&
    filteredImportList.every((item) => selectedImportIds.has(item.baseProductId));
  const isSomeVisibleSelected =
    filteredImportList.some((item) => selectedImportIds.has(item.baseProductId)) &&
    !allVisibleSelected;

  if (checkingIntegration) {
    return (
      <SectionPanel className="flex h-64 items-center justify-center p-6">
        <p className="text-muted-foreground">Checking integration status...</p>
      </SectionPanel>
    );
  }

  if (!isBaseConnected) {
    return (
      <SectionPanel className="p-6">
        <SectionHeader title="Product Import/Export" className="mb-4" />
        <div className="rounded-md border border-yellow-900/50 bg-yellow-900/20 p-4">
          <h2 className="text-lg font-semibold text-yellow-200">
            Base.com Integration Required
          </h2>
          <p className="mt-2 text-sm text-yellow-100/80">
            To import products, you must first connect the Base.com integration.
          </p>
          <div className="mt-4">
            <Link href="/admin/integrations">
              <Button variant="secondary">Go to Integrations</Button>
            </Link>
          </div>
        </div>
      </SectionPanel>
    );
  }

  return (
    <SectionPanel className="p-6">
      <SectionHeader
        title="Product Import/Export"
        description="Import products from Base.com or export your products to Base.com using templates for field mapping."
        actions={(
          <Link
            href="/admin/import"
            className="text-sm font-semibold text-blue-300 hover:text-blue-200"
          >
            CSV Import
          </Link>
        )}
        className="mb-6"
      />

      <Tabs defaultValue="imports">
        <TabsList className="border border-border bg-card/70">
          <TabsTrigger value="imports">Imports</TabsTrigger>
          <TabsTrigger value="exports">Exports</TabsTrigger>
          <TabsTrigger value="templates">Templates</TabsTrigger>
        </TabsList>

        <TabsContent value="imports" className="mt-6 space-y-6">
          <ImportTab
            inventories={inventories}
            loadingInventories={loadingInventories}
            inventoryId={inventoryId}
            setInventoryId={setInventoryId}
            handleLoadInventories={handleLoadInventories}
            handleClearInventory={handleClearInventory}
            limit={limit}
            setLimit={setLimit}
            catalogs={catalogs}
            loadingCatalogs={loadingCatalogs}
            catalogId={catalogId}
            setCatalogId={setCatalogId}
            importTemplateId={importTemplateId}
            setImportTemplateId={setImportTemplateId}
            importTemplates={importTemplates}
            loadingImportTemplates={loadingImportTemplates}
            imageMode={imageMode}
            setImageMode={setImageMode}
            allowDuplicateSku={allowDuplicateSku}
            setAllowDuplicateSku={setAllowDuplicateSku}
            importing={importing}
            handleImport={handleImport}
            importSearch={importSearch}
            setImportSearch={setImportSearch}
            uniqueOnly={uniqueOnly}
            setUniqueOnly={setUniqueOnly}
            handleLoadImportList={handleLoadImportList}
            loadingImportList={loadingImportList}
            importListStats={importListStats}
            importList={importList}
            filteredImportList={filteredImportList}
            selectedImportIds={selectedImportIds}
            setSelectedImportIds={setSelectedImportIds}
            selectedImportCount={selectedImportCount}
            allVisibleSelected={allVisibleSelected}
            isSomeVisibleSelected={isSomeVisibleSelected}
            lastResult={lastResult}
          />
        </TabsContent>

        <TabsContent value="exports" className="mt-6 space-y-6">
          <ExportTab
            baseConnections={baseConnections}
            selectedBaseConnectionId={selectedBaseConnectionId}
            setSelectedBaseConnectionId={setSelectedBaseConnectionId}
            inventories={inventories}
            exportInventoryId={exportInventoryId}
            setExportInventoryId={setExportInventoryId}
            exportActiveTemplateId={exportActiveTemplateId}
            setExportActiveTemplateId={setExportActiveTemplateId}
            exportTemplates={exportTemplates}
            loadingExportTemplates={loadingExportTemplates}
            applyTemplate={applyTemplate}
            exportWarehouseId={exportWarehouseId}
            setExportWarehouseId={setExportWarehouseId}
            warehouseOptions={warehouseOptions}
            showAllWarehouses={showAllWarehouses}
            setShowAllWarehouses={setShowAllWarehouses}
            inventoryWarehouseIds={inventoryWarehouseIds}
            exportStockFallbackEnabled={exportStockFallbackEnabled}
            setExportStockFallbackEnabled={setExportStockFallbackEnabled}
            exportStockFallbackLoaded={exportStockFallbackLoaded}
            allWarehouses={allWarehouses}
            warehouses={warehouses}
            imageRetryPresets={imageRetryPresets}
            setImageRetryPresets={setImageRetryPresets}
            imageRetryPresetsLoaded={imageRetryPresetsLoaded}
            handleLoadInventories={handleLoadInventories}
            loadingInventories={loadingInventories}
            handleLoadWarehouses={handleLoadWarehouses}
            loadingWarehouses={loadingWarehouses}
            handleDebugWarehouses={handleDebugWarehouses}
            loadingDebugWarehouses={loadingDebugWarehouses}
            includeAllWarehouses={includeAllWarehouses}
            setIncludeAllWarehouses={setIncludeAllWarehouses}
            handleSaveExportSettings={handleSaveExportSettings}
            savingExportSettings={savingExportSettings}
            debugWarehouses={debugWarehouses}
            setDebugWarehouses={setDebugWarehouses}
          />
        </TabsContent>

        <TabsContent value="templates" className="mt-6 space-y-6">
          <div className="rounded-md border border-border bg-gray-900 p-4">
            <div className="flex flex-wrap items-start justify-between gap-4">
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label className="text-xs text-gray-400">Template type</Label>
                  <Tabs
                    value={templateScope}
                    onValueChange={(value) =>
                      setTemplateScope(value === "export" ? "export" : "import")
                    }
                  >
                    <TabsList className="border border-border bg-card/60">
                      <TabsTrigger value="import">Import templates</TabsTrigger>
                      <TabsTrigger value="export">Export templates</TabsTrigger>
                    </TabsList>
                  </Tabs>
                </div>

                {isImportTemplateScope ? (
                  <div className="grid w-fit gap-2">
                    <div className="col-span-2">
                      <Label className="text-xs text-gray-400">
                        Sample product ID
                      </Label>
                      <Input
                        className="mt-2 w-full"
                        value={parameterProductId}
                        onChange={(event) =>
                          setParameterProductId(event.target.value)
                        }
                        placeholder="Base product ID to fetch parameters"
                      />
                    </div>
                    <div className="flex flex-col items-center">
                      <Button
                        type="button"
                        onClick={() => { void handleLoadParameters(); }}
                        disabled={loadingParameters}
                      >
                        {loadingParameters
                          ? "Loading..."
                          : parameterKeys.length > 0
                            ? "Unload parameters"
                            : "Load parameters"}
                      </Button>
                      <div className="mt-2 flex items-center gap-1 text-xs text-gray-400">
                        <span
                          className={`h-2 w-2 rounded-full ${
                            parameterKeys.length > 0
                              ? "bg-emerald-400"
                              : "bg-gray-600"
                          }`}
                        />
                        <span>
                          {parameterKeys.length > 0 ? "Loaded" : "Not loaded"}
                        </span>
                      </div>
                    </div>
                    <div className="flex flex-col items-center">
                      <Button
                        type="button"
                        variant="secondary"
                        onClick={() => { void handleUseExampleProduct(); }}
                        disabled={loadingParameters}
                      >
                        Use example
                      </Button>
                      <div className="mt-2 flex items-center gap-1 text-xs text-gray-400 opacity-0">
                        <span className="h-2 w-2 rounded-full bg-gray-600" />
                        <span>Not loaded</span>
                      </div>
                    </div>
                  </div>
                ) : (
                  <div className="rounded-md border border-blue-900/50 bg-blue-900/20 p-3 text-xs text-blue-200">
                    <p>
                      Export templates use Base.com API documentation for
                      parameter keys and descriptions.
                    </p>
                    <p className="mt-1 text-blue-300/70">
                      Use keys like prices.0, stock.&lt;warehouse_id&gt;, or
                      image slots.
                    </p>
                  </div>
                )}
              </div>
                              <div className="flex items-center gap-2">
                                <Button
                                  variant="secondary"
                                  onClick={() => { void handleNewTemplate(); }}
                                  type="button"
                                >
                                  New template
                                </Button>
                                <Button
                                  onClick={() => { void handleSaveTemplate(); }}
                                  disabled={savingTemplate}
                                >
                                  {savingTemplate ? "Saving..." : "Save template"}
                                </Button>
                                <Button
                                  variant="destructive"
                                  onClick={() => { void handleDeleteTemplate(); }}
                                  disabled={!currentActiveTemplateId || deletingTemplate}
                                >                  {deletingTemplate ? "Deleting..." : "Delete"}
                </Button>
              </div>
            </div>

            <div className="mt-4 grid gap-4 md:grid-cols-[220px_1fr]">
              <div className="space-y-2">
                <Label className="text-xs text-gray-400">
                  {isImportTemplateScope ? "Import templates" : "Export templates"}
                </Label>
                <div className="max-h-64 overflow-auto rounded-md border border-border bg-card/60 p-2">
                  {currentTemplates.length === 0 ? (
                    <p className="text-xs text-gray-500">
                      {currentLoadingTemplates
                        ? "Loading templates..."
                        : "No templates yet."}
                    </p>
                  ) : (
                    currentTemplates
                      .slice()
                      .sort((a, b) => a.name.localeCompare(b.name))
                      .map((template) => (
                        <Button
                          key={template.id}
                          type="button"
                                                      className={`flex w-full items-center justify-between rounded-md px-2 py-1 text-left text-xs ${
                                                        currentActiveTemplateId === template.id
                                                          ? "bg-emerald-500/20 text-emerald-100"
                                                          : "text-gray-300 hover:bg-muted/50/60"
                                                      }`}
                                                      onClick={() => { void handleSelectTemplate(template.id); }}
                                                    >                          <span>{template.name}</span>
                        </Button>
                      ))
                  )}
                </div>
              </div>

              <div className="space-y-4">
                <div className="grid gap-3 md:grid-cols-2">
                  <div>
                    <Label className="text-xs text-gray-400">
                      Template name
                    </Label>
                    <Input
                      className="mt-2"
                      value={currentTemplateName}
                      onChange={(event) => {
                        const value = event.target.value;
                        if (isImportTemplateScope) {
                          setImportTemplateName(value);
                        } else {
                          setExportTemplateName(value);
                        }
                      }}
                      placeholder="Base default mapping"
                    />
                  </div>
                  <div>
                    <Label className="text-xs text-gray-400">
                      Description
                    </Label>
                    <Input
                      className="mt-2"
                      value={currentTemplateDescription}
                      onChange={(event) => {
                        const value = event.target.value;
                        if (isImportTemplateScope) {
                          setImportTemplateDescription(value);
                        } else {
                          setExportTemplateDescription(value);
                        }
                      }}
                      placeholder="Optional"
                    />
                  </div>
                </div>

                {!isImportTemplateScope && (
                  <div className="flex items-center gap-2">
                    <Checkbox
                      id="exportImagesAsBase64"
                      checked={exportImagesAsBase64} onCheckedChange={(checked) => setExportImagesAsBase64(Boolean(checked))}
                      className="h-4 w-4 rounded border-border bg-gray-900 text-emerald-500 focus:ring-2 focus:ring-emerald-500 focus:ring-offset-0"
                    />
                    <Label
                      htmlFor="exportImagesAsBase64"
                      className="text-sm text-gray-300 cursor-pointer"
                    >
                      Export images as base64 data blobs
                    </Label>
                  </div>
                )}

                <div>
                  <Label className="text-xs text-gray-400">
                    Parameter mappings
                  </Label>
                  {hasStockMappingMismatch ? (
                    <div className="mt-2 rounded-md border border-amber-500/40 bg-amber-500/10 p-3 text-xs text-amber-200">
                      <p>
                        Some stock keys do not match the selected inventory
                        warehouses. Base.com will reject stock for these keys.
                      </p>
                      <p className="mt-1 text-amber-300/80">
                        Invalid stock keys: {invalidStockMappingLabels.join(", ")}
                      </p>
                      {stockMappingSuggestions.length > 0 ? (
                        <p className="mt-1 text-amber-300/80">
                          Suggested keys: {stockMappingSuggestions.join(", ")}
                        </p>
                      ) : null}
                    </div>
                  ) : null}
                  <div className="mt-2 space-y-2">
                    {currentTemplateMappings.map((mapping, index) => (
                      <div
                        key={index}
                        onDragOver={(event) => handleMappingDragOver(event, index)}
                        onDragLeave={handleMappingDragLeave}
                        onDrop={(event) => handleMappingDrop(event, index)}
                        className={`grid gap-2 rounded-md transition md:grid-cols-[auto_1fr_1fr_auto] ${
                          dragOverMappingIndex === index
                            ? "bg-emerald-500/10 ring-1 ring-emerald-500/60"
                            : ""
                        }`}
                      >
                        <div className="flex items-center">
                          <Button
                            type="button"
                            variant="ghost"
                            size="icon"
                            draggable
                            onDragStart={(event) =>
                              handleMappingDragStart(event, index)
                            }
                            onDragEnd={handleMappingDragEnd}
                            aria-label="Drag mapping to reorder"
                            className={`text-gray-400 hover:text-white ${
                              draggedMappingIndex === index
                                ? "cursor-grabbing"
                                : "cursor-grab"
                            }`}
                          >
                            <GripVertical className="size-4" />
                          </Button>
                        </div>
                        <div className="relative">
                          <Input
                            value={mapping.sourceKey}
                            onChange={(event) =>
                              updateMapping(index, {
                                sourceKey: event.target.value,
                              })
                            }
                            onFocus={() => setOpenKeyIndex(index)}
                            onBlur={() => {
                              window.setTimeout(() => {
                                setOpenKeyIndex((current) =>
                                  current === index ? null : current
                                );
                              }, 120);
                            }}
                            placeholder={
                              isImportTemplateScope
                                ? "Base parameter key (e.g. material)"
                                : "Export parameter key (e.g. prices.0)"
                            }
                          />
                          {openKeyIndex === index && (
                            <div className="absolute z-20 mt-1 max-h-56 w-full overflow-auto rounded-md border border-border bg-card shadow-lg">
                              {filterKeys(mapping.sourceKey).map((key) => (
                                  <Button
                                    key={key}
                                    type="button"
                                    className="block w-full px-3 py-2 text-left text-xs text-gray-200 hover:bg-muted/50"
                                    onMouseDown={(event) => {
                                      event.preventDefault();
                                      updateMapping(index, { sourceKey: key });
                                      setOpenKeyIndex(null);
                                    }}
                                  >
                                    {key}
                                  </Button>
                                ))}
                              {filterKeys(mapping.sourceKey).length === 0 ? (
                                <div className="px-3 py-2 text-xs text-gray-500">
                                  No matches
                                </div>
                              ) : null}
                            </div>
                          )}
                        </div>
                        <div className="rounded-md border border-border bg-gray-900 px-3 py-2 text-xs text-gray-500">
                          {mapping.sourceKey &&
                          currentParameterValues[mapping.sourceKey]
                            ? currentParameterValues[mapping.sourceKey]
                            : "—"}
                        </div>
                        <div className="flex items-center gap-2">
                          <select
                            className="flex-1 rounded-md border border-border bg-gray-900 px-3 py-2 text-sm text-white"
                            value={mapping.targetField}
                            onChange={(event) =>
                              updateMapping(index, {
                                targetField: event.target.value,
                              })
                            }
                          >
                            <option value="">Select product field</option>
                            {PRODUCT_FIELDS.map((field) => (
                              <option key={field.value} value={field.value}>
                                {field.label}
                              </option>
                            ))}
                          </select>
                          <Button
                            type="button"
                            variant="ghost"
                            size="icon"
                            onClick={() => removeMappingRow(index)}
                            aria-label="Remove mapping"
                            className="text-gray-400 hover:text-white"
                          >
                            <Trash2 className="size-4" />
                          </Button>
                        </div>
                      </div>
                    ))}
                  </div>
                  <div className="mt-3">
                    <Button
                      type="button"
                      variant="secondary"
                      onClick={addMappingRow}
                    >
                      Add mapping
                    </Button>
                  </div>
                  {isImportTemplateScope ? (
                    <p className="mt-3 text-xs text-gray-500">
                      Source keys can be direct Base fields or parameter names.
                      Use dotted paths for nested fields (e.g. parameters.size).
                    </p>
                  ) : (
                    <p className="mt-3 text-xs text-gray-500">
                      Source keys must match Base.com export fields. Use dotted
                      paths for nested fields (e.g. prices.0).
                    </p>
                  )}
                </div>
              </div>
            </div>
          </div>
        </TabsContent>
      </Tabs>
    </SectionPanel>
  );
}

import type { ImageRetryPreset } from "@/features/data-import-export/types/imports";

const clonePreset = (preset: ImageRetryPreset): ImageRetryPreset => ({
  ...preset,
  transform: { ...preset.transform },
});

export const DEFAULT_IMAGE_RETRY_PRESETS: ImageRetryPreset[] = [
  {
    id: "lower-dimension",
    label: "Lower max dimension (1200px)",
    description: "Resize down to 1200px and convert to JPEG.",
    imageBase64Mode: "base-only" as const,
    transform: { forceJpeg: true, maxDimension: 1200, jpegQuality: 85 },
  },
  {
    id: "lower-quality",
    label: "Lower JPEG quality (70)",
    description: "Compress harder without resizing.",
    imageBase64Mode: "base-only" as const,
    transform: { forceJpeg: true, jpegQuality: 70 },
  },
  {
    id: "lower-both",
    label: "Lower dimension + quality (1200px, 70)",
    description: "Resize and compress for maximum compatibility.",
    imageBase64Mode: "base-only" as const,
    transform: { forceJpeg: true, maxDimension: 1200, jpegQuality: 70 },
  },
].map(clonePreset);

export const getDefaultImageRetryPresets = () =>
  DEFAULT_IMAGE_RETRY_PRESETS.map(clonePreset);

export const buildImageRetryPresetLabel = (preset: ImageRetryPreset): string => {
  const maxDimension = preset.transform.maxDimension;
  const jpegQuality = preset.transform.jpegQuality;
  switch (preset.id) {
    case "lower-dimension":
      return `Lower max dimension (${maxDimension ?? "auto"}px)`;
    case "lower-quality":
      return `Lower JPEG quality (${jpegQuality ?? "auto"})`;
    case "lower-both":
      return `Lower dimension + quality (${maxDimension ?? "auto"}px, ${
        jpegQuality ?? "auto"
      })`;
    default:
      return preset.label?.trim() || "Image retry preset";
  }
};

export const buildImageRetryPresetDescription = (
  preset: ImageRetryPreset
): string => {
  const maxDimension = preset.transform.maxDimension;
  const jpegQuality = preset.transform.jpegQuality;
  switch (preset.id) {
    case "lower-dimension":
      return `Resize down to ${
        maxDimension ? `${maxDimension}px` : "your target size"
      } and convert to JPEG.`;
    case "lower-quality":
      return `Compress to quality ${jpegQuality ?? "your"} without resizing.`;
    case "lower-both":
      return `Resize to ${
        maxDimension ? `${maxDimension}px` : "your target size"
      } and compress to ${jpegQuality ?? "your"} for maximum compatibility.`;
    default:
      return preset.description?.trim() || "Adjust image export settings.";
  }
};

export const withImageRetryPresetLabels = (
  preset: ImageRetryPreset
): ImageRetryPreset => ({
  ...preset,
  label: buildImageRetryPresetLabel(preset),
  description: buildImageRetryPresetDescription(preset),
});

export const normalizeImageRetryPresets = (
  value: unknown
): ImageRetryPreset[] => {
  if (!Array.isArray(value) || value.length === 0) {
    return getDefaultImageRetryPresets();
  }
  const defaults = getDefaultImageRetryPresets();
  const byId = new Map(defaults.map((preset) => [preset.id, preset]));
  const normalized = value
    .filter((entry) => entry && typeof entry === "object")
    .map((entry) => {
      const record = entry as Partial<ImageRetryPreset> & {
        transform?: Partial<ImageRetryPreset["transform"]>;
      };
      const id = typeof record.id === "string" ? record.id : null;
      if (!id) return null;
      const fallback = byId.get(id);
      const transform = {
        ...(fallback?.transform ?? {}),
        ...(record.transform ?? {}),
      };
      const preset: ImageRetryPreset = {
        id,
        label:
          typeof record.label === "string" && record.label.trim()
            ? record.label
            : fallback?.label ?? "Image retry preset",
        description:
          typeof record.description === "string" && record.description.trim()
            ? record.description
            : fallback?.description ?? "Adjust image export settings.",
        imageBase64Mode:
          record.imageBase64Mode ?? fallback?.imageBase64Mode ?? "base-only",
        transform,
      };
      return withImageRetryPresetLabels(preset);
    })
    .filter((entry): entry is ImageRetryPreset => Boolean(entry));

  return normalized.length > 0 ? normalized : defaults;
};

import type {
  DatabaseBackupResponse,
  DatabaseInfo,
  DatabasePreviewGroup,
  DatabasePreviewMode,
  DatabasePreviewPayload,
  DatabasePreviewRow,
  DatabasePreviewTable,
  DatabaseRestoreResponse,
  DatabaseType,
} from "../types";

const safeJson = async <T>(res: Response): Promise<T> => {
  try {
    return (await res.json()) as T;
  } catch {
    return {} as T;
  }
};

const normalizeGroups = (
  groups?: Record<string, string[]> | DatabasePreviewGroup[]
): DatabasePreviewGroup[] => {
  if (!groups) return [];
  if (Array.isArray(groups)) return groups;
  return Object.entries(groups).map(([type, objects]) => ({
    type,
    objects,
  }));
};

type PreviewApiResponse = DatabasePreviewPayload & {
  stats?: {
    groups?: Record<string, string[]>;
    tables?: DatabasePreviewTable[];
  };
  data?: DatabasePreviewRow[];
};

export const fetchDatabaseBackups = async (
  dbType: DatabaseType
): Promise<DatabaseInfo[]> => {
  const res = await fetch(`/api/databases/backups?type=${dbType}`);
  if (!res.ok) {
    throw new Error("Failed to fetch backups");
  }
  return res.json() as Promise<DatabaseInfo[]>;
};

export const createDatabaseBackup = async (dbType: DatabaseType) => {
  const res = await fetch(`/api/databases/backup?type=${dbType}`, {
    method: "POST",
  });
  const payload = await safeJson<DatabaseBackupResponse>(res);
  return { ok: res.ok, payload };
};

export const restoreDatabaseBackup = async (
  dbType: DatabaseType,
  input: { backupName: string; truncateBeforeRestore: boolean }
) => {
  const res = await fetch(`/api/databases/restore?type=${dbType}`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      backupName: input.backupName,
      truncateBeforeRestore: input.truncateBeforeRestore,
    }),
  });
  const payload = await safeJson<DatabaseRestoreResponse>(res);
  return { ok: res.ok, payload };
};

export const uploadDatabaseBackup = async (
  dbType: DatabaseType,
  file: File
) => {
  const formData = new FormData();
  formData.append("file", file);
  formData.append("type", dbType);
  const res = await fetch("/api/databases/upload", {
    method: "POST",
    body: formData,
  });
  const payload = await safeJson<DatabaseBackupResponse>(res);
  return { ok: res.ok, payload };
};

export const deleteDatabaseBackup = async (
  dbType: DatabaseType,
  backupName: string
) => {
  const res = await fetch("/api/databases/delete", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ backupName, type: dbType }),
  });
  const payload = await safeJson<DatabaseBackupResponse>(res);
  return { ok: res.ok, payload };
};

export const fetchDatabasePreview = async (input: {
  backupName?: string | undefined;
  mode?: DatabasePreviewMode | undefined;
  page?: number | undefined;
  pageSize?: number | undefined;
}) => {
  const res = await fetch("/api/databases/preview", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      backupName: input.backupName,
      mode: input.mode,
      page: input.page,
      pageSize: input.pageSize,
    }),
  });
  const raw = await safeJson<PreviewApiResponse>(res);
  const groups = normalizeGroups(raw.groups ?? raw.stats?.groups);
  const tables = raw.tables ?? raw.stats?.tables ?? [];
  const tableRows = raw.tableRows ?? raw.data ?? [];
  const finalPage = raw.page ?? input.page;
  const finalPageSize = raw.pageSize ?? input.pageSize;
  const payload: DatabasePreviewPayload = {
    ...raw,
    groups,
    tables,
    tableRows,
    ...(finalPage !== undefined ? { page: finalPage } : {}),
    ...(finalPageSize !== undefined ? { pageSize: finalPageSize } : {}),
  };
  return { ok: res.ok, payload };
};

"use client";

import { Button } from "@/shared/ui";
import type { ColumnDef, Column } from "@tanstack/react-table";

import type { DatabaseInfo } from "../types";

// ✅ Use TanStack's Column type, and accept that the handler may be undefined.
const renderSortableHeader = <TData, TValue>(
  label: string,
  column: Column<TData, TValue>
) => {
  const direction = column.getIsSorted(); // false | "asc" | "desc"
  const handler = column.getToggleSortingHandler(); // ((event) => void) | undefined

  return (
    <Button
      type="button"
      onClick={handler ?? undefined}
      // optional: prevent "clickable" affordance if it can't sort
      disabled={!handler}
      className="inline-flex items-center gap-1 text-left text-sm font-medium text-foreground disabled:cursor-not-allowed disabled:opacity-60"
    >
      {label}
      <span className="text-xs text-muted-foreground">
        {direction === "asc" ? "▲" : direction === "desc" ? "▼" : "↕"}
      </span>
    </Button>
  );
};

export const getDatabaseColumns = (options?: {
  onPreview?: (backupName: string) => void;
  onRestoreRequest?: (backup: DatabaseInfo) => void;
  onDeleteRequest?: (backupName: string) => void;
}): ColumnDef<DatabaseInfo>[] => [
  {
    accessorKey: "name",
    header: ({ column }) => renderSortableHeader("Name", column),
  },
  {
    accessorKey: "size",
    header: ({ column }) => renderSortableHeader("Size", column),
    sortingFn: (rowA, rowB, columnId) => {
      const toNumber = (value: string) =>
        Number.parseFloat(value.replace(/[^0-9.]/g, "")) || 0;
      return (
        toNumber(rowA.getValue(columnId)) - toNumber(rowB.getValue(columnId))
      );
    },
  },
  {
    id: "createdAt",
    accessorFn: (row) => row.createdAt,
    header: ({ column }) => renderSortableHeader("Created", column),
    cell: ({ row }) => row.original.created,
  },
  {
    id: "lastModifiedAt",
    accessorFn: (row) => row.lastModifiedAt,
    header: ({ column }) => renderSortableHeader("Last Modified", column),
    cell: ({ row }) => row.original.lastModified,
  },
  {
    accessorKey: "lastRestored",
    header: "Last Restored",
    cell: ({ row }) => row.original.lastRestored || "Never",
  },
  {
    id: "actions",
    cell: ({ row }) => {
      const backup = row.original;
      return (
        <div className="flex space-x-2">
          {options?.onPreview && (
            <Button
              variant="secondary"
              onClick={() => options.onPreview?.(backup.name)}
            >
              Preview
            </Button>
          )}

          <Button
            onClick={() => {
              options?.onRestoreRequest?.(backup);
            }}
          >
            Restore
          </Button>

          <Button
            variant="destructive"
            onClick={() => {
              options?.onDeleteRequest?.(backup.name);
            }}
          >
            Delete
          </Button>
        </div>
      );
    },
  },
];

