"use client";

import { DataTable, Button, useToast, Input, SectionHeader, SectionPanel } from "@/shared/ui";
import { useState, useRef } from "react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";






import { getDatabaseColumns } from "../components/DatabaseColumns";
import { LogModal } from "../components/LogModal";
import { RestoreModal } from "../components/RestoreModal";
import type { DatabaseInfo, DatabaseType } from "../types";
import {
  createDatabaseBackup,
  fetchDatabaseBackups,
  restoreDatabaseBackup,
  uploadDatabaseBackup,
  deleteDatabaseBackup,
} from "../api";

export default function DatabasesPage() {
  const [activeTab, setActiveTab] = useState<DatabaseType>("postgresql");
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isLogModalOpen, setIsLogModalOpen] = useState(false);
  const [logModalContent, setLogModalContent] = useState("");
  const [isRestoreModalOpen, setIsRestoreModalOpen] = useState(false);
  const [selectedBackupForRestore, setSelectedBackupForRestore] = useState<string | null>(null);
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const backupsQuery = useQuery({
    queryKey: ["database-backups", activeTab],
    queryFn: () => fetchDatabaseBackups(activeTab),
  });
  const data = backupsQuery.data ?? [];

  const createBackup = useMutation({
    mutationFn: async ({ dbType }: { dbType: DatabaseType }) => createDatabaseBackup(dbType),
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const restoreBackup = useMutation({
    mutationFn: async ({
      dbType,
      backupName,
      truncateBeforeRestore,
    }: {
      dbType: DatabaseType;
      backupName: string;
      truncateBeforeRestore: boolean;
    }) =>
      restoreDatabaseBackup(dbType, {
        backupName,
        truncateBeforeRestore,
      }),
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const uploadBackup = useMutation({
    mutationFn: async ({ dbType, file }: { dbType: DatabaseType; file: File }) =>
      uploadDatabaseBackup(dbType, file),
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const deleteBackup = useMutation({
    mutationFn: async ({ dbType, backupName }: { dbType: DatabaseType; backupName: string }) =>
      deleteDatabaseBackup(dbType, backupName),
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["database-backups", variables.dbType] });
    },
  });

  const openLogModal = (content: string) => {
    setLogModalContent(content);
    setIsLogModalOpen(true);
  };

  const closeLogModal = () => {
    setIsLogModalOpen(false);
    setLogModalContent("");
    void queryClient.invalidateQueries({ queryKey: ["database-backups", activeTab] });
  };


  const handleRestoreRequest = (backup: DatabaseInfo) => {
    setSelectedBackupForRestore(backup.name);
    setIsRestoreModalOpen(true);
  };

  const handleRestoreConfirm = async (truncate: boolean) => {
    const backupName = selectedBackupForRestore;
    setIsRestoreModalOpen(false);
    setSelectedBackupForRestore(null);

    if (!backupName) return;

    try {
      const { ok, payload } = await restoreBackup.mutateAsync({
        dbType: activeTab,
        backupName,
        truncateBeforeRestore: truncate,
      });
      const log = payload.log ?? "No log available.";

      if (ok) {
        openLogModal(
          `${payload.message ?? "Backup restored successfully."}\n\n---LOG---\n${log}`
        );
      } else {
        const meta = [
          payload.errorId ? `Error ID: ${payload.errorId}` : null,
          payload.stage ? `Stage: ${payload.stage}` : null,
          payload.backupName ? `Backup: ${payload.backupName}` : null,
        ]
          .filter(Boolean)
          .join("\n");

        openLogModal(
          `${payload.error ?? "Failed to restore backup."}${
            meta ? `\n\n${meta}` : ""
          }\n\n---LOG---\n${log}`
        );
      }
    } catch (error) {
      console.error("Error restoring backup:", error);
      openLogModal(`An error occurred during restoration.\n\n${String(error)}`);
    }
  };

  const handleBackup = async () => {
    try {
      const { ok, payload } = await createBackup.mutateAsync({ dbType: activeTab });
      const log = payload.log ?? "No log available.";
      if (ok) {
        if (payload.warning) {
          openLogModal(
            `${payload.message ?? "Backup created"}: ${
              payload.warning
            }\n\n---LOG---\n${log}`
          );
        } else {
          openLogModal(
            `${
              payload.message ?? "Backup created successfully."
            }\n\n---LOG---\n${log}`
          );
        }
      } else {
        openLogModal(
          `${payload.error ?? "Failed to create backup."}\n\n---LOG---\n${log}`
        );
      }
    } catch (error) {
      console.error("Error creating backup:", error);
      openLogModal(`An error occurred during backup.\n\n${String(error)}`);
    }
  };

  const handleDeleteRequest = async (backupName: string) => {
    if (!window.confirm(`Delete backup ${backupName}? This cannot be undone.`)) return;
    try {
      const result = await deleteBackup.mutateAsync({ dbType: activeTab, backupName });
      if (result.ok) {
        toast("Backup deleted successfully.", { variant: "success" });
      } else {
        toast("Failed to delete backup.", { variant: "error" });
      }
    } catch (error) {
      console.error("Error deleting backup:", error);
      toast("An error occurred during deletion.", { variant: "error" });
    }
  };

  const handleUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    try {
      const result = await uploadBackup.mutateAsync({ dbType: activeTab, file });
      if (result.ok) {
        toast("Backup uploaded successfully.", { variant: "success" });
      } else {
        toast("Failed to upload backup.", { variant: "error" });
      }
    } catch (error) {
      console.error("Error uploading backup:", error);
      toast("An error occurred during upload.", { variant: "error" });
    } finally {
      event.target.value = "";
    }
  };

  const triggerFileUpload = () => {
    fileInputRef.current?.click();
  };

  const handlePreview = (backupName: string) => {
    const url = `/admin/databases/preview?backup=${encodeURIComponent(
      backupName
    )}&type=${activeTab}`;
    window.location.assign(url);
  };

  const handlePreviewCurrent = () => {
    window.location.assign(`/admin/databases/preview?mode=current&type=${activeTab}`);
  };

  return (
    <div className="container mx-auto py-10">
      {isLogModalOpen && (
        <LogModal content={logModalContent} onClose={closeLogModal} />
      )}

      {isRestoreModalOpen && selectedBackupForRestore && (
        <RestoreModal
          backupName={selectedBackupForRestore}
          onClose={() => {
            setIsRestoreModalOpen(false);
            setSelectedBackupForRestore(null);
          }}
          onConfirm={(t) => void handleRestoreConfirm(t)}
        />
      )}

      {/* Tabs */}
      <div className="mb-6 border-b border">
        <div className="flex gap-4">
          <Button
            onClick={() => setActiveTab("postgresql")}
            className={`px-4 py-2 font-medium transition ${
              activeTab === "postgresql"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-400 hover:text-gray-300"
            }`}
          >
            PostgreSQL
          </Button>
          <Button
            onClick={() => setActiveTab("mongodb")}
            className={`px-4 py-2 font-medium transition ${
              activeTab === "mongodb"
                ? "border-b-2 border-blue-500 text-blue-500"
                : "text-gray-400 hover:text-gray-300"
            }`}
          >
            MongoDB
          </Button>
        </div>
      </div>

      <SectionHeader
        title={`Databases - ${activeTab === "postgresql" ? "PostgreSQL" : "MongoDB"}`}
        description={
          activeTab === "postgresql"
            ? "PostgreSQL backups use pg_dump/pg_restore (.dump files). Restores are data-only and preserve your current schema."
            : "MongoDB backups use mongodump/mongorestore (.archive files). Full database dumps with BSON format."
        }
        actions={
          <>
            <Button
              onClick={() => {
                void handleBackup();
              }}
            >
              Create Backup
            </Button>
            <Button onClick={triggerFileUpload}>Upload Backup</Button>
            <Button variant="secondary" onClick={handlePreviewCurrent}>
              Preview Current DB
            </Button>
            <Input
              type="file"
              ref={fileInputRef}
              onChange={(e) => void handleUpload(e)}
              className="hidden"
              accept={activeTab === "postgresql" ? ".dump" : ".archive"}
            />
          </>
        }
        className="mb-6"
      />
      <SectionPanel className="p-6">
        <DataTable
          columns={getDatabaseColumns({
            onPreview: handlePreview,
            onRestoreRequest: handleRestoreRequest,
            onDeleteRequest: (name) => { void handleDeleteRequest(name); },
          })}
          data={data}
          initialSorting={[{ id: "lastModifiedAt", desc: true }]}
          sortingStorageKey={`stardb:database-backups:${activeTab}:sorting`}
        />
      </SectionPanel>
    </div>
  );
}

import "server-only";

import path from "path";
import { promises as fs } from "fs";

import {
  backupsDir as pgBackupsDir,
  ensureBackupsDir as ensurePgBackupsDir,
  getDatabaseName,
  getPgConnectionUrl,
  getPgDumpCommand,
  execFileAsync as pgExecFileAsync,
} from "@/features/database/utils/postgres";

import {
  backupsDir as mongoBackupsDir,
  ensureBackupsDir as ensureMongoBackupsDir,
  getMongoConnectionUrl,
  getMongoDatabaseName,
  getMongoDumpCommand,
  execFileAsync as mongoExecFileAsync,
} from "@/features/database/utils/mongo";
import { operationFailedError } from "@/shared/errors/app-error";

export type DatabaseBackupResult = {
  message: string;
  backupName: string;
  log: string;
  warning?: string | undefined;
};

export const createMongoBackup = async (): Promise<DatabaseBackupResult> => {
  const mongoUri = getMongoConnectionUrl();
  const databaseName = getMongoDatabaseName();
  await ensureMongoBackupsDir();

  const backupName = `${databaseName}-backup-${Date.now()}.archive`;
  const backupPath = path.join(mongoBackupsDir, backupName);
  const logPath = path.join(mongoBackupsDir, `${backupName}.log`);

  const command = getMongoDumpCommand();
  const args = [
    "--uri",
    mongoUri,
    "--db",
    databaseName,
    "--archive=" + backupPath,
    "--gzip",
  ];
  const commandString = `${command} ${args.join(" ")}`;

  let stdout = "";
  let stderr = "";
  try {
    const result = await mongoExecFileAsync(command, args);
    stdout = result.stdout;
    stderr = result.stderr;

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
    await fs.writeFile(logPath, logContent);

    return {
      message: "Backup created",
      backupName,
      log: logContent,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    const cause = (error as { cause?: { stdout?: string; stderr?: string } })
      .cause;
    stdout = cause?.stdout || "";
    stderr = cause?.stderr || "";

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}\n\nerror:\n${message}`;
    await fs.writeFile(logPath, logContent);

    const details = stderr.trim();
    const stat = await fs.stat(backupPath).catch(() => null);
    if (stat && stat.size > 0) {
      return {
        message: "Backup created with warnings",
        backupName,
        warning: details || message,
        log: logContent,
      };
    }

    throw operationFailedError(
      "Failed to create MongoDB backup",
      error,
      details ? { details } : undefined
    );
  }
};

export const createPostgresBackup = async (): Promise<DatabaseBackupResult> => {
  const databaseUrl = getPgConnectionUrl();
  const databaseName = getDatabaseName(databaseUrl);
  await ensurePgBackupsDir();

  const backupName = `${databaseName}-backup-${Date.now()}.dump`;
  const backupPath = path.join(pgBackupsDir, backupName);
  const logPath = path.join(pgBackupsDir, `${backupName}.log`);

  const command = getPgDumpCommand();
  const args = ["-Fc", "--file", backupPath, "--dbname", databaseUrl];
  const commandString = `${command} ${args.join(" ")}`;

  let stdout = "";
  let stderr = "";
  try {
    const result = await pgExecFileAsync(command, args);
    stdout = result.stdout;
    stderr = result.stderr;

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
    await fs.writeFile(logPath, logContent);

    return {
      message: "Backup created",
      backupName,
      log: logContent,
    };
  } catch (error) {
    const message = error instanceof Error ? error.message : "Unknown error";
    const cause = (error as { cause?: { stdout?: string; stderr?: string } })
      .cause;
    stdout = cause?.stdout || "";
    stderr = cause?.stderr || "";

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}\n\nerror:\n${message}`;
    await fs.writeFile(logPath, logContent);

    const details = stderr.trim();
    const stat = await fs.stat(backupPath).catch(() => null);
    if (stat && stat.size > 0) {
      return {
        message: "Backup created with warnings",
        backupName,
        warning: details || message,
        log: logContent,
      };
    }

    throw operationFailedError(
      "Failed to create Postgres backup",
      error,
      details ? { details } : undefined
    );
  }
};

export const createFullDatabaseBackup = async () => {
  const mongo = await createMongoBackup();
  const postgres = await createPostgresBackup();
  return { mongo, postgres };
};

import "server-only";

import path from "path";
import { promises as fs } from "fs";
import { execFile } from "child_process";

export const backupsDir = path.join(process.cwd(), "mongo", "backups");

export const ensureBackupsDir = async () => {
  await fs.mkdir(backupsDir, { recursive: true });
};

export const getMongoConnectionUrl = () => {
  const mongoUri = process.env.MONGODB_URI;
  if (!mongoUri) {
    throw new Error("MONGODB_URI is not set.");
  }
  return mongoUri;
};

export const getMongoDatabaseName = () => {
  const dbName = process.env.MONGODB_DB;
  if (!dbName) {
    throw new Error("MONGODB_DB is not set.");
  }
  return dbName;
};

export const getMongoDumpCommand = () =>
  process.env.MONGODUMP_PATH ?? "mongodump";

export const getMongoRestoreCommand = () =>
  process.env.MONGORESTORE_PATH ?? "mongorestore";

export const execFileAsync = (
  command: string,
  args: string[]
): Promise<{ stdout: string; stderr: string }> =>
  new Promise((resolve: (value: { stdout: string; stderr: string }) => void, reject: (reason?: unknown) => void) => {
    execFile(command, args, (error: Error | null, stdout: string, stderr: string) => {
      if (error) {
        const wrapped = new Error(error.message);
        (wrapped as { cause?: { stdout: string; stderr: string } }).cause = {
          stdout,
          stderr,
        };
        reject(wrapped);
        return;
      }
      resolve({ stdout, stderr });
    });
  });

export const assertValidBackupName = (backupName: string) => {
  const basename = path.basename(backupName);
  if (basename !== backupName) {
    throw new Error("Invalid backup name.");
  }
  if (path.extname(backupName) !== ".archive") {
    throw new Error("Invalid backup file type.");
  }
};

