};

export const getPgConnectionUrl = () => {
  const databaseUrl = getDatabaseUrl();
  try {
    const url = new URL(databaseUrl);
    url.searchParams.delete("schema");
    return url.toString();
  } catch {
    return databaseUrl;
  }
};

