  try {
    const url = new URL(databaseUrl);
    return url.pathname.replace(/^\//, "") || "database";
  } catch {
    return "database";
  }
};

export const getPgDumpCommand = () =>
  process.env.PG_DUMP_PATH ?? "pg_dump";

