  package: Package,
  "shopping-cart": ShoppingCart,
  tag: Tag,
  star: Star,
  heart: Heart,
  zap: Zap,
  gift: Gift,
  truck: Truck,
  "dollar-sign": DollarSign,
  award: Award,
  box: Box,
