                    )}
                    {draft.tagIds && draft.tagIds.length > 0 && (
                      <span className="rounded bg-gray-800 px-2 py-1">
                        {draft.tagIds.length} Tag(s)
                      </span>
                    )}
                  </div>
                </div>
                <div className="flex gap-2">
                  <Button
                    onClick={() => onEdit(draft.id)}
                    variant="outline"
                    size="sm"
                    className="flex items-center gap-1"
                  >
                    <Edit2Icon className="h-3 w-3" />
                    Edit
                  </Button>
                  <Button
                    onClick={() => void handleDelete(draft.id)}
                    variant="outline"
                    size="sm"
                    disabled={deleting === draft.id}
                    className="flex items-center gap-1 border-red-600 text-red-600 hover:bg-red-600/10"
                  >
                    <TrashIcon className="h-3 w-3" />
                    {deleting === draft.id ? "Deleting..." : "Delete"}
                  </Button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </ListPanel>
  );
}

"use client";

import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import type { ProductDraft } from "@/features/products/types/drafts";

export const draftKeys = {
  all: ["drafts"] as const,
  detail: (id: string) => ["drafts", id] as const,
};

export function useDrafts() {
  return useQuery({
    queryKey: draftKeys.all,
    queryFn: async () => {
      const res = await fetch("/api/drafts");
      if (!res.ok) throw new Error("Failed to load drafts");
      return (await res.json()) as ProductDraft[];
    },
  });
}

export function useDraft(id: string) {
  return useQuery({
    queryKey: draftKeys.detail(id),
    queryFn: async () => {
      const res = await fetch(`/api/drafts/${id}`);
      if (!res.ok) throw new Error("Failed to load draft");
      return (await res.json()) as ProductDraft;
    },
    enabled: !!id,
  });
}

export function useDeleteDraft() {
  const queryClient = useQueryClient();
  return useMutation({
    mutationFn: async (id: string) => {
      const res = await fetch(`/api/drafts/${id}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete draft");
      return id;
    },
    onSuccess: (deletedId) => {
      void queryClient.invalidateQueries({ queryKey: draftKeys.all });
      void queryClient.removeQueries({ queryKey: draftKeys.detail(deletedId) });
    },
  });
}

"use client";

import { ModalShell, Button, AppModal, SectionHeader } from "@/shared/ui";
import { useRef, useState } from "react";
import { DraftList } from "../components/DraftList";
import { DraftCreator } from "../components/DraftCreator";




export function AdminDraftsPage() {
  const [isCreatorOpen, setIsCreatorOpen] = useState(false);
  const [editingDraftId, setEditingDraftId] = useState<string | null>(null);
  const [refreshTrigger, setRefreshTrigger] = useState(0);
  const formRef = useRef<HTMLFormElement>(null);

  const handleEdit = (id: string) => {
    setEditingDraftId(id);
    setIsCreatorOpen(true);
  };

  const handleCreateNew = () => {
    setEditingDraftId(null);
    setIsCreatorOpen(true);
  };

  const handleSaveSuccess = () => {
    setRefreshTrigger((prev) => prev + 1);
    setEditingDraftId(null);
    setIsCreatorOpen(false);
  };

  const handleCloseCreator = () => {
    setEditingDraftId(null);
    setIsCreatorOpen(false);
  };

  const title = editingDraftId ? "Edit Draft" : "Create Draft";
  const submitText = editingDraftId ? "Update" : "Create";

  const header = (
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-4">
        <Button
          onClick={() => {
            if (formRef.current) {
              formRef.current.requestSubmit();
            }
          }}
          className="min-w-[100px] border border-white/20 hover:border-white/40"
        >
          {submitText}
        </Button>
        <h2 className="text-2xl font-bold text-white">{title}</h2>
      </div>
      <Button
        type="button"
        onClick={handleCloseCreator}
        className="min-w-[100px] border border-white/20 hover:border-white/40"
      >
        Close
      </Button>
    </div>
  );

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
        title="Product Drafts"
        description="Create reusable templates for products with pre-filled values"
        className="mb-6"
      />

      <DraftList
        onEdit={handleEdit}
        onCreateNew={handleCreateNew}
        refreshTrigger={refreshTrigger}
      />

      <AppModal
        open={isCreatorOpen}
        onOpenChange={(open) => !open && handleCloseCreator()}
        title={title}
      >
        <ModalShell title={title} onClose={handleCloseCreator} header={header}>
          <DraftCreator
            formRef={formRef}
            draftId={editingDraftId}
            onSaveSuccess={handleSaveSuccess}
            onCancel={handleCloseCreator}
          />
        </ModalShell>
      </AppModal>
    </div>
  );
}

