type SessionCookie = {
  name?: string;
  value?: string;
  domain?: string;
  path?: string;
  expires?: number;
  httpOnly?: boolean;
  secure?: boolean;
  sameSite?: string;
};

type SessionOrigin = {
  origin?: string;
  localStorage?: { name?: string; value?: string }[];
};

type SessionModalProps = {
  loading: boolean;
  error: string | null;
  cookies: SessionCookie[];
  origins: SessionOrigin[];
  updatedAt: string | null;
  onClose: () => void;
};

