          <div className="space-y-4 text-sm text-gray-200">
            <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
              <span className="text-gray-400">Obtained:</span>{" "}
              {updatedAt ? new Date(updatedAt).toLocaleString() : "—"}
            </div>

              <div className="space-y-3">
                {cookies.length === 0 ? (
                  <div className="rounded-md border border-border bg-card/60 p-4 text-sm text-gray-400">
                    No cookies stored.
                  </div>
                ) : (
                  cookies.map((cookie, index) => (
                    <div
                      key={`${cookie.name || "cookie"}-${index}`}
                      className="rounded-md border border-border bg-card/60 p-3"
                    >
                      <div className="flex flex-wrap items-center gap-2 text-xs text-gray-300">
                        <span className="rounded-full bg-gray-800 px-2 py-0.5 text-gray-200">
                          {cookie.name || "unknown"}
                        </span>
                        <span className="text-gray-500">
                          {cookie.domain || "—"}
                        </span>
                      </div>
                      <div className="mt-2 grid gap-2 text-xs text-gray-400 md:grid-cols-2">
                        <p>
                          <span className="text-gray-500">Value:</span>{" "}
                          <span className="break-all text-gray-200">
                            {cookie.value || "—"}
                          </span>
                        </p>
                        <p>
                          <span className="text-gray-500">Path:</span>{" "}
                          {cookie.path || "—"}
                        </p>
                        <p>
                          <span className="text-gray-500">Expires:</span>{" "}
                          {cookie.expires
                            ? new Date(cookie.expires * 1000).toLocaleString()
                            : "Session"}
                        </p>
                        <p>
                          <span className="text-gray-500">Secure:</span>{" "}
                          {cookie.secure ? "Yes" : "No"}
                        </p>
                        <p>
                          <span className="text-gray-500">HttpOnly:</span>{" "}
                          {cookie.httpOnly ? "Yes" : "No"}
                        </p>
                        <p>
                          <span className="text-gray-500">SameSite:</span>{" "}
                          {cookie.sameSite || "—"}
                        </p>
                      </div>
                    </div>
                  ))
                )}
              </div>

              {origins.length > 0 && (
                <div className="rounded-md border border-border bg-card/60 p-3">
                  <p className="text-xs text-gray-400">
                    Origins stored: {origins.length}
                  </p>
                </div>
              )}
          </div>
        )}
      </ModalShell>
    </AppModal>
  );
}
import { AppModal, ModalShell } from "@/shared/ui";

"use client";




type TestErrorModalProps = {
  testError: string | null;
  testErrorMeta: {
    errorId?: string;
    integrationId?: string | null;
    connectionId?: string | null;
  } | null;
  onClose: () => void;
};

export function TestErrorModal({
  testError,
  testErrorMeta,
  onClose,
}: TestErrorModalProps) {
  if (!testError) return null;

  const handleCopyTestError = async () => {
    if (!testError) return;
    try {
      const metaLines = [
        testErrorMeta?.errorId ? `Error ID: ${testErrorMeta.errorId}` : null,
        testErrorMeta?.integrationId
          ? `Integration ID: ${testErrorMeta.integrationId}`
          : null,
        testErrorMeta?.connectionId
          ? `Connection ID: ${testErrorMeta.connectionId}`
          : null,
      ]
        .filter(Boolean)
        .join("\n");

      const copyText = metaLines ? `${metaLines}\n\n${testError}` : testError;
      await navigator.clipboard.writeText(copyText);
    } catch {
      // Fallback
      const textarea = document.createElement("textarea");
      const metaLines = [
        testErrorMeta?.errorId ? `Error ID: ${testErrorMeta.errorId}` : null,
        testErrorMeta?.integrationId
          ? `Integration ID: ${testErrorMeta.integrationId}`
          : null,
        testErrorMeta?.connectionId
          ? `Connection ID: ${testErrorMeta.connectionId}`
          : null,
      ]
        .filter(Boolean)
        .join("\n");
      textarea.value = metaLines ? `${metaLines}\n\n${testError}` : testError;
      textarea.setAttribute("readonly", "true");
      textarea.style.position = "absolute";
      textarea.style.left = "-9999px";
      document.body.appendChild(textarea);
      textarea.select();
      document.execCommand("copy");
      document.body.removeChild(textarea);
    }
  };

  const footer = (
    <Button
      className="border border-white/20 hover:border-white/40"
      type="button"
      onClick={() => { void handleCopyTestError(); }}
    >
      Copy Error
    </Button>
  );

  return (
    <AppModal
      open={true}
      onOpenChange={(open) => !open && onClose()}
      title="Playwright Error"
    >
      <ModalShell title="Playwright Error" onClose={onClose} size="lg" footer={footer}>
        <div className="space-y-3">
          <div className="rounded-md border border-border bg-card/60 p-3 text-xs text-gray-300">
            Copy the raw error to share or debug it.
          </div>
