                  }`}
                >
                  {connection.name}
                </Button>
              ))
            )}
          </div>
        </div>
      ))}
    </div>
  );
}

"use client";

import { useMutation, useQueryClient } from "@tanstack/react-query";
import type { Integration, IntegrationConnection } from "@/features/integrations/types/integrations-ui";

export function useCreateIntegration() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async (payload: { name: string; slug: string }) => {
      const res = await fetch("/api/integrations", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const error = (await res.json().catch(() => null)) as Record<string, unknown> | null;
        throw new Error((error?.error as string) || "Failed to create integration");
      }
      return (await res.json()) as Integration;
    },
    onSuccess: () => {
      void queryClient.invalidateQueries({ queryKey: ["integrations"] });
    },
  });
}

export function useUpsertConnection() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ 
      integrationId, 
      connectionId, 
      payload 
    }: { 
      integrationId: string; 
      connectionId?: string | null; 
      payload: Record<string, unknown> 
    }) => {
      const url = connectionId
        ? `/api/integrations/connections/${connectionId}`
        : `/api/integrations/${integrationId}/connections`;

      const res = await fetch(url, {
        method: connectionId ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        const error = (await res.json().catch(() => null)) as Record<string, unknown> | null;
        throw new Error((error?.error as string) || "Failed to save connection");
      }
      return (await res.json()) as IntegrationConnection;
    },
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["integration-connections", variables.integrationId] });
    },
  });
}

export function useDeleteConnection() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: async ({ 
      integrationId: _integrationId, 
      connectionId 
    }: { 
      integrationId: string; 
      connectionId: string 
    }) => {
      const res = await fetch(`/api/integrations/connections/${connectionId}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        const error = (await res.json().catch(() => null)) as Record<string, unknown> | null;
        throw new Error((error?.error as string) || "Failed to delete connection");
      }
      return (await res.json()) as Record<string, unknown>;
    },
    onSuccess: (_data, variables) => {
      void queryClient.invalidateQueries({ queryKey: ["integration-connections", variables.integrationId] });
    },
  });
}

export function useTestConnection() {
  return useMutation({
    mutationFn: async ({ 
      integrationId, 
      connectionId, 
      type = "test" 
    }: { 
      integrationId: string; 
      connectionId: string; 
      type?: "test" | "base/test" | "allegro/test" 
    }) => {
      const res = await fetch(`/api/integrations/${integrationId}/connections/${connectionId}/${type}`, {
        method: "POST",
      });
      const data = (await res.json()) as Record<string, unknown>;
      if (!res.ok) {
        const message = (data.error as string) || (data.message as string) || res.statusText || "Connection test failed";
        const error = new Error(message);
        Object.assign(error, { data, status: res.status });
        throw error;
      }
      return data;
    },
  });
}

"use client";
import { useState, useEffect, useCallback } from "react";
import { logger } from "@/shared/utils/logger";
import type { ProductWithImages } from "@/features/products";

export function useIntegrationOperations() {
  // Integrations state
  const [integrationsProduct, setIntegrationsProduct] = useState<ProductWithImages | null>(null);
  const [showListProductModal, setShowListProductModal] = useState(false);
  const [listProductPreset, setListProductPreset] = useState<{ integrationId: string; connectionId: string } | null>(null);
  const [integrationBadgeIds, setIntegrationBadgeIds] = useState<Set<string>>(() => new Set());
  const [integrationBadgeStatuses, setIntegrationBadgeStatuses] = useState<Map<string, string>>(() => new Map());

  // Export settings state - opens ListProductModal directly for products with existing listings
  const [exportSettingsProduct, setExportSettingsProduct] = useState<ProductWithImages | null>(null);

  // Load listing badges
  const refreshListingBadges = useCallback(async () => {
    try {
      const res = await fetch("/api/integrations/product-listings");
      if (!res.ok) return;
      const payload = (await res.json()) as Record<string, string>;
      const entries = Object.entries(payload || {});
      setIntegrationBadgeStatuses(new Map(entries));
      setIntegrationBadgeIds(new Set(entries.map(([productId]) => productId)));
    } catch (error) {
      logger.warn("Failed to load listing badges", error);
    }
  }, []);

  useEffect(() => {
    const loadListingBadges = async () => {
      await refreshListingBadges();
    };
    void loadListingBadges();
  }, [refreshListingBadges]);

  const handleListProductSuccess = () => {
    if (integrationsProduct?.id) {
      setIntegrationBadgeIds((prev) => new Set(prev).add(integrationsProduct.id));
      setIntegrationBadgeStatuses((prev) => new Map(prev).set(integrationsProduct.id, "pending"));
    }
    setShowListProductModal(false);
    setIntegrationsProduct(null);
    void refreshListingBadges();
  };

  return {
    integrationsProduct,
    setIntegrationsProduct,
    showListProductModal,
    setShowListProductModal,
    listProductPreset,
    setListProductPreset,
    integrationBadgeIds,
    integrationBadgeStatuses,
    exportSettingsProduct,
    setExportSettingsProduct,
    refreshListingBadges,
    handleListProductSuccess,
  };
}

"use client";

import { useQuery } from "@tanstack/react-query";
import type { Integration, IntegrationConnection } from "@/features/integrations/types/integrations-ui";
import type { IntegrationWithConnections } from "@/features/integrations/types/listings";

export function useIntegrations() {
  return useQuery({
    queryKey: ["integrations"],
    queryFn: async () => {
      const res = await fetch("/api/integrations");
      if (!res.ok) {
        const error = (await res.json()) as Record<string, unknown>;
        throw new Error((error.error as string) || "Failed to fetch integrations");
      }
      return (await res.json()) as Integration[];
    },
  });
}

export function useIntegrationConnections(integrationId?: string) {
  return useQuery({
    queryKey: ["integration-connections", integrationId],
    queryFn: async () => {
      if (!integrationId) return [] as IntegrationConnection[];
      const res = await fetch(`/api/integrations/${integrationId}/connections`);
      if (!res.ok) {
        const error = (await res.json()) as Record<string, unknown>;
        throw new Error((error.error as string) || "Failed to fetch connections");
      }
      return (await res.json()) as IntegrationConnection[];
    },
    enabled: !!integrationId,
  });
}

export function useConnectionSession(
  connectionId?: string,
  options?: { enabled?: boolean }
) {
  return useQuery({
    queryKey: ["connection-session", connectionId],
    queryFn: async () => {
      if (!connectionId) return null;
      const res = await fetch(`/api/integrations/connections/${connectionId}/session`);
      if (!res.ok) {
        const error = (await res.json()) as Record<string, unknown>;
        throw new Error((error.error as string) || "Failed to fetch session");
      }
      return (await res.json()) as Record<string, unknown>;
    },
    enabled: !!connectionId && (options?.enabled ?? true),
    staleTime: 0, // Session cookies might change frequently during testing
  });
}

export function useIntegrationsWithConnections() {
  return useQuery({
    queryKey: ["integrations", "with-connections"],
    queryFn: async () => {
      const res = await fetch("/api/integrations/with-connections");
      if (!res.ok) {
        const error = (await res.json()) as Record<string, unknown>;
        throw new Error((error.error as string) || "Failed to load integrations");
      }
      return (await res.json()) as IntegrationWithConnections[];
    },
  });
}

