export const getIntegrationsWithConnections = async (): Promise<IntegrationWithConnectionsBasic[]> => {
  const provider = await getIntegrationDataProvider();

  if (provider === "mongodb") {
    const db = await getMongoDb();

    const integrations = await db
      .collection<{ _id: string; name: string; slug: string }>("integrations")
      .find({})
      .sort({ name: 1 })
      .toArray();

    const connections = await db
      .collection<{ _id: string; name: string; integrationId: string }>("integration_connections")
      .find({})
      .sort({ createdAt: -1 })
      .toArray();

    return integrations.map((integration) => ({
      id: integration._id,
      name: integration.name,
      slug: integration.slug,
      connections: connections
        .filter((c) => c.integrationId === integration._id)
        .map((c) => ({
          id: c._id,
          name: c.name,
          integrationId: c.integrationId,
        })),
    }));
  }

  // Prisma
  const integrations = await prisma.integration.findMany({
    include: {
      connections: {
        select: { id: true, name: true, integrationId: true },
        orderBy: { createdAt: "desc" },
      },
    },
    orderBy: { name: "asc" },
  });

  return integrations;
};

import { TestLogEntry, TestStatus } from "@/features/integrations/types/integrations-ui";

export const coerceStatus = (value: unknown): TestStatus => {
  return value === "pending" || value === "ok" || value === "failed"
    ? value
    : "failed";
};

export const normalizeSteps = (value: unknown): TestLogEntry[] => {
  if (!Array.isArray(value)) return [];
  return value.map((raw) => {
    const s =
      raw && typeof raw === "object"
        ? (raw as Record<string, unknown>)
        : {};
    const stepValue = s?.step;
    return {
      step:
        typeof stepValue === "string"
          ? stepValue
          : stepValue == null
            ? ""
            : typeof stepValue === "number" || typeof stepValue === "boolean"
              ? String(stepValue)
              : JSON.stringify(stepValue),
      status: coerceStatus(s?.status),
      timestamp:
        typeof s?.timestamp === "string"
          ? s.timestamp
          : new Date().toISOString(),
      ...(typeof s?.detail === "string" && { detail: s.detail }),
    };
  });
};

import "server-only";

import crypto from "crypto";

const KEY_ENV = "INTEGRATION_ENCRYPTION_KEY";

function getKey() {
  const raw = process.env[KEY_ENV];
  if (!raw) {
    throw new Error(`${KEY_ENV} is required`);
  }
  const key = Buffer.from(raw, "base64");
  if (key.length !== 32) {
    throw new Error(`${KEY_ENV} must be a base64-encoded 32-byte key`);
  }
  return key;
}

export function encryptSecret(value: string) {
  const key = getKey();
  const iv = crypto.randomBytes(12);
  const cipher = crypto.createCipheriv("aes-256-gcm", key, iv);
  const encrypted = Buffer.concat([cipher.update(value, "utf8"), cipher.final()]);
  const tag = cipher.getAuthTag();
  return [
    iv.toString("base64"),
    tag.toString("base64"),
    encrypted.toString("base64"),
  ].join(":");
}

export function decryptSecret(payload: string) {
  const key = getKey();
  const [ivB64, tagB64, dataB64] = payload.split(":");
  if (!ivB64 || !tagB64 || !dataB64) {
    throw new Error("Invalid encrypted payload");
  }
  const iv = Buffer.from(ivB64, "base64");
  const tag = Buffer.from(tagB64, "base64");
  const data = Buffer.from(dataB64, "base64");
  const decipher = crypto.createDecipheriv("aes-256-gcm", key, iv);
  decipher.setAuthTag(tag);
  const decrypted = Buffer.concat([decipher.update(data), decipher.final()]);
  return decrypted.toString("utf8");
}

