import {
  countryMappings,
  defaultCountries,
  defaultCurrencies,
  defaultLanguages,
} from "@/features/internationalization/lib/internationalizationDefaults";

const currencyByCode = new Map(
  defaultCurrencies.map((currency) => [currency.code, currency])
);

const countryByCode = new Map(
  defaultCountries.map((country) => [country.code, country])
);

export const fallbackCurrencies = defaultCurrencies.map((currency) => ({
  id: currency.code,
  code: currency.code,
  name: currency.name,
  symbol: currency.symbol ?? null,
}));

export const fallbackCountries = defaultCountries.map((country) => {
  const matchingMappings = countryMappings.filter(
    (mapping) => mapping.countryCode === country.code
  );
  const currencies = matchingMappings
    .map((mapping) => currencyByCode.get(mapping.currencyCode))
    .filter(Boolean)
    .map((currency) => ({
      currencyId: currency!.code,
      currency: {
        id: currency!.code,
        code: currency!.code,
        name: currency!.name,
        symbol: currency!.symbol ?? null,
      },
    }));

  return {
    id: country.code,
    code: country.code,
    name: country.name,
    currencies,
  };
});

export const fallbackLanguages = defaultLanguages.map((language) => {
  const matchingMappings = countryMappings.filter((mapping) =>
    mapping.languageCodes.includes(language.code)
  );
  const countries = matchingMappings
    .map((mapping) => countryByCode.get(mapping.countryCode))
    .filter(Boolean)
    .map((country) => ({
      countryId: country!.code,
      country: {
        id: country!.code,
        code: country!.code,
        name: country!.name,
      },
    }));

  return {
    id: language.code,
    code: language.code,
    name: language.name,
    nativeName: language.nativeName,
    countries,
  };
});

import "server-only";

import type { Prisma } from "@prisma/client";
import {
  countryMappings,
  defaultCountries,
  defaultCurrencies,
  defaultLanguages,
} from "@/features/internationalization/lib/internationalizationDefaults";

export async function ensureInternationalizationDefaults(
  tx: Prisma.TransactionClient
) {
  await tx.currency.createMany({
    data: defaultCurrencies,
    skipDuplicates: true,
  });

  await tx.language.createMany({
    data: defaultLanguages,
    skipDuplicates: true,
  });

  await tx.country.createMany({
    data: defaultCountries,
    skipDuplicates: true,
  });

  const [countries, currencies, languages] = await Promise.all([
    tx.country.findMany({ select: { id: true, code: true } }),
    tx.currency.findMany({ select: { id: true, code: true } }),
    tx.language.findMany({ select: { id: true, code: true } }),
  ]);

  const countryByCode = new Map<string, string>(
    countries.map((country) => [country.code, country.id])
  );

  const currencyByCode = new Map<string, string>(
    currencies.map((currency) => [currency.code, currency.id])
  );

  const languageByCode = new Map<string, string>(
    languages.map((language) => [language.code, language.id])
  );

  const countryCurrencyRows: Array<{
    countryId: string;
    currencyId: string;
  }> = [];
  const languageCountryRows: Array<{
    countryId: string;
    languageId: string;
  }> = [];

  for (const mapping of countryMappings) {
    const countryId = countryByCode.get(mapping.countryCode);
    const currencyId = currencyByCode.get(mapping.currencyCode);

    if (countryId && currencyId) {
      countryCurrencyRows.push({ countryId, currencyId });
    }

    for (const languageCode of mapping.languageCodes) {
      const languageId = languageByCode.get(languageCode);
      if (countryId && languageId) {
        languageCountryRows.push({ countryId, languageId });
      }
    }
  }

  if (countryCurrencyRows.length) {
    await tx.countryCurrency.createMany({
      data: countryCurrencyRows,
      skipDuplicates: true,
    });
  }

  if (languageCountryRows.length) {
    await tx.languageCountry.createMany({
      data: languageCountryRows,
      skipDuplicates: true,
    });
  }
}

"use client";

import { Button, Input, Tabs, TabsContent, TabsList, TabsTrigger, useToast, AppModal, ModalShell, SectionHeader, SectionPanel } from "@/shared/ui";
import { Suspense, useCallback, useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { useSearchParams } from "next/navigation";




import { Loader2, RefreshCcw, Trash2, XCircle, Eye } from "lucide-react";




import ProductListingJobsPanel from "@/features/jobs/components/ProductListingJobsPanel";
import type { ProductAiJob } from "@/shared/types/jobs";
import type { ProductAiJobsPanelProps } from "@/features/jobs/types/jobs-ui";

export default function ProductAiJobsPanel({
  title = "AI Jobs",
  description = "Monitor AI, import, and export jobs across the platform.",
  showTabs = true,
}: ProductAiJobsPanelProps) {
  const { toast } = useToast();
  const searchParams = useSearchParams();
  const [jobs, setJobs] = useState<ProductAiJob[]>([]);
  const [loading, setLoading] = useState(true);
  const [query, setQuery] = useState("");
  const [actionId, setActionId] = useState<string | null>(null);
  const [bulkDeleting, setBulkDeleting] = useState(false);
  const [bulkDeletingAll, setBulkDeletingAll] = useState(false);
  const [selectedJob, setSelectedJob] = useState<ProductAiJob | null>(null);

  const getPayload = (job: ProductAiJob) => {
    return job.payload && typeof job.payload === "object"
      ? (job.payload as Record<string, unknown>)
      : null;
  };

  const getJobMeta = (job: ProductAiJob) => {
    const payload = getPayload(job);
    const graph = payload?.graph as Record<string, unknown> | undefined;
    const context = payload?.context as Record<string, unknown> | undefined;
    const entityType =
      (payload?.entityType as string | undefined) ??
      (context?.entityType as string | undefined) ??
      (graph?.entityType as string | undefined);
    const entityId =
      (payload?.entityId as string | undefined) ??
      (context?.entityId as string | undefined) ??
      (payload?.productId as string | undefined) ??
      job.productId;
    const pathName = (graph?.pathName as string | undefined) ?? undefined;
    const pathId = (graph?.pathId as string | undefined) ?? undefined;
    const nodeTitle = (graph?.nodeTitle as string | undefined) ?? undefined;
    const source = (payload?.source as string | undefined) ?? undefined;
    const displayEntity =
      job.product?.name_en || job.product?.sku
        ? `${job.product?.name_en || "Untitled"} (${job.product?.sku || "N/A"})`
        : entityType || entityId
          ? `${entityType ?? "entity"} · ${entityId ?? "unknown"}`
          : "N/A";
    const subEntity = job.product?.sku
      ? `SKU: ${job.product.sku}`
      : pathName || pathId
        ? `Path: ${pathName ?? pathId}`
        : entityId
          ? `ID: ${entityId}`
          : source
            ? `Source: ${source}`
            : undefined;

    return {
      payload,
      graph,
      context,
      entityType,
      entityId,
      pathName,
      pathId,
      nodeTitle,
      source,
      displayEntity,
      subEntity,
    };
  };

  const defaultTab = useMemo(() => {
    if (!showTabs) return "ai";
    const tab = searchParams?.get("tab") ?? "ai";
    return ["ai", "import", "export"].includes(tab) ? tab : "ai";
  }, [searchParams, showTabs]);

  const loadJobs = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch("/api/products/ai-jobs");
      if (!res.ok) throw new Error("Failed to load jobs.");
      const data = (await res.json()) as { jobs?: ProductAiJob[] };
      setJobs(data.jobs ?? []);
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to load jobs.", { variant: "error" });
    } finally {
      setLoading(false);
    }
  }, [toast]);

  useEffect(() => {
    void loadJobs();
  }, [loadJobs]);

  useEffect(() => {
    const hasPendingJobs = jobs.some(job => job.status === "pending" || job.status === "running");
    if (!hasPendingJobs) {
      return;
    }

    const interval = setInterval(() => void loadJobs(), 5000);
    return () => clearInterval(interval);
  }, [jobs, loadJobs]);

  const cancelJob = async (jobId: string) => {
    setActionId(jobId);
    try {
      const res = await fetch(`/api/products/ai-jobs/${jobId}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ action: "cancel" }),
      });
      if (!res.ok) throw new Error("Failed to cancel job.");
      await loadJobs();
      toast("Job canceled", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to cancel job.", { variant: "error" });
    } finally {
      setActionId(null);
    }
  };

  const deleteJob = async (jobId: string) => {
    setActionId(jobId);
    try {
      const res = await fetch(`/api/products/ai-jobs/${jobId}`, {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete job.");
      await loadJobs();
      toast("Job deleted", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to delete job.", { variant: "error" });
    } finally {
      setActionId(null);
    }
  };

  const clearCompleted = async () => {
    if (!window.confirm("Delete all completed jobs? This cannot be undone.")) return;
    setBulkDeleting(true);
    try {
      const res = await fetch("/api/products/ai-jobs?scope=terminal", {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete completed jobs.");
      await loadJobs();
      toast("Jobs cleared", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to delete completed jobs.", { variant: "error" });
    } finally {
      setBulkDeleting(false);
    }
  };

  const clearAllJobs = async () => {
    if (!window.confirm("Delete ALL AI jobs (including running/pending)?")) return;
    setBulkDeletingAll(true);
    try {
      const res = await fetch("/api/products/ai-jobs?scope=all", {
        method: "DELETE",
      });
      if (!res.ok) throw new Error("Failed to delete all jobs.");
      await loadJobs();
      toast("All jobs deleted", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to delete all jobs.", { variant: "error" });
    } finally {
      setBulkDeletingAll(false);
    }
  };

  const filteredJobs = jobs.filter((job) => {
    const meta = getJobMeta(job);
    return [
      job.id,
      job.status,
      job.type,
      meta.entityType,
      meta.entityId,
      meta.pathName,
      meta.pathId,
      meta.nodeTitle,
      meta.source,
      job.product?.name_en,
      job.product?.sku,
    ].some((val) => val?.toLowerCase().includes(query.toLowerCase()));
  });

  const aiContent = (
    <>
      <div className="flex flex-wrap items-center justify-between gap-3">
        <Input
          placeholder="Search by ID, entity, path, or model..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          className="max-w-md bg-gray-900 border-border text-white"
        />
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => void loadJobs()} disabled={loading}>
            <RefreshCcw className={`mr-2 h-4 w-4 ${loading ? "animate-spin" : ""}`} />
            Refresh
          </Button>
          <Button variant="destructive" size="sm" onClick={() => void clearCompleted()} disabled={bulkDeleting}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear Finished
          </Button>
          <Button variant="destructive" size="sm" onClick={() => void clearAllJobs()} disabled={bulkDeletingAll}>
            <Trash2 className="mr-2 h-4 w-4" />
            Clear All
          </Button>
        </div>
      </div>

      <div className="rounded-lg border border-border bg-card overflow-hidden">
        <table className="w-full text-left text-sm text-gray-300">
          <thead className="bg-gray-900 text-xs uppercase text-gray-500">
            <tr>
              <th className="px-4 py-3">Entity</th>
              <th className="px-4 py-3">Type / ID</th>
              <th className="px-4 py-3">Status</th>
              <th className="px-4 py-3">Timing</th>
              <th className="px-4 py-3 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-border">
            {filteredJobs.length === 0 ? (
              <tr>
                <td colSpan={5} className="px-4 py-10 text-center text-gray-500">
                  {loading ? "Loading jobs..." : "No jobs found."}
                </td>
              </tr>
            ) : (
              filteredJobs.map((job) => {
                const meta = getJobMeta(job);
                return (
                  <tr key={job.id} className="hover:bg-card/50">
                  <td className="px-4 py-4">
                    <div className="font-medium text-white">{meta.displayEntity}</div>
                    {meta.subEntity && (
                      <div className="text-xs text-gray-500">{meta.subEntity}</div>
                    )}
                  </td>
                  <td className="px-4 py-4">
                    <div className="text-xs font-mono">{job.type}</div>
                    <div className="text-[10px] text-gray-600">{job.id}</div>
                  </td>
                  <td className="px-4 py-4">
                    <span className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-medium 
                      ${job.status === "completed" ? "bg-green-500/10 text-green-400" : 
                        job.status === "failed" ? "bg-red-500/10 text-red-400" :
                        job.status === "running" ? "bg-blue-500/10 text-blue-400" :
                        job.status === "canceled" ? "bg-gray-500/10 text-gray-400" :
                        "bg-yellow-500/10 text-yellow-400"}`}>
                      {job.status.toUpperCase()}
                    </span>
                    {job.errorMessage && (
                      <div className="mt-1 max-w-[200px] truncate text-[10px] text-red-400" title={job.errorMessage}>
                        {job.errorMessage}
                      </div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-xs">
                    <div>Created: {new Date(job.createdAt).toLocaleTimeString()}</div>
                    {job.finishedAt && (
                      <div className="text-gray-500">Finished: {new Date(job.finishedAt).toLocaleTimeString()}</div>
                    )}
                  </td>
                  <td className="px-4 py-4 text-right">
                    <div className="flex justify-end gap-2">
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="h-8 w-8 text-blue-500 hover:text-blue-400"
                        onClick={() => setSelectedJob(job)}
                      >
                        <Eye className="h-4 w-4" />
                      </Button>
                      {(job.status === "pending" || job.status === "running") && (
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          className="h-8 w-8 text-yellow-500 hover:text-yellow-400"
                          onClick={() => void cancelJob(job.id)}
                          disabled={actionId === job.id}
                        >
                          {actionId === job.id ? <Loader2 className="h-4 w-4 animate-spin" /> : <XCircle className="h-4 w-4" />}
                        </Button>
                      )}
                      <Button 
                        variant="ghost" 
                        size="icon" 
                        className="h-8 w-8 text-red-500 hover:text-red-400"
                        onClick={() => void deleteJob(job.id)}
                        disabled={actionId === job.id}
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </div>
                  </td>
                </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </>
  );

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
