"use client";

import { Button, Input, Label } from "@/shared/ui";
import React from "react";
import Image from "next/image";
import { Upload, FileIcon, Link2, Trash2 } from "lucide-react";
import type { NoteFileRecord } from "@/shared/types/notes";



interface FileAttachmentsProps {
  noteId?: string | undefined;
  noteFiles: NoteFileRecord[];
  maxSlots: number;
  uploadingSlots: Set<number>;
  getNextAvailableSlot: () => number | null;
  onFileUpload: (slotIndex: number, file: File) => Promise<void>;
  onMultiFileUpload: (files: FileList | File[]) => Promise<void>;
  onFileDelete: (slotIndex: number) => Promise<void>;
  onInsertFileReference: (file: NoteFileRecord) => void;
  formatFileSize: (bytes: number) => string;
  isImageFile: (mimetype: string) => boolean;
}

export function FileAttachments({
  noteId,
  noteFiles,
  maxSlots,
  uploadingSlots,
  getNextAvailableSlot,
  onFileUpload,
  onMultiFileUpload,
  onFileDelete,
  onInsertFileReference,
  formatFileSize,
  isImageFile,
}: FileAttachmentsProps) {
  const fileInputRefs = React.useRef<(HTMLInputElement | null)[]>([]);

  if (!noteId) {
    return (
      <div className="rounded-lg border border-dashed border-border/60 bg-gray-800/50 p-4 text-center text-sm text-gray-400">
        Save the note first to enable file attachments ({maxSlots} slots available)
      </div>
    );
  }

  return (
    <div className="space-y-2">
      <Label className="mb-2 block text-sm font-medium text-white">
        Attachments ({noteFiles.length}/{maxSlots} slots used)
      </Label>
      <div className="flex flex-wrap gap-3">
        {(() => {
          const nextSlot = getNextAvailableSlot();
          const isUploading = nextSlot !== null && uploadingSlots.has(nextSlot);
          return (
            <div
              className="relative h-20 w-20 rounded-md border bg-gray-800"
              onDragOver={(e) => e.preventDefault()}
              onDrop={(e) => {
                if (nextSlot === null) return;
                e.preventDefault();
                const file = e.dataTransfer.files[0];
                if (file) {
                  void onFileUpload(nextSlot, file);
                }
              }}
            >
              {isUploading ? (
                <div className="flex h-full items-center justify-center">
                  <div className="h-5 w-5 animate-spin rounded-full border-2 border-border/60 border-t-blue-500" />
                </div>
              ) : nextSlot === null ? (
                <div className="flex h-full items-center justify-center text-[10px] text-gray-500">
                  Full
                </div>
              ) : (
                <Label className="flex h-full cursor-pointer flex-col items-center justify-center text-gray-500 hover:bg-gray-700/50 hover:text-gray-400 transition-colors">
                  <Upload size={14} />
                  <span className="mt-1 text-[10px]">Upload</span>
                  <span className="mt-0.5 text-[10px] text-gray-400">
                    {maxSlots - noteFiles.length} left
                  </span>
                  <Input
                    ref={(el) => {
                      fileInputRefs.current[nextSlot] = el;
                    }}
                    type="file"
                    multiple
                    className="hidden"
                    onChange={(e) => {
                      const files = e.target.files;
                      if (files && files.length > 0) {
                        void onMultiFileUpload(files);
                      }
                      e.target.value = "";
                    }}
                  />
                </Label>
              )}
            </div>
          );
        })()}

        {noteFiles.map((file) => (
          <div
            key={file.slotIndex}
            className="relative h-20 w-24 rounded-md border bg-gray-800/70"
          >
            <div className="group relative h-full">
              {isImageFile(file.mimetype) ? (
                <Image
                  src={file.filepath}
                  alt={file.filename}
                  width={96}
                  height={80}
                  className="h-full w-full rounded-md object-cover"
                />
              ) : (
                <div className="flex h-full flex-col items-center justify-center p-2">
                  <FileIcon className="h-6 w-6 text-gray-400" />
                  <span className="mt-1 text-[10px] text-gray-400 truncate w-full text-center">
                    {file.filename.length > 12
                      ? file.filename.slice(0, 10) + "..."
                      : file.filename}
                  </span>
                </div>
              )}
              <div className="absolute inset-0 flex items-center justify-center gap-2 rounded-md bg-black/60 opacity-0 transition-opacity group-hover:opacity-100">
                <Button
                  type="button"
                  onClick={() => onInsertFileReference(file)}
                  className="rounded-full bg-blue-600 p-1.5 text-white hover:bg-blue-700"
                  title="Insert into content"
                >
                  <Link2 size={12} />
                </Button>
                <Button
                  type="button"
                  onClick={() => { void onFileDelete(file.slotIndex); }}
                  className="rounded-full bg-red-600 p-1.5 text-white hover:bg-red-700"
                  title="Delete file"
                >
                  <Trash2 size={12} />
                </Button>
              </div>
              <div className="absolute bottom-0 left-0 right-0 rounded-b-md bg-black/70 px-1 py-0.5 text-[9px] text-gray-300 truncate">
                {formatFileSize(file.size)}
              </div>
            </div>
          </div>
        ))}
      </div>
      <p className="text-xs text-gray-500">
        Drag and drop files or click to upload. Max 10MB per file.
      </p>
    </div>
  );
}

"use client";

import { useToast, Textarea } from "@/shared/ui";
import React from "react";

import { renderMarkdownToHtml } from "../../utils";

interface MarkdownEditorProps {
  content: string;
  setContent: (content: string) => void;
  showPreview: boolean;
  editorWidth: number | null;
  setEditorWidth: React.Dispatch<React.SetStateAction<number | null>>;
  isDraggingSplitter: boolean;
  setIsDraggingSplitter: (isDragging: boolean) => void;
  editorSplitRef: React.RefObject<HTMLDivElement | null>;
  contentRef: React.RefObject<HTMLTextAreaElement | null>;
  isPasting: boolean;
  contentBackground: string;
  contentTextColor: string;
  previewTypographyStyle: React.CSSProperties;
  onPaste: (e: React.ClipboardEvent<HTMLTextAreaElement>) => Promise<void>;
  setLightboxImage: (imgSrc: string | null) => void;
  isCodeMode?: boolean;
}

export function MarkdownEditor({
  content,
  setContent,
  showPreview,
  editorWidth,
  setEditorWidth,
  isDraggingSplitter,
  setIsDraggingSplitter,
  editorSplitRef,
  contentRef,
  isPasting,
  contentBackground,
  contentTextColor,
  previewTypographyStyle,
  onPaste,
  setLightboxImage,
  isCodeMode = false,
}: MarkdownEditorProps) {
  const { toast } = useToast();
  const [debouncedContentHtml, setDebouncedContentHtml] = React.useState<string>("");

  React.useEffect(() => {
    if (!showPreview) return;
    const timer = setTimeout(() => {
      setDebouncedContentHtml(renderMarkdownToHtml(content));
    }, 150); // 150ms debounce
    return () => clearTimeout(timer);
  }, [content, showPreview]);

  React.useEffect(() => {
    if (!showPreview) return;
    const container = editorSplitRef.current;
    if (!container) return;
    setEditorWidth((prev) => prev ?? Math.round(container.getBoundingClientRect().width / 2));
  }, [showPreview, editorSplitRef, setEditorWidth]);

  React.useEffect(() => {
    if (!isDraggingSplitter) return;
    const handlePointerMove = (event: PointerEvent) => {
      const container = editorSplitRef.current;
      if (!container) return;
      const rect = container.getBoundingClientRect();
      const minWidth = 260;
      const maxWidth = rect.width - 260;
      const nextWidth = Math.min(maxWidth, Math.max(minWidth, event.clientX - rect.left));
      setEditorWidth(nextWidth);
    };
    const handlePointerUp = () => {
      setIsDraggingSplitter(false);
    };
    window.addEventListener("pointermove", handlePointerMove);
    window.addEventListener("pointerup", handlePointerUp);
    return () => {
      window.removeEventListener("pointermove", handlePointerMove);
      window.removeEventListener("pointerup", handlePointerUp);
    };
  }, [isDraggingSplitter, editorSplitRef, setIsDraggingSplitter, setEditorWidth]);

  return (
    <div
      ref={editorSplitRef}
      className={`flex ${showPreview ? "gap-0" : ""}`}
    >
      <div
        className={showPreview ? "flex-shrink-0" : "flex-1"}
        style={showPreview && editorWidth ? { width: editorWidth } : undefined}
      >
        <div className="relative">
          <Textarea
            ref={contentRef}
            placeholder={isCodeMode
              ? "Enter code snippets using ```language blocks (e.g., ```javascript)"
              : "Enter note content (paste images directly!)"}
            value={content}
            onChange={(e) => setContent(e.target.value)}
            onPaste={(e) => { void onPaste(e); }}
            rows={12}
            className="w-full rounded-lg border px-4 py-2 font-mono"
            style={{
              backgroundColor: contentBackground,
              color: contentTextColor,
              ...(isCodeMode ? { fontFamily: 'ui-monospace, SFMono-Regular, "SF Mono", Menlo, Consolas, monospace' } : {})
            }}
            required
          />
          {isPasting && (
            <div className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-lg">
              <div className="flex items-center gap-2 text-white">
                <div className="h-5 w-5 animate-spin rounded-full border-2 border-gray-400 border-t-white" />
                <span className="text-sm">Uploading image...</span>
              </div>
            </div>
          )}
        </div>
      </div>
      {showPreview && (
        <>
          <div
            className="mx-3 flex w-3 cursor-col-resize items-stretch"
            onPointerDown={(event) => {
              event.preventDefault();
              setIsDraggingSplitter(true);
            }}
          >
            <div className="relative w-full rounded bg-gray-800/80 ring-1 ring-gray-600/70 hover:bg-gray-700">
              <span className="pointer-events-none absolute inset-0 flex items-center justify-center">
                <span className="h-6 w-px bg-gray-500/80" />
              </span>
            </div>
          </div>
          <div
            className="flex-1 rounded-lg border px-4 py-3"
            style={{ backgroundColor: contentBackground, color: contentTextColor }}
          >
            <div className="mb-2 text-xs uppercase tracking-wide text-gray-400">
              {isCodeMode ? "Code Preview" : "Preview"}
            </div>
            <div
              className="prose max-w-none [&_img]:cursor-pointer [&_img]:transition-opacity [&_img]:hover:opacity-80"
              style={previewTypographyStyle}
              dangerouslySetInnerHTML={{ __html: debouncedContentHtml }}
              onMouseOver={(e) => {
                const target = e.target;
                if (!(target instanceof HTMLElement)) return;
                const wrapper = target.closest("[data-code]");
                const button = wrapper?.querySelector("[data-copy-code]");
                if (button instanceof HTMLElement) button.style.opacity = "1";
              }}
              onMouseOut={(e) => {
                const target = e.target;
                if (!(target instanceof HTMLElement)) return;
                const wrapper = target.closest("[data-code]");
                const button = wrapper?.querySelector("[data-copy-code]");
                if (button instanceof HTMLElement) button.style.opacity = "0";
              }}
              onClick={(e) => {
                const target = e.target;
                if (!(target instanceof HTMLElement)) return;
                const copyButton = target.closest("[data-copy-code]");
                if (copyButton instanceof HTMLButtonElement) {
                  const wrapper = copyButton.closest("[data-code]");
                  const encoded = wrapper?.getAttribute("data-code");
                  if (!encoded) return;
                  const originalLabel = copyButton.textContent;
                  navigator.clipboard
                    .writeText(decodeURIComponent(encoded))
                    .then(() => {
                      copyButton.textContent = "Copied";
                      window.setTimeout(() => {
                        copyButton.textContent = originalLabel ?? "Copy";
                      }, 1500);
                    })
                    .catch(() => toast("Failed to copy code"));
                  return;
                }
                if (target instanceof HTMLImageElement && target.tagName === "IMG") {
                  const imgSrc = target.src;
                  setLightboxImage(imgSrc);
                }
              }}
            />
          </div>
        </>
      )}
    </div>
  );
}

"use client";

import { Button, Input, Label } from "@/shared/ui";
import { Undo, Redo } from "lucide-react";
import type { NoteFileRecord } from "@/shared/types/notes";



interface MarkdownToolbarProps {
  noteFiles: NoteFileRecord[];
  textColor: string;
  setTextColor: (color: string) => void;
  fontFamily: string;
  setFontFamily: (font: string) => void;
  showPreview: boolean;
  setShowPreview: (show: boolean) => void;
  onApplyWrap: (prefix: string, suffix: string, placeholder: string) => void;
  onApplyLinePrefix: (prefix: string) => void;
  onInsertAtCursor: (value: string) => void;
  onApplyBulletList: () => void;
  onApplyChecklist: () => void;
  onApplySpanStyle: (color: string, font: string) => void;
  onInsertFileReference: (file: NoteFileRecord) => void;
  onUndo?: () => void;
  onRedo?: () => void;
  canUndo?: boolean;
  canRedo?: boolean;
  editorMode: "markdown" | "wysiwyg" | "code";
  onEditorModeChange: (mode: "markdown" | "wysiwyg" | "code") => void;
  isEditorModeLocked?: boolean;
  isMigrating?: boolean;
  onMigrateToWysiwyg?: () => void;
  onMigrateToMarkdown?: () => void;
}

export function MarkdownToolbar({
  noteFiles,
  textColor,
  setTextColor,
  fontFamily,
  setFontFamily,
  showPreview,
  setShowPreview,
  onApplyWrap,
  onApplyLinePrefix,
  onInsertAtCursor,
  onApplyBulletList,
  onApplyChecklist,
  onApplySpanStyle,
  onInsertFileReference,
  onUndo,
  onRedo,
  canUndo = false,
  canRedo = false,
  editorMode,
  onEditorModeChange,
  isEditorModeLocked = false,
  isMigrating = false,
  onMigrateToWysiwyg,
  onMigrateToMarkdown,
}: MarkdownToolbarProps) {
  return (
    <div className="mb-2 flex flex-wrap items-center gap-2 rounded-lg border bg-gray-900 px-3 py-2">
      {/* Editor Mode Display/Toggle */}
      <div className="flex items-center gap-2">
        {isEditorModeLocked ? (
          <>
            {/* Display current mode (locked) */}
            <span className="px-2 py-1 text-xs bg-gray-800 text-gray-300 rounded border border-border/60">
              {editorMode === "markdown" ? "Markdown" : editorMode === "wysiwyg" ? "WYSIWYG" : "Code"}
            </span>
            {/* Migration buttons */}
            {editorMode === "markdown" && (
              <div className="flex gap-1">
                {onMigrateToWysiwyg && (
                  <Button
                    type="button"
                    onClick={onMigrateToWysiwyg}
                    disabled={isMigrating}
                    className="px-2 py-1 text-xs bg-purple-600/20 text-purple-300 border border-purple-500/40 rounded hover:bg-purple-600/30 disabled:opacity-50"
                    title="Convert this note to WYSIWYG format"
                  >
                    {isMigrating ? "Migrating..." : "To WYSIWYG"}
                  </Button>
                )}
              </div>
            )}
            {editorMode === "wysiwyg" && onMigrateToMarkdown && (
              <Button
                type="button"
                onClick={onMigrateToMarkdown}
                disabled={isMigrating}
                className="px-2 py-1 text-xs bg-purple-600/20 text-purple-300 border border-purple-500/40 rounded hover:bg-purple-600/30 disabled:opacity-50"
                title="Convert this note to Markdown format"
              >
                {isMigrating ? "Migrating..." : "To Markdown"}
              </Button>
            )}
            {editorMode === "code" && onMigrateToMarkdown && (
              <Button
                type="button"
                onClick={onMigrateToMarkdown}
                disabled={isMigrating}
                className="px-2 py-1 text-xs bg-purple-600/20 text-purple-300 border border-purple-500/40 rounded hover:bg-purple-600/30 disabled:opacity-50"
                title="Convert this note to Markdown format"
              >
                {isMigrating ? "Migrating..." : "To Markdown"}
              </Button>
            )}
          </>
        ) : (
          /* Mode toggle for new notes */
          <div className="flex rounded-md border border-border/60 overflow-hidden">
            <Button
              type="button"
              onClick={() => onEditorModeChange("markdown")}
              className={`px-2 py-1 text-xs transition-colors ${
                editorMode === "markdown"
                  ? "bg-blue-600 text-white"
                  : "bg-gray-800 text-gray-300 hover:bg-gray-700"
              }`}
              title="Markdown editor"
            >
              Markdown
            </Button>
            <Button
              type="button"
              onClick={() => onEditorModeChange("wysiwyg")}
              className={`px-2 py-1 text-xs transition-colors ${
                editorMode === "wysiwyg"
                  ? "bg-blue-600 text-white"
                  : "bg-gray-800 text-gray-300 hover:bg-gray-700"
              }`}
              title="WYSIWYG editor"
            >
              WYSIWYG
            </Button>
            <Button
              type="button"
              onClick={() => onEditorModeChange("code")}
              className={`px-2 py-1 text-xs transition-colors ${
                editorMode === "code"
                  ? "bg-green-600 text-white"
                  : "bg-gray-800 text-gray-300 hover:bg-gray-700"
              }`}
              title="Code snippets editor"
            >
              Code
            </Button>
          </div>
        )}
      </div>
      <div className="h-6 w-px bg-gray-700 mx-1" />
      {(editorMode === "markdown" || editorMode === "code") && (
        <>
          <Button
            type="button"
            onClick={() => setShowPreview(!showPreview)}
            className="rounded border bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
            title="Toggle preview"
          >
            {showPreview ? "Hide Preview" : "Show Preview"}
          </Button>
          <div className="h-6 w-px bg-gray-700 mx-1" />
      {onUndo && (
        <Button
          type="button"
          onClick={onUndo}
          disabled={!canUndo}
          className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
          title="Undo"
        >
          <Undo className="size-3.5" />
        </Button>
      )}
      {onRedo && (
        <Button
          type="button"
          onClick={onRedo}
          disabled={!canRedo}
          className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700 disabled:opacity-50 disabled:cursor-not-allowed"
          title="Redo"
        >
          <Redo className="size-3.5" />
        </Button>
      )}
      <div className="h-6 w-px bg-gray-700 mx-1" />
      <Button
        type="button"
        onClick={() => onApplyWrap("**", "**", "bold text")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Bold"
      >
        Bold
      </Button>
      <Button
        type="button"
        onClick={() => onApplyWrap("*", "*", "italic text")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Italic"
      >
        Italic
      </Button>
      <Button
        type="button"
        onClick={() => onApplyWrap("`", "`", "code")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Inline code"
      >
        Code
      </Button>
      <Button
        type="button"
        onClick={onApplyBulletList}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Bullet list"
      >
        Bullet
      </Button>
      <Button
        type="button"
        onClick={onApplyChecklist}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Checklist"
      >
        Checklist
      </Button>
      <Button
        type="button"
        onClick={() => onApplyLinePrefix("# ")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Heading"
      >
        H1
      </Button>
      <Button
        type="button"
        onClick={() => onApplyLinePrefix("## ")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Heading 2"
      >
        H2
      </Button>
      <Button
        type="button"
        onClick={() => onApplyLinePrefix("### ")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Heading 3"
      >
        H3
      </Button>
      <Button
        type="button"
        onClick={() => onApplyLinePrefix("> ")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Blockquote"
      >
        Quote
      </Button>
      <Button
        type="button"
        onClick={() => onInsertAtCursor("\n---\n")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Horizontal rule"
      >
        HR
      </Button>
      <Button
        type="button"
        onClick={() => onInsertAtCursor("\n```text\ncode\n```\n")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Code block"
      >
        Code Block
      </Button>
      <Button
        type="button"
        onClick={() => onApplyWrap("[", "](https://example.com)", "link text")}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Link"
      >
        Link
      </Button>
      <Button
        type="button"
        onClick={() =>
          onInsertAtCursor(
            "\n| Header | Header |\n| --- | --- |\n| Cell | Cell |\n")
        }
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Table"
      >
        Table
      </Button>
      {noteFiles.length > 0 && (
        <div className="relative">
          <select
            value=""
            onChange={(e) => {
              const slotIndex = parseInt(e.target.value, 10);
              const file = noteFiles.find((f) => f.slotIndex === slotIndex);
              if (file) {
                onInsertFileReference(file);
              }
              e.target.value = "";
            }}
            className="rounded border bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
            title="Insert file reference"
          >
            <option value="">Insert File</option>
            {noteFiles.map((file) => (
              <option key={file.slotIndex} value={file.slotIndex}>
                Slot {file.slotIndex + 1}: {file.filename.replace(/^slot-\d+-\d+-/, "").slice(0, 15)}
                {file.filename.replace(/^slot-\d+-\d+-/, "").length > 15 ? "..." : ""}
              </option>
            ))}
          </select>
        </div>
      )}
      <div className="ml-2 flex items-center gap-2 border-l border pl-2">
        <Label className="text-xs text-gray-400">Font</Label>
        <select
          value={fontFamily}
          onChange={(event) => setFontFamily(event.target.value)}
          className="rounded border bg-gray-800 px-2 py-1 text-xs text-gray-200"
        >
          <option value="inherit">Default</option>
          <option value="Georgia, serif">Serif</option>
          <option value="Trebuchet MS, sans-serif">Sans</option>
          <option value="Courier New, monospace">Mono</option>
        </select>
      </div>
      <div className="flex items-center gap-2">
        <Label className="text-xs text-gray-400">Color</Label>
        <Input
          type="color"
          value={textColor}
          onChange={(event) => setTextColor(event.target.value)}
          className="h-7 w-10 rounded border bg-gray-800"
        />
      </div>
      <Button
        type="button"
        onClick={() => onApplySpanStyle(textColor, fontFamily)}
        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-200 hover:bg-gray-700"
        title="Apply font and color"
      >
        Apply
      </Button>
        </>
      )}
    </div>
  );
}

"use client";

import { Button, Input, Label, Checkbox } from "@/shared/ui";
import React from "react";
import { X } from "lucide-react";
import type { TagRecord, NoteWithRelations, ThemeRecord } from "@/shared/types/notes";




interface NoteMetadataProps {
  title: string;
  setTitle: (title: string) => void;
  showTitle?: boolean;
  selectedFolderId: string;
  setSelectedFolderId: (id: string) => void;
  flatFolders: Array<{ id: string; name: string; level: number }>;
  color: string;
  setColor: (color: string) => void;
  isPinned: boolean;
  setIsPinned: (isPinned: boolean) => void;
  isArchived: boolean;
  setIsArchived: (isArchived: boolean) => void;
  isFavorite: boolean;
  setIsFavorite: (isFavorite: boolean) => void;
  selectedTagIds: string[];
  availableTags: TagRecord[];
  tagInput: string;
  setTagInput: (input: string) => void;
  isTagDropdownOpen: boolean;
  setIsTagDropdownOpen: (isOpen: boolean) => void;
  filteredTags: TagRecord[];
  onAddTag: (tag: TagRecord) => void;
  onCreateTag: () => Promise<void>;
  onRemoveTag: (tagId: string) => void;
  onTagClick?: ((tagId: string) => void) | undefined;
  selectedRelatedNotes: Array<{ id: string; title: string; color: string | null; content: string }>;
  setSelectedRelatedNotes: React.Dispatch<React.SetStateAction<Array<{ id: string; title: string; color: string | null; content: string }>>>;
  relatedNoteQuery: string;
  setRelatedNoteQuery: (query: string) => void;
  isRelatedDropdownOpen: boolean;
  setIsRelatedDropdownOpen: (isOpen: boolean) => void;
  relatedNoteResults: NoteWithRelations[];
  isRelatedLoading: boolean;
  onSelectRelatedNote: (noteId: string) => void;
  effectiveTheme: ThemeRecord;
  noteId?: string | undefined;
}

export function NoteMetadata({
  title,
  setTitle,
  showTitle = true,
  selectedFolderId,
  setSelectedFolderId,
  flatFolders,
  color,
  setColor,
  isPinned,
  setIsPinned,
  isArchived,
  setIsArchived,
  isFavorite,
  setIsFavorite,
  selectedTagIds,
  availableTags,
  tagInput,
  setTagInput,
  isTagDropdownOpen,
  setIsTagDropdownOpen,
  filteredTags,
  onAddTag,
  onCreateTag,
  onRemoveTag,
  onTagClick,
  selectedRelatedNotes,
  setSelectedRelatedNotes,
  relatedNoteQuery,
  setRelatedNoteQuery,
  isRelatedDropdownOpen,
  setIsRelatedDropdownOpen,
  relatedNoteResults,
  isRelatedLoading,
  onSelectRelatedNote,
  effectiveTheme,
  noteId,
}: NoteMetadataProps) {
  const tagInputRef = React.useRef<HTMLInputElement>(null);

  const relatedNoteStyle = {
    borderWidth: `${effectiveTheme.relatedNoteBorderWidth ?? 1}px`,
    borderColor: effectiveTheme.relatedNoteBorderColor,
    backgroundColor: effectiveTheme.relatedNoteBackgroundColor,
    color: effectiveTheme.relatedNoteTextColor,
  };

  return (
    <div className="space-y-4">
      {showTitle ? (
        <div>
          <Label className="mb-2 block text-sm font-medium text-white">
            Title
          </Label>
          <Input
            type="text"
            placeholder="Enter note title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full rounded-lg border bg-gray-800 px-4 py-2 text-white"
            required
          />
        </div>
      ) : null}

      <div>
        <Label className="mb-2 block text-sm font-medium text-white">Folder</Label>
        <select
          value={selectedFolderId}
          onChange={(e) => setSelectedFolderId(e.target.value)}
          className="w-full rounded-lg border bg-gray-800 px-4 py-2 text-white"
        >
          <option value="">No Folder</option>
          {flatFolders.map((folder) => (
            <option key={folder.id} value={folder.id}>
              {Array.from({ length: folder.level }).map(() => "- ").join("")}
              {folder.name}
            </option>
          ))}
        </select>
      </div>

      <div>
        <Label className="mb-2 block text-sm font-medium text-white">Color</Label>
        <div className="flex items-center gap-2">
          <Input
            type="color"
            value={color}
            onChange={(e) => setColor(e.target.value)}
            className="h-10 w-full cursor-pointer rounded-lg border bg-gray-800"
          />
          <Button
            type="button"
            onClick={() => setColor("#ffffff")}
            className="whitespace-nowrap rounded-lg border px-3 py-2 text-xs text-gray-200 hover:bg-muted/50"
            title="Use folder theme background"
          >
            Use Folder Theme
          </Button>
        </div>
      </div>

      <div className="space-y-2">
        <div className="flex flex-wrap gap-2">
          {selectedTagIds.map((tagId) => {
            const tag = availableTags.find((t) => t.id === tagId);
            if (!tag) return null;
            return (
              <span
                key={tag.id}
                className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-medium bg-blue-500/20 text-blue-200 border border-blue-500/30"
              >
                <Button
                  type="button"
                  onClick={() => onTagClick?.(tag.id)}
                  className="hover:text-white"
                >
                  {tag.name}
                </Button>
                <Button
                  type="button"
                  onClick={() => onRemoveTag(tag.id)}
                  className="hover:text-white"
                >
                  <X size={12} />
                </Button>
              </span>
            );
          })}
        </div>
        <div className="relative">
          <div className="flex gap-2">
            <Input
              ref={tagInputRef}
              type="text"
              placeholder={selectedTagIds.length === 0 ? "Tags" : "Add tag..."}
              value={tagInput}
              onChange={(e) => {
                setTagInput(e.target.value);
                setIsTagDropdownOpen(true);
              }}
              onFocus={() => setIsTagDropdownOpen(true)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  if (tagInput.trim()) {
                    void onCreateTag();
                  }
                }
              }}
              className="flex-1 rounded-none border-x-0 border-t border-b border bg-transparent px-0 py-2 text-white text-sm focus:outline-none focus:border-gray-500 placeholder:text-gray-500"
            />
          </div>

          {isTagDropdownOpen && (tagInput || filteredTags.length > 0) && (
            <div className="absolute z-10 mt-1 w-full rounded-md border bg-gray-800 shadow-lg">
              <ul className="max-h-60 overflow-auto py-1 text-sm text-gray-300">
                {filteredTags.map((tag) => (
                  <li
                    key={tag.id}
                    onClick={() => onAddTag(tag)}
                    className="cursor-pointer px-4 py-2 hover:bg-gray-700 hover:text-white"
                  >
                    {tag.name}
                  </li>
                ))}
                {tagInput &&
                  !filteredTags.find(
                    (t) => t.name.toLowerCase() === tagInput.toLowerCase()
                  ) && (
                    <li
                      onClick={() => void onCreateTag()}
                      className="cursor-pointer px-4 py-2 text-blue-400 hover:bg-gray-700"
                    >
                      Create &quot;{tagInput}&quot;
                    </li>
                  )}
              </ul>
            </div>
          )}
          {isTagDropdownOpen && (
            <div
              className="fixed inset-0 z-0"
              onClick={() => setIsTagDropdownOpen(false)}
            />
          )}
        </div>
      </div>

      <div className="space-y-2">
        <Label className="mb-2 block text-sm font-medium text-white">
          Related Notes
        </Label>
        <div className="flex flex-wrap gap-2">
          {selectedRelatedNotes.map((related) => (
            <div
              key={related.id}
              className="relative flex min-w-[180px] max-w-[240px] cursor-pointer flex-col gap-1 rounded-md border p-2 text-left transition"
              style={relatedNoteStyle}
              role="button"
              tabIndex={0}
              onClick={() => onSelectRelatedNote(related.id)}
              onKeyDown={(event) => {
                if (event.key === "Enter" || event.key === " ") {
                  event.preventDefault();
                  onSelectRelatedNote(related.id);
                }
              }}
            >
              <div className="text-xs font-semibold truncate">
                {related.title}
              </div>
              <div className="text-[11px] leading-snug max-h-8 overflow-hidden opacity-80">
                {related.content ? related.content : "No content"}
              </div>
              <Button
                type="button"
                onClick={(event) => {
                  event.stopPropagation();
                  setSelectedRelatedNotes((prev) =>
                    prev.filter((item) => item.id !== related.id)
                  );
                }}
                className="absolute right-1 top-1 opacity-70 hover:opacity-100"
                aria-label="Remove related note"
              >
                <X size={12} />
              </Button>
            </div>
          ))}
        </div>
        <div className="relative">
          <div className="flex gap-2">
            <Input
              type="text"
              placeholder="Search notes to relate..."
              value={relatedNoteQuery}
              onChange={(e) => {
                setRelatedNoteQuery(e.target.value);
                setIsRelatedDropdownOpen(true);
              }}
              onFocus={() => setIsRelatedDropdownOpen(true)}
              className="flex-1 rounded-none border-x-0 border-t border-b border bg-transparent px-0 py-2 text-white text-sm focus:outline-none focus:border-gray-500 placeholder:text-gray-500"
            />
          </div>

          {isRelatedDropdownOpen && relatedNoteQuery && (
            <div className="absolute z-10 mt-1 w-full rounded-md border bg-gray-800 shadow-lg">
              <ul className="max-h-60 overflow-auto py-1 text-sm text-gray-300">
                {isRelatedLoading && (
                  <li className="px-4 py-2 text-gray-500">Searching...</li>
                )}
                {relatedNoteResults
                  .filter((candidate) =>
                    noteId ? candidate.id !== noteId : true
                  )
                  .filter(
                    (candidate) =>
                      candidate.title
                        .toLowerCase()
                        .includes(relatedNoteQuery.toLowerCase()) &&
                      !selectedRelatedNotes.some(
                        (selected) => selected.id === candidate.id
                      )
                  )
                  .map((candidate) => (
                    <li
                      key={candidate.id}
                      onClick={() => {
                        setSelectedRelatedNotes((prev) => [
                          ...prev,
                          {
                            id: candidate.id,
                            title: candidate.title,
                            color: candidate.color ?? null,
                            content: candidate.content ?? "",
                          },
                        ]);
                        setRelatedNoteQuery("");
                        setIsRelatedDropdownOpen(false);
                      }}
                      className="cursor-pointer px-4 py-2 hover:bg-gray-700 hover:text-white"
                    >
                      {candidate.title}
                    </li>
                  ))}
                {!isRelatedLoading &&
                  relatedNoteResults.filter(
                    (candidate) =>
                      (noteId ? candidate.id !== noteId : true) &&
                      candidate.title
                        .toLowerCase()
                        .includes(relatedNoteQuery.toLowerCase()) &&
                      !selectedRelatedNotes.some(
                        (selected) => selected.id === candidate.id
                      )
                  ).length === 0 && (
                    <li className="px-4 py-2 text-gray-500">No matches</li>
                  )}
              </ul>
            </div>
          )}
          {isRelatedDropdownOpen && (
            <div
              className="fixed inset-0 z-0"
              onClick={() => setIsRelatedDropdownOpen(false)}
            />
          )}
        </div>
      </div>

      <div className="flex gap-4">
        <Label className="flex items-center gap-2 text-white">
          <Checkbox
            checked={isPinned} onCheckedChange={(checked) => setIsPinned(Boolean(checked))}
            className="rounded"
          />
          <span className="text-sm">Pinned</span>
        </Label>
        <Label className="flex items-center gap-2 text-white">
          <Checkbox
            checked={isArchived} onCheckedChange={(checked) => setIsArchived(Boolean(checked))}
            className="rounded"
          />
          <span className="text-sm">Archived</span>
        </Label>
        <Label className="flex items-center gap-2 text-white">
          <Checkbox
            checked={isFavorite} onCheckedChange={(checked) => setIsFavorite(Boolean(checked))}
            className="rounded"
          />
          <span className="text-sm">Favorite</span>
        </Label>
      </div>
    </div>
  );
}

"use client";

import { Button } from "@/shared/ui";
import React, { useEffect, useCallback, useRef } from "react";
import { useEditor, EditorContent } from "@tiptap/react";
import StarterKit from "@tiptap/starter-kit";
import Link from "@tiptap/extension-link";
import Image from "@tiptap/extension-image";
import TaskList from "@tiptap/extension-task-list";
import TaskItem from "@tiptap/extension-task-item";
import { Table } from "@tiptap/extension-table";
import { TableRow } from "@tiptap/extension-table-row";
import { TableCell } from "@tiptap/extension-table-cell";
import { TableHeader } from "@tiptap/extension-table-header";

import {
  Bold,
  Italic,
  Code,
  List,
  ListOrdered,
  CheckSquare,
  Heading1,
  Heading2,
  Heading3,
  Quote,
  Minus,
  Link as LinkIcon,
  Image as ImageIcon,
  Table as TableIcon,
  Undo,
  Redo,
} from "lucide-react";

interface WysiwygEditorProps {
  content: string;
  setContent: (content: string) => void;
  contentBackground: string;
  contentTextColor: string;
}

interface ToolbarButtonProps {
  onClick: () => void;
  isActive?: boolean;
  disabled?: boolean;
  title: string;
  children: React.ReactNode;
}

const ToolbarButton = ({
  onClick,
  isActive = false,
  disabled = false,
  title,
  children,
}: ToolbarButtonProps) => (
  <Button
    type="button"
    onClick={onClick}
    disabled={disabled}
    title={title}
    className={`rounded p-1.5 transition-colors ${
      isActive
        ? "bg-blue-600 text-white"
        : "bg-gray-800 text-gray-200 hover:bg-gray-700"
    } ${disabled ? "opacity-50 cursor-not-allowed" : ""}`}
  >
    {children}
  </Button>
);

const sanitizeContent = (html: string | undefined | null): string => {
  if (!html) return '';
  // Ensure content is a string
  if (typeof html !== 'string') return '';
  // Remove any script tags and potentially dangerous content
  const temp = document.createElement('div');
  temp.innerHTML = html;
  // Get safe HTML back
  return temp.innerHTML;
};

export function WysiwygEditor({
  content,
  setContent,
  contentBackground,
  contentTextColor,
}: WysiwygEditorProps) {
  const lastContentRef = useRef(content);

  const editor = useEditor({
    extensions: [
      StarterKit.configure({
        heading: {
          levels: [1, 2, 3],
        },
      }),
      Link.configure({
        openOnClick: false,
        HTMLAttributes: {
          class: "text-blue-400 underline hover:text-blue-300",
        },
      }),
      Image.configure({
        HTMLAttributes: {
          class: "max-w-full rounded-lg",
        },
      }),
      TaskList,
      TaskItem.configure({
        nested: true,
      }),
      Table.configure({
        resizable: true,
      }),
      TableRow,
      TableCell,
      TableHeader,
    ],
    content: sanitizeContent(content),
    editorProps: {
      attributes: {
        class:
          "prose prose-invert max-w-none min-h-[200px] focus:outline-none px-4 py-3",
      },
    },
    onUpdate: ({ editor }) => {
      // Convert HTML to markdown-like format for storage
      const html = editor.getHTML();
      if (html !== lastContentRef.current) {
        lastContentRef.current = html;
        setContent(html);
      }
    },
  });

  // Update editor content when content prop changes externally
  useEffect(() => {
    if (!editor || content === lastContentRef.current) {
      return;
    }
    const sanitized = sanitizeContent(content);
    if (sanitized !== editor.getHTML()) {
      try {
        lastContentRef.current = content;
        editor.commands.setContent(sanitized, { emitUpdate: false });
      } catch (error) {
        console.error("Failed to set WYSIWYG content:", error);
        // Try to recover by clearing and setting plain text
        try {
          editor.commands.clearContent();
          if (typeof content === 'string' && content.trim()) {
            editor.commands.insertContent(sanitizeContent(content));
          }
        } catch (fallbackError) {
          console.error("Failed to recover from WYSIWYG error:", fallbackError);
        }
      }
    }
  }, [content, editor]);

  const addLink = useCallback(() => {
    if (!editor) return;
    const url = window.prompt("Enter URL:");
    if (url) {
      editor.chain().focus().setLink({ href: url }).run();
    }
  }, [editor]);

  const addImage = useCallback(() => {
    if (!editor) return;
    const url = window.prompt("Enter image URL:");
    if (url) {
      editor.chain().focus().setImage({ src: url }).run();
    }
  }, [editor]);

  const addTable = useCallback(() => {
    if (!editor) return;
    editor
      .chain()
      .focus()
      .insertTable({ rows: 3, cols: 3, withHeaderRow: true })
      .run();
  }, [editor]);

  if (!editor) {
    return (
      <div
        className="w-full rounded-lg border px-4 py-3 min-h-[200px]"
        style={{ backgroundColor: contentBackground, color: contentTextColor }}
      >
        <div className="text-gray-400 text-sm">Loading editor...</div>
      </div>
    );
  }

  return (
    <div className="space-y-2">
      {/* WYSIWYG Toolbar */}
      <div className="flex flex-wrap items-center gap-1 rounded-lg border bg-gray-900 px-3 py-2">
        {/* Undo/Redo */}
        <ToolbarButton
          onClick={() => editor.chain().focus().undo().run()}
          disabled={!editor.can().undo()}
          title="Undo"
        >
          <Undo className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().redo().run()}
          disabled={!editor.can().redo()}
          title="Redo"
        >
          <Redo className="size-4" />
        </ToolbarButton>

        <div className="h-6 w-px bg-gray-700 mx-1" />

        {/* Text formatting */}
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleBold().run()}
          isActive={editor.isActive("bold")}
          title="Bold"
        >
          <Bold className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleItalic().run()}
          isActive={editor.isActive("italic")}
          title="Italic"
        >
          <Italic className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleCode().run()}
          isActive={editor.isActive("code")}
          title="Inline Code"
        >
          <Code className="size-4" />
        </ToolbarButton>

        <div className="h-6 w-px bg-gray-700 mx-1" />

        {/* Headings */}
        <ToolbarButton
          onClick={() =>
            editor.chain().focus().toggleHeading({ level: 1 }).run()
          }
          isActive={editor.isActive("heading", { level: 1 })}
          title="Heading 1"
        >
          <Heading1 className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() =>
            editor.chain().focus().toggleHeading({ level: 2 }).run()
          }
          isActive={editor.isActive("heading", { level: 2 })}
          title="Heading 2"
        >
          <Heading2 className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() =>
            editor.chain().focus().toggleHeading({ level: 3 }).run()
          }
          isActive={editor.isActive("heading", { level: 3 })}
          title="Heading 3"
        >
          <Heading3 className="size-4" />
        </ToolbarButton>

        <div className="h-6 w-px bg-gray-700 mx-1" />

        {/* Lists */}
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleBulletList().run()}
          isActive={editor.isActive("bulletList")}
          title="Bullet List"
        >
          <List className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleOrderedList().run()}
          isActive={editor.isActive("orderedList")}
          title="Numbered List"
        >
          <ListOrdered className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleTaskList().run()}
          isActive={editor.isActive("taskList")}
          title="Task List"
        >
          <CheckSquare className="size-4" />
        </ToolbarButton>

        <div className="h-6 w-px bg-gray-700 mx-1" />

        {/* Block elements */}
        <ToolbarButton
          onClick={() => editor.chain().focus().toggleBlockquote().run()}
          isActive={editor.isActive("blockquote")}
          title="Quote"
        >
          <Quote className="size-4" />
        </ToolbarButton>
        <ToolbarButton
          onClick={() => editor.chain().focus().setHorizontalRule().run()}
          title="Horizontal Rule"
        >
