"use client";

import { createContext, useContext, useState, useEffect, useRef, ReactNode } from "react";
import type { NoteSettings } from "@/features/notesapp/types/notes-settings";

export const DEFAULT_NOTE_SETTINGS: NoteSettings = {
  sortBy: "created",
  sortOrder: "desc",
  showTimestamps: true,
  showBreadcrumbs: true,
  showRelatedNotes: true,
  searchScope: "both",
  selectedFolderId: null,
  selectedNotebookId: null,
  viewMode: "grid",
  gridDensity: 4,
  autoformatOnPaste: false,
  editorMode: "markdown",
};

const STORAGE_KEY = "noteSettings";
const DB_SETTING_KEY = "noteSettings:selectedFolderId";
const DB_NOTEBOOK_KEY = "noteSettings:selectedNotebookId";
const DB_AUTOFORMAT_KEY = "noteSettings:autoformatOnPaste";
const DB_EDITOR_MODE_KEY = "noteSettings:editorMode";

interface NoteSettingsContextType {
  settings: NoteSettings;
  updateSettings: (updates: Partial<NoteSettings>) => void;
  resetToDefaults: () => void;
}

const NoteSettingsContext = createContext<NoteSettingsContextType | undefined>(
  undefined
);

// Helper to save selectedFolderId to database
async function saveSelectedFolderToDb(folderId: string | null): Promise<void> {
  try {
    await fetch("/api/settings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        key: DB_SETTING_KEY,
        value: folderId ?? "",
      }),
    });
  } catch (error) {
    console.error("Failed to save selectedFolderId to database:", error);
  }
}

async function saveSelectedNotebookToDb(notebookId: string | null): Promise<void> {
  try {
    await fetch("/api/settings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        key: DB_NOTEBOOK_KEY,
        value: notebookId ?? "",
      }),
    });
  } catch (error) {
    console.error("Failed to save selectedNotebookId to database:", error);
  }
}

// Helper to load selectedFolderId from database
async function loadSelectedFolderFromDb(): Promise<string | null> {
  try {
    const response = await fetch("/api/settings");
    if (!response.ok) return null;

    const settings = await response.json() as Array<{ key: string; value: string }>;
    const setting = settings.find((s) => s.key === DB_SETTING_KEY);

    if (setting && setting.value) {
      return setting.value;
    }
    return null;
  } catch (error) {
    console.error("Failed to load selectedFolderId from database:", error);
    return null;
  }
}

async function loadSelectedNotebookFromDb(): Promise<string | null> {
  try {
    const response = await fetch("/api/settings");
    if (!response.ok) return null;

    const settings = await response.json() as Array<{ key: string; value: string }>;
    const setting = settings.find((s) => s.key === DB_NOTEBOOK_KEY);

    if (setting && setting.value) {
      return setting.value;
    }
    return null;
  } catch (error) {
    console.error("Failed to load selectedNotebookId from database:", error);
    return null;
  }
}

async function saveAutoformatToDb(enabled: boolean): Promise<void> {
  try {
    await fetch("/api/settings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        key: DB_AUTOFORMAT_KEY,
        value: enabled ? "true" : "false",
      }),
    });
  } catch (error) {
    console.error("Failed to save autoformatOnPaste to database:", error);
  }
}

async function loadAutoformatFromDb(): Promise<boolean | null> {
  try {
    const response = await fetch("/api/settings");
    if (!response.ok) return null;

    const settings = await response.json() as Array<{ key: string; value: string }>;
    const setting = settings.find((s) => s.key === DB_AUTOFORMAT_KEY);

    if (setting && setting.value) {
      return setting.value === "true";
    }
    return null;
  } catch (error) {
    console.error("Failed to load autoformatOnPaste from database:", error);
    return null;
  }
}

async function saveEditorModeToDb(mode: "markdown" | "wysiwyg" | "code"): Promise<void> {
  try {
    await fetch("/api/settings", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        key: DB_EDITOR_MODE_KEY,
        value: mode,
      }),
    });
  } catch (error) {
    console.error("Failed to save editorMode to database:", error);
  }
}

async function loadEditorModeFromDb(): Promise<"markdown" | "wysiwyg" | "code" | null> {
  try {
    const response = await fetch("/api/settings");
    if (!response.ok) return null;

    const settings = await response.json() as Array<{ key: string; value: string }>;
    const setting = settings.find((s) => s.key === DB_EDITOR_MODE_KEY);

    if (setting && (setting.value === "markdown" || setting.value === "wysiwyg" || setting.value === "code")) {
      return setting.value;
    }
    return null;
  } catch (error) {
    console.error("Failed to load editorMode from database:", error);
    return null;
  }
}

export function NoteSettingsProvider({ children }: { children: ReactNode }) {
  const [settings, setSettings] = useState<NoteSettings>(DEFAULT_NOTE_SETTINGS);
  const [isInitialized, setIsInitialized] = useState(false);
  const previousFolderIdRef = useRef<string | null>(null);
  const previousNotebookIdRef = useRef<string | null>(null);
  const previousAutoformatRef = useRef<boolean>(false);
  const previousEditorModeRef = useRef<"markdown" | "wysiwyg" | "code">("markdown");

  // Load settings from localStorage first (fast), then from database (authoritative)
  useEffect(() => {
    if (typeof window === "undefined") return;

    const loadSettings = async () => {
      // First, load from localStorage for immediate UI
      try {
        const stored = window.localStorage.getItem(STORAGE_KEY);
        if (stored) {
          const parsed = JSON.parse(stored) as Partial<NoteSettings>;
          setSettings((prev) => ({ ...prev, ...parsed }));
          previousFolderIdRef.current = parsed.selectedFolderId ?? null;
          previousNotebookIdRef.current = parsed.selectedNotebookId ?? null;
        }
      } catch (error) {
        console.error("Failed to load note settings from localStorage:", error);
      }

      // Then, load selectedFolderId from database (authoritative source)
      const dbFolderId = await loadSelectedFolderFromDb();
      if (dbFolderId !== null) {
        setSettings((prev) => ({ ...prev, selectedFolderId: dbFolderId }));
        previousFolderIdRef.current = dbFolderId;
        // Update localStorage cache
        try {
          const stored = window.localStorage.getItem(STORAGE_KEY);
          const current = (stored ? JSON.parse(stored) : {}) as Record<string, unknown>;
          window.localStorage.setItem(
            STORAGE_KEY,
            JSON.stringify({ ...current, selectedFolderId: dbFolderId })
          );
        } catch (error) {
          console.error("Failed to update localStorage cache:", error);
        }
      }

      setIsInitialized(true);

      // Load selectedNotebookId from database
      const dbNotebookId = await loadSelectedNotebookFromDb();
      if (dbNotebookId !== null) {
        setSettings((prev) => ({ ...prev, selectedNotebookId: dbNotebookId }));
        previousNotebookIdRef.current = dbNotebookId;
        try {
          const stored = window.localStorage.getItem(STORAGE_KEY);
          const current = (stored ? JSON.parse(stored) : {}) as Record<string, unknown>;
          window.localStorage.setItem(
            STORAGE_KEY,
            JSON.stringify({ ...current, selectedNotebookId: dbNotebookId })
          );
        } catch (error) {
          console.error("Failed to update localStorage cache:", error);
        }
      }

      // Load autoformatOnPaste from database
      const dbAutoformat = await loadAutoformatFromDb();
      if (dbAutoformat !== null) {
        setSettings((prev) => ({ ...prev, autoformatOnPaste: dbAutoformat }));
        previousAutoformatRef.current = dbAutoformat;
        try {
          const stored = window.localStorage.getItem(STORAGE_KEY);
          const current = (stored ? JSON.parse(stored) : {}) as Record<string, unknown>;
          window.localStorage.setItem(
            STORAGE_KEY,
            JSON.stringify({ ...current, autoformatOnPaste: dbAutoformat })
          );
        } catch (error) {
          console.error("Failed to update localStorage cache:", error);
        }
      }

      // Load editorMode from database
      const dbEditorMode = await loadEditorModeFromDb();
      if (dbEditorMode !== null) {
        setSettings((prev) => ({ ...prev, editorMode: dbEditorMode }));
        previousEditorModeRef.current = dbEditorMode;
        try {
          const stored = window.localStorage.getItem(STORAGE_KEY);
          const current = (stored ? JSON.parse(stored) : {}) as Record<string, unknown>;
          window.localStorage.setItem(
            STORAGE_KEY,
            JSON.stringify({ ...current, editorMode: dbEditorMode })
          );
        } catch (error) {
          console.error("Failed to update localStorage cache:", error);
        }
      }
    };

    void loadSettings();
  }, []);

  // Save settings to localStorage whenever they change
  useEffect(() => {
    if (!isInitialized || typeof window === "undefined") return;

    try {
      window.localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
    } catch (error) {
      console.error("Failed to save note settings:", error);
    }
  }, [settings, isInitialized]);

  // Save selectedFolderId to database when it changes
  useEffect(() => {
    if (!isInitialized) return;

    // Only save to DB if the folder actually changed
    if (settings.selectedFolderId !== previousFolderIdRef.current) {
      previousFolderIdRef.current = settings.selectedFolderId;
      void saveSelectedFolderToDb(settings.selectedFolderId);
    }
  }, [settings.selectedFolderId, isInitialized]);

  useEffect(() => {
    if (!isInitialized) return;
    if (settings.selectedNotebookId !== previousNotebookIdRef.current) {
      previousNotebookIdRef.current = settings.selectedNotebookId;
      void saveSelectedNotebookToDb(settings.selectedNotebookId);
    }
  }, [settings.selectedNotebookId, isInitialized]);

  // Save autoformatOnPaste to database when it changes
  useEffect(() => {
    if (!isInitialized) return;
    if (settings.autoformatOnPaste !== previousAutoformatRef.current) {
      previousAutoformatRef.current = settings.autoformatOnPaste;
      void saveAutoformatToDb(settings.autoformatOnPaste);
    }
  }, [settings.autoformatOnPaste, isInitialized]);

  // Save editorMode to database when it changes
  useEffect(() => {
    if (!isInitialized) return;
    if (settings.editorMode !== previousEditorModeRef.current) {
      previousEditorModeRef.current = settings.editorMode;
      void saveEditorModeToDb(settings.editorMode);
    }
  }, [settings.editorMode, isInitialized]);

  const updateSettings = (updates: Partial<NoteSettings>) => {
    setSettings((prev) => ({ ...prev, ...updates }));
  };

  const resetToDefaults = () => {
    setSettings(DEFAULT_NOTE_SETTINGS);
    // Also clear the database values
    void saveSelectedFolderToDb(null);
    void saveSelectedNotebookToDb(null);
    void saveAutoformatToDb(false);
    void saveEditorModeToDb("markdown");
  };

  return (
    <NoteSettingsContext.Provider
      value={{ settings, updateSettings, resetToDefaults }}
    >
      {children}
    </NoteSettingsContext.Provider>
  );
}

export function useNoteSettings() {
  const context = useContext(NoteSettingsContext);
  if (context === undefined) {
    throw new Error("useNoteSettings must be used within a NoteSettingsProvider");
  }
  return context;
}

import { useToast } from "@/shared/ui";
import { useState, useEffect } from "react";

// Why: Editor mode (markdown/wysiwyg) has complex migration logic:
// - Existing notes lock to their type
// - New notes use preferences
// - Conversion requires async HTML/Markdown transformation
// - Migration involves API calls and content updates
// Extracting this prevents NoteForm bloat and makes migrations testable.
export function useEditorMode(
  note: { id?: string; editorType?: string; content?: string } | null,
  settingsEditorMode: "markdown" | "wysiwyg" | "code"
) {
  const { toast } = useToast();
  const [editorMode, setEditorMode] = useState<"markdown" | "wysiwyg" | "code">(
    (note?.editorType as "markdown" | "wysiwyg" | "code") || settingsEditorMode
  );
  const [isMigrating, setIsMigrating] = useState(false);

  // Sync editor mode from note's editorType
  useEffect(() => {
    if (note?.editorType) {
      setEditorMode(note.editorType as "markdown" | "wysiwyg" | "code");
    } else {
      setEditorMode(settingsEditorMode);
    }
  }, [note?.id, note?.editorType, settingsEditorMode]);

  const isEditorModeLocked = Boolean(note?.id);

  const handleEditorModeChange = (mode: "markdown" | "wysiwyg" | "code") => {
    if (!note?.id) {
      setEditorMode(mode);
    }
  };

  const convertMarkdownToHtml = (markdown: string): string => {
    let html = markdown;
    html = html.replace(/^### (.+)$/gm, "<h3>$1</h3>");
    html = html.replace(/^## (.+)$/gm, "<h2>$1</h2>");
    html = html.replace(/^# (.+)$/gm, "<h1>$1</h1>");
    html = html.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");
    html = html.replace(/\*(.+?)\*/g, "<em>$1</em>");
    html = html.replace(/`(.+?)`/g, "<code>$1</code>");
    html = html.replace(/^- (.+)$/gm, "<li>$1</li>");
    html = html.replace(/(<li>.*<\/li>\n?)+/g, "<ul>$&</ul>");
    html = html
      .split("\n\n")
      .map((p) => {
        if (!p.startsWith("<")) return `<p>${p}</p>`;
        return p;
      })
      .join("\n");
    return html;
  };

  const convertHtmlToMarkdown = async (html: string): Promise<string> => {
    const TurndownService = (await import("turndown")).default;
    const turndownService = new TurndownService({
      headingStyle: "atx",
      codeBlockStyle: "fenced",
    });
    return turndownService.turndown(html);
  };

  const handleMigrateToWysiwyg = async (
    content: string,
    onSuccess?: () => void
  ) => {
    if (!note?.id) return;

    setIsMigrating(true);
    try {
      const htmlContent = convertMarkdownToHtml(content);

      const res = await fetch(`/api/notes/${note.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          content: htmlContent,
          editorType: "wysiwyg",
        }),
      });

      if (!res.ok) {
        throw new Error("Failed to migrate note");
      }

      setEditorMode("wysiwyg");
      toast("Note migrated to WYSIWYG format", { variant: "success" });
      onSuccess?.();
      return htmlContent;
    } catch {
      toast("Failed to migrate note", { variant: "error" });
      throw new Error("Migration failed");
    } finally {
      setIsMigrating(false);
    }
  };

  const handleMigrateToMarkdown = async (
    content: string,
    onSuccess?: () => void
  ) => {
    if (!note?.id) return;

    setIsMigrating(true);
    try {
      const markdownContent = await convertHtmlToMarkdown(content);

      const res = await fetch(`/api/notes/${note.id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          content: markdownContent,
          editorType: "markdown",
        }),
      });

      if (!res.ok) {
        throw new Error("Failed to migrate note");
      }

      setEditorMode("markdown");
      toast("Note migrated to Markdown format", { variant: "success" });
      onSuccess?.();
      return markdownContent;
    } catch {
      toast("Failed to migrate note", { variant: "error" });
      throw new Error("Migration failed");
    } finally {
      setIsMigrating(false);
    }
  };

  return {
    editorMode,
    setEditorMode: handleEditorModeChange,
    isEditorModeLocked,
    isMigrating,
    handleMigrateToWysiwyg,
    handleMigrateToMarkdown,
  };
}

"use client";

import { useEffect, useMemo, useRef, useCallback } from "react";
import { useQueryClient } from "@tanstack/react-query";
import type { UseNoteDataProps } from "@/features/notesapp/types/notes-hooks";
import type { NotebookRecord, NoteWithRelations } from "@/shared/types/notes";
import { getCategoryIdsWithDescendants } from "../utils";
import {
  useNotebooks,
  useNoteFolderTree,
  useNoteTags,
  useNoteThemes,
  useNotes,
  type FetchNotesParams,
} from "@/features/notesapp/api/useNoteQueries";

export function useNoteData({
  selectedNotebookId,
  selectedFolderId,
  searchQuery,
  searchScope,
  filterPinned,
  filterArchived,
  filterFavorite,
  filterTagIds,
  setSelectedNotebookId,
}: UseNoteDataProps) {
  const queryClient = useQueryClient();

  // Queries
  const notebooksQuery = useNotebooks();
  const folderTreeQuery = useNoteFolderTree(selectedNotebookId ?? undefined);
  const tagsQuery = useNoteTags(selectedNotebookId ?? undefined);
  const themesQuery = useNoteThemes(selectedNotebookId ?? undefined);

  const folderTree = useMemo(() => folderTreeQuery.data ?? [], [folderTreeQuery.data]);
  const folderTreeRef = useRef(folderTree);

  useEffect(() => {
    folderTreeRef.current = folderTree;
  }, [folderTree]);

  // Derived category IDs for notes filter
  const categoryIds = useMemo(() => {
    if (!selectedFolderId) return [];
    const descendantIds = getCategoryIdsWithDescendants(selectedFolderId, folderTree);
    return descendantIds.length > 0 ? descendantIds : [selectedFolderId];
  }, [selectedFolderId, folderTree]);

  const notesParams = useMemo(() => {
    const params: FetchNotesParams = {
      search: searchQuery,
      searchScope,
      isPinned: filterPinned,
      isArchived: filterArchived,
      isFavorite: filterFavorite,
      tagIds: filterTagIds,
      categoryIds,
    };
    if (selectedNotebookId) {
      params.notebookId = selectedNotebookId;
    }
    return params;
  }, [
    selectedNotebookId,
    searchQuery,
    searchScope,
    filterPinned,
    filterArchived,
    filterFavorite,
    filterTagIds,
    categoryIds,
  ]);

  const notesQuery = useNotes(notesParams);

  const notes = useMemo(() => notesQuery.data ?? [], [notesQuery.data]);
  const notesRef = useRef(notes);

  useEffect(() => {
    notesRef.current = notes;
  }, [notes]);

  // Load initial notebook if none selected
  useEffect(() => {
    if (selectedNotebookId) return;
    const firstNotebook = notebooksQuery.data?.[0];
    if (firstNotebook) {
      setSelectedNotebookId(firstNotebook.id);
    }
  }, [selectedNotebookId, notebooksQuery.data, setSelectedNotebookId]);

  const notebook = useMemo(() => 
    notebooksQuery.data?.find(n => n.id === selectedNotebookId) ?? null,
    [notebooksQuery.data, selectedNotebookId]
  );

  const setNotes = useCallback((updater: NoteWithRelations[] | ((prev: NoteWithRelations[]) => NoteWithRelations[])) => {
    queryClient.setQueryData(["notes", notesParams], updater);
  }, [queryClient, notesParams]);

  const setNotebook = useCallback((updated: NotebookRecord) => {
    queryClient.setQueryData(["notebooks"], (prev: NotebookRecord[] | undefined) => {
      if (!prev) return [updated];
      return prev.map(n => n.id === updated.id ? updated : n);
    });
  }, [queryClient]);

  return {
    notes,
    setNotes,
    tags: tagsQuery.data ?? [],
    themes: themesQuery.data ?? [],
    notebook,
    setNotebook,
    folderTree,
    loading: notesQuery.isLoading || folderTreeQuery.isLoading || notebooksQuery.isLoading,
    folderTreeRef,
    notesRef,
    fetchNotes: async () => { await notesQuery.refetch(); },
    fetchFolderTree: async () => { await folderTreeQuery.refetch(); },
    fetchTags: async () => { await tagsQuery.refetch(); },
    fetchThemes: async () => { await themesQuery.refetch(); },
  };
}

import { useState } from "react";
import type { NoteFileRecord } from "@/shared/types/notes";

// Why: File attachment management has multiple interdependent states:
// - Upload slots track in-progress uploads
// - Multiple files can be attached with validation
// - Lightbox for preview management
// - Paste handling for direct image insertion
// Extracting prevents form component bloat and makes attachment logic testable.
export function useNoteFileAttachments(initialFiles: NoteFileRecord[] = []) {
  const [noteFiles, setNoteFiles] = useState<NoteFileRecord[]>(initialFiles);
  const [uploadingSlots, setUploadingSlots] = useState<Set<number>>(new Set());
  const [lightboxImage, setLightboxImage] = useState<string | null>(null);
  const [isPasting, setIsPasting] = useState(false);

  const MAX_SLOTS = 10;

  const addUploadingSlot = (slotIndex: number) => {
    setUploadingSlots((prev) => new Set([...prev, slotIndex]));
  };

  const removeUploadingSlot = (slotIndex: number) => {
    setUploadingSlots((prev) => {
      const next = new Set(prev);
      next.delete(slotIndex);
      return next;
    });
  };

  const isSlotUploading = (slotIndex: number) => uploadingSlots.has(slotIndex);

  const canAddMoreFiles = () => noteFiles.length < MAX_SLOTS;

  const addFile = (file: NoteFileRecord) => {
    if (canAddMoreFiles()) {
      setNoteFiles((prev) => [...prev, file]);
      return true;
    }
    return false;
  };

  const removeFile = (fileId: string) => {
    setNoteFiles((prev) => prev.filter((f) => f.id !== fileId));
  };

  const updateFile = (fileId: string, updates: Partial<NoteFileRecord>) => {
    setNoteFiles((prev) =>
      prev.map((f) => (f.id === fileId ? { ...f, ...updates } : f))
    );
  };

  const openLightbox = (imageUrl: string) => {
    setLightboxImage(imageUrl);
  };

  const closeLightbox = () => {
    setLightboxImage(null);
  };

  return {
    noteFiles,
    setNoteFiles,
    uploadingSlots,
    addUploadingSlot,
    removeUploadingSlot,
    isSlotUploading,
    lightboxImage,
    openLightbox,
    closeLightbox,
    isPasting,
    setIsPasting,
    MAX_SLOTS,
    canAddMoreFiles,
    addFile,
    removeFile,
    updateFile,
  };
}

import { useState, useEffect, useCallback } from "react";
import type { UseNoteFiltersProps } from "@/features/notesapp/types/notes-hooks";
import type { NoteWithRelations } from "@/shared/types/notes";

export function useNoteFilters({ settings, updateSettings: _updateSettings }: UseNoteFiltersProps) {
  const [searchQuery, setSearchQuery] = useState("");
  const [debouncedSearchQuery, setDebouncedSearchQuery] = useState(searchQuery);
  const [filterPinned, setFilterPinned] = useState<boolean | undefined>(undefined);
  const [filterArchived, setFilterArchived] = useState<boolean | undefined>(undefined);
  const [filterFavorite, setFilterFavorite] = useState<boolean | undefined>(undefined);
  const [filterTagIds, setFilterTagIds] = useState<string[]>([]);
  const [highlightTagId, setHighlightTagId] = useState<string | null>(null);

  // Pagination
  const [page, setPage] = useState(1);
  const [pageSize, setPageSize] = useState(24);

  // Debounce search
  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedSearchQuery(searchQuery);
    }, 250);
    return () => clearTimeout(timer);
  }, [searchQuery]);

  // Reset page when filters change
  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setPage(1);
  }, [
    debouncedSearchQuery,
    filterPinned,
    filterArchived,
    filterTagIds,
    settings.selectedFolderId,
    settings.sortBy,
    settings.sortOrder,
    settings.selectedNotebookId,
  ]);

  // Clear highlight tag
  useEffect(() => {
    if (!highlightTagId) return;
    const timer = setTimeout(() => {
      setHighlightTagId(null);
    }, 2000);
    return () => clearTimeout(timer);
  }, [highlightTagId]);

  const handleFilterByTag = useCallback((tagId: string, setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => {
    setSelectedFolderId(null);
    setFilterTagIds([tagId]);
    setSearchQuery("");
    setSelectedNote(null);
    setIsEditing(false);
    setHighlightTagId(tagId);
  }, []);

  const handleToggleFavoritesFilter = useCallback((setSelectedFolderId: (id: string | null) => void, setSelectedNote: (val: NoteWithRelations | null) => void, setIsEditing: (val: boolean) => void) => {
    setFilterFavorite((prev) => (prev ? undefined : true));
    setSelectedFolderId(null);
    setSelectedNote(null);
    setIsEditing(false);
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    debouncedSearchQuery,
    filterPinned,
    setFilterPinned,
    filterArchived,
    setFilterArchived,
    filterFavorite,
    setFilterFavorite,
    filterTagIds,
    setFilterTagIds,
    highlightTagId,
    setHighlightTagId,
    page,
    setPage,
    pageSize,
    setPageSize,
    handleFilterByTag,
    handleToggleFavoritesFilter,
  };
}

import { useState } from "react";

// Why: Note metadata (title, color, status flags) has synchronized state:
// - Title syncs when note changes
// - Color requires normalization and contrast calculation
// - Pins/archives/favorites need reactive updates
// Extracting prevents prop drilling and makes metadata updates testable.
export function useNoteMetadata(note: { id?: string; title?: string; color?: string | null; isPinned?: boolean; isArchived?: boolean; isFavorite?: boolean } | null) {
  const [title, setTitle] = useState(note?.title || "");
  const [color, setColor] = useState(note?.color?.toLowerCase().trim() || "#ffffff");
  const [isPinned, setIsPinned] = useState(note?.isPinned || false);
  const [isArchived, setIsArchived] = useState(note?.isArchived || false);
  const [isFavorite, setIsFavorite] = useState(note?.isFavorite || false);

  const [prevNoteId, setPrevNoteId] = useState(note?.id);

  // Sync when note changes - adjusting state during render
  if (note?.id !== prevNoteId) {
    setPrevNoteId(note?.id);
    setTitle(note?.title || "");
    setColor(note?.color?.toLowerCase().trim() || "#ffffff");
    setIsPinned(note?.isPinned || false);
    setIsArchived(note?.isArchived || false);
    setIsFavorite(note?.isFavorite || false);
  }

  const getReadableTextColor = (hex: string) => {
    const normalized = hex.replace("#", "");
    if (normalized.length !== 6) return "#f8fafc";
    const num = parseInt(normalized, 16);
    const r = (num >> 16) & 0xff;
    const g = (num >> 8) & 0xff;
    const b = num & 0xff;
    const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
    return luminance > 0.7 ? "#0f172a" : "#f8fafc";
  };

  return {
    title,
    setTitle,
    color,
    setColor,
    isPinned,
    setIsPinned,
    isArchived,
    setIsArchived,
    isFavorite,
    setIsFavorite,
    getReadableTextColor,
  };
}

import { useCallback } from "react";
import type { NoteWithRelations } from "@/shared/types/notes";
import type { UseNoteOperationsProps } from "@/features/notesapp/types/notes-hooks";
import { findFolderParentId, findFolderById } from "@/features/foldertree";

export function useNoteOperations({
  selectedNotebookId,
  notesRef,
  folderTreeRef,
  fetchNotes,
  fetchFolderTree,
  setUndoStack,
  toast,
  setSelectedFolderId,
  setSelectedNote,
  selectedNote,
}: UseNoteOperationsProps) {

  const handleCreateFolder = useCallback(async (parentId?: string | null) => {
    const folderName = prompt("Enter folder name:");
    if (!folderName) return;

    try {
      if (!selectedNotebookId) return;
      const response = await fetch("/api/notes/categories", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: folderName,
          parentId: parentId ?? null,
          notebookId: selectedNotebookId,
        }),
      });

      if (response.ok) {
        const created = (await response.json()) as { id?: string };
        await fetchFolderTree();
        if (created?.id) {
          setSelectedFolderId(created.id);
        }
        toast("Folder created successfully");
      } else {
        toast("Failed to create folder", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to create folder:", error);
      toast("An unexpected error occurred while creating the folder", { variant: "error" });
    }
  }, [selectedNotebookId, fetchFolderTree, setSelectedFolderId, toast]);

  const handleDeleteFolder = useCallback(async (folderId: string) => {
    if (!confirm("Delete this folder and all its contents (subfolders, notes, and attachments)? This action cannot be undone.")) return;

    try {
      const response = await fetch(`/api/notes/categories/${folderId}?recursive=true`, {
        method: "DELETE",
      });

      if (response.ok) {
        await fetchFolderTree();
        await fetchNotes();
        toast("Folder deleted successfully");
        // Since we don't have access to current selectedFolderId in state directly here (only via setter),
        // we might rely on the parent component to handle clearing selection if needed,
        // or pass current selection as prop.
        // For now, assuming caller handles side-effects if needed or we re-fetch.
      } else {
        toast("Failed to delete folder", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to delete folder:", error);
      toast("An unexpected error occurred while deleting the folder", { variant: "error" });
    }
  }, [fetchFolderTree, fetchNotes, toast]);

  const handleRenameFolder = useCallback(async (folderId: string, newName: string) => {
    const currentFolder = findFolderById(folderTreeRef.current, folderId);
    const previousName = currentFolder?.name ?? "";
    try {
      const response = await fetch(`/api/notes/categories/${folderId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: newName }),
      });

      if (response.ok) {
        if (previousName && previousName !== newName) {
          setUndoStack((prev) => [
            { type: "renameFolder", folderId, fromName: previousName, toName: newName },
            ...prev,
          ]);
        }
        await fetchFolderTree();
        toast("Folder renamed successfully");
      } else {
        toast("Failed to rename folder", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to rename folder:", error);
      toast("An unexpected error occurred while renaming the folder", { variant: "error" });
    }
  }, [fetchFolderTree, folderTreeRef, setUndoStack, toast]);

  const handleDuplicateNote = useCallback(async (noteId: string) => {
    try {
      const response = await fetch(`/api/notes/${noteId}`, { cache: "no-store" });
      if (!response.ok) {
        toast("Failed to fetch note details for duplication", { variant: "error" });
        return;
      }

      const note = (await response.json()) as NoteWithRelations;

      const baseTitle = note.title.replace(/\s*\(\d+\)$/, "");
      let newTitle = `${baseTitle} (1)`;

      const existingNotes = notesRef.current.filter((n) =>
        n.title.startsWith(baseTitle) && n.title !== note.title
      );
      if (existingNotes.length > 0) {
        const numbers = existingNotes
          .map((n) => {
            const match = n.title.match(/\((\d+)\)$/);
            return match ? parseInt(match[1]!, 10) : 0;
          })
          .filter((n) => n > 0);
        const maxNumber = Math.max(0, ...numbers);
        newTitle = `${baseTitle} (${maxNumber + 1})`;
      }

      const createResponse = await fetch("/api/notes", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title: newTitle,
          content: note.content,
          color: note.color,
          isPinned: note.isPinned,
          isArchived: note.isArchived,
          isFavorite: note.isFavorite,
          tagIds: note.tags.map((t) => t.tagId),
          categoryIds: note.categories.map((c) => c.categoryId),
          notebookId: note.notebookId ?? selectedNotebookId ?? null,
        }),
      });

      if (createResponse.ok) {
        await fetchNotes();
        await fetchFolderTree();
        toast("Note duplicated successfully");
      } else {
        toast("Failed to create duplicated note", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to duplicate note:", error);
      toast("An unexpected error occurred while duplicating the note", { variant: "error" });
    }
  }, [selectedNotebookId, fetchNotes, fetchFolderTree, notesRef, toast]);

  const handleDeleteNoteFromTree = useCallback(async (noteId: string) => {
    if (!confirm("Are you sure you want to delete this note?")) return;

    try {
      const response = await fetch(`/api/notes/${noteId}`, { method: "DELETE" });
      if (response.ok) {
        await fetchNotes();
        await fetchFolderTree();
        if (selectedNote?.id === noteId) {
          setSelectedNote(null);
        }
        toast("Note deleted successfully");
      } else {
        toast("Failed to delete note", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to delete note:", error);
      toast("An unexpected error occurred while deleting the note", { variant: "error" });
    }
  }, [fetchNotes, fetchFolderTree, selectedNote, setSelectedNote, toast]);

  const handleRenameNote = useCallback(async (noteId: string, newTitle: string) => {
    const currentNote = notesRef.current.find((note) => note.id === noteId);
    const previousTitle = currentNote?.title ?? "";
    try {
      const response = await fetch(`/api/notes/${noteId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: newTitle }),
      });

      if (response.ok) {
        if (previousTitle && previousTitle !== newTitle) {
          setUndoStack((prev) => [
            { type: "renameNote", noteId, fromTitle: previousTitle, toTitle: newTitle },
            ...prev,
          ]);
        }
        await fetchNotes();
        await fetchFolderTree();
        if (selectedNote?.id === noteId) {
          const updatedNote = (await response.json()) as NoteWithRelations;
          setSelectedNote(updatedNote);
        }
        toast("Note renamed successfully");
      } else {
        toast("Failed to rename note", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to rename note:", error);
      toast("An unexpected error occurred while renaming the note", { variant: "error" });
    }
  }, [fetchNotes, fetchFolderTree, selectedNote, setSelectedNote, notesRef, setUndoStack, toast]);

  const handleMoveNoteToFolder = useCallback(async (noteId: string, folderId: string | null) => {
    const currentNote = notesRef.current.find((note) => note.id === noteId);
    const previousFolderId = currentNote?.categories?.[0]?.categoryId ?? null;
    try {
      const response = await fetch(`/api/notes/${noteId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          categoryIds: folderId ? [folderId] : [],
        }),
      });

      if (response.ok) {
        if (previousFolderId !== folderId) {
          setUndoStack((prev) => [
            { type: "moveNote", noteId, fromFolderId: previousFolderId, toFolderId: folderId },
            ...prev,
          ]);
        }
        await fetchFolderTree();
        await fetchNotes();
        toast("Note moved successfully");
      } else {
        toast("Failed to move note", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to move note:", error);
      toast("An unexpected error occurred while moving the note", { variant: "error" });
    }
  }, [fetchFolderTree, fetchNotes, notesRef, setUndoStack, toast]);

  const handleMoveFolderToFolder = useCallback(async (folderId: string, targetParentId: string | null) => {
    const previousParentId = findFolderParentId(folderTreeRef.current, folderId);
    try {
      const response = await fetch(`/api/notes/categories/${folderId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          parentId: targetParentId,
        }),
      });

      if (response.ok) {
        if (previousParentId !== targetParentId) {
          setUndoStack((prev) => [
            { type: "moveFolder", folderId, fromParentId: previousParentId, toParentId: targetParentId },
            ...prev,
          ]);
        }
        await fetchFolderTree();
        await fetchNotes();
        toast("Folder moved successfully");
      } else {
        toast("Failed to move folder", { variant: "error" });
      }
    } catch (error) {
      console.error("Failed to move folder:", error);
      toast("An unexpected error occurred while moving the folder", { variant: "error" });
    }
  }, [fetchFolderTree, fetchNotes, folderTreeRef, setUndoStack, toast]);

  const handleRelateNotes = useCallback(async (sourceNoteId: string, targetNoteId: string) => {
    if (!sourceNoteId || !targetNoteId) return;
    if (sourceNoteId === targetNoteId) return;
    try {
      const [sourceRes, targetRes] = await Promise.all([
        fetch(`/api/notes/${sourceNoteId}`, { cache: "no-store" }),
        fetch(`/api/notes/${targetNoteId}`, { cache: "no-store" }),
      ]);
      if (!sourceRes.ok || !targetRes.ok) {
        toast("Failed to link notes", { variant: "error" });
        return;
      }
      const [sourceNote, targetNote] = (await Promise.all([
        sourceRes.json(),
        targetRes.json(),
      ])) as [NoteWithRelations, NoteWithRelations];

      const sourceRelatedIds =
        sourceNote.relationsFrom?.map((rel) => rel.targetNote.id) || [];
      const alreadyLinked = sourceRelatedIds.includes(targetNoteId);
      if (alreadyLinked) {
        toast("Notes are already linked", { variant: "info" });
        return;
      }

      const nextSourceIds = Array.from(new Set([...sourceRelatedIds, targetNoteId]));

      const targetRelatedIds =
        targetNote.relationsFrom?.map((rel) => rel.targetNote.id) || [];
      const nextTargetIds = Array.from(new Set([...targetRelatedIds, sourceNoteId]));

      const [sourcePatch, targetPatch] = await Promise.all([
        fetch(`/api/notes/${sourceNoteId}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ relatedNoteIds: nextSourceIds }),
        }),
        fetch(`/api/notes/${targetNoteId}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ relatedNoteIds: nextTargetIds }),
        }),
      ]);

      if (!sourcePatch.ok || !targetPatch.ok) {
        toast("Failed to link notes", { variant: "error" });
        return;
      }

      await fetchFolderTree();
      await fetchNotes();

      // Refresh the selected note if it was involved in the linking
      if (selectedNote && (selectedNote.id === sourceNoteId || selectedNote.id === targetNoteId)) {
        try {
          const refreshRes = await fetch(`/api/notes/${selectedNote.id}`, { cache: "no-store" });
          if (refreshRes.ok) {
            const refreshedNote = (await refreshRes.json()) as NoteWithRelations;
            setSelectedNote(refreshedNote);
          }
        } catch (error) {
          console.error("Failed to refresh selected note:", error);
        }
      }

      toast("Notes linked");
    } catch (error) {
      console.error("Failed to relate notes:", error);
      toast("Failed to link notes", { variant: "error" });
    }
  }, [fetchFolderTree, fetchNotes, selectedNote, setSelectedNote, toast]);

  return {
    handleCreateFolder,
    handleDeleteFolder,
    handleRenameFolder,
    handleDuplicateNote,
    handleDeleteNoteFromTree,
    handleRenameNote,
    handleMoveNoteToFolder,
    handleMoveFolderToFolder,
    handleRelateNotes,
  };
}

import { useToast } from "@/shared/ui";
import { useState, useMemo } from "react";

import type { TagRecord } from "@/shared/types/notes";

// Why: Tag selection has complex state:
// - Input filtering against available tags
// - Dropdown visibility
// - Creating new tags with API call
// - Adding/removing tags from note
// Extracting prevents form bloat and makes tag logic testable.
export function useNoteTags(
  initialTagIds: string[] = [],
  availableTags: TagRecord[] = [],
  notebookId?: string | null,
  noteNotebookId?: string | null,
  onTagCreated?: () => void
) {
  const { toast } = useToast();
  const [selectedTagIds, setSelectedTagIds] = useState<string[]>(initialTagIds);
  const [tagInput, setTagInput] = useState("");
  const [isTagDropdownOpen, setIsTagDropdownOpen] = useState(false);

  const filteredTags = useMemo(() => 
    availableTags.filter(
      (tag) =>
        tag.name.toLowerCase().includes(tagInput.toLowerCase()) &&
        !selectedTagIds.includes(tag.id)
    ), 
    [availableTags, tagInput, selectedTagIds]
  );

  const handleAddTag = (tag: TagRecord) => {
    setSelectedTagIds([...selectedTagIds, tag.id]);
    setTagInput("");
    setIsTagDropdownOpen(false);
  };

  const handleCreateTag = async () => {
    if (!tagInput.trim()) return;

    const existingTag = availableTags.find(
      (t) => t.name.toLowerCase() === tagInput.trim().toLowerCase()
    );

    if (existingTag) {
      if (!selectedTagIds.includes(existingTag.id)) {
        handleAddTag(existingTag);
      } else {
        setTagInput("");
        setIsTagDropdownOpen(false);
      }
      return;
    }

    try {
      const response = await fetch("/api/notes/tags", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: tagInput.trim(),
          notebookId: notebookId ?? noteNotebookId ?? null,
        }),
      });

      if (response.ok) {
        const newTag = (await response.json()) as TagRecord;
        onTagCreated?.();
        setSelectedTagIds((prev) => [...prev, newTag.id]);
        setTagInput("");
        setIsTagDropdownOpen(false);
      }
    } catch (error) {
      console.error("Failed to create tag:", error);
      toast("Failed to create tag", { variant: "error" });
    }
  };

  const handleRemoveTag = (tagId: string) => {
    setSelectedTagIds(selectedTagIds.filter((id) => id !== tagId));
  };

  return {
    selectedTagIds,
    setSelectedTagIds,
    tagInput,
    setTagInput,
    isTagDropdownOpen,
    setIsTagDropdownOpen,
    filteredTags,
    handleAddTag,
    handleCreateTag,
    handleRemoveTag,
  };
}

import { useMemo, useCallback } from "react";
import type { NoteWithRelations, NotebookRecord } from "@/shared/types/notes";
import type { UseNoteThemeProps } from "@/features/notesapp/types/notes-hooks";
import { findFolderById } from "@/features/foldertree";

export function useNoteTheme({
  themes,
  notebook,
  folderTree,
  selectedFolderId,
  selectedNotebookId,
  selectedNote,
  fetchFolderTree,
  setNotebook,
}: UseNoteThemeProps) {

  const themeMap = useMemo(
    () => new Map(themes.map((theme) => [String(theme.id), theme])),
    [themes]
  );

  const defaultTheme = notebook?.defaultThemeId
    ? themeMap.get(String(notebook.defaultThemeId)) ?? null
    : null;

  const getThemeForFolderId = useCallback(
    (folderId: string | null | undefined) => {
      if (!folderId) return null;
      const folder = findFolderById(folderTree, folderId);
      const themeId = folder?.themeId ? String(folder.themeId) : null;
      if (!themeId) return null;
      return themeMap.get(themeId) ?? null;
    },
    [folderTree, themeMap]
  );

  const selectedFolderTheme = useMemo(
    () => getThemeForFolderId(selectedFolderId),
    [getThemeForFolderId, selectedFolderId]
  );

  const selectedFolderThemeId = selectedFolderId
    ? (() => {
        const folder = findFolderById(folderTree, selectedFolderId);
        return folder?.themeId ? String(folder.themeId) : "";
      })()
    : notebook?.defaultThemeId
      ? String(notebook.defaultThemeId)
      : "";

  const getThemeForNote = useCallback(
    (note: NoteWithRelations | null | undefined) => {
      if (!note) return null;
      // 1. Check selected folder's theme
      if (selectedFolderId) {
        const selectedTheme = getThemeForFolderId(selectedFolderId);
        if (selectedTheme) return selectedTheme;
      }
      // 2. Check note's category themes
      const categoryIds = note.categories?.map((category) => category.categoryId) ?? [];
      for (const categoryId of categoryIds) {
        const theme = getThemeForFolderId(categoryId);
        if (theme) return theme;
      }
      // 3. Fall back to notebook's default theme
      return defaultTheme;
    },
    [getThemeForFolderId, selectedFolderId, defaultTheme]
  );

  const selectedNoteTheme = useMemo(
    () => getThemeForNote(selectedNote),
    [getThemeForNote, selectedNote]
  );

  const handleUpdateFolderTheme = useCallback(
    async (themeId: string | null) => {
      if (!selectedFolderId) return;
      try {
        const response = await fetch(`/api/notes/categories/${selectedFolderId}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ themeId }),
        });
        if (response.ok) {
          await fetchFolderTree();
        }
      } catch (error) {
        console.error("Failed to update folder theme:", error);
      }
    },
    [selectedFolderId, fetchFolderTree]
  );

  const handleUpdateNotebookDefaultTheme = useCallback(
    async (themeId: string | null) => {
      if (!selectedNotebookId) return;
      try {
        const response = await fetch(`/api/notes/notebooks/${selectedNotebookId}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ defaultThemeId: themeId }),
        });
        if (response.ok) {
          const updated = (await response.json()) as NotebookRecord;
          setNotebook(updated);
        }
      } catch (error) {
        console.error("Failed to update notebook default theme:", error);
      }
    },
    [selectedNotebookId, setNotebook]
  );

  const handleThemeChange = useCallback(
    async (themeId: string | null) => {
      if (selectedFolderId) {
        await handleUpdateFolderTheme(themeId);
      } else {
        await handleUpdateNotebookDefaultTheme(themeId);
      }
    },
    [selectedFolderId, handleUpdateFolderTheme, handleUpdateNotebookDefaultTheme]
  );

  return {
    getThemeForNote,
    selectedNoteTheme,
    selectedFolderTheme,
    selectedFolderThemeId,
    handleThemeChange,
  };
}

"use client";

import { Button, useToast, Input, Label, SectionHeader, SectionPanel } from "@/shared/ui";
import { useEffect, useState, useMemo } from "react";
import { MoreVertical } from "lucide-react";


import { useNoteSettings } from "@/features/notesapp/hooks/NoteSettingsContext";
import { useNotebooks } from "@/features/notesapp/api/useNoteQueries";
import {
  useCreateNotebook,
  useUpdateNotebook,
  useDeleteNotebook,
} from "@/features/notesapp/api/useNoteMutations";
import type { NotebookRecord } from "@/shared/types/notes";
import { useRouter } from "next/navigation";




export function AdminNotesNotebooksPage() {
  const { toast } = useToast();
  const { settings, updateSettings } = useNoteSettings();
  const { selectedNotebookId } = settings;
  const router = useRouter();
  const [name, setName] = useState("");
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editingName, setEditingName] = useState("");
  const [menuNotebookId, setMenuNotebookId] = useState<string | null>(null);

  const notebooksQuery = useNotebooks();
  const notebooks = useMemo(() => notebooksQuery.data ?? [], [notebooksQuery.data]);
  const loading = notebooksQuery.isPending;

  const createNotebook = useCreateNotebook();
  const updateNotebook = useUpdateNotebook();
  const deleteNotebook = useDeleteNotebook();

  useEffect(() => {
    if (!selectedNotebookId && notebooks.length > 0) {
      updateSettings({ selectedNotebookId: notebooks[0]!.id });
    }
  }, [selectedNotebookId, notebooks, updateSettings]);

  const handleCreate = async () => {
    if (!name.trim()) {
      toast("Notebook name is required", { variant: "error" });
      return;
    }
    try {
      await createNotebook.mutateAsync({ name: name.trim() });
      setName("");
      toast("Notebook created", { variant: "success" });
    } catch (error) {
      console.error("Failed to create notebook:", error);
      toast("Failed to create notebook", { variant: "error" });
    }
  };

  const handleEditStart = (notebook: NotebookRecord) => {
    setEditingId(notebook.id);
    setEditingName(notebook.name);
    setMenuNotebookId(null);
  };

  const handleEditCancel = () => {
    setEditingId(null);
    setEditingName("");
  };

  const handleUpdate = async (id: string) => {
    if (!editingName.trim()) {
      toast("Notebook name is required", { variant: "error" });
      return;
    }
    try {
      await updateNotebook.mutateAsync({ id, name: editingName.trim() });
      toast("Notebook updated", { variant: "success" });
      handleEditCancel();
    } catch (error) {
      console.error("Failed to update notebook:", error);
      toast("Failed to update notebook", { variant: "error" });
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Delete this notebook and all its notes/tags/folders?")) return;
    try {
      await deleteNotebook.mutateAsync(id);
      if (selectedNotebookId === id) {
        updateSettings({ selectedNotebookId: null });
      }
      toast("Notebook deleted", { variant: "success" });
    } catch (error) {
      console.error("Failed to delete notebook:", error);
      toast("Failed to delete notebook", { variant: "error" });
    }
  };

  const handleDuplicate = async (notebook: NotebookRecord) => {
    const baseName = notebook.name.trim();
    const existing = notebooks
      .filter((item) => item.name.startsWith(baseName))
      .map((item) => {
        const match = item.name.match(/\((\d+)\)$/);
        return match ? Number(match[1]) : 0;
      });
    const nextNumber = existing.length > 0 ? Math.max(...existing) + 1 : 1;
    const newName = `${baseName} (${nextNumber})`;
    try {
      await createNotebook.mutateAsync({ name: newName });
      toast("Notebook duplicated", { variant: "success" });
    } catch (error) {
      console.error("Failed to duplicate notebook:", error);
      toast("Failed to duplicate notebook", { variant: "error" });
    } finally {
      setMenuNotebookId(null);
    }
  };

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
        title="Notebooks"
        description="Create and manage notebooks. Notes, folders, and tags are scoped per notebook."
        className="mb-6"
      />

      <div className="max-w-3xl space-y-6">
        <SectionPanel className="p-6">
          <SectionHeader title="Create Notebook" size="sm" className="mb-4" />
          <div className="flex flex-col gap-4 sm:flex-row sm:items-end">
            <div className="flex-1">
              <Label className="mb-2 block text-sm font-medium text-gray-200">
                Notebook Name
              </Label>
              <Input
                type="text"
                value={name}
                onChange={(event) => setName(event.target.value)}
                className="w-full"
                placeholder="Enter notebook name"
              />
            </div>
            <Button onClick={() => { void handleCreate(); }} disabled={createNotebook.isPending}>
              {createNotebook.isPending ? "Saving..." : "Create"}
            </Button>
          </div>
        </SectionPanel>

        <SectionPanel className="p-6">
          <SectionHeader
            title="Your Notebooks"
            size="sm"
            className="mb-4"
            actions={(
              <Button variant="outline" onClick={() => { void notebooksQuery.refetch(); }}>
                Refresh
              </Button>
            )}
          />
          {loading ? (
            <div className="text-sm text-gray-400">Loading notebooks...</div>
          ) : notebooks.length === 0 ? (
            <div className="text-sm text-gray-500">No notebooks created yet.</div>
          ) : (
            <div className="grid gap-3 sm:grid-cols-2">
              {notebooks.map((notebook) => {
                const isEditing = editingId === notebook.id;
                const isActive = selectedNotebookId === notebook.id;
                return (
                  <div
                    key={notebook.id}
                    className="flex cursor-pointer items-center justify-between gap-3 rounded-lg border bg-card px-4 py-3 transition hover:border-border/60"
                    onClick={() => {
                      updateSettings({ selectedNotebookId: notebook.id });
                      router.push("/admin/notes");
                    }}
                  >
                    <div className="flex flex-1 items-center gap-3">
                      {isEditing ? (
                        <div className="flex flex-1 flex-col gap-2 sm:flex-row sm:items-center">
                          <Input
                            type="text"
                            value={editingName}
                            onChange={(event) => setEditingName(event.target.value)}
                            className="w-full"
                          />
                        </div>
                      ) : (
                        <div className="flex flex-col">
                          <Button
                            type="button"
                            onClick={() => handleEditStart(notebook)}
                            className="text-left text-sm text-gray-200 hover:text-white"
                          >
                            {notebook.name}
                          </Button>
                          {isActive && (
                            <span className="text-[11px] text-blue-300">Active</span>
                          )}
                        </div>
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      {isEditing ? (
                        <>
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => { void handleUpdate(notebook.id); }}
                            disabled={updateNotebook.isPending}
                          >
                            Save
                          </Button>
                          <Button
                            variant="ghost"
                            size="sm"
                            onClick={handleEditCancel}
                          >
                            Cancel
                          </Button>
                        </>
                      ) : (
                        <></>
                      )}
                      {!isEditing && (
                        <div className="relative">
                          <Button
                            type="button"
                            onClick={(event) => {
                              event.stopPropagation();
                              setMenuNotebookId((prev) =>
                                prev === notebook.id ? null : notebook.id
                              );
                            }}
                            className="rounded p-1 text-gray-400 hover:bg-muted/50 hover:text-gray-200"
                            aria-label={`Notebook actions for ${notebook.name}`}
                          >
                            <MoreVertical size={16} />
                          </Button>
                          {menuNotebookId === notebook.id && (
                            <>
                              <div
                                className="fixed inset-0 z-40"
                                onClick={() => setMenuNotebookId(null)}
                              />
                              <div className="absolute right-0 top-full z-50 mt-2 w-44 rounded-md border bg-card p-1 shadow-lg">
                                <Button
                                  type="button"
                                  onClick={(event) => {
                                    event.stopPropagation();
                                    handleEditStart(notebook);
