export const ProductListPanel = memo(function ProductListPanel({
  onCreateProduct,
  onCreateFromDraft,
  activeDrafts,
  page,
  totalPages,
  setPage,
  pageSize,
  setPageSize,
  nameLocale,
  setNameLocale,
  languageOptions,
  currencyCode,
  setCurrencyCode,
  currencyOptions,
  catalogFilter,
  setCatalogFilter,
  catalogs,
  loadError,
  actionError,
  onDismissActionError,
  search,
  setSearch,
  sku,
  setSku,
  minPrice,
  setMinPrice,
  maxPrice,
  setMaxPrice,
  startDate,
  setStartDate,
  endDate,
  setEndDate,
  data,
  rowSelection,
  setRowSelection,
  onSelectAllGlobal,
  loadingGlobal,
  onDeleteSelected,
  onAddToMarketplace,
  handleProductsTableRender,
  tableColumns,
  setRefreshTrigger,
  productNameKey,
  priceGroups,
  onProductNameClick,
  onProductEditClick,
  onIntegrationsClick,
  onExportSettingsClick,
  integrationBadgeIds,
  integrationBadgeStatuses,
  getRowId,
  isLoading,
  skeletonRows,
}: ProductListPanelProps) {
  const headerProps = useMemo(
    () => ({
      onCreateProduct,
      onCreateFromDraft,
      activeDrafts,
      page,
      totalPages,
      setPage,
      pageSize,
      setPageSize,
      nameLocale,
      setNameLocale,
      languageOptions,
      currencyCode,
      setCurrencyCode,
      currencyOptions,
      catalogFilter,
      setCatalogFilter,
      catalogs,
    }),
    [
      onCreateProduct,
      onCreateFromDraft,
      activeDrafts,
      page,
      totalPages,
      setPage,
      pageSize,
      setPageSize,
      nameLocale,
      setNameLocale,
      languageOptions,
      currencyCode,
      setCurrencyCode,
      currencyOptions,
      catalogFilter,
      setCatalogFilter,
      catalogs,
    ]
  );

  const filtersProps = useMemo(
    () => ({
      search,
      setSearch,
      sku,
      setSku,
      minPrice,
      setMinPrice,
      maxPrice,
      setMaxPrice,
      startDate,
      setStartDate,
      endDate,
      setEndDate,
    }),
    [
      search,
      setSearch,
      sku,
      setSku,
      minPrice,
      setMinPrice,
      maxPrice,
      setMaxPrice,
      startDate,
      setStartDate,
      endDate,
      setEndDate,
    ]
  );

  const tableProps = useMemo(
    () => ({
      columns: tableColumns,
      data,
      setRefreshTrigger,
      productNameKey,
      currencyCode,
      priceGroups,
      onProductNameClick,
      onProductEditClick,
      onIntegrationsClick,
      onExportSettingsClick,
      integrationBadgeIds,
      integrationBadgeStatuses,
      getRowId,
      rowSelection,
      onRowSelectionChange: setRowSelection,
      isLoading,
      skeletonRows,
    }),
    [
      tableColumns,
      data,
      setRefreshTrigger,
      productNameKey,
      currencyCode,
      priceGroups,
      onProductNameClick,
      onProductEditClick,
      onIntegrationsClick,
      onExportSettingsClick,
      integrationBadgeIds,
      integrationBadgeStatuses,
      getRowId,
      rowSelection,
      setRowSelection,
      isLoading,
      skeletonRows,
    ]
  );

  const alerts = useMemo(() => {
    if (!loadError && !actionError) return null;
    return (
      <>
        {loadError && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            {loadError}
          </div>
        )}
        {actionError && (
          <div className="rounded-md border border-red-500/40 bg-red-500/10 px-4 py-3 text-sm text-red-200">
            {actionError}
            <Button
              onClick={onDismissActionError}
              className="ml-4 bg-transparent text-red-200 hover:bg-red-500/20"
            >
              Dismiss
            </Button>
          </div>
        )}
      </>
    );
  }, [actionError, loadError, onDismissActionError]);

  return (
    <ListPanel
      header={<ProductListHeader {...headerProps} />}
      alerts={alerts}
      filters={<ProductFilters {...filtersProps} />}
      actions={
        <ProductSelectionActions
          data={data}
          rowSelection={rowSelection}
          setRowSelection={setRowSelection}
          onSelectAllGlobal={onSelectAllGlobal}
          loadingGlobal={loadingGlobal}
          onDeleteSelected={onDeleteSelected}
          onAddToMarketplace={onAddToMarketplace}
        />
      }
    >
      <Profiler id="ProductsTable" onRender={handleProductsTableRender}>
        <DataTable {...tableProps} />
      </Profiler>
    </ListPanel>
  );
});

"use client";
import { ModalShell, Button, AppModal } from "@/shared/ui";



import { FileManager } from "@/features/files";
import ProductForm from "@/features/products/components/ProductForm";
import { ProductListingsModal } from "@/features/integrations";
import { ListProductModal } from "@/features/integrations";
import { MassListProductModal } from "@/features/integrations";
import {
