  useProductFormContext,
} from "@/features/products/context/ProductFormContext";
import type { ProductWithImages } from "@/features/products/types";
import type { ProductDraft } from "@/features/products/types/drafts";

interface ProductModalsProps {
  isCreateOpen: boolean;
  initialSku: string;
  createDraft?: ProductDraft | null;
  onCloseCreate: () => void;
  onCreateSuccess: () => void;
  editingProduct: ProductWithImages | null;
  onCloseEdit: () => void;
  onEditSuccess: () => void;
  onEditSave: (saved: ProductWithImages) => void;
  integrationsProduct: ProductWithImages | null;
  onCloseIntegrations: () => void;
  onStartListing: (integrationId: string, connectionId: string) => void;
  showListProductModal: boolean;
  onCloseListProduct: () => void;
  onListProductSuccess: () => void;
  listProductPreset: { integrationId: string; connectionId: string } | null;
  // Export settings (opened via Store icon)
  exportSettingsProduct?: ProductWithImages | null;
  onCloseExportSettings?: () => void;
  onListingsUpdated?: () => void;
  // Mass Listing
  massListIntegration?: { integrationId: string; connectionId: string } | null;
  massListProductIds?: string[];
  onCloseMassList?: () => void;
  onMassListSuccess?: () => void;
}

function ProductFormModalContent({ 
  onClose, 
  title, 
  submitButtonText 
}: { 
  onClose: () => void;
  title: string;
  submitButtonText: string;
}) {
  const { showFileManager, handleMultiFileSelect, handleSubmit, uploading } =
    useProductFormContext();

  const header = (
    <div className="flex items-center justify-between">
      <div className="flex items-center gap-4">
        <Button
          onClick={() => void handleSubmit()}
          disabled={uploading}
          className="min-w-[100px] border border-white/20 hover:border-white/40"
        >
          {uploading ? "Saving..." : submitButtonText}
        </Button>
        <h2 className="text-2xl font-bold text-white">{title}</h2>
      </div>
      <Button
        type="button"
        onClick={onClose}
        className="min-w-[100px] border border-white/20 hover:border-white/40"
      >
        Close
      </Button>
    </div>
  );

  return (
    <ModalShell title={title} onClose={onClose} header={header}>
      {showFileManager ? (
        <FileManager onSelectFile={handleMultiFileSelect} />
      ) : (
        <ProductForm submitButtonText={submitButtonText} />
      )}
    </ModalShell>
  );
}

export function ProductModals({
  isCreateOpen,
  initialSku,
  createDraft,
  onCloseCreate,
  onCreateSuccess,
  editingProduct,
  onCloseEdit,
  onEditSuccess,
  onEditSave,
  integrationsProduct,
  onCloseIntegrations,
  onStartListing,
  showListProductModal,
  onCloseListProduct,
  onListProductSuccess,
  listProductPreset,
  exportSettingsProduct,
  onCloseExportSettings,
  onListingsUpdated,
  massListIntegration,
  massListProductIds,
  onCloseMassList,
  onMassListSuccess,
}: ProductModalsProps) {
  return (
    <>
      <AppModal
        open={isCreateOpen}
        onOpenChange={(open) => !open && onCloseCreate()}
        title="Create Product"
      >
        <ProductFormProvider
          key={createDraft?.id ?? "create"}
          onSuccess={onCreateSuccess}
          initialSku={initialSku}
          draft={createDraft ?? undefined}
        >
          <ProductFormModalContent
            onClose={onCloseCreate}
            title="Create Product"
            submitButtonText="Create"
          />
        </ProductFormProvider>
      </AppModal>

      <AppModal
        open={!!editingProduct}
        onOpenChange={(open) => !open && onCloseEdit()}
        title="Edit Product"
      >
        {editingProduct && (
          <ProductFormProvider
            product={editingProduct}
            onSuccess={onEditSuccess}
            onEditSave={onEditSave}
          >
            <ProductFormModalContent
              onClose={onCloseEdit}
              title="Edit Product"
              submitButtonText="Update"
            />
          </ProductFormProvider>
        )}
      </AppModal>

      <AppModal
        open={!!integrationsProduct && !showListProductModal}
        onOpenChange={(open) => !open && onCloseIntegrations()}
        title="Product Listings"
      >
        {integrationsProduct && (
          <ProductListingsModal
            product={integrationsProduct}
            onClose={onCloseIntegrations}
            onStartListing={onStartListing}
            onListingsUpdated={onListingsUpdated}
          />
        )}
      </AppModal>

      <AppModal
        open={!!integrationsProduct && showListProductModal}
        onOpenChange={(open) => !open && onCloseListProduct()}
        title="List Product"
      >
        {integrationsProduct && (
          <ListProductModal
            product={integrationsProduct}
            onClose={onCloseListProduct}
            onSuccess={onListProductSuccess}
            initialIntegrationId={listProductPreset?.integrationId ?? null}
            initialConnectionId={listProductPreset?.connectionId ?? null}
          />
        )}
      </AppModal>

      <AppModal
        open={!!exportSettingsProduct && !!onCloseExportSettings}
        onOpenChange={(open) => !open && onCloseExportSettings?.()}
        title="Export Settings"
      >
        {exportSettingsProduct && onCloseExportSettings && (
          <ProductListingsModal
            product={exportSettingsProduct}
            onClose={onCloseExportSettings}
            filterIntegrationSlug="baselinker"
            onListingsUpdated={onListingsUpdated}
          />
        )}
      </AppModal>

      <AppModal
        open={!!massListIntegration && !!massListProductIds && massListProductIds.length > 0}
        onOpenChange={(open) => !open && onCloseMassList?.()}
        title="Mass List Products"
      >
        {massListIntegration && massListProductIds && onCloseMassList && onMassListSuccess && (
          <MassListProductModal
            integrationId={massListIntegration.integrationId}
            connectionId={massListIntegration.connectionId}
            productIds={massListProductIds}
            onClose={onCloseMassList}
            onSuccess={onMassListSuccess}
          />
        )}
      </AppModal>
    </>
  );
}

"use client";

import { MissingImagePlaceholder } from "@/shared/ui";
import React, { useCallback, useEffect, useRef, useState } from "react";
import Image from "next/image";

interface ProductImageCellProps {
  imageUrl: string | null;
  productName: string;
}

const PREVIEW_SIZE = 136;
const OFFSET_X = 72;
const OFFSET_Y = -90;

export const ProductImageCell = React.memo(function ProductImageCell({
  imageUrl,
  productName,
}: ProductImageCellProps) {
  const [showPreview, setShowPreview] = useState(false);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const [viewport, setViewport] = useState({ w: 0, h: 0 });
  const containerRef = useRef<HTMLDivElement>(null);
  const rafRef = useRef<number | null>(null);
  const pendingPosRef = useRef({ x: 0, y: 0 });

  const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
    pendingPosRef.current = { x: e.clientX, y: e.clientY };
    if (rafRef.current !== null) return;
    rafRef.current = window.requestAnimationFrame(() => {
      setMousePos(pendingPosRef.current);
      rafRef.current = null;
    });
  }, []);

  useEffect(() => {
    const updateViewport = () => {
      setViewport({ w: window.innerWidth, h: window.innerHeight });
    };
    updateViewport();
    window.addEventListener("resize", updateViewport);
    return () => {
      window.removeEventListener("resize", updateViewport);
      if (rafRef.current !== null) {
        window.cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
      }
    };
  }, []);

  if (!imageUrl) {
    return <MissingImagePlaceholder className="size-16" />;
  }

  return (
    <div
      ref={containerRef}
      className="relative"
      onMouseEnter={() => setShowPreview(true)}
      onMouseLeave={() => setShowPreview(false)}
      onMouseMove={handleMouseMove}
    >
      <Image
        src={imageUrl}
        alt={productName}
        width={64}
        height={64}
        className="size-16 rounded-md object-cover cursor-pointer transition-opacity hover:opacity-80"
        style={{ width: "auto", height: "auto" }}
      />

      {showPreview && (
        <div
          className="fixed z-50 pointer-events-none"
          style={{
            left: `${(() => {
              const margin = 8;
              const left = mousePos.x - PREVIEW_SIZE - OFFSET_X;
              const right = mousePos.x + OFFSET_X;
              const fitsLeft = left >= margin;
              const fitsRight = right + PREVIEW_SIZE <= viewport.w - margin;
              if (fitsLeft) return left;
              if (fitsRight) return right;
              return Math.max(margin, Math.min(viewport.w - PREVIEW_SIZE - margin, left));
            })()}px`,
            top: `${(() => {
              const margin = 8;
              const below = mousePos.y + OFFSET_Y;
              const above = mousePos.y - PREVIEW_SIZE - OFFSET_Y;
              const fitsBelow = below + PREVIEW_SIZE <= viewport.h - margin;
              const fitsAbove = above >= margin;
              if (fitsBelow) return below;
              if (fitsAbove) return above;
              return Math.max(margin, Math.min(viewport.h - PREVIEW_SIZE - margin, below));
            })()}px`,
          }}
        >
          <div className="bg-card rounded-lg overflow-hidden shadow-2xl border border-border/60">
            <Image
              src={imageUrl}
              alt={productName}
              width={PREVIEW_SIZE}
              height={PREVIEW_SIZE}
              className="rounded-lg object-cover"
              style={{ width: "auto", height: "auto" }}
              priority
              quality={90}
            />
          </div>
        </div>
      )}
    </div>
  );
});

"use client";

import { useToast, Button, AppModal, Input, Label, Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/shared/ui";
import { useState } from "react";
import { Plus, Trash2 } from "lucide-react";






import type { CatalogRecord } from "@/features/products/types";
import type { ProductParameter } from "@/features/products/types";

type ParametersSettingsProps = {
  loading: boolean;
  parameters: ProductParameter[];
  catalogs: CatalogRecord[];
  selectedCatalogId: string | null;
  onCatalogChange: (catalogId: string) => void;
  onRefresh: () => void;
};

export function ParametersSettings({
  loading,
  parameters,
  catalogs,
  selectedCatalogId,
  onCatalogChange,
  onRefresh,
}: ParametersSettingsProps) {
  const { toast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [editingParameter, setEditingParameter] = useState<ProductParameter | null>(null);
  const [formData, setFormData] = useState({
    name_en: "",
    name_pl: "",
    name_de: "",
    catalogId: "",
  });

  const openCreateModal = () => {
    if (!selectedCatalogId) {
      toast("Please select a catalog first.", { variant: "error" });
      return;
    }
    setEditingParameter(null);
    setFormData({
      name_en: "",
      name_pl: "",
      name_de: "",
      catalogId: selectedCatalogId,
    });
    setShowModal(true);
  };

  const openEditModal = (parameter: ProductParameter) => {
    setEditingParameter(parameter);
    setFormData({
      name_en: parameter.name_en,
      name_pl: parameter.name_pl ?? "",
      name_de: parameter.name_de ?? "",
      catalogId: parameter.catalogId,
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!formData.name_en.trim()) {
      toast("English name is required.", { variant: "error" });
      return;
    }
    if (!formData.catalogId) {
      toast("Catalog is required.", { variant: "error" });
      return;
    }

    setSaving(true);
    try {
      const endpoint = editingParameter
        ? `/api/products/parameters/${editingParameter.id}`
        : "/api/products/parameters";
      const res = await fetch(endpoint, {
        method: editingParameter ? "PUT" : "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name_en: formData.name_en.trim(),
          name_pl: formData.name_pl.trim() || null,
          name_de: formData.name_de.trim() || null,
          catalogId: formData.catalogId,
        }),
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to save parameter.");
      }
      toast(editingParameter ? "Parameter updated." : "Parameter created.", {
        variant: "success",
      });
      setShowModal(false);
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to save parameter.";
      toast(message, { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (parameter: ProductParameter) => {
    const confirmed = window.confirm(
      `Delete parameter "${parameter.name_en}"?`
    );
    if (!confirmed) return;
    try {
      const res = await fetch(`/api/products/parameters/${parameter.id}`, {
        method: "DELETE",
      });
      if (!res.ok) {
        const payload = (await res.json()) as { error?: string };
        throw new Error(payload.error || "Failed to delete parameter.");
      }
      toast("Parameter deleted.", { variant: "success" });
      onRefresh();
    } catch (error) {
      const message =
        error instanceof Error ? error.message : "Failed to delete parameter.";
      toast(message, { variant: "error" });
    }
  };

  const selectedCatalog = catalogs.find(
    (catalog) => catalog.id === selectedCatalogId
  );

  return (
    <div className="space-y-5">
      <div className="rounded-md border border-border bg-card/60 p-4">
        <p className="text-sm font-semibold text-white mb-3">Select Catalog</p>
        <p className="text-xs text-gray-400 mb-3">
          Parameters are managed per catalog.
        </p>
        <div className="w-full max-w-xs">
          <Select
            value={selectedCatalogId || ""}
            onValueChange={onCatalogChange}
          >
            <SelectTrigger>
              <SelectValue placeholder="Select a catalog..." />
            </SelectTrigger>
            <SelectContent>
              {catalogs.map((catalog) => (
                <SelectItem key={catalog.id} value={catalog.id}>
                  {catalog.name}
                  {catalog.isDefault ? " (Default)" : ""}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      {selectedCatalogId && (
        <>
          <div className="flex justify-start">
            <Button
              onClick={openCreateModal}
              className="bg-white text-gray-900 hover:bg-gray-200"
            >
              <Plus className="size-4 mr-2" />
              Add Parameter
            </Button>
          </div>

          <div className="rounded-md border border-border bg-card/60 p-4">
            <p className="text-sm font-semibold text-white mb-4">
              Parameters for &quot;{selectedCatalog?.name}&quot;
            </p>

            {loading ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                Loading parameters...
              </div>
            ) : parameters.length === 0 ? (
              <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
                No parameters yet for this catalog. Create your first parameter!
              </div>
            ) : (
              <div className="space-y-2">
                {parameters.map((parameter) => (
                  <div
                    key={parameter.id}
                    className="flex items-center justify-between gap-3 rounded-md border border-border bg-gray-900 px-3 py-2"
                  >
                    <div className="min-w-0">
                      <p className="text-sm text-gray-100 truncate">
                        {parameter.name_en}
                      </p>
                      <div className="text-xs text-gray-400 space-x-2">
                        {parameter.name_pl && (
                          <span>PL: {parameter.name_pl}</span>
                        )}
                        {parameter.name_de && (
                          <span>DE: {parameter.name_de}</span>
                        )}
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Button
                        type="button"
                        onClick={() => openEditModal(parameter)}
                        className="rounded bg-gray-800 px-2 py-1 text-xs text-gray-100 hover:bg-gray-700"
                      >
                        Edit
                      </Button>
                      <Button
                        type="button"
                        onClick={() => void handleDelete(parameter)}
                        className="rounded bg-red-600/80 px-2 py-1 text-xs text-white hover:bg-red-600"
                        title="Delete parameter"
                      >
                        <Trash2 className="size-3" />
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </>
      )}

      {!selectedCatalogId && catalogs.length === 0 && (
        <div className="rounded-md border border-dashed border p-4 text-center text-sm text-gray-400">
          No catalogs found. Please create a catalog first in the Catalogs section.
        </div>
      )}

      {showModal && (
        <AppModal
          open={showModal}
          onOpenChange={(open) => !open && setShowModal(false)}
          title={editingParameter ? "Edit Parameter" : "Create Parameter"}
        >
          <div className="w-full max-w-md rounded-lg bg-card p-6 shadow-lg">
            <div className="mb-4 flex items-center justify-between">
              <h2 className="text-xl font-semibold text-white">
                {editingParameter ? "Edit Parameter" : "Create Parameter"}
              </h2>
            </div>
            <div className="space-y-3">
              <div>
                <Label className="text-sm">Name (EN)</Label>
                <Input
                  value={formData.name_en}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_en: event.target.value,
                    }))
                  }
                  placeholder="Parameter name in English"
                />
              </div>
              <div>
                <Label className="text-sm">Name (PL)</Label>
                <Input
                  value={formData.name_pl}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_pl: event.target.value,
                    }))
                  }
                  placeholder="Optional"
                />
              </div>
              <div>
                <Label className="text-sm">Name (DE)</Label>
                <Input
                  value={formData.name_de}
                  onChange={(event) =>
                    setFormData((prev) => ({
                      ...prev,
                      name_de: event.target.value,
                    }))
                  }
                  placeholder="Optional"
                />
              </div>
            </div>

            <div className="mt-6 flex justify-end gap-2">
              <Button variant="outline" onClick={() => setShowModal(false)}>
                Cancel
              </Button>
              <Button onClick={() => void handleSave()} disabled={saving}>
                {saving ? "Saving..." : "Save"}
              </Button>
            </div>
          </div>
        </AppModal>
      )}
    </div>
  );
}

"use client";

import { Button, Input, Label, Textarea, Tabs, TabsList, TabsTrigger, TabsContent, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, useToast } from "@/shared/ui";
import { useState, useEffect } from "react";
import { useFormContext } from "react-hook-form";
import { useProductFormContext } from "@/features/products/context/ProductFormContext";
import { useQueryClient } from "@tanstack/react-query";






import { logger } from "@/shared/utils/logger";
import { cn } from "@/shared/utils";
import { ProductFormData } from "@/features/products/types";
import type { ProductAiJob } from "@/shared/types/jobs";
import type {
  AiNode,
  PathConfig,
  PathMeta,
  PathDebugSnapshot,
  PathDebugEntry,
} from "@/features/ai-paths";
import {
  evaluateGraph,
} from "@/features/ai-paths";
import {
  PATH_CONFIG_PREFIX,
  PATH_DEBUG_PREFIX,
  PATH_INDEX_KEY,
  TRIGGER_EVENTS,
  createDefaultPathConfig,
  normalizeNodes,
  sanitizeEdges,
} from "@/features/ai-paths";

export default function ProductFormGeneral() {
  const queryClient = useQueryClient();
  const safeJsonStringify = (value: unknown) => {
    const seen = new WeakSet();
    const replacer = (_key: string, val: unknown) => {
      if (typeof val === "bigint") return val.toString();
      if (val instanceof Date) return val.toISOString();
      if (val instanceof Set) return Array.from(val.values()) as unknown[];
      if (val instanceof Map) return Object.fromEntries(val.entries()) as Record<string, unknown>;
      if (typeof val === "function" || typeof val === "symbol") return undefined;
      if (val && typeof val === "object") {
        if (seen.has(val)) return undefined;
        seen.add(val);
      }
      return val;
    };
    try {
      return JSON.stringify(value, replacer);
    } catch {
      return "";
    }
  };
  const {
    filteredLanguages,
    errors,
    generationError,
    setGenerationError,
    product,
    imageSlots,
    selectedCatalogIds,
  } = useProductFormContext();

  const { register, getValues, setValue, watch } = useFormContext<ProductFormData>();
  const { toast } = useToast();

  const [generating, setGenerating] = useState(false);
  const [translating, setTranslating] = useState(false);
  const [identifierType, setIdentifierType] = useState<"ean" | "gtin" | "asin">("ean");
  const allValues = watch();
  const hasCatalogs = selectedCatalogIds.length > 0;
  const languagesReady = filteredLanguages.length > 0;

  useEffect(() => {
    const vals = getValues();
    if (vals.asin) {
      setIdentifierType("asin");
    } else if (vals.gtin) {
      setIdentifierType("gtin");
    }
  }, [getValues]);

  const handleGenerateDescription = async () => {
    logger.log("Generating description...");
    setGenerating(true);
    setGenerationError(null);
    const productData = getValues();
    const imageUrls = imageSlots
      .filter((slot): slot is NonNullable<typeof slot> => slot !== null)
      .map((slot) => slot.previewUrl);

    try {
      if (product?.id) {
        const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            productId: product.id,
            type: "description_generation",
            payload: {} 
          }),
        });

        const enqueueData = (await enqueueRes.json()) as { error?: string; jobId?: string };
        if (!enqueueRes.ok) throw new Error(enqueueData.error || "Failed to enqueue generation job.");
        const jobId = enqueueData.jobId;

        let completed = false;
        let attempts = 0;
        while (!completed && attempts < 30) {
          await new Promise(r => setTimeout(r, 2000));
          const statusRes = await fetch(`/api/products/ai-jobs/${jobId}`);
          if (!statusRes.ok) break;
          const { job } = (await statusRes.json()) as { job: ProductAiJob };

          if (job.status === "completed") {
            const description = job.result?.description;
            if (typeof description === "string") {
              setValue("description_en", description);
            }
            completed = true;
          } else if (job.status === "failed") {
            throw new Error(job.errorMessage || "Generation failed.");
          }
          attempts++;
        }
        if (!completed) throw new Error("Generation is taking longer than expected. Check the AI Jobs page.");
      } else {
        const res = await fetch("/api/generate-description", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ productData, imageUrls }),
        });
        if (!res.ok) {
          const payload = (await res.json()) as { error?: string; errorId?: string };
          throw new Error(payload?.error || "Failed to generate description");
        }
        const { description } = (await res.json()) as { description: string };
        setValue("description_en", description);
      }
    } catch (error) {
      logger.error("Failed to generate description:", error);
      setGenerationError(error instanceof Error ? error.message : "Failed to generate description.");
    } finally {
      setGenerating(false);
    }
  };

  const buildTriggerContext = (
    triggerNode: AiNode,
    triggerEvent: string,
    event?: React.MouseEvent<HTMLButtonElement>,
    pathInfo?: { id?: string; name?: string }
  ) => {
    const timestamp = new Date().toISOString();
    const nativeEvent = event?.nativeEvent;
    const pointer = nativeEvent
      ? {
          clientX: nativeEvent.clientX,
          clientY: nativeEvent.clientY,
          pageX: nativeEvent.pageX,
          pageY: nativeEvent.pageY,
          screenX: nativeEvent.screenX,
          screenY: nativeEvent.screenY,
          offsetX: "offsetX" in nativeEvent ? nativeEvent.offsetX : undefined,
          offsetY: "offsetY" in nativeEvent ? nativeEvent.offsetY : undefined,
          button: nativeEvent.button,
          buttons: nativeEvent.buttons,
          altKey: nativeEvent.altKey,
          ctrlKey: nativeEvent.ctrlKey,
          shiftKey: nativeEvent.shiftKey,
          metaKey: nativeEvent.metaKey,
        }
      : undefined;
    const location =
      typeof window !== "undefined"
        ? {
            href: window.location.href,
            origin: window.location.origin,
            pathname: window.location.pathname,
            search: window.location.search,
            hash: window.location.hash,
            referrer: document.referrer || undefined,
          }
        : {};
    const ui =
      typeof window !== "undefined"
        ? {
            viewport: {
              width: window.innerWidth,
              height: window.innerHeight,
              devicePixelRatio: window.devicePixelRatio,
            },
            screen: {
              width: window.screen?.width,
              height: window.screen?.height,
              availWidth: window.screen?.availWidth,
              availHeight: window.screen?.availHeight,
            },
            userAgent: navigator.userAgent,
            platform: navigator.platform,
            language: navigator.language,
            languages: navigator.languages,
            timeZone: Intl.DateTimeFormat().resolvedOptions().timeZone,
            documentTitle: document.title,
            visibilityState: document.visibilityState,
            scroll: {
              x: window.scrollX,
              y: window.scrollY,
            },
          }
        : {};
    return {
      timestamp,
      location,
      ui,
      user: null,
      event: {
        id: triggerEvent,
        nodeId: triggerNode.id,
        nodeTitle: triggerNode.title,
        type: event?.type,
        pointer,
      },
      source: {
        pathId: pathInfo?.id,
        pathName: pathInfo?.name ?? "Product Panel",
        tab: "product",
      },
      extras: {
        triggerLabel: "Path Generate Description",
      },
      entityId: product?.id,
      productId: product?.id,
      entityType: "product",
    };
  };

  const handlePathGenerateDescription = async (
    event?: React.MouseEvent<HTMLButtonElement>
  ) => {
    if (!product?.id) {
      toast("Save the product before running a path trigger.", {
        variant: "error",
      });
      return;
    }
    try {
      const prefsRes = await fetch("/api/user/preferences", { cache: "no-store" });
      if (!prefsRes.ok) {
        throw new Error("Failed to load AI Paths preferences.");
      }
      const prefs = (await prefsRes.json()) as {
        aiPathsPathConfigs?: Record<string, PathConfig> | string | null;
        aiPathsPathIndex?: Array<{ id?: string }> | null;
      };
      let configs: Record<string, PathConfig> = {};
      let settingsPathOrder: string[] = [];
      if (typeof prefs.aiPathsPathConfigs === "string") {
        try {
          const parsed = JSON.parse(prefs.aiPathsPathConfigs) as Record<string, PathConfig>;
          configs = parsed && typeof parsed === "object" ? parsed : {};
        } catch {
          configs = {};
        }
      } else if (prefs.aiPathsPathConfigs && typeof prefs.aiPathsPathConfigs === "object") {
        configs = prefs.aiPathsPathConfigs;
      }
      if (!configs || Object.keys(configs).length === 0) {
        try {
          const settingsRes = await fetch("/api/settings", { cache: "no-store" });
          if (settingsRes.ok) {
            const data = (await settingsRes.json()) as Array<{ key: string; value: string }>;
            const map = new Map(data.map((item) => [item.key, item.value]));
            const indexRaw = map.get(PATH_INDEX_KEY);
            if (indexRaw) {
              try {
                const parsedIndex = JSON.parse(indexRaw) as PathMeta[];
                if (Array.isArray(parsedIndex)) {
                  settingsPathOrder = parsedIndex
                    .map((meta) => meta?.id)
                    .filter((id): id is string => typeof id === "string" && id.length > 0);
                  parsedIndex.forEach((meta) => {
                    if (!meta?.id) return;
                    const configRaw = map.get(`${PATH_CONFIG_PREFIX}${meta.id}`);
                    if (!configRaw) {
                      configs[meta.id] = createDefaultPathConfig(meta.id);
                      return;
                    }
                    try {
                      const parsedConfig = JSON.parse(configRaw) as PathConfig;
                      configs[meta.id] = {
                        ...createDefaultPathConfig(meta.id),
                        ...parsedConfig,
                        id: meta.id,
                        name: parsedConfig?.name || meta.name || `Path ${meta.id}`,
                      };
                    } catch {
                      configs[meta.id] = createDefaultPathConfig(meta.id);
                    }
                  });
                }
              } catch {
                settingsPathOrder = [];
              }
            }
            if (Object.keys(configs).length === 0) {
              const legacyRaw =
                map.get(`${PATH_CONFIG_PREFIX}default`) ?? map.get("ai_paths_config");
              if (legacyRaw) {
                try {
                  const parsedConfig = JSON.parse(legacyRaw) as PathConfig;
                  const fallback = createDefaultPathConfig(parsedConfig.id ?? "default");
                  configs[fallback.id] = {
                    ...fallback,
                    ...parsedConfig,
                    id: parsedConfig.id ?? fallback.id,
                    name: parsedConfig.name || fallback.name,
                  };
                } catch {
                  const fallback = createDefaultPathConfig("default");
                  configs[fallback.id] = fallback;
                }
              }
            }
          }
        } catch {
          // If settings fallback fails, keep configs empty.
        }
      }
      const configsList = Object.values(configs);
      const pathOrder = Array.isArray(prefs.aiPathsPathIndex)
        ? prefs.aiPathsPathIndex
            .map((item) => item?.id)
            .filter((id): id is string => typeof id === "string" && id.length > 0)
        : settingsPathOrder;
      const orderedConfigs = pathOrder.length
        ? pathOrder
            .map((id) => configs[id])
            .filter((config): config is PathConfig => Boolean(config))
        : configsList;
      const triggerEvent = TRIGGER_EVENTS[0]?.id ?? "path_generate_description";
      const triggerCandidates = orderedConfigs.filter((config) =>
        Array.isArray(config?.nodes)
          ? config.nodes.some(
              (node) =>
                node.type === "trigger" &&
                (node.config?.trigger?.event ?? triggerEvent) === triggerEvent
            )
          : false
      );
      const selectedConfig = triggerCandidates[0] ?? orderedConfigs[0];
      if (!selectedConfig) {
        toast(
          "No AI Path found. Configure a path with the Path Generate Description trigger.",
          { variant: "error" }
        );
        return;
      }
      toast(`Running AI Path: ${selectedConfig.name}`, { variant: "success" });
      const nodes = normalizeNodes(
        Array.isArray(selectedConfig.nodes) ? selectedConfig.nodes : []
      );
      const edges = sanitizeEdges(
        nodes,
        Array.isArray(selectedConfig.edges) ? selectedConfig.edges : []
      );
      const triggerNodes = nodes.filter(
        (node) =>
          node.type === "trigger" &&
          (node.config?.trigger?.event ?? triggerEvent) === triggerEvent
      );
      const triggerNode =
        triggerNodes.find((node) => edges.some((edge) => edge.from === node.id)) ??
        triggerNodes.find((node) =>
          edges.some((edge) => edge.from === node.id || edge.to === node.id)
        ) ??
        triggerNodes[0] ??
        nodes.find((node) => node.type === "trigger");
      if (!triggerNode) {
        toast("No trigger node found in the selected path.", { variant: "error" });
        return;
      }
      const triggerContext = buildTriggerContext(triggerNode, triggerEvent, event, {
        id: selectedConfig.id,
        name: selectedConfig.name,
      });
      const runAt = new Date().toISOString();
      const runtimeState = await evaluateGraph({
        nodes,
        edges,
        activePathId: selectedConfig.id ?? "path",
        activePathName: selectedConfig.name ?? undefined,
        triggerNodeId: triggerNode.id,
        triggerEvent,
        triggerContext,
        deferPoll: false,
        fetchEntityByType: async (entityType: string, entityId: string) => {
          if (entityType !== "product") return null;
          const res = await fetch(`/api/products/${encodeURIComponent(entityId)}`, {
            cache: "no-store",
          });
          if (!res.ok) return null;
          return (await res.json()) as Record<string, unknown>;
        },
        reportAiPathsError: (error, meta, summary) => {
          logger.error(summary ?? "AI Paths trigger failed", error, meta);
        },
        toast,
      });
      void queryClient.invalidateQueries({ queryKey: ["products"] });
      void queryClient.invalidateQueries({ queryKey: ["products-count"] });
      try {
        const updatedConfig: PathConfig = {
          ...selectedConfig,
          nodes,
          edges,
          runtimeState,
          lastRunAt: runAt,
          updatedAt: runAt,
        };
        const debugEntries = nodes
          .filter((node) => node.type === "database")
          .map((node): PathDebugEntry | null => {
            const output = runtimeState.outputs[node.id] as
              | { debugPayload?: unknown }
              | undefined;
            const debugPayload = output?.debugPayload;
            if (debugPayload === undefined || debugPayload === null) return null;
            return {
              nodeId: node.id,
              title: node.title,
              debug: debugPayload,
            };
          })
          .filter((entry): entry is PathDebugEntry => Boolean(entry));
        const debugSnapshot: PathDebugSnapshot | null = debugEntries.length
          ? {
              pathId: updatedConfig.id,
              runAt,
              entries: debugEntries,
            }
          : null;
        configs[updatedConfig.id] = updatedConfig;
        const orderedIds = pathOrder.length
          ? pathOrder
          : orderedConfigs.map((config) => config.id);
        const safeConfigs = safeJsonStringify(configs);
        await fetch("/api/user/preferences", {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            aiPathsPathConfigs: safeConfigs || configs,
            aiPathsActivePathId: updatedConfig.id,
            ...(orderedIds.length > 0 && {
              aiPathsPathIndex: orderedIds.map((id) => ({ id })),
            }),
          }),
        });
        try {
          const configValue = safeJsonStringify(updatedConfig);
          const indexValue = JSON.stringify(orderedIds.map((id) => ({ id })));
          const debugValue = debugSnapshot ? safeJsonStringify(debugSnapshot) : "";
          if (configValue) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: `${PATH_CONFIG_PREFIX}${updatedConfig.id}`,
                value: configValue,
              }),
            });
          }
          if (debugValue) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({
                key: `${PATH_DEBUG_PREFIX}${updatedConfig.id}`,
                value: debugValue,
              }),
            });
          }
          if (orderedIds.length > 0) {
            await fetch("/api/settings", {
              method: "POST",
              headers: { "Content-Type": "application/json" },
              body: JSON.stringify({ key: PATH_INDEX_KEY, value: indexValue }),
            });
          }
        } catch (error) {
          logger.error("Failed to persist AI Paths settings snapshot", error);
        }
      } catch (error) {
        logger.error("Failed to persist AI Paths runtime state", error);
      }
    } catch (error) {
      logger.error("Failed to run AI Path trigger", error);
      toast("Failed to run AI Path trigger.", { variant: "error" });
    }
  };

  const handleTranslate = async () => {
    logger.log("Translating product...");
    setTranslating(true);

    try {
      if (!product?.id) {
        throw new Error("Product must be saved before translating.");
      }

      const enqueueRes = await fetch("/api/products/ai-jobs/enqueue", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          productId: product.id,
          type: "translation",
          payload: {}
        }),
      });

      const enqueueData = (await enqueueRes.json()) as { error?: string; jobId?: string };
      if (!enqueueRes.ok) throw new Error(enqueueData.error || "Failed to enqueue translation job.");

      logger.log(`Translation job ${enqueueData.jobId} created successfully.`);

      // Show success message - user can check Jobs page for progress
      toast("Translation job created successfully. Check the AI Jobs page for progress.", {
        variant: "success"
      });

    } catch (error) {
      logger.error("Failed to translate:", error);
      toast(
        error instanceof Error ? error.message : "Failed to create translation job.",
        { variant: "error" }
      );
    } finally {
      setTranslating(false);
    }
  };

  return (
    <div className="space-y-4">
      {!hasCatalogs && (
        <div className="rounded-md border border-amber-500/40 bg-amber-500/10 px-4 py-3 text-sm text-amber-100">
