  useEffect,
} from "react";
import { useQueryClient } from "@tanstack/react-query";
import {
  UseFormRegister,
  UseFormSetValue,
  UseFormGetValues,
  FieldErrors,
  FormProvider,
  useForm,
  Resolver,
} from "react-hook-form";

import type {
  CatalogRecord,
  ProductWithImages,
  PriceGroupWithDetails,
  ProductFormData,
  ProductDraft,
} from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
