"use client";

import { useState, useEffect } from "react";
import { AppModal, Button, Input, Label } from "@/shared/ui";
import { Save, X, Plus, Loader2 } from "lucide-react";
import type { Asset3DRecord, Asset3DUpdateInput } from "../types";
import { updateAsset3D } from "../api";

interface Asset3DEditModalProps {
  open: boolean;
  onClose: () => void;
  asset: Asset3DRecord;
  onSave: (updated: Asset3DRecord) => void;
  existingCategories?: string[];
  existingTags?: string[];
}

export function Asset3DEditModal({
  open,
  onClose,
  asset,
  onSave,
  existingCategories = [],
  existingTags = [],
}: Asset3DEditModalProps) {
  const [name, setName] = useState(asset.name ?? "");
  const [description, setDescription] = useState(asset.description ?? "");
  const [category, setCategory] = useState(asset.category ?? "");
  const [tags, setTags] = useState<string[]>(asset.tags);
  const [newTag, setNewTag] = useState("");
  const [isPublic, setIsPublic] = useState(asset.isPublic);
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    setName(asset.name ?? "");
    setDescription(asset.description ?? "");
    setCategory(asset.category ?? "");
    setTags(asset.tags);
    setIsPublic(asset.isPublic);
    setError(null);
  }, [asset]);

  const handleAddTag = () => {
    const trimmed = newTag.trim().toLowerCase();
    if (trimmed && !tags.includes(trimmed)) {
      setTags([...tags, trimmed]);
      setNewTag("");
    }
  };

  const handleRemoveTag = (tag: string) => {
    setTags(tags.filter((t) => t !== tag));
  };

  const handleSave = async () => {
    setIsSaving(true);
    setError(null);

    try {
      const data: Asset3DUpdateInput = {
        name: name.trim() || null,
        description: description.trim() || null,
        category: category.trim() || null,
        tags,
        isPublic,
      };

      const updated = await updateAsset3D(asset.id, data);
      onSave(updated);
      onClose();
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to save");
    } finally {
      setIsSaving(false);
    }
  };

  const formatFileSize = (bytes: number) => {
    if (bytes < 1024) return `${bytes} B`;
    if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
    return `${(bytes / 1024 / 1024).toFixed(2)} MB`;
  };

  return (
    <AppModal
      open={open}
      onOpenChange={(o) => !o && onClose()}
      title="Edit 3D Asset"
    >
      <div className="bg-gray-900 rounded-lg shadow-2xl w-[90vw] max-w-lg border border-gray-700">
        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-gray-700">
          <h2 className="text-lg font-semibold text-white">Edit 3D Asset</h2>
          <Button variant="ghost" size="icon" onClick={onClose}>
            <X className="h-4 w-4" />
          </Button>
        </div>

        {/* Content */}
        <div className="p-4 space-y-4 max-h-[60vh] overflow-y-auto">
          {/* File Info (read-only) */}
          <div className="p-3 bg-gray-800 rounded-lg text-sm">
            <p className="text-gray-400">
              <span className="text-gray-500">File:</span>{" "}
              <span className="text-white">{asset.filename}</span>
            </p>
            <p className="text-gray-400 mt-1">
              <span className="text-gray-500">Size:</span>{" "}
              {formatFileSize(asset.size)}
            </p>
          </div>

          {/* Name */}
          <div>
            <Label htmlFor="name" className="text-sm text-gray-300">
              Name
            </Label>
            <Input
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter asset name..."
              className="mt-1 bg-gray-800 border-gray-700"
            />
          </div>

          {/* Description */}
          <div>
            <Label htmlFor="description" className="text-sm text-gray-300">
              Description
            </Label>
            <textarea
              id="description"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Enter description..."
              rows={3}
              className="mt-1 w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-md text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
            />
          </div>

          {/* Category */}
          <div>
            <Label htmlFor="category" className="text-sm text-gray-300">
              Category
            </Label>
            <div className="mt-1 flex gap-2">
              <Input
                id="category"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                placeholder="Enter category..."
                list="categories-list"
                className="bg-gray-800 border-gray-700 flex-1"
              />
              <datalist id="categories-list">
                {existingCategories.map((cat) => (
                  <option key={cat} value={cat} />
                ))}
              </datalist>
            </div>
          </div>

          {/* Tags */}
          <div>
            <Label className="text-sm text-gray-300">Tags</Label>
            <div className="mt-1 flex gap-2">
              <Input
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add tag..."
                list="tags-list"
                className="bg-gray-800 border-gray-700 flex-1"
              />
              <datalist id="tags-list">
                {existingTags
                  .filter((t) => !tags.includes(t))
                  .map((tag) => (
                    <option key={tag} value={tag} />
                  ))}
              </datalist>
              <Button
                type="button"
                variant="secondary"
                size="icon"
                onClick={handleAddTag}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            {tags.length > 0 && (
              <div className="flex flex-wrap gap-1 mt-2">
                {tags.map((tag) => (
                  <span
                    key={tag}
                    className="inline-flex items-center gap-1 px-2 py-1 bg-gray-700 text-gray-300 rounded text-xs"
                  >
                    {tag}
                    <button
                      type="button"
                      onClick={() => handleRemoveTag(tag)}
                      className="text-gray-500 hover:text-red-400"
                    >
                      <X className="h-3 w-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Visibility */}
          <div>
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={isPublic}
                onChange={(e) => setIsPublic(e.target.checked)}
                className="rounded border-gray-600 bg-gray-800 text-blue-500 focus:ring-blue-500"
              />
              <div>
                <span className="text-sm text-white">Public visibility</span>
                <p className="text-xs text-gray-500">
                  Make this asset accessible publicly
                </p>
              </div>
            </label>
          </div>

          {/* Error */}
          {error && (
            <div className="p-3 bg-red-500/10 border border-red-500/30 rounded text-red-400 text-sm">
              {error}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-2 p-4 border-t border-gray-700">
          <Button variant="ghost" onClick={onClose} disabled={isSaving}>
            Cancel
          </Button>
          <Button onClick={() => void handleSave()} disabled={isSaving}>
            {isSaving ? (
              <>
                <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                Saving...
              </>
            ) : (
              <>
                <Save className="h-4 w-4 mr-2" />
                Save Changes
              </>
            )}
          </Button>
        </div>
      </div>
    </AppModal>
  );
}

"use client";

import { AppModal, Button, Label } from "@/shared/ui";
import { Viewer3D, type LightingPreset, type EnvironmentPreset } from "./Viewer3D";
import {
  Download,
  X,
  Sun,
  Moon,
  Sparkles,
  RotateCcw,
  Settings2,
  ChevronDown,
  ChevronUp,
  Eye,
  Layers,
} from "lucide-react";
import { useState } from "react";
import type { Asset3DRecord } from "../types";
import { cn } from "@/shared/utils";

interface Asset3DPreviewModalProps {
  open: boolean;
  onClose: () => void;
  asset: Asset3DRecord;
}

const environmentPresets: { value: EnvironmentPreset; label: string }[] = [
  { value: "studio", label: "Studio" },
  { value: "sunset", label: "Sunset" },
  { value: "dawn", label: "Dawn" },
  { value: "night", label: "Night" },
  { value: "warehouse", label: "Warehouse" },
  { value: "forest", label: "Forest" },
